begin;

insert into public.lesson_records (lesson_record_id, student_id, course_id, staff_id, lesson_date, start_time, end_time, title, content, homework, memo) values
  ('e8ab5413-69f5-5407-8605-bdecf40566dc', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-07-08', '16:30:00', null, '通常 / 親子大会作品の作成続き', 'クレーンの部分は完成している、とのことなので、大会のサイトを見せ、テーマが必要なことを説明しました。 テーマの中から「八王子」を選ぶことに決め、クレーンゲームでゲットしたクリオネと八王子の観光名所を組み合わせたい、ということになりました。 八王子の観光案内を調べて、行ったことのある5か所を選び、写真を取り込んで背景を作成しました。写真は八王子市のサイトなどから暫定的に借りています。 選んだ名所はファイルにはさんでおきました。高尾山、陣馬山、夕焼け小焼けの里、サイエンスドーム、エスフォルタアリーナ八王子が候補です。 お迎えのお母さんに、もし上記の写真があれば用意してほしいとお伝えしました。', null, 'タイピング: 学校でやったからいい、とのことでした。最近ホームポジションを意識して打っているそうで、自分の名前をブラインドタッチで打って見せてくれました。
盛り上がり: ゲームの内容が一気にふくらんできたので、気分も新たに楽しそうに作成していました。 そうすけくんに慣れてきて、作っているものを見せ合ったり、話しかけたりすることもありました。'),
  ('3ab31646-c1fe-5935-89ed-e313375b79b4', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-07-08', '16:30:00', null, '通常 / スキルチェックをしながら作品作りを楽しむ', '前回まで作成していたシューティングゲームは、もうやりたくない、とのことで、新しい作品か、気分転換と力試しのために検定関係も勧めてみましたが、どれも反応がイマイチでした。 新しいことに抵抗があるようだったので、自分の過去の作品を見て、今ならできることが増えているから新しいアレンジを思いつくかも、と提案してみると、ちょっと嬉しそうに作品の振り返りを始めました。 過去の作品のデザインアレンジやアイディアをいくつか褒めるとちょっとやる気になってきて、3つくらいの作品に手を加えてゲームバランスの調整などをしていました。 過去にアレンジしていた「ピンポンゲーム＿コンピュータ（チート使い）と対戦」のアイディアが面白かったので、ちゃんとプレイできるように完成させて公開してみないかと声をかけると、真剣に取り組んで、作品の説明も丁寧に書いてくれました。 話しかけ方次第で会話がはずむようにもなってきて、祥太君とも話すようになりました。 祥太君が観光名所を選んでいるときに、滝山城址の話や陣馬山の標高などに詳しいところを披露してくれました。', null, '盛り上がり: もうすぐ日光に行くのだと楽しみにしていました。最後に公開を目指してアレンジと説明を書きをしたピンポンゲームについては、私や祥太君が面白がったこともあり、とても熱心に向き合っていました。'),
  ('988931be-c31b-5609-ade4-3417c289bf64', '337872be-4ce4-5436-88f8-5f97e8c5252e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-07-08', '17:30:00', null, '通常 / スキルチェックのための検定問題チャレンジ', 'スキルアップとスキルチェックのために、検定問題をやってみないかと勧めてみると、素直に問題を選んで始めました。 3級の問題はさすがに簡単だったようで、30分以内に余裕で完成させていました。さすがに簡単だったようで、アレンジをするまでもなかったので、新しいものをもう一つやってみたい、と自分から申し出てきました。 2級のスロットマシーンの問題について、面白そうだけど難しいかも、と躊躇していたので、難しくても苦手なところのチェックになるから、とフォローをした上で始めました。 やり始めてみたら想像以上に簡単だったようで、20分くらいで最後まで解き終わって、コインの出方やスロットの速さを難しくしたりして遊んでいました。 問題文を読んで作成することに対しては、まったく抵抗がないようで、作品作りとして楽しめていたようでした。', null, '盛り上がり: 実際にやってみたら、自分の予想以上にスラスラとできたというのが嬉しかったようでした。 定義やリストに自信がないというので1級はまだ難しいですが、この辺りを少しずつ覚えて、いろんな問題を楽しんでみようと声掛けをすると、素直に喜んでいました。'),
  ('f338ac02-f2ce-568a-b7cc-3c2659c9f5c3', '1c7005cc-2815-558f-993a-9c7617d34c44', null, null, '2025-07-08', '16:30:00', null, '休み（未対象）', null, null, null),
  ('f38b8f6b-09a1-5c5a-9fbd-13e7916a03bc', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-10', '16:30:00', null, '通常 / 親子大会作品作り', '今回は残り春、夏を作っていきました。ここで、メッセージ名がテキトーになっていたので、わかりやすいように変えてくれました。普段なら面倒くさいと背くと思ったが、従順に作り直してくれました。前回の次の季節に移り替わる流れができていたので、ここからは自分でどこまでの動きを春、夏とするのか自分で組み立てられていました。次回はそれぞれの季節で背景を作るそうです。', null, null),
  ('d272eabd-65e1-5777-8149-4b413fc2399f', '0d16e234-e60d-5fdb-978f-1722acf9a2b2', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-07-10', '16:30:00', null, '通常 / アルスタジオレッスン/ゾンビをたおせ1', '今回はレッスンのゾンビをたおせ1をやって，向きと動きの関係性について学んでいきました．動画を見ながらの制作で詰まることもあるかと思いましたが，一緒にやっていく中でも自分で解決できた部分も多くあり時間内に終えることができました．戸惑っていたこととしては，プログラムについてではなくパソコンの操作で戸惑っていたことが多かったので，制作を行っていくなかで確認していければ良いと思います．', null, null),
  ('2f13aec8-c336-5960-a63b-1cb778b8ae8f', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-07-10', '16:30:00', null, '通常 / 曹', '魔女のキャラクターを作成したいとのことでしたが「どうすればいいかわからない」とのことだったので、まず画像を検索させて資料を調べてからデザインしたいキャラクターの要素を考えてもらうことにしました。アイビスペイントを使って以前八王子のイベントで使った人型の素材をもとに絵を描いてもらいました。', null, 'タイピング: なし'),
  ('2947867e-f653-596e-924b-da83dc427089', '57f45872-1f3e-5540-b676-bf9023444e39', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-10', '16:30:00', null, '通常 / 親子大会つくり', '球種を作っていましたが、明らかに前回まで作っていた作り方の流れが飛んでいます。座標認識も見え張る癖があるので、理解度があやふやです。「カーブ」の球の軌道を切り替えがどの座標までよいかわかりにくく感じていたので、山なりの曲がりを3つに分けて考えてあげました。そのあとは、数値を自分で調節してやってみてでしたが、この試行錯誤が苦手だとみて感じられます。', null, null),
  ('a592d3bf-34b4-5c36-9e5b-bf9902bfc7d4', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-07-10', '17:30:00', null, '通常 / イラストコース_キャラクターデザイン', '前回も女の子のキャラクターデザインを考えてくれましたが、今回はまた別のデザインを考えてもらうことにしました。デザインのコンテストということでかなりイメージを膨らませて描いてくれました。自分で手の動きをアレンジして描いたりしていたのが良かったです。', null, null),
  ('f2abc7fa-8114-53af-87af-934dee622a63', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-07-10', '17:30:00', null, '通常 / 親子大会作品制作', '大会作品制作の続きを行っていきました．シューティングゲームを作成しているため，敵が段階的に出現して，最後にボスが登場するまでの流れについて完成させていきました．敵の内容については既に決まっているようなので，次回以降の制作で一気に完成まで近づけていくことができると感じました．', null, null),
  ('954c1daa-31d2-5a67-87a2-2b9e527625a2', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-07-10', '17:30:00', null, '通常 / U13大会作品制作', '大会作品制作の続きを行っていきました．ゲーム内容として，オープニングがストーリーになっているため，プレイヤーが操作する前の部分のストーリーを制作していきました．やりたいことやゲーム内容は既に決定しているため，スラスラと作っていくことができました．今回でオープニングは完成させることができたようなので，次回からはゲーム部分を本格的に作っていきたいです．', null, null),
  ('b5406c46-0613-5f5c-b86a-15e679102a2e', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-10', '17:30:00', null, '通常 / 親子大会作品つくり', '今回は門を破壊された後の櫓のステージについて作っていきました。敵が通る道筋を作ったり、ステージが切り替わるところにセリフを追加したりしていきました。前回、ステージ切り替えで「まで待つ」のブロックを使って作成しましたが、今回はその機能について忘れている感じがしたので、再度確認を行いました。次からは、守る側に勝利演出がなかったので、変数「タイマー」を使ってセリフなどを追加していく予定です。', null, '盛り上がり: たいようくんの隣に座って作っていますが、話が弾んでたいようくんの画面に集中してしまい、自分の画面が進んでいない場合が多いです。'),
  ('83c3aea5-f2ba-5af7-b70c-011fa0e556a2', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-10', '17:30:00', null, '通常 / U16大会つくり', '最初にU16大会の日程の締め切りを伝えると、本人的に短いと感じてました。締め切りは10月中ですが、9月までに余裕をもって終えたいところです。内容は、使う武将が作り揃えたところです。それで、戦いの部分を作成のために、参考にしているゲームを見て、使え層の部分を探していました。元のゲームはかなり定義で引数を使っているので、たいようくんなりに自分で作れるコードを模索している最中です。', null, null),
  ('a0fc1ef2-ff2c-5aa9-8316-569cc858e86c', 'd3885e29-ee68-501b-bf31-6c050fd50c36', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-07-11', '16:30:00', null, '通常 / 親子大会', 'コードがごちゃっとしていてバグの原因になっていたので右クリックで「きれいにする」を教えると、わかりやすいと言って整理していました。作業内容としては、場面切り替えのときにスプライトを隠すのと、ジャンプゲームのプログラミングをしました。作らないといけない処理を紙に書いて細分化し、それを1つずつtodoリストのように終えていくという方式を取ってみたところ、今何をやらないといけないのかがはっきりしたようで集中して進めてくれました。', null, '盛り上がり: 気が散るときもあるのですが、スイッチが入った時は「どうすれば優勝できるかな」などと意欲を示しています。'),
  ('5e62a88e-a9ec-5c22-a734-d66c20dbbf10', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-07-11', '17:30:00', null, '通常 / roblox', '前回roblox studioで自由作成した作品は活路を見いだせずボツにしてしまったとのことで、動画教材の中から興味の持てそうなものがないか見てもらいました。するとコロコロボーリングが気に入って作り始めてくれましたが、自分のオリジナル要素も入れたいというのは譲れないようでした。ただ、「試合開始までの時間を表示できるようにしたい」と言っているので、そこからprint,wait関数などの学習につなげられそうです。また今回作るゲームでは、robuxで買えるゲーム内アイテムを設置して稼ぎたいという目標ができたので、今度はボツにはならなそうです。', null, null),
  ('e27c5328-e390-53e4-bed3-bdb34eee9697', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-07-11', '18:40:00', null, '振替 / 親子大会', '締め切りについて把握していなかったようなので、あと2回のレッスンで完成させないといけない話をしたところ頑張って進めてくれました。たくさんのブロックがあることで作成時間がかかってしまいそうでしたが、本質的にやりたいことを考えた結果、ブロックは3種類くらいにしぼっても大丈夫だという結論になりました。なめらかに横スクロールすることに夢中でゲーム性があいまいだったのでどうするのかを問いかけると、マグマのブロックをジャンプでよけないとゲームオーバーということに決めていました。またそのためにコスチュームからマグマブロックを作りました。次回は色判定でゲームオーバーを作ればよさそうです。※ルール説明など自力でできそうな部分は作成を家で進めてもらうことになりました。それでも厳しそうな場合、8月分の振り替えを7月中にして対応する可能性があります', null, null),
  ('afe0990a-f756-5e24-a6ba-db340e06e221', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-07-11', '16:30:00', null, '通常 / 親子大会作品制作', '今日を含めて残り３回なので、次回にはほぼ完成できるようにしようということで意識づけをして始めました。最初に、ゲーム画面の背景を完成させたいとのことだったので、その部分を作成しました。関西空港のような海に囲まれた空港にしたいということで、海の色で飛行場を囲んで、飛行場の建物、橋、管制塔等細かいものまで背景として作っていました。その後は、赤い飛行機の動きがおかしということで、バグ取りのようなものをしていましたが、それに時間がかかってしまい、肝心の、ゲーム性の部分（どのようにすればゲームクリアになるのか？スコアや制限時間等入れたり？等々）の作りこみができませんでした。本人は、そこまでゲーム性を持たせることしなくても、飛行場シミュレーションのようなものでも良いとは言っているので、来週には、どのような完成形にするかをきっちりと決めて、その方向性である程度完成一歩手前くらいまでは進めたいところです。', null, null),
  ('1e426f76-753e-5f7e-a762-21569d940b70', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-07-11', '17:30:00', null, '通常 / 親子大会作品作り', 'Undertail風味の対戦ゲームのようなものを作っていました。最初にある君が、レクチャーがてらゲームの遊び方を教えてくていて、「弾幕を避けてね」みたいな説明が出てから、実際に弾幕が発射されて、それを避ける処理（避けられなかったらHPが減ってゲームオーバー）まではできていました。最初にちょっとしたバグ修正をしてから、弾幕避けた後の処理を作っていきました。弾幕の後の処理は、攻撃の仕方の説明と、実際に攻撃をする部分なのですが、この処理の作成で時間切れになりました。具体的には、ある君が「攻撃ボタンを押してね」との説明後、「kougeki」ボタンを押すと、照準となるスプライトが左右に動きながら表示されます。その動いている照準をクリックできると、アル君の体力が減っていく仕組みですが、照準クリック処理のところで今日は終わってしまいました。やりたいことは、照準を簡単にはクリックできない速度で動かして、クリックできたら、アル君の体力（初期値は変数で３に設定）が１減るようにする。アル君の体力はハートマークで、左上に表示させたくて、ハート３つのコスチューム、ハート２つのコスチューム、ハート１つのコスチュームを作って、ある君の体力が減るたびに、コスチュームを切り替えていって、体力が０になったらアルくんの撃退に成功し、次の処理に移るという流れ。本当は、敵を何体も用意して、順々にやっつけていくようにしたかったらしいのですが、時間がないので、もしかしたら、アルくん退治の処理を完璧に作るだけで終わりになるかもです。その辺は、話しながら完成形を決めていくしかないのかなと思います。', null, null),
  ('6aa3d174-d20e-5da3-a4dd-71fdb90fb0ce', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-07-11', null, null, '通常 / robloxの続き', 'レインボーロードの動画を見ながらコツコツと進めていましたが、途中何回か動画が途中で止まってしまう現象が起こってしまい、デジタネを一旦閉じて、また開くときちんと再生されるようになりました。デジタネのサーバー（？）の問題なのか、たまにこのようなことが起こるようなので気になります。レッスンに関しては、スクリプトでパーツの色を変えることをしっかりとできていて、問題なく進められましたが、全て終わらせることはできなかったので、次回はレインボーロードの続きからとなります。', null, '時間帯: その他'),
  ('23d565f4-f682-5478-91b1-b75423f89a35', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-07-11', null, null, '通常 / エクセル・Roblox', 'エクセルとロブロックスを交互にやる予定となっているのですが、ロブロックスを進めたい熱が高いようで、エクセルを少し進めてからロブロックスをするということにしました。エクセルの一つの演習を終わらせてからロブロックスに進みました。デジタネは、動画とテキストの二つを用意してくれているのですが、今日は動画ではなくテキストベースで進めました（なので、デジタネの進捗が進んでいないように見えますが、すべて終わらせた上で確認問題をしています）。人によっては、ゆっくり喋って時間のかかる動画よりも、テキストを見て進めたほうが良いこともあるかと思います。スクリプトで、Partの色を変えることと、そのスクリプトの書き方、waitで処理の待ち時間を入れること等、きちんと理解して、確認テストも１００％でレインボーロードを終わらせました。次からは少し動きが出てくるのでより楽しみながら挑戦できると思います。', null, '時間帯: その他'),
  ('c28f9fa9-1d43-5e48-8ede-af103c7dfdce', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-07-12', null, null, '通常 / roblox', '寿司だに結構夢中でしたが、それを終わらせた後に、コロコロボーリングの動画を見始めて、特に質問等もなく、順調に進めていたように思います。大体６０％くらい終了した状態なので、次回ロブロックスはその続きからとなります。', null, '時間帯: その他
タイピング: 集中して取り組んでいました。レッスン終了後も何回か挑戦していました'),
  ('ab241816-99da-5c9e-ba28-6067239b1b7d', 'ec153bd8-5b4d-5684-9704-382af23cf64a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-12', null, null, '通常 / 親子大会作品作り', '着々と周りの部分が埋まっていきました。ショップ画面でボタンが押されたら能力アップする仕組みを作っていました。イベントの「押されたら」はあるが、それを使わずに作成したいとのことだったので、触れると押されたのかつ条件を教えてあげました。「かつ」について話した時、初めて知るようなリアクションだったので、これで条件を使う幅が広がったと思います。本人的には次回で終わると言っていました。', null, '時間帯: その他'),
  ('8d71cd6c-ab71-5793-b50e-104cd55dc958', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-12', '16:30:00', null, '通常 / Excel', '最初はガサガサ関係の時間をつぶしていました。エクセルに取り掛かると、今回は畏怖分のところだったので、例題はすんなり進めましたが。実習18では時間がかかっているように思えました。まだ、途中なので復習でよく見た方がいい気がします。', null, null),
  ('cb1cd4a8-7201-5206-a4c9-b851eb4e7518', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-12', '16:30:00', null, '通常 / 親子大会作品作り', '前回オーバーの演出を作りかけであったが、時間が空き気が変わって別のものになっていました。オーバーでは悪者が出現する演出でよくなっていました。クリアの演出はスコアで作るように条件を提案して、自力で作れていました。だが、演出の方は、見ないすきにスプライトであふれていました。手が詰まるとスプライトを多く持ってきてしまう傾向があるので、恐竜に絞りました。決まりさえ巣rば、音をつけたり、演出もこだわってくれました。', null, 'タイピング: よくやっていました'),
  ('fdc4d2bd-74b4-56d2-9116-8661bba8d4fa', '655ad2c9-dfb5-5fc7-b41a-1d784603c1d0', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-07-12', null, null, '通常 / 変数の使い方を覚える', '変数の使い方をレッスンしました。○歩動かすの「歩数」や、クリック時の「クリック数」等、３パターンの変数の使い方を教えて、すべて理解してくれました。集中力も理解力も素晴らしいと思います。飲み込みが早いので、予定した計画以上のことを教えてしまいましたが、若干詰め込み過ぎたかもしれません。少し休憩等適切に取りながらすべきだったかなと思ったりもしました。', null, '時間帯: その他
タイピング: 今日も集中して取り組み、上位１３％で、納得がいかなかったらしく、もう一回挑戦して上位１１％となりました。いずれにせよかなりすごいと思います。ブラインドタッチとかもっと早くなる方法を教えたらもっと伸びるような気がします'),
  ('e0336176-d7f8-57f5-86a0-5bc3269eca00', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-12', null, null, '通常 / 親子大会作品作り', 'パズルのかげぶしゃを使う方法を共有しました。その前に、パズルの分割に時間が買ってしまい、一通りの流れを教え終わったときには、時間が終わっていました。全体的に見ればあまり進んでイなのですが、繰り返しの作業があるので、家で整えてくれると思います。', null, '時間帯: その他'),
  ('0d4c4fec-b451-5346-9b0b-077e3a520ae8', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-12', null, null, '通常 / エクセル', '3の続きをやっていきました。流れの中で、並び替えのやり方にわからなくて、苦戦していました。今回は見れてない部分もあるが、全体的に時間がかかっている気がします。ショートカットなどの要素を復習した方がいいと思います。', null, '時間帯: その他'),
  ('279dec38-9c2f-51eb-bc7f-b5251496a3a9', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-07-12', null, null, '通常 / 親子大会作品作り', 'ホラーゲームの制作の続き。ホラーな背景をうまく作れていたと思います。ゲーム自体は、それぞれの処理（ライフルを打つ、敵が迫ってくる、体力の増減）等はある程度できているようですが、その処理を使って、どのように終わらせるかまではできていないので、次回に、ある程度形のあるものにして、完成一歩手前まで持っていきたいところです。', null, '時間帯: その他
タイピング: 親にローマ字をやれと言われているとか言って、プレイグラムを集中して取り組んでいました'),
  ('253a88ea-41ea-59f9-8a6f-692bd0dc1679', '49fc73e4-fc37-5c75-a77f-02a27f5e169b', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-07-12', null, null, '通常 / 基礎の復習', '以前覚えた基礎の復習をするよというと、「もう忘れた」「覚えたない」等のネガティブな言葉を返されて、じゃあ初めて覚える感じでも良いからと、レベル１の最初からはじめましが、いきなり最初から脱線してしまい、「○歩動かすというブロックを持ってきて」というのに対して、「僕これ知ってる」と、◯度回すみたいなブロックを勝手に使いはじめて、スクリプトをくるくる回転させはじめて、○歩動かすの処理に戻ろうとするも、また別の脱線が始まりと、決まった順番で進めることができない状態でした。ですので、その時のやりたい事、今回でいえば、レベル１の問題をペラペラめくって、これやってみたいというのがあって、それを写経してもらって、動かして、また脱線してみたいな感じで進める形になってしまいました。できるだけ新しいものを覚えてほしいので、スプライトが右に少し動いて、別のスプラライトに接触するくらいのタイミングでうまく効果音を鳴らすようなことを試して喜んではいました。（赤ちゃんスプライとに、剣が刺さるみたいなシチュエーションだったので、正直あまりやりたくはなかったですが、切り付ける音の効果音を鳴らしました）。予定通りにはなかなか進まないので、レッスン中に何か一つでも覚えられるものがあれば良いのかなと思いました。', null, '時間帯: その他
タイピング: F,G,Hのキーを叩くだけなのですが、どこを押せば良いかわからないという感じでぐちゃぐちゃにキーボードを叩いていました。何かおかしいなと思ったら、ココアタイピングの表示は大文字のFGHに対して、用意されたPCでは、小文字のfghでした。この辺も影響してたのか？それとも、ただ単に、ガチャガチャ叩いていただけなのかは微妙な感じですが、大文字、小文字は合わせた方が良いですね。'),
  ('dd5eb2d0-2036-53e7-bac5-bba3be375d77', '5b56509a-ab37-5b95-9b2b-2750525ad8a5', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-07-12', null, null, '通常 / U16作品作り', '前回、ゲームの進め方終わり方等のイメージがあまりないようだったので、その辺を考えておいてねと言っていたのですが、その辺も考えて、家で作品作りも進めていたようです。その続きを教室でしていて、順調だというので、たまに様子を伺う程度だったのですが、途中、動きがおかしいということで、一緒に挙動を見ていきました。プレイヤーキャラがブロックに接触した際に、いきなりY座標がぶっ飛んでしまうみたいな事象が見られたので、起きた事象から、Y座標が変に上書きされてしまう理由を推測しました。その時の、推測に至る考え方や、デバッグ手法についてアドバイスをして、実際にその推測が正しく、そのバグを修正することができました。りゅうとくんはやっていることが割と高度で、スクラッチの知識は問題ないので、スクラッチをレッスンするというよりは、スクラッチ向けというよりは一般的なプログラミング手法やらデバッグ方法についてアドバイスすることが多いです', null, '時間帯: その他'),
  ('aa78ceb4-6460-5003-8acd-d33b6b470ffb', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-07-12', null, null, '通常 / 親子大会作品作り', '最初に、バグがあるから一緒に見てほしいとのことだったので、スクリプトを見て、一つ条件文が抜けているところを発見したので、直すことができました。これは、スクリプトが若干ゴチャゴチャし過ぎたからというのも原因の一つなので、もう少し綺麗にスクリプトを書いた方が良いとは伝えました。 その後に、実際に私がプレイして、気になるところを何点か指摘しました。最初のゲームプレイの説明文を１０秒だけ表示となっていたのを、１０秒待たせるのではなく、スタートボタン設置して、プレイヤーが説明を読んだらスタートボタンを押してプレイを開始して貰えば良いという言葉に納得したらしくその通りに修正していました。また、出題が切り替わるタイミングがわかりづらいので、出題が切り替わったら、何か効果音を鳴らして、切り替わった出題文を一時的に大きく表示して、すぐ小さく戻るという処理を入れようかという話にまとまりましたが、それはできなかったので、来週入れたいとのこと。それを入れて、ゲームクリア時の処理をなんとかすれば、大体完成形になるとのことでした。', null, '時間帯: その他'),
  ('34561252-0e88-5068-90c4-1c8446fc269a', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-06-28', null, null, '通常 / roblox', 'いつも通り15分遊んでから取り掛かりました。それでも途中それることが多かったので、わけを聞いてみると、「期末テスト前だから遊ばせて」と。ふむ、まあ仕方がないと言えるか？今回はライトの光に関するところなので、真面目に見てほしいです。', null, '時間帯: その他'),
  ('c92008e4-84d7-5eb2-b752-59a409174871', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-12', null, null, '通常 / ロブロックス', '前回テキトーな進みだったので、光の範囲とブライトネスについて解説していきました、最初から白とびのような光加減だったので、そこを意識させました。ほかに、作成画面についてウィンドウの機能管理がうまくいっていなかったので、そこも説明しました。内容としてはほんの少しでしたが。機能面では大いに進歩できたと思います。確認テストが済んでいないので、そこからやるように', null, '時間帯: その他
盛り上がり: いがいとこうしろうくんとゲーム仲間として仲が良いです。'),
  ('be4e3dfd-3ca6-54b2-8a97-6db3e3a5b19f', '80660755-d846-5cdd-91a4-0ab78fe29034', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-07-12', null, null, '通常 / 親子大会', '隔週で時間がないので、今日である程度完成形に近づかないといけないと話したところ、冷静かつスムーズに進めてくれました。前回作れなかったゲームオーバーについては最初少し詰まっていましたが、色判定+変数「移動距離」を使うというヒントを出したところ、きちんと頭の中で処理が組み立てられていました。あとはコースをもう少し伸ばしました。階段状にしたり大きな障害物を置いてみたりと面白味を出し、テストプレイで難易度を調整していました。 ほとんど完成にはなっている(やるとすればクリア演出くらい？)ので、次回は早めに提出作業に移れそうです。', null, '時間帯: その他'),
  ('301d1029-b183-58c8-be68-21e70b96e510', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-14', '16:30:00', null, '通常 / 親子大会作品作り', '前回のスマブラバグがよくわからなかったので、とりあえず、元のキャラをもう一度コードごと持ってこさせるようにしました。そこで、互換性があるように名前を変更させたりしました。ほかにバグが感じていた必殺技が大きくなりすぎると、でなくなる問題は、大きさに上限を設けることによって、解消することができました。比較的に、コードを直すときは切り替えができて進めているので、本人がどこで迷っているかわかりやすかったです。 元の作品のイラストがパクリにならないようにステージも変更することができました。 あとはゲームの進行に支障はないが、変数名やメッセージ名を変えられたとよく、ゲームに所掌がある技の吹っ飛びが反映されないバグも直していきたいです。', null, null),
  ('997dc0d2-3042-57b6-81e3-176ba3f9a8aa', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-14', '16:30:00', null, '通常 / 親子大会作品作り', '授業前から早くゲームを作成し終わりたいと言って制作にとりかかっていましたが、隣でゲームしているゆうさくくんに気を取られ、全く進んでなかったです。授業中もその現象はたびたび出ていました。がくくんは切り替えがうまくいかないような子です。クリアから作成していくのことでしたが、先生が「メッセージ」で作成しようと提案しても、どのブロック化わからないと言ってきました。前回まで使っていたやろの突っ込みを入れたいところです。コードの定着がまだ進んでないようです。それから1個1個指示して、なんとか作れていました。OPがまだなようなので次回作成', null, null),
  ('1d6ae9a0-9320-5c89-9d9f-9f8142d6ce11', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-14', '17:30:00', null, '通常 / エクセル', 'もくもくとやり続けてくれました。VLOOKUPや文字列に関する関数などありましたが、不都合なく着々と進めれていました。', null, null),
  ('fc2b91ad-d5c1-5a50-ab85-7d7bd6e49f09', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-14', '17:30:00', null, '通常 / 親子大会作品作り', '今回はメインのコード作りはほぼ完成していたので、背景などの細かい部分を修正していって今hした。電車の装飾や背景の架線など細かく作りこまれていました。ゲームのところに関しては、スピード調整に難ありだったので、最後に授業延長で調節していました。レバースイッチに関してマウスの位置の範囲に上下限あったのですが、困っていたので、コードのつながりを意識させながら教えていきました。見た目ほぼ完成なので、提出できそうです', null, null),
  ('a0033ff7-3fd0-5ea6-889b-9e0450e1b51e', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-07-15', '16:30:00', null, '通常 / 親子大会作品の作成続き', '八王子の名所を取り入れることで目新しさが出たのか、基本的に楽しそうに取り組んでいました。 背景の色にクレーンのアームの色がかぶることがあったせいか、1つのクリオネをゲットすると3つくらいがゲット済みのところにならんでしまう不具合が出たため、色に触れたらという判定ではなく、アームとクレーンのスプライトをわけて、スプライトに触れた判定に修正しました。その過程で、任意の位置を指定する「スプライトの〇座標」に引き算を併用する方法を学習しました。わりとスムーズに理解して活用できていました。', 'クレーンゲームの回数制限を作成したいとのこと。 また、使用していない変数や条件分岐があるので、時間があればコードの見直しを一緒にやってあげてください。', '盛り上がり: 移動教室や体験学習の行先、八王子祭りの経験など、作成しながら楽しそうに話していました。おしゃべりしながらも、きちんと作成を進められるところがさすがでした。
備考: お母さんにエントリーシートのお渡しと説明済み。'),
  ('bb32f396-fefc-5931-85cb-a0f85022c98f', '1c7005cc-2815-558f-993a-9c7617d34c44', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-07-15', '16:30:00', null, '通常 / 親子大会', 'これまで基本操作コースをやってきましたが、保護者アンケートでは親子大会に参加意欲があるとのことなので、これまで作成した作品で好きなものを選んでもらってそれをうまくアレンジする方向で進めました。ゾンビを倒せが個人的に気に入っていたようなので選んでいました。ゾンビとディラックのそれぞれに体力を設定したいとのことで、変数や「～に触れたら」を使って作りました。各ブロックの意味は理解してきていますが、置いてある場所がなかなか記憶に残らないので都度教える必要がありました。ただ、ゾンビで作ったコードと構造が同じものをディラックで作った際、反復練習のようになり少し覚えることができました。', null, '盛り上がり: 教室に来てすぐにやる気を見せ、レッスン時間前からプログラミングを始めました。'),
  ('4b4c4e04-5439-5fdb-89b5-d269670a2f3d', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-07-15', '17:30:00', null, '通常', '第1,第2ステージがそれぞれおわったときの背景やセリフの設定から始めました。メッセージ名の1と2を間違えるなどして変な動きになっていましたが、旗を押してからの時系列を追いながらメッセージの流れを確認し、バグつぶしをしました。それが終わるともう完成だと言っていましたが、もう少しゲーム性があるとよさそうなのでアイデアを話し合いました。制限時間をつけようという案が本人も気に入ったので変数「時間」を作ってつけてみました。その作成はほぼ一人でできました。', null, null),
  ('547ef6b7-cee4-5eef-b54f-70e976bc9fd7', '337872be-4ce4-5436-88f8-5f97e8c5252e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-07-15', '17:30:00', null, '通常 / 1級相当のスキルを獲得する', '今後の作成の幅を広げることと検定合格を目標とするために、1級相当のスキルを獲得しようという目標を最初に説明し、納得した上で課題を進めました。 リストについてはすぐに理解できたようですが、実際に作成するとなると、変数の「リスト番号」とリストの「リストの〇番目」「リストの長さ」の使い分けに少し混乱が見られました。何度か使用して慣れていけば大丈夫かと思われます。 リストを学習したので、新しいゲームをリストを使用して作る目的で、検定問題にもチャレンジしました。問題最後の方の定義とクローンが未履修の為、次回に持ち越しということで終了しました。', '検定問題の続きをしても構いませんが、定義とクローンの学習をしてから続きをしてもよいので、本人の希望次第で。特に希望がなければ、一度離れて定義の学習でもよいかと。', '盛り上がり: 新しい知識の獲得ということで、素直に話を聞いて熱心に取り組めていました。'),
  ('b5f71663-b6fa-5a02-9fcf-bebde9ffe1b4', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, 'd45d6c5d-18cd-5aa2-99ea-932c81442c55', '2025-07-15', '16:30:00', null, '通常 / 親子大会作品または自由制作', '親子大会については親御さんから参加を迷っているというご連絡があったため、今の作品を作り込んで、できたら提出してみてもよいのでは、という感じで始めてみました。今日はあまり拒否反応を見せず、とりあえず作品のアレンジに取りかかってくれました。（大原） 前に作成したピンポンゲームを元に作成しました。 効果音をつけたりお邪魔ボールの見た目をピンポンに寄せたりしていました。 跳ね返った回数を追加していましたがもう少しゲーム性(ステージを複数用意するなど)を面白くできると良いかなと思います。 加速器(ピンポンやお邪魔ボールなどが通った時速度が上がる)を次回作成したいと言っていました。（榊原）', null, 'タイピング: 毎回必ず取り組んでいます'),
  ('e2523767-1829-52d3-ac25-dc5cc78de6f8', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-07-17', '16:30:00', null, '通常 / 親子大会作品制作', 'イラスト部分の作成は途中までにして，作品のエンディング部分を作成していきました．今まで使用していたものではシンプルすぎてイマイチだということで，使用していたドラゴンを透過して別の背景にスプライトとして入れる形で変更していきました．プログラム部分は現在の状態で完成のようなので，次回作成しているイラストを完成させて作品に取り込めれば終了の予定です．', null, null),
  ('20c5ba70-7a80-56cb-8a7f-7b5dfb6a9e54', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-07-17', '16:30:00', null, '通常 / 親子大会作品制作', '今回は作品を完成させたため，シート上に作品内容を書いていきました．イチゴの反乱を軸に作成されているため，本人がどんな箇所を工夫したのかを重視して書いていきました．ステージが四季で区切られており，季節が変わると敵の攻撃手段も変わるという部分を特にアピールしていきたい様子でした．', null, null),
  ('4306a200-669e-50d1-aeb4-341c6e87fee3', '05439956-11b9-5ac7-a44a-3e6f5a6831d8', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-07-10', '16:30:00', null, '通常 / 親子大会作品の作成続き', 'U16大会の方が重複作品が不可だということで、自分で親子大会用の作品を作ってきていました。飛行機がCO2をどのくらい出しているかを可視化しているシミュレーションで、国内線の動きを入れるのが大変だった！という大作でした。 プログラムとしてやりたいことは自力でできているので、デザイン面などでの相談に乗る形のレッスンとなりました。 入賞を狙っているため、発表することを前提として、大きなスクリーンに映した時の見た目を考えた方が良いという話を熱心に聴いていました。文字と背景の色が近くて読みにくいところなどを指摘して調整していました。 他の大会などがあれば、そちらも出してみたいというので、選抜の東京都大会をComiruで紹介しました。親御さんからすぐに、本人がそちらも参加したいと言っている、との返事がありました。', null, '盛り上がり: とにかく大会に出す！という目的がはっきりしているため、とても一生懸命に作成に励んでいました。
備考: 親子大会、U13＆U16大会、選抜大会すべてエントリー予定です。'),
  ('c1845d14-61a6-5252-9b4d-0de53d0c2d1e', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-07-17', '17:30:00', null, '通常 / U-13大会作品制作', '前回でストーリー部分をほとんど終了することができたため，今回はゲーム部分に入っていきました．しかし，本人のこだわりが出てきたようで導入部分での火のつき方や燃え広がり方に時間を割いてしまい，思うように進みませんでした．次回はゲーム部分のみを作成していくようにする予定です．', null, null),
  ('f0c22bdb-3b8a-5ac8-b444-a22617c36ed3', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-07-10', '17:30:00', null, '通常 / IF関数のマスター、U16大会作品の作成続き', 'IF関数のネストについては、）の位置がわかりにくいようで、式の途中で毎回閉じていてエラーになっていました。)は最後にまとめるということが納得いかない、という様子だったので、Scratchの条件分岐のブロックを思い出してもらい、ブロックの終わりがどうなっているかを考えてもらったところ、すっきりと理解できたようでした。 残り時間は熱心にU16大会作品のストーリー作りを進めていました。', null, '盛り上がり: Excelも大会作品も、「難しい」とぼやいたりしつつも頑張っていました。他の子や先生とおしゃべりすることも増えてきて、教室に来ることを楽しんでくれているようです。'),
  ('db0cba74-3bd3-5b9d-a17d-4ca50ed046b3', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-07-17', '17:30:00', null, '通常 / 親子大会作品制作', '前回の続きから作成していきました．ゲーム部分は完成しているようなので，オープニング部分を作成していきました．どんなものを作るのかは既に決まっていたようなのでスラスラと作っていくことができていました．今回でほとんど作ることができたようなので，次回で完成と可能であればシート記入も行っていきたいです．', null, null),
  ('f4f63499-3c41-5fae-adb9-d4bd06c6ed86', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-07-11', '17:30:00', null, '通常 / 親子大会作品の作成', '家でお母さんと考えてきたという「すいはんき」を作成しました。 コンテストに出すということを意識してもらい、背景名をわかりやすく変えたり、コードの整理をしたりする作業を中心に行いました。 メッセージの追加、スプライトの表示非表示を明確にすること、クリア画面の作成などをし、本人は満足そうでした。 そうすけくんとしてはほぼ完成、という感じでしたが、せっかくなのでもう少し分岐の要素を追加してみるのもよいかも。 可能であれば、自宅で考えてきてもらうよう、お母さんに提案しました。', null, '盛り上がり: 家で考えてきた内容がだいたい形になったので、とても満足気でした。'),
  ('57596b89-1fc5-5947-81f4-8e0bab72fcf1', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-07-11', null, null, '通常 / Excelの学習', '30時間マスターで、個別の問題にはだいぶ自信がついてきたとのことだったので、久しぶりに総合問題に戻ってみよう、ということで、練習問題１に取り組んでもらいました。 値として貼り付ける意味がわからなかったようで、普通に貼り付けてから書式を消そうとしていたので、貼り付けの種類について教えました。 また、テーブルの書式を設定するときに半端に範囲選択をしてから書式を選んでうまくいかなくなっていたので、どこか1か所を選択しておくか、全体を選択しておくかということを助言しました。 それ以外はほぼ自分でできていました。', null, '時間帯: その他
盛り上がり: たまにおしゃべりをしたりしながらも、スムーズに学習を進めていました。'),
  ('758be33a-5517-523f-bc8d-ebb8ea746ec7', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-07-17', '17:30:00', null, '通常 / 親子大会作品制作', '前回の続きから作成していきました．タワーディフェンスとしての部分は完成したため，今回は勝利部分と敗北部分について作っていきました．キャラクターのコスチュームの変化やセリフを喋らせるなどでデザインをおこなっていきました．イラスト部分にはこだわっていきたいようなので，次回でイラストに手を加えて完成としていく予定です．', null, null),
  ('525e4e72-6c13-588d-8078-b40ac67e91a7', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-07-11', null, null, '通常 / 親子大会作品の作成', '親子大会用に作成していたものに納得がいかなかったようで、新しいものを作成したいとの申し出がありました。隔週ということもあり、親子大会に新作は間に合わないので、U13大会へのエントリーに目標を変更しました。 はじめはスマブラを作りたがったいましたが、目新しさがないのと、できれば入賞をねらいたいとのことで、完全オリジナルで学習色を強くした作品にすることにしました。 学校を舞台に算数の問題を解いて爆弾解除をするゲームを作成予定です。 今日はステージの要素作りがメインでした。', null, '時間帯: その他
盛り上がり: 新しい作品について考えるのが楽しそうでした。'),
  ('414a68ee-06e3-58e2-946f-4dc9bbf5046a', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-07-18', null, null, '通常 / Excelの学習', '本人の希望で模擬テストをやりましたが、かなり眠そうで、ほとんど進められませんでした。何度も声掛けをして、はるちゃんも起きようとはしていましたが、それでもあまり集中できなかったようです。以前もそうでしたが、あの問題形式が苦手？なのかもしれません。', null, '時間帯: その他
盛り上がり: 今日はあまり集中できなかったようでした。'),
  ('355275b6-0448-5508-b9f7-214fb3a8f527', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-07-18', '16:30:00', null, '通常 / 親子大会作品作り', '今日でほぼゲームは完成形にする必要があると伝えて作品作りの続きから始めました。背景が気に入らない部分があるとのことで、少し修正した後、ゲームをはじめから見せてもらいました。が、ところどころ細かいバグがあり、それの修正に時間を取られてしまいました。バグ取りの際、スクリプトの細かい部分を見てましたが、メッセージ名の付け方、全体的な作り込み（いわゆる上流設計部分に当たるところ）が、分かりづらいし、冗長な作りになっていて、そりゃあ作った本人でも、規模が大きいスクリプトになったらこんがらがっちゃうだろうなという感じになっていました。低学年でいろんなブロックを使いこなしているのはすごいのですが、もっと丁寧に綺麗なスクリプトを書くことが必要と感じました。本当は、ゲームクリアの仕方など、もっと面白いものを追加させたかったところですが、そんな時間はなく、ただ、飛行機１０基を着陸したらゲームクリアになるという、ゲームというか、飛行機シミュレーターみたいなものになってしまいました。低学年でこのようなちょっと難しいものに挑戦してすごいなと思う一方で、もう少し、ゲームとして良いものにできたのにという惜しいなあという気持ちもあります。まだバグを取りきれていないので、家で少しやってくるとのことでした。', null, null),
  ('17e1d046-8d84-5275-999e-3bc1f2024bc1', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-07-18', '17:30:00', null, '通常 / ロブロックス', '前回作っていたコロコロボーリングの続き。ただ、デジタネの動画通りには全く作っておらず、オリジナルで色々と追加要素を盛り込もうとしているのですが、さすがに、そのやり方がわからず、「わからない、できない、もうやめようかな」というネガティブワード連発していました。スクリプトの勉強を全然できていないので、ハルくんのやりたいことを実現させるためには、なかなかハードルが高いのですが、極力スクリプトプログラミングをするように、興味を持つような話をしてみましたが、今日は食いついてこなかったため、スクリプトの作成等は今日しませんでした。ブロックの追加、変形等でゲームの世界を作る程度で終わってしまいました。障害物をランダムで表示させたり、ボールをスポーンさせる部分で何かアイディアがあるようですが、その部分はスクリプトを書かなくてはいけないので、次回その辺からできたら良いのですが、デジタネからは全く離れた内容になっているので、私が対応するしかないかなと思っています。（次回は私もいる予定なので）', null, null),
  ('3a4ff5a7-6f6b-5376-b766-101b6f2984cb', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-07-18', '17:30:00', null, '通常 / エクセル', '久々のレッスンで、他の子とも色々お話をしていました。特に他の生徒の親子大会作品について、色々アドバイス等していて、先生のような感じになる時間帯もありました。ケイト君もやろうとしていたことが、部長のアドバイスでできるようになって嬉しそうでした。本人のレッスンとしては、エクセル３０時間マスター2章の、練習６くらいまで進めたようで、質問等もなくスムーズに進められたようです。', null, null),
  ('a3bd0a7b-f6ef-5960-ac91-8d7e2639dd48', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-07-18', '17:30:00', null, '通常 / 親子大会作品', '前回に引き続き、undertail風の戦闘ゲームの続き。チュートリアル処理を完成させて、ゲーム本編を８割型完成させたところかな。本当は、いろんな敵を出現させて、何体か倒したら終了させるということを考えていたようですが、時間的にできず、敵１体を倒すゲームになってしまいました。やるべきこととしては、敵の弾幕攻撃を避けながら、攻撃をして、攻撃成功したら、相手の体力を減らして、体力がゼロになったら、ゲームクリア処理をする。というシンプルなものだったのですが、自分自身で、どのように細分化するのがうまくできないのか、どうプログラムを組めば良いのかわからない自信がない、アドバイス欲しいというのが多かったです。極力、ヒントを与えるのみで自分で考える訓練をして欲しかったのですが、時間の制約もあり、こういうふうに細分化してみようと、ほぼ私が設計をするような形になってしまいました。その細分化に従って、大体ブロックの作成はできてきたので、ゴールは目前だと思います。次回は、敵を倒した時のゲームクリア処理ができれば最低限の完成にはなりそうです。あとは、必要に応じて、効果音とか細かいところをつできればやるのが良いかなと思います。', null, null),
  ('e88981d8-ea0b-59fa-80cc-ad0c696bf46d', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-07-18', null, null, '通常 / ロブロックス', 'ロブロックス、レインボーロードの続きから。前回、it自由研究室のアカウントでやってしまったのか、自分のアカウントでデータがなかったので、レインボーロードで覚えるべき、スクリプトからパーツの色を変える方法と、時間経過で色を変える方法を直接教えて、確認テストをしてレインボーロードの章はOKとしました。確認テストでは、理解度が低くて、ほぼ全滅だったので、一つ一つ細かく教えてました。次回、記憶の定着も兼ねて、この確認テストをもう一度やった方が良いと思います。 確認テスト後、コロコロボーリングを始めました。特にこれといった質問もなく、途中で終わったので、この続きからとなります。', null, '時間帯: その他'),
  ('9e066c91-4932-5e61-b298-40935d27a38f', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-07-18', null, null, '通常 / ロブロックス', '瑞くんは、動画ではなく、テキストベースで進めたいようです。今日もテキストで進めていました。特にこれといった質問はなく、スムーズに進めて、応用課題まで行ったのですが、この応用課題部分で、瑞くんもモチベーションが高いこともあり、少しスペシャルな課題を追加しました。ボールがピンに触れたら、ぶつかった時の効果音を鳴らすスクリプトを教えました。英語が得意なようで、スクリプトの意味を割と簡単に理解してもらえることができました。こうやって引き出しを少しずつ増やして、自分なりのゲームが早く作れるようになったら良いなと思っています。', null, '時間帯: その他'),
  ('e98aab5f-efe1-5a52-813f-329440058f35', '57f45872-1f3e-5540-b676-bf9023444e39', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-07-17', '16:30:00', null, '通常 / 親子大会作品の作成続き', '6つの球種を完成させたら満足してしまったのか、もうこれで完成！となってしまいました。 バッターの動きを作るなどの提案もしてみましたが、もう飽きてしまったのか、これでいい、というのでエントリーシートを書かせて終了となりました。 この後の学習について、塁くんの影響で検定にも少し興味を示しましたが、とりあえずは学校で友達に見せられるようなゲームを作りたい、とのこと。残り時間は自由作成にあてました。', '惰性で自由作成にならないように、いくつかテーマを提示する必要があるかもしれません。', 'タイピング: 合間を見つけては熱心にやっていました。
盛り上がり: 最近の興味はタイピングのようで、隙を見ては寿司打をしていました。こちらはかなり根気よくがんばっていました。'),
  ('40824f93-6618-5ee6-9940-778f7376bee6', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-07-19', null, null, '通常 / Roblox', '前回IT自由研究室のアカウントでやっていたのですが、今回も、自分のアカウントのパスワードを忘れてしまったとのことで、今日もIT自由研究室のアカウントでやってもらいました。前回の保存がされていなかったようなので、デジタネの記録を頼りに、途中から進めました。ロブロックススタジオの進め方に不安を感じている（？）とのことを聞いていたので、一度、簡単なおさらいがてら、スクラッチと、ロブロックススタジオの比較をしながら基礎を教えて、直接クイズロブロックスの中身で重要な部分を教えて終わらせました。確認テストも１００％で問題なかったです。残り時間でレインボーロードをすすめました。次回はその続きからになります。', null, '時間帯: その他'),
  ('b35426e5-3f26-5595-980e-5d7b2e7c90e8', '82396ac6-71bd-59d4-a372-57212866fd5d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-19', null, null, '通常 / 親子大会作品作り', '前回からかなり空いてしまったから、思い出しが必要かと思ったら、よく覚えていたのでスムーズに進められました。前回のバグははじめくんには理解しがたい原因だったので、教えて解決しました。そこから、ガチャからカードが出てくる、そしてプレゼントを開けるようになる流れを作っていきました。基本の形は変数で判別する仕組みを作ったので、後半は1つ1つ指示をしなくてもパターンを知り自力を作っていけました。画面上に名前を付けてたり、進め方をせりふで行ったり、わかりやすくなりました。残りはコインを稼ぐためにミニゲームを作ることです。本人には、依然作ったゲームをコインを稼げるように少しアレンジして持ってきてはよいよとは伝えてあげました。', '急いで仕上げ', '時間帯: その他'),
  ('15c8997f-c1cc-59d6-829e-4263c7619670', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-19', null, null, '通常 / 親子大会作品作り', 'まずは全体のステージ位置調整をしました。ゲームのバランスがよくなってきました。次に、ジャンプしているときに、コースちゅーむを固定したいのことでした。ある程度開設を加えながら、メッセージとほかのスプリクトを止めるの活用法教えてあげました。のこりはジャンプの落下ができていないので、そこを直してあげたら。', null, '時間帯: その他'),
  ('863f68f7-74a2-56e0-8921-48a563139522', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-07-19', null, null, '通常 / ロブロックス', '黙々と質問もなく進めて、あとは応用課題くらいのようです。途中、scriptを用いて色を変える部分の処理をきちんと理解しているかを確認したのですが、大丈夫理解しているとのことで問題ないように思ったのですが、前回の記録と照らし合わせてみると、進みが少し遅いかなと今更ながら感じました。本当に問題ないか、何かモヤモヤな部分不安な部分がないかを念の為フォローしといた方が良いのかも知れません。（ロブロックスは、大丈夫といっておきながら、不安を抱えている子が結構多い印象なので、、、）', null, '時間帯: その他'),
  ('87e86c51-7d3e-5035-b5bc-7c25e25c18b0', 'ec153bd8-5b4d-5684-9704-382af23cf64a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-19', '16:30:00', null, '通常 / 親子大会作品作り', '完成度95％まで持ってくることができました。メニュー画面での操作、切り替えもきれいに作り上げられていました。最後に、ビームの打ち感覚を調節できていないとのことだったので、そこ直せればよいものになります。', null, null),
  ('bc051bee-e7dc-5d74-a4c2-2f4e4cb45555', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'ff7e06ae-d26a-5dde-b959-ba1811924b23', '2025-07-19', null, null, '通常 / 亀卦川', 'コロコロボーリングを１から開始して、応用課題の途中まで進めました。レッスン内容はきちんと理解しているようですし、Roblox studioの操作スピードも、デジタネの進捗スピードも問題ないと思います。', null, '時間帯: その他'),
  ('e5183a11-e5fa-55bc-a608-5c56093eef11', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-07-19', '17:30:00', null, '通常 / Excelの学習', 'Excel学習中、声をかけると「大丈夫です」と返事をするのですが、実際にのぞくと完全に手が止まっていたので、一緒にやろうかと声をかけました。 実習18のIF関数のネストのところで、「こうやるんですよね？」と言いながら入力をしていたので、余分なカンマがあること、IFの中にIFを書くやり方がわからなかったようで、""で何かをしようとしていたのを指摘し、Scratchの条件分岐のブロックを見せて、「もし～なら」の次に真の場合の内容を書き、続けて「もし～なら」と入れていき、最後に「でなければ」がきて、最後にまとめて閉じる括弧を入れる、という説明をしたところ納得したようで、その後は自力で作成することができました。 実習19、20のスパークラインは自分でできていました。 Excelのあとは、熱心にガサガサの仕事をしていました。', null, '盛り上がり: Excelで納得できた時は良い笑顔でした。'),
  ('a8e5f183-8f86-5655-b38f-f94ddd5552e7', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-19', null, null, '通常 / 親子大会作品作り', '残りのクリアの演出を加えていきました。恐竜たちが祝福してくれる良い形になりました。クリアの主張もよいです。のこりは、見栄え的に悪い所を自分で発見して直してくれました。本人も満足が行き完成することができました。文章はある程度できているそうなので、次回提出のみです。', null, '時間帯: その他'),
  ('d6bb5e18-4f31-56fe-a10f-0b7cbc2b55ff', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-19', '16:30:00', null, '通常 / 親子大会作品作り', '前回教えたパズルのはめ方を今回はほかのパーツを作っていきました。転用すれば、すぐできると思っていたが、うまくいかずわかりにくいバグが伴っていました。それがこちらが直し方を模索していたが、それが気になってほかのパーツにコードを映し返すことができずな状態でした。授業の最後の方に直し方を教えましたが、時間が足らず、3分の一未完成な感じです。一応直し方の検討要素は伝えたのでお家でできてもらえれば、うれしいです。', null, null),
  ('89e9aeae-ffec-58bf-94a3-f4222fb22ef3', '49fc73e4-fc37-5c75-a77f-02a27f5e169b', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-07-19', null, null, '通常 / 基礎の復習', '練習問題レベル１で何か興味のある問題を選んでもらってやろうとしましたが、何もやりたくない、とのことで、じゃあ何がやりたいのと、少し雑談がてら話を進めて、低俗なのですが「ウ○チで、xxが踏み潰されて、血がブシャーと出るようなの作りたい」みたいなことを言っていて、それに近いことを、実際にアニメーションのような形で作ることをしました。そのアニメーションの中で、今日は、以下のようなことをレッスンしました。次回以降覚えてくれていると良いですが。 ・「ずっと」の中で大きさを変える方法 ・○秒松で、セリフを適切なタイミングで話すこと ・音声を自分で録音して、その音声に合わせて、キャラクターを動かすこと。 決められたレッスン通りに進めることが、（まだ）できない可能性が高いので、本人の気になること興味のあることから、やれることをその場で考えて、何か一つでも身につけてもらう（ことを祈る）ということをするしかないのかなと感じています。', null, '時間帯: その他
タイピング: 今日も集中できず、適当なキーをバラバラに押すような状態を繰り返していました'),
  ('15bd1a3c-2255-5988-aca7-83c14f237631', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-19', '17:30:00', null, '通常 / ロブロックス', '本人が飛ばしていたところをやる予定でした。今日はいつも以上にやる気がなかったです。こちらが目を向けられていなかったこともあるが、あそびほうけていたところをやる予定でした。今日はいつも以上にやる気がなかったです。こちらが目を向けられていなかったこともあるが、あそびほうけた状態が多かったです。来週は藤田兄弟がいないので詰めて進められそうです。', null, null),
  ('ede4aac6-e7f8-581e-93e3-75938bfe5ad9', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-07-19', null, null, '通常 / 親子大会作品', '前回で大体完成するような状態だったのですが、家で作品作りを進めていて、新たにミニゲームを追加するとのことでした。この締切間近のギリギリタイミングでの追加だったので、本当にこれを入れるの？と念押し確認したのですが、入れたいとのことだったので、ミニゲーム追加を進めてもらいました。ミニゲーム自体は大体できたのですが、ミニゲームから本編ゲームに戻る処理の作成途中で終わってしまいましたが、その部分は家で続きをしてくるとのことでした。この部分を終わらせレバ、大体完成なのかと思います。', null, '時間帯: その他'),
  ('6a3f57db-6bda-593a-bcc2-296de4a083b5', '5b56509a-ab37-5b95-9b2b-2750525ad8a5', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-07-19', null, null, '通常 / U16作品作り', '黙々と作品作りを進めていて、自走できるので、あまりお話はしませんでしたが、効果音を「効果音ラボ」から持ってきていい？とかちょっとしたバグの修正の仕方の質問を受けました。効果音ラボはOKと回答、バグ修正も一緒にスクリプトを見ながら、時折、もっと良いスクリプトの書き方をあると教えることをしつつ、バグ修正も完了できました。バグの説明の仕方、言語化方法は、まだつたない部分はありますが、それ自体が良いレッスンになっていると思います。（というか、これくらいのゲームになると、こちらの教える力、バグを見つける＆修正する力も試されるというか、大学生レベルでも良いレッスンにもなるなーと思ったりしました。）', null, '時間帯: その他'),
  ('5f514b31-7130-52ed-81c4-6536f50faeee', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-07-22', '17:30:00', null, '通常 / 親子大会完成', '改めて親子大会についてやりたいことがないか聞くともう完成だというので、提出作業に取り組みました。エントリーシートは忙しくて書く時間がなかったとのことでしたが、この場で一から書いてもらうと、すんなりとすべての項目を埋めることができました。説明部分も簡潔にわかりやすく書けました。最終的にフォームでの提出が無事に完了しました。', null, null),
  ('0549e2a6-9ed6-5f56-b889-ad9d08187b47', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-07-22', '16:30:00', null, '通常 / 親子大会', 'あまり締め切りを意識させずゲームを面白くすることに注目させると、モチベーションが上がって集中できたようでした。ピンポンボールが段々加速するギミックを、加速度の変数を使って作りました。ちょうどいい速度になるように変数を調整していました。また、ボールが反射した時の音や、隠しコマンドで出てくる新しいキャラクターなど細かい要素も追加して楽しいゲームになりました。次回そのまま提出できそうです。', null, 'タイピング: 真面目にやっていました
盛り上がり: かつて何をするのも面倒だと言っていたそうすけくんが、一つの作品をきちんと作り切ることができました。'),
  ('eb634a36-2b60-522d-b612-356b9ffcafa7', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-07-22', '16:30:00', null, '通常 / 親子大会', 'クレーンゲームの回数制限の作成をやりました。最初はやり方に戸惑っていましたが、「変数の作成→最初回数を何回にするのか→回数を減らすのはいつか」という流れで誘導すると比較的スムーズに作れました。残った時間は、余計な条件分岐があるので整理したり、コードを「きれいにする」をしたりとブラッシュアップしました。また、隠しコマンドで幻の背景を見られるようにして遊び心を入れていました。', null, '盛り上がり: お迎えが来る直前まで楽しく作っていました。'),
  ('917e06c6-4834-5f75-913e-00b98c80b63d', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-07-18', '17:30:00', null, '通常 / 親子大会', '締め切りが近いながらも、親子大会の糸作りゲームの作成を進めました。糸を回転させて巻く部分がうまく再現できなかったところ、興味を持った部長がアドバイスしてくれてできたので嬉しそうにしていました。回転角度とできる糸の長さの関係を調べ、ゲームに反映するという工夫もしていました。最後にテストプレイしてもらったところ、ゲームとしての大枠はきちんとできていました。あとは家で効果音など細かい所を追加してくるとのことです。', null, null),
  ('8c117729-85c1-5e1a-95d0-163432df0102', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-07-18', '17:30:00', null, '通常 / 親子大会', '親子大会の炊飯器ゲームは、家での作成によりだいたいの流れはできている状態で始まりました。しかし、場面がうまく遷移しなかったり、この場面で出てくるはずのスプライトが出てこないなどバグが数多くあったので一緒に修正しました。場面やスプライトの数が多かったためコードの内容整理に時間がかかり、バグ直しは難航しました。結果としては、一度メッセージを送ったらそこで止めるべきスクリプトがずっと動いていたため、無駄なメッセージが送られ続けていたことが原因でした。途中そうすけくんが「なんでちゃんと動かないの！」と涙目でイライラしてしまう場面があったのですが、「メッセージを受け取ったときのコードは完璧だったから自信もっていいよ」と声をかけ落ち着いてもらいました。最終的には、うまく完成したことに安心した様子を見せてくれました。', null, null),
  ('50d21f2c-8838-5edf-ae97-1afd93b52ae7', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-07-18', '17:30:00', null, '通常 / excel', '今回も実技問題を進めました。前回と同様、突っかかるポイントもあまりなく自走してくれました。特に数式やグラフ作成などの作業をもう一度やるとき、だんだん慣れてスムーズにできるようになってきました。', null, null),
  ('f6f9a66c-6f02-5020-83a0-6a7406705ea1', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-07-18', '18:40:00', null, '通常 / 親子大会', 'あさひくんはお休みの回があるので、親子大会は今日まででだいたい完成させたいという話をすると集中してくれました。まずは前回やっていたハッピーエンド・バッドエンドの背景を作成し、それはすぐ終わりました。そのあとはコードの作成に移り、「画面上でOK/NGボタンを押したらこうなる」「このキーを押したらこの料理の種類が変わる」という処理が動くようにしました。きちんと場合分けして考えることができたのでこれもうまくいきました。本人的にも満足いくゲームになったようなので、家でエントリーシートを書いて送ってもらうことになりました。', null, null),
  ('edf6077a-3c1a-5541-aaa3-d8bdd46f5089', 'd3885e29-ee68-501b-bf31-6c050fd50c36', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-07-18', '16:30:00', null, '通常 / 親子大会', '作ろうとしていたジャンプゲームで、50点取ったらクリアにするという終わりの処理から作り始めました。一通りできたので試しにやってみると、ジャンプ力が低すぎて爆弾を全然飛び越えられない問題が出てきました。そこでジャンプのコードを読み返してもらうと、一度に変えるy座標の量や繰り返し回数を変えればよさそうだと気づくことができ、遊びやすく修正できました。もう作りたいところはなく完成だというので、次回は提出できそうです。', null, null),
  ('15fc5e2f-e65a-5c7e-8039-209617844553', '0d16e234-e60d-5fdb-978f-1722acf9a2b2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-07-17', '16:30:00', null, '通常 / 前回の復習をしながら、基本的なブロックの学習', '前回やったことはわりと覚えていて、授業開始時に得意げに見せてくれました。 これまでの様子からも、基本操作コースの新しい課題にチャレンジするよりは、もう少し同じような課題をこなした方が良さそうと判断し、アルスタジオのレッスンからやりたい課題を選ばせました。 スプライトを矢印キーで動かす時に、「x座標を⚪︎ずつ変える」ではなく、先に向きを指定してから「⚪︎歩動かす」という課題だったため、初めは少し戸惑っていましたが、理解仕切れてかはともかく、そういうものか、という感じで納得していました。 キャッチゲームの仕様は気に入ったようで、コスチュームを少し編集したり、音にこだわって選んでみたりと楽しんで作成していました。 背景に地面があるタイプの絵を選んだため、りんごが土の中を通り抜けて「端に触れたら割れる」のが納得いかなかったようなので、何を変えればいいかと考えさせるところから、「茶色に触れたら」ブロックを教えました。', '「物語を作りたい」といっていたので、基本操作コースの3や6をやらせてあげてください。アルくんのピンポンダッシュのストーリーを作りたいそうです。', 'タイピング: まだあまり興味はないようです…
盛り上がり: 一通り、思った通りに完成できたようで、満足そうにしていました。 授業が楽しかったのか、次にやりたいことをリクエストして帰っていきました。'),
  ('29ff529e-95e7-54d2-b4ee-656f80df8092', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-07-17', '17:30:00', null, '通常 / Excel検定学習、U16大会の作品作成', '一応今日の課題としてExcelの準備もしていたのですが、締め切りが近い親子大会組に影響されたのか、作品を作りたいと焦っていたので、今日はそちらのみにしました。 やりたいことをコードにすることはできているようなのですが、とにかくテキスト部分が膨大になりそうなので、まずは予選を突破するためのインパクトのある資料が必要なことを説明し、ストーリー部分は後からでも追加できるため、技術面をアピールできる部分を先に仕上げていく方針にしました。', null, 'タイピング: 小学生たちから「タイピングのはやい人」扱いされて苦笑いしてました
盛り上がり: 適度なおしゃべりと、好きなプログラミングを楽しんで、息抜きになっている、といった感じでした。'),
  ('998c8aac-d92b-59ac-a974-30fec902bdb0', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-07-17', '17:30:00', null, '通常 / 親子大会作品の作成', '女の子の色々なパーツはとても上手く描けていて、本人も満足そうでした。 これらのパーツを使って着せ替えのようにしたいけれど、何から始めて良いのか全くわからない、といった感じで、途中で疲れたといって5分間仮眠を取ったりしていました。 プログラム面でのアイディアを出すことがとにかく難しそうだったので、着せ替えゲームっぽい【DKアート】05 ふくわらいを見せました。この通りに作る必要はないけれど、参考までにということで、手順書も渡しました。 とりあえず、パーツの初期位置を決めたいということになり、座標の指定をしていました。', '自分でアイディアをコードにすることはちょっと難しそうなので、最低限やりたいことを話し合って、ある程度道筋を示してあげる必要はあるかもしれません。', '盛り上がり: 絵を描いている時の方が楽しそうではありますが、なんとか着せ替えっぽいものができそう、となってからは、頑張って取り組もうとしていました。'),
  ('7a39775e-0f72-5a25-b867-1d533c3a0093', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-07-17', '17:30:00', null, '通常 / U16大会作品作成の続き', '順調に作成を楽しんでいます。 信長が、近所に武将がいる時に「戦争」モードに入れるようにしたかったらしいのですが、信長と武将の座標の差が一定の数値以下のときにフラグを立てる、というアイディアを提案して作成し始めたところ、武将の数が多くて途中で面倒になったようで、誰でも戦闘可能でいいや、となっていました。 基本的に思いつきでどんどん作成を進めているので、後から思いついたアイディアを追加する際に、少し苦戦するようです。', 'アイディアはどんどん湧いてくるので、コード面を上手く整理して、せっかくのアイディアを形にできるよう誘導してあげられると良いのですが…', '盛り上がり: いつも通り、教室の誰とでもよくおしゃべりして楽しそうでした。'),
  ('6458ae20-0343-5123-bc11-666649bc3c77', '1c7005cc-2815-558f-993a-9c7617d34c44', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-07-22', '16:30:00', null, '通常 / 親子大会作品の作成', '今日も作品を仕上げる気満々で、授業開始前から始めたがりました。 途中でのアメ休憩は頻繁ではあるものの、声をかけると素直に学習に戻ることはできるようになってきています。 ゲームに勝った時や負けたときのセリフの追加、クリア時のスプライト表示、背景の変更など、やりたいことを順に申し出ることができたので、その都度、なるべく自分で考えさせる時間を多く取りながら進めていきました。発問時は「わからない！」と言いがちですが、誘導していくと多少は自分で考えることもできるようです。 ゲーム自体は完成し、タイトルの変更を嬉々としてやっていました。', 'エントリー用紙も提出してくれているので、次回はそれを元に作品の提出となります。', 'タイピング: タイピングはやりたがらないです…
盛り上がり: お迎えのお母さんにできあがった作品を見せて、嬉しそうにしていました。'),
  ('60ae25b3-fed2-52e0-9d1b-c85ee9784d68', '337872be-4ce4-5436-88f8-5f97e8c5252e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-07-22', '17:30:00', null, '通常 / 定義の学習', 'これまで未履修だった定義の学習として、カニカニハンマーをプレイしてからコードを見てもらいました。定義をどういうところで使っているか、使うことにどんなメリットがあるかを発問し、口頭で答えることができていました。定義ブロックを全て削除した状態で作成をさせましたが、30分くらいで完成させていました。今回は引数もなかったためか、比較的簡単だったようでした。 残り時間は、カニカニのアレンジか、新しい学習か、クイズかを選ばせたところ、クイズに興味を示したため、エラーで学ぶシリーズをやってもらいました。 演算式の等号と不等号の使い分けは自力でできていましたが、リストの長さについては初見だったようで、説明が必要でした。', null, '盛り上がり: クイズ形式が新鮮だったようで、それなりに楽しんで学習できていました。'),
  ('6860e610-26e6-5eed-b079-4703131935e4', 'ec153bd8-5b4d-5684-9704-382af23cf64a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-24', '16:30:00', null, '振替 / 親子大会作品完成', '最後のビームの射出速度の調整をしていきました。調節方法を変数の形で何通りか教えたところ、自分なりに形に調整できていました。変数をほかのコードに埋め込ませることが少なかったので、今回の作品作りは役に立てたと思います。組み合わせ方を教えると他へつながりが自分で作れることができるので、見たことないコードの組み方をどんどん触れさせていった方がいいと思います。', null, null),
  ('25eb87ce-d50f-5cf5-978b-d80cf52f9849', '57f45872-1f3e-5540-b676-bf9023444e39', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2025-07-24', '16:30:00', null, '通常 / 親子大会作品提出', '野球ピッチングゲームの作品を完成させて提出しました。 お隣の塁君に遊んでもらい、変な箇所を指摘してもらい。２球種ほど修正を加えて完成させました。 相変わらず、塁君と飴食べたり、ウロウロしたりしており。集中力がイマイチだったので、久しぶりの私が厳しく「やろうよ、やらないなら応募手伝わない」と言うとその後最後まで頑張りました。', null, 'タイピング: 割愛'),
  ('964706bf-888f-54aa-a058-21b06887995b', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2025-07-24', '16:30:00', null, '通常 / 親子大会作品提出', '季節の漢字をやっつけるという、面白いアイデアのゲームです。きちんとイメージ通りに動作できており、成長したな＝～と思いました。 作品説明文は、最初は彼が書いた文章の意味がわからなかったので。一か所ずつ質疑応答方式で作文を完成させることで、よい説明文になったかと思います。 一方で、虎太朗君の記録にも書きましたが。 相変わらず、虎太朗君と飴食べたり、ウロウロしたりしており。集中力がイマイチだったので、久しぶりの私が厳しく「やろうよ、やらないなら応募手伝わない」と言うとその後最後まで頑張りました( ;∀;)', null, 'タイピング: 割愛'),
  ('4dd8d47d-9ca5-59bc-af34-ba4ec5fe38a3', '0d16e234-e60d-5fdb-978f-1722acf9a2b2', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-24', '16:30:00', null, '通常 / ピンポンダッシュみたいな話を作ろう', '切り替えが疎い子なので、前回のやったことから振り返っていきました。どんなことをやったの？と尋ねたところ、色判定のところの見せてくれました。その流れで、ピンポンダッシュ系のつなげようとしたが、目がついてないと寄り道が多くなるばかりでした。1つだけでもやろうと、扉の色に触れたら、アラームが鳴るところを作りました。次回から内容をしっかり作れていけたらいいと思います。 自分だけかもしれないが、なんとも思わずに足を踏んでくることが気になります。', null, '盛り上がり: 陸君の作品を除いている時間が長かったです。'),
  ('8ac437ab-a763-567b-9c1f-21cc21b3d9c4', '05439956-11b9-5ac7-a44a-3e6f5a6831d8', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2025-07-24', '16:30:00', null, '通常 / 親子大会作品つくり', 'ウィルスと抗体のシミュレーションゲーム。すごい作品です( ﾟДﾟ) 抗体が発射するシーンで、動作がカクカクとまるのが気に入らないとのことでしたが。クローンの多様が要因かな、と少しいじりましたが解決できず。 後で、AIにも確認しながら。 「メッセージ」を５回送って 抗体がそれを受け取ると「クローン」が生まれる この流れの場合、クローンが瞬時同時に発生するこで動作が止まる＝PC処理の負荷が高かったと予想される。 そのため「0.05秒待つ」を加えた。 あるいは、 メッセージを１回だけにして。受け取った抗体側でクローンを増産させる方法。 ※要は、クローンが多いことで動作が遅くなるは「違う」 ※瞬時同時作業が多いことで、動作が遅くなる（＝PCの負荷）という違い ここは、今後も出てきそうなので。共有します。', null, 'タイピング: 割愛
盛り上がり: 本当に熱心です。また細部のこだわりがすごいので。３冠とってほしいですね。'),
  ('1e5f3641-7fce-57b6-ba72-6173be8ec052', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-24', '16:30:00', null, '通常 / 親子大会作品作り', '今回はEDや効果音を選んでしました。結構細かいところまで見て修正をしていたので、完成度は高そうです。魔法の打つ効果音を運よくよいのが巡り合えたので、よかったです。今日で完成まで行けたので、次回提出です。', null, null),
  ('c3c64211-d8c6-593f-91a2-90e0b97f1f24', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2025-07-24', '17:30:00', null, '通常 / 親子大会作品つくり', '着せ替え用のイラストはできあがっていたものの。プログラミングは手付かず。 類似作品をscratchから見つけてみせると。イメージが膨らんだようで。一方で、どうやって動かしていいか、わからないということで。 「メッセージ」を提案すると、そこからイメージが沸いたようで手が動きました。 今回の大きな収穫は「変数」の理解でした。 ・髪型を選ぶ ・場面が切り替わる ・トップスを選ぶ ・再び場面が切り替わる… という一連の流れをつくるにあたって、「セット」という変数を用いる方法を提案しました。 最初は「変数をどう使えばよいか分からない」という反応でしたが、 「セットが1のときは表示、0のときは隠す」という条件設定を例に説明すると、仕組みの本質を理解したようで、スムーズに構想が進みました。', null, 'タイピング: 割愛
盛り上がり: 制作途中で、扱うアイテムが増えてしまい（トップス・ボトムス・靴・目 など）、今のペースでは大会の締切には間に合わないかもしれない、という話をしましたが、 本人は「それなら、もう一つの大会（U13）に出す」と、自らの判断で「間に合わせる」よりも「やりたい表現を優先する」という選択は、クリエイター的にで良いなと思いました！'),
  ('968c1681-fb7a-5fe5-b3ea-67d25d213d35', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2025-07-24', '16:30:00', null, '通常 / 親子大会作品つくり', '振替を使い、２時間連続 上から「緑の敵」が降ってくるようにしたいと。 結構、シンプルなコードだけどどうやったらいいか、わからなかったようです。 「Y座標」を使おうとヒントだししたところ。いじりはじめて理解できました。その後は「X座標」をランダムにして複数敵を登場させることができました。 学年の割に、通った歴がまだ短いためもあり。案外基礎的なことが積まれていないので。大会終わったら、ドリルや検定でしっかり理解度を深められるといいなと思いました。', '大会の作品はほぼ完成ということで。用紙を渡したので、作文してきてねと伝えています。', 'タイピング: 割愛
盛り上がり: イメージがあるものについては、似たような動きをいくつか見せて、イメージの共有をしました。これは違う、これ、など。自分のイメージが明確な様子が頼もしいです。
備考: 8/1大原追記（今後の指導のための備忘録） 大会の作品提出にあたって確認したところ、授業中で見ていた動作ががまったく動かなくなっている箇所を発見。おそらく完成に向けていろいろいじっているうちに壊してしまったのか？作成中はできていたところも見ていたため、数か所直して提出。それを踏まえて、今後の課題↓ ・定義の使い方が適切でない。かえってブロックを増やす結果になっているところもあり。このあたりは授業中も一度説明したが、納得するまで学習する必要有り。 ・演算式の使い方。変数が場所によって左項だったり右項だったり。そのため不等号の向きに混乱が見られる。今後の為にも統一を勧めたい。 ・スプライト本体とクローンの区別が曖昧。クローンも独学でなんとなく使えると思ってやっている可能性あり。 ・アイディアは出る方なので、思い付きでどんどん作成していくタイプ。そのため、同じコードが複数のスプライトに書かれていたり、想定外のところに書かれていたりして動きに影響を与えている場合がある。紙に細分化するのはあまり得意そうではないので、せめて、関連するスプライトにコードを書いていく習慣をつけて、あとから混乱しないようにしたい。'),
  ('42beec25-cabc-5448-b431-086286ce5e79', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-24', '17:30:00', null, '通常 / 親子大会作品作り', '前回場面移りなどのコードやせりふができていたので、今回は仕上げのクリアorオーバーのコード及び演出を作っていました。クリアの方法が何もなかったので、タイム２００でクリアする方法を提案しました。そこで、このゲームの作成で何度か使っている「までまつ」を使ってみようと伝えたが、全くぴんと来てなかったです。一通りコードが完成した後、少し時間があったので、追加でイラストを加えるとことをしましたが、結局ぐちゃぐちゃで終わり、思考の具現化が苦手みたいです。来週はバグがないか見直して、提出です。', null, null),
  ('cd783490-3a8c-53eb-a6f6-b06927940c05', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-24', '17:30:00', null, '通常 / 親子大会作品作り', 'ジャンプのあしばは完成していたので、肝心の足場から落ち続けるコードを作っていきました。時間もなかったので、落下も対応しているコードと見くべさせて、どこがどう違うのか考えてもらいました。色判定による違いが発見できたので良かったです。ほぼほぼ完成なのですが、終わりがどこか見えないので、そこをつくってあげるとよいと思います。', null, null),
  ('e0c1a201-f14f-53c8-a5f6-52598459d0ab', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-24', '17:30:00', null, '通常 / U13大会に向けて', '今回は花火打ち上げ後の展開を作っていました。コードは過不足なく作れているのでバグが発生しづらくよいです。たいようくんとの会話をはずむのはよいですが、親子大会の締め切りが近かったので、そうたくんのちょーーと邪魔になっていたな、会話につられてしまうので、', null, null),
  ('61249eb8-2753-586b-b1ea-2e682e436ed0', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-24', '17:30:00', null, '通常 / U16に向けて', '今回はコードが少なめでしたが、プレイヤー画面キャラのレイアウトと基本的なコードが組めたそうです。これを基に、ほかのキャラなどを動かしていくので、進捗的には手ごたえありだそうです。', null, null),
  ('ea4e8ef4-d4a5-5195-ab8e-e3242db388cd', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-24', '17:30:00', null, '通常 / U16に向けて', '戦いの構図をメインに作っていたそうです。途中、織田家の家紋がどうやら、歴史知識の脱線もあり、ありました。そうたろうくんとの会話がよく弾みました。あなたは、しゃべりながら手も動かせるが、周りはそんな器用じゃないので、ほどほどに、', null, null),
  ('80f3f1e0-0d6d-5c88-bf7c-4c214c715b5e', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-07-25', '16:30:00', null, '通常 / 親子大会作品完成と作品提出完了', '家でバグ潰しをしてきたようですが、私が動作確認してみると、新たなバグを何個か見つけてしまい、一緒にバグ修正をしました。その際、プログラムの流れをきちんと理解した上で、何がおかしいかを論理的に考えるのではなく、一つのプログラムだけに注目して、ここがおかしいかもというような、場当たり的なバグ修正をしていたので、プログラムの流れをしっかりと頭に入れた上で細分化してバグ潰しすると良いことを伝えました。が、正直そう簡単にできることでもないので、ことあるごとに伝えて、少しずつでも、そういう考え方ができるようになれれば良いかなと思っています。バグ修正に30分近くかかりましたが、それでゲーム完成とのことで、残りの30分ほどで、作品提出フォームを自分でタイピングして登録してもらい、確認の上、無事提出完了しました。', null, null),
  ('dbc4f78d-b5e6-5905-bc30-43bb7748e392', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-07-25', '17:30:00', null, '通常 / 親子大会提出', '親子大会の提出を行いました。作品は家で完成していましたが、エントリーおよび提出フォーム用紙の記入をしていなかったので、今日全てやりました。しかし本人がパソコン操作に慣れていて説明文もすらすら書けたので、問題なくできました。 それが終わると、scratchで個人的に作っていたコーラのクリッカーゲームの作成をしていました。コーラが溜まる速度の変更や、自動クリック機能などもつけていてクオリティが高かったです。', null, '盛り上がり: ゆづきくんの完成作品に興味を持っていました'),
  ('abd1ae8c-57d0-53e6-a842-008fed555f89', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-07-25', '18:40:00', null, '通常 / excel', '前回うまく進まなかった模擬問題のやり直しを提案したところ進めてくれました。前回と同じように眠気に襲われる場面はあったのですが、だいたいの時間は集中できていて自力で進められました。問題4の中盤までできました。', null, null),
  ('600493b2-f663-5da5-9d46-886ff706f47a', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-07-25', '17:30:00', null, '通常 / ロブロックス・コロコロボーリングの続き', '前回コロコロボーリングをもとにしたオリジナル作品を作っていて、その続きを作る予定でしたが、これ全然面白くないこれ以上作りたくないとのことで、面白くなくても一回作り上げようと言っても、聞き入れてくれず、新たにアスレチックゲームを作るとのことで、作り始めました。Roblox studioでプレイヤーが着れる服（自分でデザインしたTシャツみたいなもの）を自作してそれが気に入っているみたいで、それを見せてくれて、これを売ったりしたいとのことを言っていました。実際に、Robloxでは、公開したゲームの中で、そう言ったものをゲーム内通貨で売ることが可能です。なので、実際に自分のゲームを作る。そこで自分の作ったものを売るということに興味は持っていて、それがモチベーションになって、roblox studioのゲーム作りも集中してくれてはいます。ただ、スクリプト作成が疎かになっているので、所々で、スクリプトを使うことを促したり、簡単なスクリプトの使い方を教えたりしています。次回は、作成中のアスレチックゲームの続きです。', null, null),
  ('494d84ad-dbcf-5967-89af-dc5d48cb8740', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-07-25', null, null, '通常 / ロブロックス・コロコロボーリング', '前回、レインボーロードの確認テストの理解度があまり良くなかったので、その復習から。プログラムに、「script」と書いたときに、それが何を示すかということは、残念ながらきちんと理解できていないようでした。再度教えましたが、なかなかこのような概念を理解するのは難しいとも思うし、スクリプトを書く頻度が上がってくれば、徐々に分かるようになるとは思いますので、ひとまず、様子見で進めていくで良いと思います。この後、コロコロピンボールを進めて、時間内に、すべて完了して、確認テスト６０％で今日は終了となりました。やるべきことはきちんとやって、質問もないのですが、いざ確認テストをしてみると、理解度が低いことが、ちょっと多いので、きちんとフォローして進めてあげる必要があるかと思います。', null, '時間帯: その他'),
  ('62d9310e-34d0-55e8-9196-78fc311bc373', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-07-25', null, null, '通常 / エクセル・ロブロックス', 'ロブロックスを進めたい気持ちが強いので、エクセルを少し進めた（３０時間4章例題４）上で、roblox studioの続きであるハラハラピンボールを最初から始めました。ただ単に、ブロックを組み合わせてゲームを作るだけではなく、きちんとプログラムを書いて動きのあるものを作りたい意欲があるようなので、デジタネプラスアルファで、簡単なスクリプトを教えています。ハラハラピンボールでは、スクラッチでもお馴染みのクローン処理を使って、ボールをクローンさせる方法を教えている途中で終わりました。次回はこの続きからとなります。なお、瑞くんは動画は見ていなくて、テキストベースで進めているので、デジタネ上の個人記録の進捗が反映されていませんが、きちんと全て終わらせていますので、ご注意を。確認テストが終わっていれば、その部分はきちんと全て終わっています。', null, '時間帯: その他'),
  ('e36419ec-0846-578f-bd8a-cf4e33bfcae6', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '19c3ff7e-f3fb-5570-9f85-06429f30290f', '2025-07-25', '18:40:00', null, '通常 / U13大会', '前回に引き続き、U13大会に向けた作品の制作を行いました。 今回は計算問題の出題に関するプログラムを作成しました。最初はリストを用いて一問ずつあらかじめ登録しておく方法を取ろうとしていましたがお兄ちゃんから乱数を使ってはどうかと提案があったため、乱数を用いた手法に切り替えました。 難しいところは先生で手助けしつつ、試行錯誤して乱数を用いてプレイするごとに問題が変わるシステムを作ることができていました。 次回も引き続きゲームシステムの制作をできればよいと思います。', null, null),
  ('9da1fee2-1edf-55d7-a4a3-76d0b4cd9588', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '19c3ff7e-f3fb-5570-9f85-06429f30290f', '2025-07-25', '16:30:00', null, '振替 / 親子大会', '炊飯器のゲームを完成させ、親子大会に応募しました。 ゲームはほとんど完成していたため、前半でコスチュームを少し変え交換音をつけ、残っていたバグの修正をしてから応募しました。バグ取りでは原因がよくわかっていなかったようなので少し助言しました。 作品を自分で完成させることができたので、自信をもって応募していたように見えました。', null, null),
  ('0f02484a-5c9c-5e15-a62e-4bdb2832be5b', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '19c3ff7e-f3fb-5570-9f85-06429f30290f', '2025-07-25', '17:30:00', null, '通常 / 親子大会', '親子大会作品を仕上げ、提出しました。 前回までで弾幕や自分、敵のHPの仕組み、gameover時の画面は完成していたため、今回は攻撃に成功しても敵HPが減らないバグの修正とgame clear画面の作成を行いました。 バグに関しては本人に任せていると到底時間内に終わらないと判断してほとんど私が修正するような形になってしまいました。一応何が悪かったのかは説明しましたが、きちんと理解は出来ていないような雰囲気がありました。 作品が形になって提出できたことに対しては満足そうにしていました。', null, null),
  ('6ca06dbc-b0a0-5f8b-8006-a58bfa400cbb', '655ad2c9-dfb5-5fc7-b41a-1d784603c1d0', null, '19c3ff7e-f3fb-5570-9f85-06429f30290f', '2025-07-26', '16:30:00', null, '通常 / PRG10', '本日は2時間連続の授業で、レースゲームを完成させました。 前回変数について学んだので、今回はそれを応用してレースゲームの作成をしました。まず完成品を遊ばせてみてどのような挙動をしているか、実装するには何を考えればいいかと誘導し1ステップごとに進めていきました。 長丁場だったため途中休憩を挟みましたが、自分で作ってみて動かないときは何で動かないのか考えていろいろやってみるなど、興味を研ぎらすことなく取り組めていたと思います。 変数と「りんごとバナナ」を用いた秒数表示の方法についても理解できており、飲み込みが早かったです。', null, null),
  ('083e7dc0-7e55-5026-a0f9-f194adc7e387', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '19c3ff7e-f3fb-5570-9f85-06429f30290f', '2025-07-26', '17:30:00', null, '通常 / 親子大会', '親子大会に向けたホラーシューティングゲームの仕上げと提出を行いました。 来た段階で内容はほとんど完成していましたが、最後の最後まで驚かせるための背景を追加したりと調整していました。 また、応募する際のアピールポイントなどを書いた用紙を忘れてしまっていたため新しく考えてもらいました。操作方法の説明やホラーゲームである点をプレイヤー向けに注意する文章で、初見の人でもわかるように書くことが出来ていました。 自分の作成した作品に対して、自信をもって提出していたと思います。', null, null),
  ('982c630d-3c32-5324-9deb-81e5386335e3', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-26', null, null, '通常 / ロブロックスの要確認、今後について', '作成を終わっていたので、確認テストしていきました。明らかに1問だけを全くわからず悩んでいたので、その詳しく問いただしていきました。その分while分の中のcancollideの軌道の有無がわからなかったそうです。やったけど、わからない状態だったので、スタジオに戻らせて、その機能を実践して確認していきました。色より先のコードの種類の記憶が悪くなっている感じでした。 授業後、ゆき先生と親御さんと話して、まだスクラッチの検定が1級取り終えていないので、その対策をしていく方針になりました。検定の問題を触れていくことで、コードの組合せの種類が広がっていけることを期待しまうs。', null, '時間帯: その他'),
  ('3b10c466-ba94-5b86-897d-14f9608fd43e', '82396ac6-71bd-59d4-a372-57212866fd5d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-26', null, null, '通常 / 親子大会作品完成', '来て早々、やる気満々作成を進めてもらいました。今回はミニゲームでコインを稼ぐ部分を作成しました。ゲーム用に背景を変えたときにほかのスプライトを表示切替をメッセージで作ってもらいました。意外と一個一個作らないといけなくて、面倒かと思ったら不足なく作れていました。ゲームの内容を作っていたら、1時間たってしまいました。そこから細かいバグを見てもらい、文章も自分で考え、何とか完成に持ち込めることができました。何回か休みがあっったので、少し作るルートをこちらからの提示が多かったですが完成できてよかったです。', null, '時間帯: その他'),
  ('befcedcd-9717-518f-b076-11a1ad031226', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-26', '16:30:00', null, '通常 / エクセル', 'ほかのこの親子大会提出の手間がとられていたので、ほとんど見れていません。今回はグラフの部分でしたが、特に声を掛けられることがなかったので、おそらく平気だと思います。', null, null),
  ('efd27517-63ce-5afd-86b2-073bd3c18e59', '49fc73e4-fc37-5c75-a77f-02a27f5e169b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-26', '16:30:00', null, '通常 / チーズを探せ', '前回まで基礎レッスンの部分が多かったので、スタンプ埋めのために、チーズを探せをメインに作っていきました。その前に、さいころの乱数の話をしましたが、そもそもさいころ自体が知らないので、あまりピンと来ていないかもしれないです。さいころ以外に身近な例があると思うのですが、、、 チーズを探せでは、今日の目標として、チーズがランダムにとったら動くことを進めていきました。前段階として、上下左右に動かすこともやっていきました。途中でそれることもあったが、ノリツッコミ的に会話のラリーを続け行けば、後半はうまく進めていけました。向きの考えの導線を伝えたら、楽しんで矢印の向きの数字を確認して打ち込むことができたので、感覚が養えたと思います。チーズをランダムに動かすを一応作りましたが、乱数の幅が狭いため、広げる作業をしていきたいです。', null, 'タイピング: なんで毎回やるのと聞かれたので、早くできた方がかっこいいと伝えてあげました
盛り上がり: 迷路の衝突判定'),
  ('368cd560-604e-5748-bb70-a028c1b6fddd', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-26', '16:30:00', null, '通常 / ロブロックス', '安定の３０分もやらずに遊んでいました。明らかに今日はコードまで動かさない、前半部分だけだったので、このゲームを軽々しく見ていました。次くらいに2時間続いてやるそうなので、詰めるように', null, null),
  ('b5e12af2-2247-538f-a1db-ee38e2442d25', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-28', '16:30:00', null, '通常 / 親子大会作品完成提出', '前回にパズルの設置法教えて、お家で作成してきてくれました。しかし、少しずれてしまう場合があるということだったので、細かい修正を行っていきました。そして、OPとEDも作り、今回メインで使ってきた「まで待つ」のコードを自分で使いこなして作成することができました。これで完成することができました。', null, null),
  ('6e6e87d4-3e39-51c0-9d32-f6cef43de77e', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-28', '16:30:00', null, '通常 / ロブロックス', 'いつもながら授業が始まる前には1レッスン終わっていました。今回の内容は関数に着目した内容だそうです。やっている最中が全く見えてないので、理解度がどれほどなのか？です。 今回、珍しく確認テストが60％で止まっていたので、そこ次回確認するようにしてください', null, null),
  ('5437d0f5-595c-5e20-a627-f575d1fefbe4', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-28', '17:30:00', null, '通常 / 完成＆提出', 'コード及び全体の流れはほぼ終わっていたので、ゲーム性のバランスやイラスト、見やすさについて調整していました。今まで停車位置がわかりずらかったので、本物の停車位置を作ってよくなりました。電車に系統の文字を入れたり、残りの距離を表示させたり、宮須なっていました。授業20分オーバーで完成提出することができました。', null, null),
  ('a91c7d35-2589-5f76-bb6c-1af3c16a7832', 'd3885e29-ee68-501b-bf31-6c050fd50c36', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-07-25', '16:30:00', null, '通常 / 親子大会', '今のゲームに追加したい要素などはもうないとのことでしたが、最後のテストプレイをすると、途中でステージが逆戻りするというバグを見つけました。各ステージ開始のメッセージを送るコードを一緒に確認したところ、意図しないところでメッセージがもう一回送られていたので、一度作動したらスクリプトを止めました。そうしてバグは直ったので提出作業に入りました。書く内容はもう十分用意してくれていたので割とスムーズに提出でき、残りの時間は達成感と開放感からscratchで遊んでいました。', null, null),
  ('c6ce46a8-91eb-5691-a098-7563f4e335b8', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-07-25', '18:40:00', null, '通常 / excel', '隣の席のみずきくんと時々話しながらでしたが集中力は保っており、スムーズに進めていました。グラフの作成は前の回からやっていますがだいぶ慣れてきた様子で、レベルが上がってきた実習をいくつか終えていました。', null, null),
  ('41530c8c-1bc7-50ab-818b-5ec1d4481a10', '80660755-d846-5cdd-91a4-0ab78fe29034', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-07-26', null, null, '通常 / 親子大会', '作品の最終調整から行いました。ゲームクリアの演出や効果音など、必須ではないがあれば楽しくなる要素を入れていました。ジャンプの効果音を鳴らすコードでは、ジャンプの動作そのものと音を同じスクリプトに入れてしまうと干渉してしまいうまく動かないので、スクリプトを分けるというように的確な対処ができていました。大会エントリーシートの紙を忘れてしまったというのでその場で書いてもらいましたが、わかりやすい説明文がすぐに書けていました。無事に提出完了しました。', null, '時間帯: その他'),
  ('56f7760f-b495-560d-aaf1-55c4eea4b6a7', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-07-26', null, null, '通常 / 親子大会', 'もう作品自体はほとんどできていたので、今日の作成はスプライトの見た目の調整くらいで済みました。ただ大会エントリーシートの紙を忘れてしまったというのでその場で書いてもらいました。ゲームを説明するところで少し時間を使って考えていたので、書くべき内容について一つずつ問いかけをしてサポートしました。無事に提出が完了し、本人は少し達成感があったようでした。', null, '時間帯: その他'),
  ('81fc3c12-14dc-5aa0-bda1-781ddf10d996', '337872be-4ce4-5436-88f8-5f97e8c5252e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-07-29', '17:30:00', null, '通常 / リストの応用', 'リストの応用としてジャンプゲームに取り組みました。まずは細分化として以下を確認しました。 ・場面変化のボタン「スタート」「スコア」がメッセージを送ることで、各スプライトに指示を出している ・記録のリストは、ゲームオーバーしたときに、今の記録を降順になるように挿入している ・変数を使ってy座標の移動距離をだんだん変える放物ジャンプの仕組み(意外にも初めてでした) ・2つの背景が横並びで左に流れていく横スクロールの仕組み(以前やっていたのでこれは理解済みでした) その後は動画を見ながら、その内容をきちんと理解しながら進めていきました。途中で動作確認したところ動かない部分があったので一緒にバグ直ししました。バグの原因は、動いていないスクリプトそのものではなく、そこにメッセージを送っているスクリプトでした。このように、バグ直しするときはまず場所を絞り込み、ときにメッセージをさかのぼって見る必要もあるという話をしたところ納得してくれました。動画は21分ごろまで終わりました。', null, null),
  ('503749ac-73cb-53f5-9537-9324fb744151', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-07-29', '16:30:00', null, '通常 / 親子大会', '親子大会の作品はもう完成していて、最終テストプレイまで終わったので提出に入りました。説明の文章については、あらかじめ紙に書いたときと仕様が変わったので内容を修正しながら打ち込みました。出来には満足した様子で最後まで終えることができました。', null, null),
  ('67c14377-1962-550d-a38d-627a62dbb69c', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-07-29', '16:30:00', null, '通常 / 親子大会', '最後に何かおかしいところがないか確認しましたがなかったので提出に入りました。途中「説明の文章は任意だって書いてある」と拒否しようとしていましたが、みんなしっかり書いていることを知るとすんなり書いてくれました。押すと邪魔者が出てくるキーが何キーなのか書いてなかったので忘れてるのかと思ったのですが、遊ぶ人が自分で探してほしいというスタンスのようで、少し遊び心がありました。最終的に無事に提出できました。', null, null),
  ('f4a3fb62-b2a5-56b8-9cbe-c4d3501b68b8', '655ad2c9-dfb5-5fc7-b41a-1d784603c1d0', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-31', '17:30:00', null, '振替 / 夏休みリフレッシュ', '今回は親子大会作品完成お疲れとして、コンテストとしてジオメトリーダッシュ_シップ編（簡単プログラムVer）をやっていきました。最初はむりーと言いながらも、どんどんのめりこんでいきました。アレンジも進めていましたが、ゲームに夢中でした。', null, 'タイピング: タイピングが好きそうだったので、秋の毎パソについて親御さんにご案内しました。案内すると、親御さんもやりたそうでした。'),
  ('004bdf79-a469-5c9f-8b2f-8b635eb7cf04', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-31', '17:30:00', null, '通常', 'U13の作品もあるものの、今日はコンテストだと切り替えてずっとやっていました。後半なればなるほど、400以上が当たり前になっていました。ベストが530くらいに対してランキングではスコアがバグの補正がかかって実際より多きスコアになっていました。この偽りの記録を自慢せず、ベストスコアを自慢していました。', null, null),
  ('8ccb73f0-60f8-5020-b947-ca12c2add21a', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-31', '16:30:00', null, '通常 / リフレッシュ', '親子大会作品完成お疲れとして、コンテストで遊んでいました。最初はクラウド変数でバグが起こり、スコア補正がかかる問題が起きました。ほかに、背景の色が見づらかったりしたら、アレンジで白黒に変えたりして、自分好みに変化していました。500の壁は遠かったみたいです。', null, null),
  ('5ea32560-b144-5140-8ae9-43e501a5a112', '57f45872-1f3e-5540-b676-bf9023444e39', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-31', '16:30:00', null, '通常 / リフレッシュ', 'コンテストでスコアを競っていました。こたろうくんなががら、他人のPCでプレイする行為が目立ちました。そのさい、ハイスコアが出てしまい、悔しがる場面も見られました。スコア更新するたびに、響き渡るように自慢してくれました。', null, null),
  ('b3c11899-c5ee-5c45-b079-1b5376ad0f91', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-07-31', '16:30:00', null, '通常 / 親子大会作品完成提出', '初めに前回にほぼ完成した作品を見直しをしていきました。ここで、クリアゲームオーバー時に音などを追加して完成しました。提出の際には、書いてきた作品概要の部分が短かったので、ヒアリングをしながら完成させていきました。 その後、周りでやっていたジオメトリーダッシュ_シップ編（簡単プログラムVer）を沼りこんでいきました。', null, null),
  ('742509f7-82d1-5cce-981f-f68f3d26b29f', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-08-01', '17:30:00', null, '通常 / Roblox studio', 'レッスン時間前半Robloxのゲーム作りではなくて、何かゲームをずっと続けていて、レッスンに入るよう促すも、あれやこれや言ってなかなか始めてくれませんでした。３０分近く経ったところで、やっとで始めてくれたのですが、前回の続きのアスレチックゲーム制作は、ありきたりで面白くないから、それはボツにすると言い前回の続き再開してくれない。じゃあ、何かデジタネの動画からひらめきを得て何か新しいことが始められるかもということで、デジタネ動画のどれかをやってみないかと進めたのですが、全然ダメで、このままだと何も進められないので、何か作ってみたいゲームがないか聞いてみると、色々とこんなゲームが好きでプレイしているとかいう話をしてくれました。ただ、説明はするものの、「こんなゲーム難しくて絶対作れない」と否定的な話ばかり、やってみないとわからないし、簡単でシンプルなものをまずは作ってみようよということで、好きなホラータイプのゲームの制作を開始してくれました。残り時間は、黙々とそのゲームの制作をしていました。スクリプトを利用するとかではないので、質問もなく、パーツを組み合わせて、ホラーハウス？的なものを作っていました。具体的などんなものを作りたいかの詳細までは話はできていませんが、一歩進んだのは良かったです。（とはいえ、次回、またボツにすると引っ返さなければ良いですが、、、）', null, null),
  ('e73418e3-a269-55f8-89f4-7ddcdbda82e7', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-08-01', '17:30:00', null, '通常 / エクセル', '前回の続きから開始して、2章の実習０１の途中まで進められました。自走で、特に質問もなく進めて時間となりました。途中でエクセルの話をしてみたら、エクセルは楽しいとのことでした、もっと以前から知ってたかったとも言っていました。学校のPCにエクセル入っているので、数学とかで利用してみると言っていました。', null, null),
  ('68bf0ad4-6424-53a9-aae7-0aacd4b62e08', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-08-01', '17:30:00', null, '通常 / エクセル', '前回からの続きで、実技練習問題３を進めました。一人で自走していて、途中質問等ないか尋ねても、何もなくスムーズに進めていたようです。良い調子だと思います。', null, null),
  ('104da4ed-e953-5300-a1e7-405acce23223', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-08-01', null, null, '通常 / roblox studio', 'ハラハラピンボールで覚えること(CanCollideやTransparencyの使い方)は、動画でみると写すだけなので簡単にできるように思いがちですが、いざ自分でプログラムを書くとなると、なかなかできないものなので、ハラハラピンボールで一番重要となる部分を、自分で何も頼らずにスクリプト作成してもらいました。やはり、細かい部分の理解が甘かったり、間違って覚えていることが露呈したので、その部分がわかって、きちんとした理解につながったので良かったです。一応、覚えるべきところは終わったので、追加でスクラッチで言うクローンを用いて、ボールを坂の上に２秒おきに作成するようなプログラムを作成して、こう言うこともできると言うことを示したかったのですが、今日は早く帰らないといけないと言うことで、途中で終わってしまいました。覚えるべきところは終わっているので、あとは、確認テストだけして、次に進んで大丈夫と思います。（作成途中のクローンのことはスキップして構いません。私が入るときに後でフォローしておきます）', null, '時間帯: その他'),
  ('1096c122-444a-5a53-bc16-ed607db38a7c', '31feac25-f850-5d21-8e43-ed4d7badb6a0', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-06-28', null, null, '通常 / 【体験】', '学校のパソコンクラブでゲームを作っているそう。基本操作コースのネコの動きは自力で余裕。塾に併設されているプログラミング教室では、内容が簡単すぎてつまらなかったとのこと。洞窟ダイヤではメッセージを使ったアレンジをしていた。ジオメトリーダッシュは遊んだことはあったが作ろうとしたことはないそうで、背景スクロールをとても喜んでやっていた。座標や不等号の向きなどの勘が良く、きちんと理解して作成することができていた。', null, '時間帯: その他'),
  ('6a360333-0b1d-5d76-ae0b-f917cbf6e38c', 'ec153bd8-5b4d-5684-9704-382af23cf64a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-08-02', '16:30:00', null, '通常 / リフレッシュ', '親子大会作品完成提出のお疲れリフレッシュとして、シップのジオメトリーダッシュをコンテストでやっていきました。最初はなんなんこれ無理げーだとと感じていましたが。すぐに慣れハイスコアを連発しいました。500の壁も突破も余裕であり、左手や親指に変えたり遊び方も工夫していました。今日の教室内でトップの記録を出しました。', null, null),
  ('39aff313-f7c5-5683-907c-19a2088c281d', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-08-02', '16:30:00', null, '通常 / リフレッシュ', '親子大会お疲れでシップのジオメトリーダッシュをコンテストでやっていきました。授業来る前から作ってくれました。始めると、やりこんでいろいろとアレンジしたいことがあふれてきました。アレンジを始めると、偽の障害物を作り、当たり判定をかいくぐるスプライトを作ってくれました。形も様々でいろいろと惑わす形になっていきゲーム性もアップしていきました。', null, null),
  ('b1e84d5e-9b0f-588d-b69a-211f4807650f', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-08-02', null, null, '振替 / roblox', '振替のため2時間連続でした。前半の1時間はアルスタジオのコンテストで遊び、後半はrobloxをやりました。 今日はしっかりやる約束だったので時間になったらやってくれました。動画はスピードが遅くてめんどくさいというのでpdfのテキストで進めました。数秒経ったら床がすり抜けるように設定するスクリプトの内容を学びました。script.Parent, CanCollide, true/falseといったコード内に出てくる単語の意味を確認しました。記憶や読み方が抜けているところがありましたが、一度おさらいするとしっかり理解していました。オブジェクト複数選択の方法を扱ったときは「一つずつ選べばそんなやり方覚えなくていいのに」と文句を言っていましたが、roblox以外でもパソコン全体で使える便利な技だと説明しました。最終的に確認テストで満点を取って完了しました。', null, '時間帯: その他'),
  ('301cf947-d992-5d3f-bb33-5bfce92c87a1', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-02', null, null, '通常 / ロブロックスの続き、または、コンテストのゲーム参加を通してScratchのプログラミングを思い出す', 'ロブロックスかアルスタジオのコンテストかを選ばせたところ、久しぶりにアルスタジオをいじってみたいということで、コンテストのゲームをしました。 途中、コードを見て懐かしがっていて、マウスの操作をスペースキーに置きかえていました。 今日はゲームの方に夢中で、授業はあまり進みませんでしたが、久しぶりにおしゃべりをしながらPCに向かっていて、良い気分転換にはなったかもしれません。', null, '時間帯: その他
盛り上がり: こういうゲームはあまり得意じゃないかも、と言いながらも、かなり熱中していました。'),
  ('d61c1e57-5837-5927-863a-fd687a9a04e2', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-08-02', '16:30:00', null, '通常 / リフレッシュ', '親子大会作品完成提出のリフレッシュとしてコンテストでシップのジオメトリーダッシュをやっていきました。記録を更新するたびに、喜んで次にはまり込んでいきました。400を超えるのは余裕になっていました。後半、アレンジを始めると、シップののイラストを変えたり、ステージを優しくしてみたり、より良いものになりました。アレンジしたものをスコア更新を授業時間を超えて挑んでいました。', null, null),
  ('9ab4dfcd-cc62-544c-a02b-d02475ad58a2', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-02', null, null, '通常 / U16大会作品の構想を練る', 'ExcelかU16大会の準備か、やりたい方を選んでもらったところ、U16大会で何を作るか考えたい、ということで、1時間かけていろいろなサイトを見ながら構想を練っていました。 他の大会の入選作品を見たり、障害者支援のサイトを見たりもしていましたが、とりあえずデジタルフラッシュカードのようなものに興味が出たようでした。', null, '時間帯: その他
盛り上がり: 色々調べながら作りたいものを探しているのが楽しそうでした。'),
  ('eaf0e53d-f063-5446-ae46-b3890651a9a0', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-08-02', '16:30:00', null, '通常 / リフレッシュ', 'コンテストしてシップのジオメトリーダッシュをやっていきました。最初は慣れないものの、少しずつ伸びてきましあ。ただクリックしているだけで、利き手を変えたり独自に遊んでいました。アレンジではステージを優しく変えて、あたかも自動で捜査している風に見せました。実際は、本人が隠れて捜査しているのですが、、でも、結構楽しく周りと共有してできてました。', null, null),
  ('ab18c081-b194-5cc1-9b51-faa051815af9', '31feac25-f850-5d21-8e43-ed4d7badb6a0', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-02', null, null, '通常 / 教室に慣れる', '5分前くらいに来室し、教室に来てからの導線や準備を説明しました。 今日は教室全体がコンテスト作品への取り組みだったので、一人だけ基本操作コースをさせるよりも、一緒に楽しんで参加させる方針にしてみました。 結果としてゲームもとても楽しみつつ、教室の子たちと会話をしたりして馴染むことができました。 途中から自主的にアレンジに入り、連打要素を取り入れたり、背景の動きを工夫してみたりと、かなり熱中してアレンジしていました。 連打数を数えてみたら、などのこちらの提案にも素直に応じて、しっかりと作り込んでいました。 学校でも作成することがある、とのことだったので、アルスタジオへのログイン方法とアカウントを教えました。', null, '時間帯: その他
盛り上がり: 時間いっぱいまでアレンジとゲームプレイを思い切り楽しんでいました。'),
  ('823cdd73-41c0-5e8d-afdb-c8cd457d6327', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-08-02', null, null, '通常 / アルスタジオコンテスト', 'コンテストは楽しんで遊んでいました。先日バグがあったから修正したという話をしたあとも、バグで高得点を取ろうと企んでいました。アレンジとしては、まずマウス操作が不便だというのでスペースキーに変えてみました。横スクロールしている背景のクローンは、目指している検定1級の範囲なので内容をおおまかに押さえました。コスチュームを変えながらクローンを生成していることは理解したようでした。', null, '時間帯: その他'),
  ('5ee1c72f-ae8f-5e0d-80b7-67f8ae351abf', '82396ac6-71bd-59d4-a372-57212866fd5d', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-08-02', null, null, '通常 / アルスタジオコンテスト', 'コンテストで遊んでいるときは、自己ベスト更新となる400点を目指して何度もがんばっていました。アレンジのときは、まずスペースキーでの操作にしたらやりやすいといって変更していました。また、移動の速さを変えたいというので、「x座標を〇ずつ変える」の数字をいじりつつ、横スクロールの仕組みも一緒に確認しました。', null, '時間帯: その他'),
  ('88255a7e-4eaa-5a27-97b9-5f91ed902418', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-08-02', null, null, '通常 / アルスタジオコンテスト', 'コンテストでしばらく楽しく遊んで、アレンジに入りました。まずはマウス操作が不評なので上向き矢印キー操作に変更しました。そのあとコードを読み、白色に当たったらゲームオーバーであることを読み取り、それを利用して白い線で新しいステージを描きました。アンダーテール風の背景だったり白文字を障害物にしてみたりと、面白いアイデアを思いついていました。', null, '時間帯: その他'),
  ('611c79bb-2e49-5ef8-b723-7c348544b486', '5b56509a-ab37-5b95-9b2b-2750525ad8a5', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-02', null, null, '通常 / U16大会作品の作成続き', '作品にテストプレイ要素を追加したそうで、テストプレイ中に見える向きを正面から側面にしたときにブロックが消えたり上に飛んで行ったりしてしまうバグを直していました。 こちらにバグの現象を説明している最中に思いついたようで、結局自力でコードを追加して直していました。', '一通り作品を作り込んだら、セーブできるように作り込んでいきたいそうです。', '時間帯: その他
盛り上がり: 作品を作ることがとにかく楽しそうで、夏休み中に現在作成中の部分を完成させたいと意気込んていました。'),
  ('df1722a3-b661-5fd7-a102-db035cf7dd7f', '49fc73e4-fc37-5c75-a77f-02a27f5e169b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-08-02', '16:30:00', null, '通常 / リフレッシュ', '周りに合わせてコンテストのシップのジオメトリーダッシュをやっていきました。やり始めると、「つまんない」「いやだ」と大連呼しつつ、遊んでいました。ほかのことをするかと聞いてみても「いやだ」と拒否して遊び続けていました。あまりにも周りに気を下げる発言が多かったので、ゆき先生から注意をしました。前回授業をしてたときには、発言あったものの今回のほど量はなくうまく進められていた。今回の様子を見ると、ゆきとくん一人でゲームを遊ぶのが苦手だと感じます。ゲーム方法もなかなか見つけらなったし、その後のコツもなかなか習得できなかったので。観察眼が同学年として比べても弱い感じがあります。前回の授業みたいにすべてを伝えれば、考えながらできていました。なので、その辺を伸ばせたらいいと思います。', null, null),
  ('77316c87-38fc-5238-a283-ba0c1c5e87cf', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-04', '16:30:00', null, '通常 / 遊んだゲームのコードを読んでアレンジを考える', '先週木曜日のコンテストの記録が、バグ修正によって消えてしまったので、かえってやる気になって、授業前から何度もチャレンジしていました。 先週の授業ではゲームだけで終わってしまいましたが、今日はさすがに少し落ち着いたのか、20分くらい遊んだ後で、アレンジを促すこちらの話を聞いてくれました。 アレンジをしよう、コードを見よう、というと「いやだ」と返事をするのですが、もっと具体的に「コースを変えてみよう」などと言うと乗ってくるようでした。 ゲームオーバーになる条件や、背景がスクロールして変わっていく仕組みなどは、ちょっとした誘導で読み解くことができました。背景の最初のコスチュームを色々と変えてテストプレイをしてみたり、コスチュームの絵をいじってみたりというアレンジをしていました。 遊び時間は長かったですが、コードを見て納得できたところは、先週からの進歩と言えなくもないかと思われます。', null, '盛り上がり: ずっと、岳くんと一緒に楽しそうにしていました。 記録更新は岳くんに任せていたようですが、一緒にプレイしたり、アレンジもそれなりに楽しんでいたと思います。'),
  ('1d14a834-628f-5639-8e4a-d69988f4c762', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-04', '16:30:00', null, '通常 / 遊んだゲームのコードを読んでアレンジを考える', 'こういうゲームは得意、と言って、ずっと記録更新にチャレンジしていました。 アレンジは、勇作くん同様はじめは乗り気ではありませんでしたが、コスチュームをいじるところから入らせると興味を持って、ついでのようにコードも少し見てくれました。 途中でこうしろうくんがiPadを使っているのが羨ましくなってしまったようで、絵を描きたいモードになってしまい、みうちゃんにアイビスペイントを少し教えてもらっていました。', null, '盛り上がり: コンテストのランキングに入れたのをとても喜んでいました。'),
  ('4e334e44-07bd-5331-ab25-14429607a591', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-07-28', '16:30:00', null, '通常 / 親子大会作品の完成、提出', '家で親御さんと手を入れてきたと得意そうでした。 本人が納得いくところまで見直して少し手を入れ、あとは一生懸命に提出フォームをタイピングしていました。タイピングは一生懸命覚えている最中のようで、自分でやろうとする意欲もありました。 提出が済んだら満足したのか、あとは藤田兄弟とおしゃべりしたりしながら遊んでいました。', null, '盛り上がり: 作品の提出ができて満足したようでした。'),
  ('378aeade-2769-5555-8bf5-26aac432f39d', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-07-28', '16:30:00', null, '振替 / 親子大会作品の完成、提出', '最後のチェックと言いながら、少し手を入れては戻してみたりと楽しそうでした。 提出の入力は、親御さんが入れてくれた概要以外は自分でしっかりと入力していました。 提出が無事にできて、とても満足そうでした。', null, '盛り上がり: 提出ができた！ととても嬉しそうでした。'),
  ('ae2983c2-fb9f-59c8-b715-fdc8d10bd1cf', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-07-28', '17:30:00', null, '振替 / 親子大会作品の完成、提出', 'ギリギリまでパンサーの動きにこだわって、自然なジャンプに見えるようにコスチュームを細かく編集していました。 ジャンプのときの動きが良くなった反面、ブロックを飛び越えるのがとても難しくなってしまったため、ブロックの位置の編集や速さの調整などに時間を使っていて、授業終了まであきらめずに頑張っていました。 なんとかやりたかった動きだけは完成したので、授業後にお母さんの立ち合いで提出作業を完了させました。', null, '盛り上がり: イラストコースで頑張っているせいか、デザイン面で妥協したくなかったようで、とても熱心に作業をしていました。これからは自分で描いたキャラクターを使って作成していきたい、と楽しみにしているようでした。'),
  ('853c3a58-e5bd-50f6-88f1-878989eab4fc', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-07-28', '17:30:00', null, '通常 / Excel検定3級受験', 'スムーズに試験準備のログインやダウンロードも終え、試験に取りかかっていました。 試験終了まで10分近くの余裕を持って終えていました。 「いつものようにできた」と、ほっとしたような感じで帰っていきました。', '次は2級に挑戦したい、とのことでした。', '盛り上がり: 手ごたえはしっかりあったようで、笑顔を見せていました。'),
  ('3c10b648-4611-5805-b408-30525c89abda', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-04', '16:30:00', null, '振替 / コンテストを楽しみながらアレンジとコードの復習をする', '集中してゲーム制作に取り組んでいた。 自分でイラストを書いてアンダーテールの世界観に落とし込んでいた。 自分でゲームの難易度を考えて後ろから迫ってくるスプライトを作成などをしていた。', null, null),
  ('6f5bcc46-7062-5e9e-bd48-2ae84d5bb881', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-04', '17:30:00', null, '通常 / コンテストを楽しみながらアレンジとコードの復習をする', '色々な電車のデザインのプレイヤースキン、ゲームオーバー画面を作成していた。 数値の変更やお邪魔ブロックに手を加えていなそうなので少し変更してみても良いかなと感じた。 プレイヤースキンを沢山作っていたので距離によってスキンが変わるなど活用する方法を一緒に考えられると良いなと思います。', null, null),
  ('2ae4771b-cea7-52be-aa2d-814bc78c2909', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-04', '17:30:00', null, '振替 / コンテストを楽しみながらアレンジとコードの復習をする', '集中して作成していた。 プレイヤーの数値を変えて挙動を横広にしていた。 挙動が変わることによって元のお邪魔ブロックの配置だと難易度が高くなってしまうので自分で挙動に合うような配置に変えていた。', null, null),
  ('9044dae0-568f-56a4-b362-a41f2da5e81e', '0d16e234-e60d-5fdb-978f-1722acf9a2b2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-07-31', '16:30:00', null, '通常 / コンテストを楽しみながらアレンジとコードの復習をする', 'お家の都合で20分ほど遅れてきました。 入室時は教室全体がゲーム大会の雰囲気だったため、すぐに遊び始めていました。 ゲームとしては少し難しかったようですが、他の子のプレイをのぞいたり、いちおうリミックスして中身を見たりと授業時間は楽しんでいたようでした。 コードの内容は朔太郎君にはまだ難しかったため、地面のコスチュームがたくさんあって順番に出てくること、コスチュームは1から始まっていること、プレイヤーが白色に触れたらどうなっているか⇒ゲームオーバーになる、という程度の確認をしました。', null, '盛り上がり: 今日はお楽しみDayだったせいか、のびのびと楽しんでいたようでした。'),
  ('d3308e20-3f06-5d98-b9da-a9829fa4fe82', '1c7005cc-2815-558f-993a-9c7617d34c44', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-05', '16:30:00', null, '通常 / コンテストを楽しみながらアレンジとコードの復習をする', 'あまりマウス操作になれていなかったようでしたが楽しそうに遊んでいました。記録が伸びるたびに嬉しそうに報告してれました。', null, null),
  ('bd33f4db-1c9a-537c-9afc-5afa27271a25', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-05', '17:30:00', null, '通常 / コンテストを楽しみながらアレンジとコードの復習をする', 'ゲーム慣れしているのか数回プレイしただけでかなりスムーズに先まで進めるようになっていました。 記録更新に向けてゲームオーバーになるコードを書き換え練習をしていました。', null, null),
  ('f9091dd6-54b1-530c-9702-cd81e2a26776', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-05', '16:30:00', null, '通常 / コンテストを楽しみながらアレンジとコードの復習をする', 'ゲーム自体は300点台を超えることが難しかったようで、記録を出すことはわりと早めに諦めていました。そうすけくんが記録を伸ばしていたので、何度ものぞきにいっていました。 20分くらい遊んだらプログラムがしたくなったようだったので、コードを見て、記録を伸ばすためにできることを考えてもらいました。 地面のスプライトのコスチュームとコードを編集して、苦手なところから始まってそこを重点的に練習できるようにする、ゲームオーバー判定をなくして、途中でゲームオーバーにならずに先まで進めて感覚をつかんでみる、などの対策を考えて実行していました。 ジャンプの勢いの数値を編集してゲームの雰囲気をかなり変えて、そうすけくんにプレイさせて面白がっていました。 途中で画面のソースコードを開いてみて、こういうのがやってみたい、と話していたので、頑張って検定をすすめてロブロックスに進むことを提案し、お母さんにもお話してみました。検定はまだ4級だから、と謙遜していましたが、現在の実力なら2、3級のW受験くらいはできそうだというと、お母さん共々嬉しそうにしていました。', null, '盛り上がり: この先に対する向上心もあり、もっと頑張って色々できるようになりたい、という意欲が感じられました。'),
  ('24e6fbd3-5d1f-54e8-a123-3df9a423e023', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-07-31', '16:30:00', null, '通常 / コンテストを楽しみながらアレンジとコードの復習をする', 'コンテストのゲームは、初めは喜んでプレイしていましたが、なかなか記録が出せないとわかると興味も薄れてきたようで、自分から「何か作る方がやりたい」と申し出てきました。 大会作品の作成中から、早く検定で上の級を取りたいと言っていたので、無理にとは言わないけれど…という感じで検定問題を勧めてみました。こちらの想像以上に食いついてきて、早速問題に取り組んでいました。 試験時間が足りなかったので、次回は続きからになります。', '検定問題の続きから', '盛り上がり: 検定を早く終わらせてロブロックスをやってみたい、と、やる気を見せてくれていました。'),
  ('3bd1c51c-1f3e-5adf-b78c-32a372524673', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-07-31', '16:30:00', null, '振替 / 遊んだゲームのコードを読んでアレンジを考える', 'いつもと違うメンバーの教室に入ってきたときは、月曜日より少しだけおとなしかったですが、まわりのメンバーにつられたのと、今日はお楽しみデーでゲームのコンテストだとわかると、すぐに普段の調子を取り戻していました。 勇作君が好きそうなゲームだったこともあるのか、とにかく盛り上がって、「今日はずっとこれをやっている！」と何度も宣言をしていました。 途中でコードを見たり、アレンジをしたりすることも勧めてみましたが、今日はとにかくゲームで記録を出したいと聞きませんでした。 クラウド変数のバグのせいで、一時的にランキング2位に入っていましたが、自分の本来の記録の数字をしっかり覚えているようで、ラッキーというよりも、納得がいかない、という反応でした。', null, '盛り上がり: 授業時間中ずっとゲームで盛り上がって、ある意味スッキリしたようでした。'),
  ('9668fdbc-8fe5-537b-a91f-bde8a63641c2', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-07-31', '17:30:00', null, '通常 / ExcelおよびU16大会作品の作成', '親子大会が終わった小学生向けの話を聞いていて、自分も少しチャレンジしたいとコンテストのゲームを始めていました。 クラウド変数の設定ミスで、記録は消えてしまいましたが、しっかりコースを2周以上進めて1800点以上の記録を出していました。 今日は疲れていてあまり頭が回らないと言って、この日はひたすらゲームの記録更新に励んでいました。 夏休みの自由課題をどうするか、先生達に相談してきたので、興味がある科目などについて少し雑談もしました。理科の中では生物が点数が良いそうです。', null, 'タイピング: 木曜日の小学生たちから完全に尊敬の目で見られていて、寿司打を始めると周りに見学者がくるのに苦笑してました
盛り上がり: 授業にはなりませんでしたが、リフレッシュできたので、家で少し頑張ってみる、と明るい感じで帰っていきました。'),
  ('75526efb-e7db-552a-af42-fdc134175724', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-07-31', '17:30:00', null, '通常 / U16大会作品の作成', '作成中の着せ替えゲームのエントリー先を、親子大会からU16大会に切り替えたということで、作品の作成続きを勧めてはみましたが、連日のテニスで相当疲れているようで、この後こんな風にしたい（パーツを選んだらウィンドウが切り替わる？）という話をしたら、あとはコンテストのゲームになってしまいました。 ゲームをしている最中は起きていられる、といった感じでした。 テニスはかなり本格的にやっているそうで、地方への遠征もあり、関東大会？あたりまで出たりしているようです。練習も一日数時間の日もあるとのことでした。 それでも教室には楽しみに来てくれているようで、目的がイラストとおしゃべりのような気もしないではないですが、リフレッシュにはなっているようです。', null, '盛り上がり: コンテストのゲームと先生とのおしゃべりを楽しんでいました。'),
  ('3e86f702-91fd-57dd-8402-4afddd92f712', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-04', '17:30:00', null, '通常 / ロブロックス', 'いつも通り、教室にきたらすぐにロブロックスを進めようとしていました。 今日の担当が大原とみうちゃんで、ロブロックスに慣れていなかったため、デジタネへのログインに少し手間取りました。すみません。そうた君本人も、デジタネを使用しているのはわかっていますが、ロブロックススタジオとデジタネのアカウントについては記憶があいまいなようでした。 ロブロックスについては、みうちゃんが質問してくれるのが嬉しかったようで、わりと得意げに今やっているところを説明していました。 周りの様子をみて、少しだけコンテストに参加したりもしましたが、記録を出すのが難しそうとなるとあっさりあきらめて、残りはロブロックスで遊んでいました。 今回の課題のオープニングからチャレンジまで、チャプター7つ分を20分ほどで終えているので、理解が早いのか、聞き流しているのかがちょっと判断がつきませんでした。', '演習テストから', '盛り上がり: 課題自体には自分からさっさと取り組み、余った時間は好きに遊んで、時間が来たらパッと帰る、といった感じで、楽しそうには見えました。'),
  ('cfb25ef6-28d5-5e47-86de-068be8933336', 'ec153bd8-5b4d-5684-9704-382af23cf64a', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-04', '17:30:00', null, '振替 / コンテストを楽しみながらアレンジとコードの復習をする', '記録を出すのにかなり熱中していて、授業時間内に最高記録を出すことができて満足そうでした。コースをかなりよく見ていて、どこの障害物までクリアしたら大体何点とか、実況しながら楽しそうにプレイしていました。最高点を出した時は、2周目に入った時から興奮気味に実況していました。 途中でコードを見るよう促したところ、ざっと見てすぐに、キーで操作するようにアレンジをしていました。コード自体は初見である程度わかる範囲とのことでした。 サマーランド帰りとのことで、ちょっとおつかれ気味で、今日はのんびりScratchに触れる日となりました。', null, '盛り上がり: 得意な分野のゲームだったようで、とても楽しんでいました。'),
  ('42da3ff1-c603-56d6-ad29-630dafb9bb20', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-04', '17:30:00', null, '振替 / U16大会作品の作成', '周りの雰囲気につられて少しだけコンテストのゲームに参加していましたが、一通り遊んだらまた作成に戻っていました。 前回のコンテストが自分の作品だったためか、途中で過去の自作ゲームを振り返っていて、今ならもうちょっと凝ったものができるかも、などと、ひとしきり感想を話していました。 大会作品の方では、総大将をクリックしたら出陣するか確認し、マウスをクリックした先に移動する動きを作成していました。クリックしたところに移動させるコードに悩んでいたので、マウスのx座標ブロックについて説明し、早速使用していました。 クリックしたところに移動する動きは納得のいくものができたようですが、オブジェクトをドラッグするイメージで、移動先の前に総大将スプライトをクリックするとスプライトがおされたときのスクリプトを繰り返してしまうので、後々変数で制御する必要があるかもしれません。', null, '盛り上がり: 総大将を移動させる動きが意図した通りにできたようで、この部分についてはとても満足そうでした。'),
  ('e0175872-b1cb-5501-bbfc-9db83915381f', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-05', '16:30:00', null, '通常 / コンテストを楽しみながらアレンジとコードの復習をする', 'ゲームをプレイしながらもかなり冷静にコースなどを見ていて、マウスを操作しながら何度も「このブロックがもう少しこうだったら」などと解説をしてくれていました。 アレンジを勧めただけではあまりのってこなかったので、ゲームの記録を伸ばすための練習コースを作ってみて、と促すと、素直に考え始めて手を動かしていました。 アレンジではいつも通り、まずはコスチュームの編集から入っていました。プレイしながら分析していたところをすぐに見つけては、微妙に位置やサイズを調整していました。 祥太くんにだいぶ慣れてきたのか、自分が記録を出しているところを見せたり、祥太くんがアレンジしたものをお試しプレイをしたりと、交流する姿が見られました。', null, 'タイピング: 毎回1回ですが、律義にやっています
盛り上がり: 自分がアレンジしたもので練習してからコンテストに戻った際に記録を伸ばすことができたのが嬉しそうでした。'),
  ('7197bc62-b928-5e66-bcd5-79adf661cacf', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-08-18', '17:30:00', null, '通常 / 3級検定練習', '3級1回目の練習をやっていきました。昨年度やっていたので、最初に解き方のコツだけ教えて取り組んでいきました。解いていく中で、ひと文が長いものだと、何を動かせばよいかわからなくなってごちゃごちゃになっていました。なので、分を区切ってあげてたら、自力で答えることができました。ほぼ時間通りくらいで完成に持っていけることができました。次回からの演習する際には、分を区切ることを教えていけたらよいと思います。', null, '盛り上がり: 前回のコンテストのゲームにはまっています。'),
  ('dba3c859-3450-546a-a666-37dfaeacde59', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-08-18', '17:30:00', null, '通常 / ロブロックス', '前回の確認テストを完璧にせず、次に進もうとしたので引き戻しました。ステージ2の部分から関数が出てきて、英語の分量が急に増えていくので、しっかり確認を取っていきました。確認テストを解いてる際に、かなりあてずっぽの感じで解いてたので、わからないなら必ず先生を呼ぶように伝えました。for文のことが何も理解ができていなかったので、今一度教えていきました。不慣れな英語を扱うから、忘れても放置しないでほしいです。一度、確認テストだけ見直す回も必要だと感じます。', null, null),
  ('ec292f57-1b1d-5f1e-976d-c310034bf97b', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-08-18', '16:30:00', null, '通常 / 初めての検定練習', '3人まとめて検定の練習をやっていきました。最初は、すでに置いてあるコードを繋げてコードを作っていったが、順番がぐちゃぐちゃでした。そのことを指摘すると、「作ってあるじゃん」と返事をしました。書いてあることを上から順につなげていかないと正しくいかないことがある、とコードの順番の大切さを伝えると、順に作ることができました。結果的に、50分くらいかけて問題文のコードを完成しました。以前にも、コードの順番の認識ができていないことがあったので、本人のプログラミングスキルを上げるためには、検定はかなり重要要素だと思います。ほかに、コードの種類もあやふやな覚えなので、多く見知る経験も必要だと思います。また、がくくんは集中力が周囲に向いてしまいやすい性格なので、自分のやってることも忘れやすいです。なので、ほか二人よりも丁寧に検定練習をやっていきべきだと思います。', null, null),
  ('9d54be49-e03d-5ff6-a92e-3a46183d9ee3', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '19c3ff7e-f3fb-5570-9f85-06429f30290f', '2025-08-19', '16:30:00', null, '振替 / 3級検定練習', '3級の2回目の練習に取り組みました。昨日に引き続きだったため解き方を説明する必要はなく、最初から自分で問題に従ってプログラミングすることができていました。 途中、ドラゴンを打っても消えない状態でしたが、見本と見比べて修正してみようと伝えると自分で直すことができていました。 問題が終わった後は、アレンジでリアルな電車の絵を書いて登場させていました。 それっぽくなった時点で完成したと思ってしまう節が見受けられたので、次回は見本とよく見比べて本当に問題通りにできているか確認する癖をつけられるとよいと思います。', null, null),
  ('f1bcaf9f-d1d7-56b3-960c-012357be3f15', '5b56509a-ab37-5b95-9b2b-2750525ad8a5', null, '19c3ff7e-f3fb-5570-9f85-06429f30290f', '2025-08-19', '17:30:00', null, '振替 / 検定1級練習', '検定1級に向けて、1回目の練習問題を解きました。解くのに手間取った部分は感じられず、ものの30分程度で完成させることができていました。 完成した後は自分なりのアレンジを加える余裕もあったため、理解が足りていない部分はなかったようです。 今後は検定で100点を目指すべく残りの練習問題にチャレンジし、（おそらく時間は余ると思われるため）アレンジの練習をしていけると良いと思います。', null, null),
  ('f73f4e37-d9fb-52cb-9648-2bf68309e544', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '19c3ff7e-f3fb-5570-9f85-06429f30290f', '2025-08-19', '16:30:00', null, '通常 / 検定2級練習', '今回は検定に向けて2級の1回目の練習問題を解きました。 乱数を用いた足し算と「りんごとバナナ」を用いた表示方法に多少苦戦していたためその部分は一緒に取り組みましたが、ほかの部分は概ね自分でプログラムすることができていました。 今回は自分で作成する部分は完成できたものの元からあるコードの修正までたどり着くことができませんでした。能力的に難しいというよりは集中力が切れて喋っている時間があったせいだと思うので、次回以降は自分の問題が解けるまでは集中して取り組めるよう訓練していけると良いと思います。', null, null),
  ('4090c0b0-57eb-579c-96bf-a2d1ccd15c67', 'd3885e29-ee68-501b-bf31-6c050fd50c36', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-08-01', '16:30:00', null, '通常 / コンテストのゲーム', 'しばらくコンテストのゲームで遊び、りょうまくんと楽しくスコアを競い合っていました。アレンジでは、障害物を消してみたり新しい障害物を描いてみたりと自分なりのコースを作っていました。できれば横スクロールの学習も軽くしたかったですがそこまでは気乗りしないようでした。', null, null),
  ('ed3d82cd-7ccd-5c74-83fe-5dbf7eb99d07', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-08-01', '16:30:00', null, '通常 / コンテストのゲーム', 'しばらくかなめくんと競争するようにコンテストのゲームで遊び、その後アレンジに入りました。まずはこのゲームのマウス操作が不便だというので、スペースキーでも動くようにしていました。マウスクリックしたときのコードを見つけて、スペースキー操作を「または」でくっつけることができました。真ん中にあった障害物を消すなどもして、最終的にはアレンジ作品として公開までしました。', null, null),
  ('f9cdbc56-2d57-5e17-8ce8-84b02c0361ec', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-08-01', '17:30:00', null, '通常 / 自由製作', 'ロブロックスの選択肢もありましたが、scratchで今作っているオリジナルゲームを仕上げたいというのでそれに取り組みました。クリックごとにコーラを飲むクリッカーゲームでしたが、クリック数が貯まると一度に開けられる本数が追加で買えたり、自動クリック機能も買えたりと大枠はできていました。今日はうまく動作しない部分のバグつぶしをしました。一緒に怪しい場所を絞り込んでいったのですが、クリックされた際のメッセージ送信のときに何回も送られていたので、「押されたではないまで待つ」を置いて解決しました。また、マウスのポインターに指示棒のスプライトを置くなどして見た目も豪華にしていきました。', null, null),
  ('f2a4f213-259a-53a8-98bc-50abbdd39fa1', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-08-01', '18:40:00', null, '通常 / robloxでscriptの習得', '前回やった確認テストでミスしたところがあったので解きなおしたところ、間違えたところは覚えたようできちんと満点を取れました。次のハラハラピンボールに進み、CanCollideやtrue/falseなど、以前のscriptで出てきた言葉が出てくるときに意味を確認すると、今回の状況に合わせてしっかり意味を説明できていました。', null, null),
  ('c4eba5d9-b403-5bbd-b6c3-b2a6749a3efe', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-08-01', '18:40:00', null, '通常 / コンテストのゲーム', '通常授業+振替で2時間連続でしたが、終始集中して取り組んでいました。コンテストのゲームをそれなりに遊ぶとアレンジに興味を持って取り掛かりました。ハロウィンをテーマにしたいとのことで、障害物をカボチャ、骸骨、クモの糸などにしてステージほぼ全てを作り変えていました。テストプレイを挟みつつ障害物の大きさや位置を変えることで難易度調整もしていました。しっかりした世界観のあるアレンジができました。', null, null),
  ('7e6d8344-b2bb-598e-b2a3-7d62c083b7c7', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-08-01', '17:30:00', null, '通常 / コンテストのゲーム', 'まずは開催中のコンテストで遊び、ここが難しいなど言いながらやりこんでいました。アレンジでは背景の見た目をいじっていたので、背景が順番に左に流れてくるという横スクロールの概念を伝えたところ納得していました。通れる隙間が狭すぎて誰もクリアできないレベルにしてみて楽しんでいました。', null, null),
  ('791113da-be50-539c-92e4-d243cfb1f40b', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-08-21', '16:30:00', null, '通常 / 2級検定練習', '1時間早く教室に来てしまったので、そのまま4時半から授業を始めました。2級の問題でしたが、演算式や変数の活用に迷うことなくスキル面が整っていました。そのため、ゆったりと問題を進めることができました。ただ、2級の文章から難しくなるため、コードの順番や配置に迷う場面がたびたびありました。その辺は、やっていくうちの慣れでどうにかなると思います。また、1時間たっても終了しなったため、スキルを素早く使いこなすことも必要です。', null, null),
  ('ef2a111d-d98e-53fc-a1d8-3d95d44a9d55', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-08-21', '17:30:00', null, '通常 / U16大会作成', '着々と進めていました。カードの動きに関しては、けいとくんから第3者の意見を一方的に聞かされていたので、すこしは動きに関して役に立っていたと思います。', null, 'タイピング: 久しぶりにやって熱がこもっていました。'),
  ('ddf60873-575c-574d-b56d-9045847283aa', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-08-21', '17:30:00', null, '振替 / 大会に向けて', 'scratchでオリジナル作品作りをしている場面もありつつも、きょうはかなりフリーダムでした。コーラをクリックして開けるクリッカーゲームでしたが、細かいバグを修正している場面が見られました。クリックの判定が大きくなっているとか ほかは、承太郎君に一方的に助言をしたり、周りのこののぞいたり、ほどよく探訪してました。', null, 'タイピング: 睦月君の速さに驚愕していました'),
  ('9dac23bd-102f-5f85-978d-d25d8ae575d7', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-08-21', '17:30:00', null, '振替 / 大会に向けて', '自宅で作りこんでいた、列車ゲームを作成していました。時速や列車の揺れなどを細やかに再現して、いぜんよりも見た目のゲーム性が向上していました。', null, null),
  ('5414e26a-b7d3-5115-a038-95e7d2879b57', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-08-21', '17:30:00', null, '通常 / 初めての検定練習', '北海道帰りから直行できていて、かなり眠そうでしたが、やる気はともっていました。今回は初めて検定練習を行いました。やっている最中に、コードの内容がわからなくて止まることはなく、スムーズに進めていました。「以下のa, bが動作する」のような文章があると、次はどうすればよいか文章的にわからなくなり止まることはありました。「止まる」のコードも直接的に「ほかのスプリクトを止める」の表現がなく迷う場面がありました。これらの点亜gやっていくうちに慣れていくと思います。スキル面は問題なく進められそうです。', null, null),
  ('71875a2f-7816-555c-9994-a9e1a3d777d4', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '19c3ff7e-f3fb-5570-9f85-06429f30290f', '2025-08-22', '16:30:00', null, '振替 / 検定4級対策', '検定に向けて練習問題を解きました。以前も練習したことがあったため検定の流れや問題にそってプログラミングしていくことへの問題はなさそうでした。また、授業時間内に終わらせることができていました。 カーソルに触れるとアクションを起こすプログラムでは、どこまでを条件分岐の処理に含め、どこからがその外なのかで混乱していたためif文の練習から重点的にやっていくとよいと思います。', null, null),
  ('36059583-97ab-5983-8929-4b509d43eae6', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '19c3ff7e-f3fb-5570-9f85-06429f30290f', '2025-08-22', '16:30:00', null, '通常 / 検定4級対策', '今回は検定4級の最初の問題に挑戦しました。最初は動画を見るなり自分でそれっぽい動きを実装しようとしていましたが、問題文通りに出来ているのかをみられるのが検定だと説明するとちゃんと問題文に沿って書いていました。 問題自体は30分程度で終わり、今回の問題では難しいif文などもなかったため特に不安な単元はありませんでした。内容というよりは、まず初手から文章通り愚直にプログラムしていく練習を積むと良いと思います。 アレンジでは乱数を使って動きを複雑化した雲を追加していました。', null, null),
  ('5469aaab-35f8-5e29-870d-257e53b493dd', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '19c3ff7e-f3fb-5570-9f85-06429f30290f', '2025-08-22', '17:30:00', null, '振替 / 検定2級対策', '検定2級対策の1問目に取り組みました。ロケットの動きの処理や点数処理はスラスラと書けましたが、変数を乱数としてランダムな足し算問題を出す部分と正解、不正解の条件分岐処理で苦戦しました。 問題自体は時間内でほぼ完成まで持っていけましたが、「ランダムな」に対して乱数を用いるという発想が浮かばなかったのと、「りんごとバナナ」を複数用いた条件分岐ができなかったため、変数の扱いと複雑なif文を練習していくとよいと思います。 また、眠かったのか授業を通して怠そうにしていました。', null, null),
  ('df3bc7d4-3236-5c71-ab06-e645845c60d0', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '19c3ff7e-f3fb-5570-9f85-06429f30290f', '2025-08-22', '17:30:00', null, '通常 / 検定4級復習', '前回対策したものの受けることができなかった4級の復習をしました。検定の流れは理解しており、動画を見てスムーズに問題に沿って制作していました。 全体的にスムーズに作成できていて動画の動きに近いものはすぐにできましたが、コードの順番が問題と違ったり「～という」を空白にすることで現在のセリフを消す処理など若干戸惑った場面もありました。 終わった後はアレンジで、マウスカーソルに触れた魚が消えるようにしたりと独創性を見せていました。 問題文通りのコードを使うことはできているので、書いてある順番通りに正しく並べる練習をしていけるとよいと思います。', null, null),
  ('a73fc757-f4a8-5493-b246-9fa10bfb4248', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-08-23', null, null, '通常 / 1級検定練習', '1級検定練習を行っていきました。まず、「点滅する」言葉に引っかかって、すでにできているところをあれやこれやといじってしまっている場面がありました。意味を伝えてたら、その通り作ることができましたが、時間を余分にとってしまっているので、これからは「わからなかったら次へ進む」ことも助言していく必要があると思います。全体的に見てみると、悩んだうえで正解にたどり着く場面が何度かあり、解くスピードがかなりゆっくりです。座標の足し合わせの部分もコードはできているが、そこまでいくのに時間が買っている感じです。できなかった部分として、「ロケットより右側にいる時」の条件式が最後までできませんでした。間接的な表現になっており、座標の考えに結び付くのはヒントブロックの存在を教えるまで時間がかかっていました。そのあとも、不等号の組み立てに時間を要していたので、不等号も苦手意識があるっぽいです。クローンに関しては何の疑問もなく使えていました。 半分程度しか作り終わらなかったので、まずは解き方の流れ、修正での注意を身に感じる必要があります。', null, '時間帯: その他'),
  ('5df70c0f-2e05-53aa-a317-1b45fb0c3b09', '31feac25-f850-5d21-8e43-ed4d7badb6a0', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-08-23', null, null, '通常 / 初めての検定練習', '始めて検定問題にやっていきました。文章から読み解いてコードを作ることはスムーズにいき、スピードも時間内に余裕をもって終わる程度でした。バグあったとしても、しっかりと動画を見比べて、どこが違うのか探すこともしっかりできていました。迷う場面として、「まで繰り返す」や「ほかのスプリクトを止める」が初めて使うコードだったので、最初はそれが使えずに悩んでいました。そのコードを教えて時に、新たな発見の喜びがあったので、教室はいる前までの知識に偏りがあります。なので、検定本番までは、9月末くらいまでは、新しいコードの種類に触れることをメインにやっていった方がよいと思います。', null, '時間帯: その他'),
  ('a04c501e-93fa-592b-8711-ce51b3c96866', '82396ac6-71bd-59d4-a372-57212866fd5d', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-08-23', null, null, '通常 / 検定練習', '初めての検定だったのでその内容と意味を説明してから取り組んでもらいました。お手本ムービーを見ると「こういうアレンジがしたい」というアイデアを話してくれましたが、「まずは設計書通りに作る→その後アレンジ」という順番を伝えると素直に理解してくれました。指示文を上から順に丁寧に読むことができ、おおむね自力でできました。「他のスクリプトを止める」など慣れていない内容だけサポートしました。完成後のアレンジとても楽しそうにやって、特定の場面で出てくるキャラを追加しました。はじめくんはこれから隔週クラスなので検定までレッスンが5回くらいですが、検定練習は3回くらいやろうというお話をしました。', null, '時間帯: その他'),
  ('e9309ef8-df03-521f-8805-b88b6330ecf4', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-08-23', null, null, '通常 / 大会製作', '11月にエクセル検定3級があることを伝え、その上で本人は今日U16の製作を選びました。デジタルフラッシュカードについて、まずはカード自体をCanvaで作るなどしていました。黙々と作業を進めていました。', null, '時間帯: その他'),
  ('60e07d59-faf7-57ee-890b-503af2249351', '49fc73e4-fc37-5c75-a77f-02a27f5e169b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-08-23', null, null, '通常 / チーズを探せの続き', '1か月ほど前に行ったチーズを探せをやっていきました。みみの動きを作っていたことを覚えていたので、気持ちよく遊んでいました。最初に、今は自由に動けるから取れなくなるように迷路を作るよ伝えて、方針をぶれずにやっていくことを目指しました。どうしたら、通れなくなりそうと聞いても、あんま返答がなく違うことに走りそうだったので、とりあえず必要なブロックを持ってこさせました。そして、組み上げて、何ができたか聞いた方が返答はよかったです。そのあと、目を少し放していたら、めちゃくちゃ迷路が複製され、ミミとチーズをみえないカオス状態になっていました。なので、裏ワザとして「最前面」「最背面」のコードを使ったら、以外にも好評で使ってくれました。最後に、変数も追加して、この単元に触れたポイント乱数、変数、最前面確認させました。この子は、最初から理解させるはなかなか大変なので、「そういえばこんなコードあったなセンサ」増やしていけたらいいと思います。', null, '時間帯: その他'),
  ('b51edb52-d446-5f9b-81b6-ea162c6dba92', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-08-23', null, null, '通常 / 検定練習', '検定問題について、基本的にもくもくと集中して進められました。ただ「ではないまで待つ」「～かつ～」といった難しいポイントでつまづくと少しパニックになってしまいました。レベルが上がったからいきなりできなくても当然ということや、ゆっくり時間かけて練習すればいいことをお話して落ち着いてもらいました。分からなかった場所について、嫌にならずに質問してくれたので、やる気はとても感じました。今後の検定練習について、毎回ではないがじっくりやっていきたいという話もしました。', null, '時間帯: その他'),
  ('e05b5edb-9fb8-5f10-b986-f0706377626b', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-08-23', null, null, '通常 / 検定練習', '検定練習は昨日やったので、prgの中から興味を持った脱出ゲームを作りました。スプライトのx座標を調整するとき、苦手な負の数が出てきて混乱していました。「真ん中が0、プラスなら数字が大きいほうが右、マイナスなら数字が大きいほうが左」という内容を図を使って伝えるとイメージがわいたようでした。最初のステージの動きを作り、動画の11分くらいまで終わりました。', null, '時間帯: その他'),
  ('cd66b665-767c-515a-9e25-efc91a385405', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-08-23', null, null, '通常 / 検定練習', '最初、u13?u16?用に家で作っている作品(以前作った元素ゲームの続編っぽいシューティングゲーム)について質問を受けました。リストの中身にリストを入れていてバグっていたので、その中身は文字列でじゅうぶんだとアドバイスすると直りました。 そのバグつぶしはすぐ終わったので、検定練習をしました。2級は初めてで修正問題などもありましたが、ほぼ順調に終えることができました。間違いとしては、テストプレイをした際に正誤判定ができておらず、足し算と掛け算を間違えて設定していた程度でした。今回テーマになっていたような計算ゲームはとても好きなのでアレンジに力を入れていました。 今後の検定練習は軽くやっていけば大丈夫そうという話をしました。', null, '時間帯: その他'),
  ('2c3a3696-366b-5676-87a6-a908f2f0c38d', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-08-23', '16:30:00', null, '通常 / 検定練習', 'やっている最中は、試運転の回数が長くて、そこに時間が食われています。すべて解き終わるのも1時間もかかってしまっていました。ほかに、わからないところがあると、無意識に飛ばして、それ振り返らずに完成としている箇所が何か所もありました。その箇所は、変数の条件式のところで、この理解が、そういえばあったくらいの理解のなので、ここは重点的にやる必要があります。「まで繰り返す」とかも怪しいです。途中の試運転も短くしような。', null, null),
  ('4a69a05b-9a23-5043-8c86-0874f545b221', '5b56509a-ab37-5b95-9b2b-2750525ad8a5', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-08-23', '17:30:00', null, '通常 / 検定練習', '解くスピードはバグが発生しましたが、自力で解決でき40分くらいで終えました。リストも全然悩むことなく解けていました。問題文の文章構造ややこしさで1ミスしたくらいで、よくできています。なので、検定対策は今はしつこくやらずに、U16を優先させてもいいかもしれません。', null, null),
  ('ccc68d82-d583-5227-b704-eacdfaaa912a', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '19c3ff7e-f3fb-5570-9f85-06429f30290f', '2025-08-22', '18:40:00', null, '通常 / U13大会', '今日もU13大会に向けた大会作品の作成をしました。前回までで乱数を使った計算問題の出題はできるようになっていたため、特定の問題数正解したら爆弾解除成功、答えを間違えたら解除失敗と表示される部分を条件分岐を用いて作りました。 また「〇を▲で割ったあまり」のブロックと変数を使って、正解数が偶数個であるときに「次のコスチュームにする」を実行する部分も作れました。 今回である程度ゲームシステムは完成しているため、今後は細かい梃入れをしていければよいと思います。 また、ロブロックスをやるために11月に2級検定合格を目指そうという話をしました。', null, null),
  ('e0701367-714f-5507-8ca7-07bc823efb6e', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '19c3ff7e-f3fb-5570-9f85-06429f30290f', '2025-08-22', '18:40:00', null, '通常 / 検定4級対策', '今日は検定4級に向けた対策の1問目を解きました。検定は初めてなのでまずお手本ムービーを見て動きを確認し、問題の流れに沿って作るということを説明してから作り始めました。 1問目ということもあり基本的には問題文通りに作ることができ、「～という」の中身を空白にしてセリフを消す動き以外はつまずくことなく制作できました。終わった後はワニの姿を自分で書いたお化けに変えるアレンジをしていました。 今後はもう少し複雑なifやwhileの使い方、今回の「～という」のようにスクラッチ独特の書き方を学び、検定問題の傾向に慣れられるとよいと思います。', null, null),
  ('119838cc-381c-5a16-b146-de856d10db12', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-18', '16:30:00', null, '通常 / 検定問題の進め方を学習する', 'あえて「試験」ということは強調せず、だいぶレベルアップしてきたので、どこまでできるようになったのかチェックしてみよう、と声をかけ、こういう問題ができるようになったらロブロックスができるようになる、と説明すると、やるやる！と言った感じでのってきました。 問題文は必ず順番に読んでいき、できたところはマークをつけること、どこに作成するべきコードなのか、必ず「○○の場所」という表記を確認することなどの注意事項を伝えたところ、スムーズに理解ができたようでした。 一問解くごとに「先生、合ってる？」と確認したがりますが、聞いてくる段階でほぼ正解をプログラミングできていました。 動画と同じものを作成する、という課題もきちんと理解できていて、問題を進めていく上で、動画と見比べて「ネコの足が動いていない」ということにも気づき、間違えているところがあるのかと見直そうとしていました。これについては、問題を最後までやって、それでもおかしかったら見直そう、と声かけをすることで納得させました。ラストの問題を解いたところで動画と動きが同じになり、喜んでいました。 混乱したのは最後から3？問目の「⑨のコードを止める」という問題文で、まだ作成していないコードを止めるというのがよくわからなかったようでした。 こちらも、先に⑨のコードを完成させてから、そのスプライトのコード全体を見せ、現在作成している箇所とは別のスクリプトを止めるという意味だと解説すると、納得していました。 問題自体は解説時間や雑談時間も含めて30分くらいで解き終わり、新しいスプライトを表示させるなどのアレンジをして楽しんでいました。（今日はアレンジを楽しむことを優先し、コードのアレンジをしないと得点にはならないことについては敢えて言及せず、好きなようにさせました） アレンジが終わった後は、約束通りご褒美として自由時間にしました。', '★タイピングコンクールの参加部門を決めてください。 （参加部門が決まっていないためエントリーができていないので、体験版でやらせてください）', 'タイピング: タイピングコンクールを受ける気はあるようです。次回、ホームポジション基礎にするか、ローマ字にするか、両方試してみて決める約束をしました。
盛り上がり: 検定の問題自体を楽しむことができていました。 ストーリーがある課題でイメージがしやすかったようでした。'),
  ('470281b3-6324-50f6-8091-299143388faa', 'e22d8f70-f1a1-5ca4-9ed4-4d27cb0e164f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-18', '16:30:00', null, '通常 / 検定問題の進め方を学習する', 'まだ基本操作コースをすべて終えたわけではないため、わからないところは一緒にやろう、という感じで声をかけましたが、特に臆することもなくやる気になってくれました。 問題文は必ず順番に読んでいくこと、できたところはマークをつけること、どこに作成するべきコードなのか、必ず「○○の場所」という表記を確認することなどの注意事項も素直に聞いて、その通りに進めることができていました。 一つの文章の中に複数の要素があるときに、軽く解説が必要でしたが（「端に触れるまでずっと5歩ずつ動かす」という場合に、○○まで繰り返す、というのはやったことある？繰り返す系のブロックはどこにあったっけ？といった感じで）この程度のヒントで正解を出すことができていました。 最後から3？問目の「⑨のコードを止める」という問題文については、「別のスクリプトを止める」という解説が必要でしたが、⑨のコードで「〇秒待つ」を使うことなどは、自力でできていました。 アレンジも、新しいスプライトを出してきちんとコードを作成するなど、楽しんでやることができていました。', null, '盛り上がり: 検定というよりも、新しい作品を作ること自体を楽しめていたようでした。'),
  ('dcbbdfbc-44d3-5782-8171-ebe81d6b8230', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, null, '2025-08-18', '17:30:00', null, '休み（未対象）', null, null, '備考: Comiru既読なし'),
  ('07208492-e66a-5089-9b19-05bbf02e65d5', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-18', '17:30:00', null, '通常 / Excel検定2級の準備', '2級での新出範囲について学習していくことを説明してから始めました。 VLOOKUP関数については3級受験のときに例題、実習問題ともに解いていたようですが、復習ということでやってもらいました。疑問点もなく、スラスラとできていました。 条件付き書式についても、質問はなく、大丈夫とのことでした。 アウトラインとピボットテーブルについての学習をする予定でしたが、例題20のファイルが項目名しか入っていなかったため、適当なデータを入れてもらって、アウトラインのみ学習しました。', 'ピボットテーブルの学習をしたいところです。', '盛り上がり: 新出事項についても問題なく進めることができているので、自信もついているように見えました。
備考: 30時間マスターの教本の黄色い付箋は、2級新出項目です。'),
  ('6a8fba63-974e-5034-a00e-cf30873cd7b1', 'd3885e29-ee68-501b-bf31-6c050fd50c36', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-08-22', '16:30:00', null, '通常 / 検定をやってみる', '検定について説明したうえで初めての問題に取り組みました。検定という仕組み自体はそこまで嫌がったりせずに取り組んでくれたのですが、長い文章を読むことで集中力がすぐ切れてしまいました。そこでお手本ムービーを見ながら動きをイメージしてもらったり、終わった部分は問題用紙に〇をつけたりすると効率が少し上がりました。問題を全部解くことはできませんでしたが、前半まで終わらせるという目標を立てて達成しました。', null, null),
  ('816a2302-5dfd-5e90-8c51-6ace21f62429', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-08-22', '17:30:00', null, '通常 / 検定の復習', '前回2級を受けたときに足りなかったのはたった5点などと説明して、検定のリトライを促しました。今日いきなりだと忘れていると思うから、とりあえず雰囲気を思い出すくらいでいいよと伝えると最初の方を少し取り組んでくれました。ただ、受検するかどうかについては「また失敗するだろうから受けたくない」とかなり消極的な態度でした。', null, null),
  ('35e229ff-524f-577a-b3d7-0519f02421c9', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-08-22', '17:30:00', null, '通常 / 検定練習', '2級の最初の問題に取り組みました。3級までとは違ってところどころ間接的に書いてある指示(「入力が正解だったとき」など)にとまどいつつも、真剣に取り組んでいました。「りんごとバナナ」ブロックをいくつも組み合わせてセリフに変数を入れるという部分が難しかったようでした。そのセリフをどう分割したらいいのかを一緒に考えるとうまく整理して作れました。', null, null),
  ('a14000be-ea2e-5c20-878f-756f6065cbd4', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-08-22', '18:40:00', null, '通常 / excel', '以前飛ばしていた問題があったというのでそこを取り組みました。内容としては既に先取りで理解していたものだそうで、いい復習と実践になっていました。検定3級の受検について話すと、やってみたいと前向きな態度をとってくれました。', null, null),
  ('83acaa5b-ff30-5458-a95c-3b115190518d', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-08-22', '18:40:00', null, '通常 / excel', '4章の続きからやりました。セルを折り返す方法など細かい質問はありましたが、大事なところは自力で理解していました。検定3級の受検を促したところ、高校受験に使えるメリットがあるのならやってみたいという返答でした。', null, null),
  ('279352b9-69e5-5e3a-b1fa-49a8ccfc62a3', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-08-22', '18:40:00', null, '通常 / excel', '前回途中だった疑似問題の続きをやりました。無事に問題の最後まで自走することができました。検定3級の受検について話したところ、やっておきたいと言ってくれました。', null, null),
  ('e8fa2ced-8ee8-5449-a46b-111ac8a378fb', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-08-25', '17:30:00', null, '通常 / excel検定対策', '検定2級の対策として、第7章のピボットを題材とした問題に取り組みました。自走してスムーズに進められていました。', null, null),
  ('d63ae7f7-8963-5c0e-b3b2-bd98efcca2a5', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-08-25', '17:30:00', null, '通常 / U16作成', '11月に検定がある話をしましたが、U16の締め切りまではそっちを時間を割かないと間に合わなそうな状況とのことでした。(検定は次2級ですが、スキル的には十分なので直前に軽く練習すればよさそうです) 今日は久しぶりで色々忘れているとのことですが頑張っていました。まずは「スプライトをクリックするたびに移動対象のスプライトを上書きする」という処理を作らないといけなかったのですが、クリックされたことを示すフラグ変数を使うことで解決しました。本人もフラグ変数についてはよく理解していました。 敵の動く向きを上下左右からランダムに決めるときは、リストを一緒に復習しながら活用して作りました。また、「他のキャラが近づいてきたらその方を向いて追いかけ続ける」などといった敵の動きを言語化すること、およびコードに変換することが難しかったようなのでサポートしました。 レッスン時間終了後も「ここまでやる」という目標を決め、集中して居残り作業していました。 次回は、敵の移動先が複数あり干渉しまったときの対処を行うとのことでした。', null, null),
  ('cbd55bb4-89b3-5974-bc30-faecff2cd1ff', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-19', '16:30:00', null, '通常 / 検定1級のお試しにチャレンジする', 'ご家庭からのComiruのお問い合わせによると、受験に対してハッキリした態度を示していないが、親御さんは受験希望という雰囲気だったため、それを踏まえた上で…プレッシャーをかけると拒否反応が出るので、受験するかしないかは即決しなくても良いことを説明し、新しい作品作りを楽しむのと、そのついでにスキルチェックや新しい技を覚えていこう、という感じで検定問題を勧めてみました。その結果、こちらの想定よりもスムーズに試験問題に取り組んでくれました。 問題1の(3)の①で、「X座標がロケットの X座標より「20」だけ大きい 値」という言葉の意味がわからなかったようで、集中力が切れかけましたが、一緒に問題文を読み直してどういう意味か問いかけると、自分で解決することができていました。正解を作成しながらも、「なんだこの問題、意味わからない」とぶつぶつ文句は言っていましたが、落ち着いて問題を読めれば使うコードはわかっていることを指摘すると、まんざらでも無さそうでした💦 45分間くらい、おとなしく課題に取り組んで、最後まで解き終わりはしたようですが、動画のように動かなかった、ということで気が抜けて、残り時間はゲームをしていました。 それでも初めての1級問題を最後まで解き終えたことは、達成感を得られたのではないかと…。', '一緒に見直しをして、難しかったところや、まだ知らなかったところなどをつぶしていこう、と約束しています。', '盛り上がり: 口ではぶつぶつ言ったりもしていましたが、1級にチャレンジできたことは、多少なりとも自信につながったように見えました。'),
  ('ee5c8a2e-583e-5082-b3af-26252a311a2b', '1c7005cc-2815-558f-993a-9c7617d34c44', null, 'd45d6c5d-18cd-5aa2-99ea-932c81442c55', '2025-08-19', '16:30:00', null, '通常 / スキル確認を兼ねて、検定問題にチャレンジする', 'せいぎょのブロックなど少しづつどこにどんなブロックがあるのかを覚えてきました。 ではないのブロックの使い方を理解していて実際に使う場面はありませんでしたが、会話中でどんな場面で使ったらいいかを話してくれました。 最後の猫がセリフを言ってから消える部分が、セリフを言っている最中に消えてしまっていたので次回はその部分の修正から行いたいです。', null, '盛り上がり: 検定というものをどこまで理解できているかはわかりませんが、新しい取り組みを面白がってくれました。
備考: お母さんには、検定問題にチャレンジはしてみましたが、検定受験を強制するものではなく授業の課題の一環として取り組んでみた、ということを説明しました。 現段階では親御さんも、検定合格を目指すよりはむしろ、せっかく楽しく通っているので、興味を持ち続けられる方向で進めていくという方針で同意されていました。'),
  ('498d11c5-687b-5900-a672-e28baf7be493', '337872be-4ce4-5436-88f8-5f97e8c5252e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-19', '17:30:00', null, '通常 / 検定1級のお試し', '先月の段階で2級の問題は簡単にできていて、そのあと2回ほど、授業で定義とリストの学習をしたところなので、一度問題にチャレンジして、わからないところを見つけるつもりで取りかかってもらいました。 まだクローンに慣れていないのか、「クローンを作成する」のと「クローンされたとき」の区別がやや曖昧なようでした。 修正問題の途中までで授業時間終了となりました。', '前回の続きからやりたいところですが、まだ歴が浅いこともあり、未履修範囲や学習が足りていない所をうめていく目的もあるので、クローンのあたりを再確認してから進めるか、とりあえず自力で最後まで解いて、バグつぶしをしてみたいか、本人の意向を確認してもらってもよいかもしれません。', 'タイピング: 申込をされたので、チャレンジしてみました。スピードにはまったく問題はないので、ミスタイプを少なくすることを心がけて上位を狙いたいところです。 サインインID：0560-45471 パスワード：so0102
盛り上がり: タイピングは速いので、楽しそうにやっていました。 検定の方も、2級が簡単だったのに比べて1級はそれなりにやりがいもあったようで、頑張って取り組んでいました。'),
  ('28a64364-6cd3-5a5e-866c-dda2ddc10133', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-19', '17:30:00', null, '振替 / Excelへの取り組み、またはScratchの復習', '久しぶりの来室で、懐かしそうにしていました。自分のスリッパがなくなっているのがちょっと寂しそうでした💦 タイピングをかなり頑張った後、Excelの話もしてみましたが、今日は久しぶりなこともあって、なんとなくScratchの気分…ということで、導入としてコンテストのジオメトリーダッシュをやってもらいました。このタイプのゲームは得意！と言って、こちらもかなり熱心に記録に挑戦していました。 ひとしきり遊んだ後、記録を伸ばすための練習作品を作る、ということで、アレンジをしてもらいました。 今日はタイピングとゲームの時間がメインだったので、次回以降に少しずつ、プログラミングの基礎としてのScratchを意識していけたらと思います。', null, 'タイピング: 前回の記録もよかったので、今回もやってみようかなあ、どうしようかなあ、と言いながら、結構本気で練習していました。
盛り上がり: 得意なことがメインだったためか、とても生き生きと楽しんでいました。'),
  ('0ec4f3a8-f691-556f-956d-c8987a810a54', '57f45872-1f3e-5540-b676-bf9023444e39', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-21', '16:30:00', null, '通常 / 検定問題にチャレンジする', '検定は無理だからと初めは拒否していましたが、やや持ち上げる意味も含めて💦スキルをたくさん覚えてきた弊害でごちゃついているので少し整理するために検定が有効だから、ここで一度やっておこうという感じで勧めたところ、それならやってみるか、という姿勢で始めました。 問題を1文1文読むのが少し苦手なのもあるのか、問題文と自分の作成したコードが合っているか照らし合わせるのが面倒なのか、一つブロックを作るたびに合っているか確認したがる傾向がありました。ただ、確認してはくるものの、このレベルの問題ではほぼ正解を出せていました。 あと1回くらい並走してあげて自信を付けさせてから、自力でやらせてみると良いかもしれません。 なんだかんだ言いつつ、アレンジまで終えて、残りは誰かに話しかけたりゲームをしたりしていました。', null, 'タイピング: タイピングは形式に慣れずにちょっとイラつくこともありましたが、タイピング自体は速いので落ち着いてやれればそれなりの得点を出せていました。本人もそれは納得したようです。
盛り上がり: 検定は絶対無理！と言いつつも、このレベルのスキル自体は身についていたことが、少し嬉しそうでした。'),
  ('8c88f841-3f15-5b6d-b409-4979f4a9bb5c', '05439956-11b9-5ac7-a44a-3e6f5a6831d8', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-21', '16:30:00', null, '通常 / 検定体験と選抜大会の準備', '授業開始時に、選抜大会の締め切りとテーマを確認しました。親子大会とはテーマが違うことも本人がしっかり把握していて、それに合わせてアレンジを描けていく予定だそうです。 検定には興味があるとのことだったので、来室時には検定準備と大会準備を並行して進めていくことで同意しました。 自分でかなり作り込んでいる反面、このように問題を解く形でプログラミングをしていくのは初めてだったようで、回答していく過程で、その先に出てくるはずのコード（メッセージを送るなど）がないことを気にして手が止まったりしていました。1級問題には修正箇所もあるため、問題の途中では動きが不完全なことが多々あることを説明し、とりあえず最後まで解き終えることを勧めました。 一応時間内に完成はしましたが、敵の弾の動きがおかしいところがあり、解決できないまま授業終了となりました。 凛久くん帰宅後にこちらで確認したところ、不等式の左辺と右辺が違っていたために動かなかった箇所がありました。また、ネストのレベルがずれている箇所がいくつかありました。プログラムの構成をよく考えると共に、問題文の読み方がヒントになることにも慣れてほしいところです。 来室が隔週で、次回までに間があいてしまうので、正答例とコメントと問題文をComiruで送付しておきました。 （追記：自宅で確認し、修正ができたとの連絡あり）', null, 'タイピング: タイピングコンクールにはあまり興味を示しませんでした。
盛り上がり: たまにこたろうくんと野球の話をしたりしながらも、熱心に取り組んでいました。'),
  ('1917d896-a81f-5888-964b-3d7bac3c3de3', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-21', '17:30:00', null, '通常 / 検定にチャレンジする', '検定問題には素直に取り組み始めていました。 Ifの条件が2つある場合で少し悩んでいましたが、一緒に問題文を読んであげたところで「かつ」を使用することに気付くことができました。 同様に、「もし」が2つ続いたあとのブロックをどこに入れるか悩んでいたので、問題文から細分化させ、実際の動きを考えた上でどこに続けていくかを考えるという手順を一緒に踏むことで納得できたようでした。', null, 'タイピング: 毎パソの形式にもわりとすぐに慣れ、落ち着いてやったほうが記録が伸びることにも納得していました。
盛り上がり: 自分で納得して解き終えることができたので、スッキリした様子でした。'),
  ('6b0b9c9d-177a-597b-b504-fe07966cd39c', '655ad2c9-dfb5-5fc7-b41a-1d784603c1d0', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-21', '17:30:00', null, '振替 / 初めての検定問題にチャレンジする', '検定問題は楽しそうにやっていました。 問題文の「以下」の意味がわからなかったり、「② ①の後」のような書き方に混乱していましたが、一度解説をすると、自分で番号の後に線を引いたりして工夫して、問題文を読み取ろうと努力する姿勢が見られました。 「スプライトの他のスクリプトを止める」箇所で、「他のスクリプト」が問題文の先に出てくる形式のために少しとまどっていましたが、その他のブロックは自分でしっかり覚えていて、問題文の意味を説明した箇所以外は自力で解き終えることができました。', null, 'タイピング: 基本的には準1級を出せていました。級認定でもっと上を狙う気満々で、かなり長い時間やりこんでいました。とにかくタイピングは速いのですが、画面を見ないで打つため、ミスタイプに気付かずに先までうってしまって不正解数が増えてしまうことが多いです。落ち着いてやったほうが得点が上がることも実感はしていましたが、いざやると夢中になってしまうようでした。
盛り上がり: タイピングも検定も、しっかりとやる気を出して、楽しそうに取り組めていました。'),
  ('393e9dbf-368c-5b88-a956-a16f7584eb9b', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-08-25', '16:30:00', null, '通常 / ジャンプゲームの復習', '以前も作ったことあるよと言われてしまったが、今回の趣旨の「ゲームから自分で読み取って細分化して作ろう」と伝えてあげたら、やる気を出して、岳君と相談しながら作ってくれました。最初の試遊で、「コスが常に変わってる、スペースキーで音が鳴ってジャンプ、木にぶつかると点滅」と勇作君側から出してくれました。ほかの要素は岳君が出してくれたので、8割がた要素を読み取ることができました。 まずはジャンプを作り始めてたら、「何回繰り返す」のコードをすぐさま思い出し作れていました。上がって下がることで10歩とー10歩もコードを自力で持ってこれていましたが、1つの繰り返しに入れてしまい迷い込んでいました。けど何度か試して、正解を導き出していました。コードを作ることに根気強さがあります。そのあとは、スプライトを変えたい、音を選びたいで時間を取られていしまいました。障害物の動きを作ってみようと提案してみたところ、見ただけはコード作成に移れなかったです。右から左に動くということは、座標がどのように変化しているか考え方の流れにそうと、x座標が小さくなる発想を一緒に出せました。右から左の流れを繰り返すことは時間が足りなかったので、次回そこと当たり判定をお願いします。', null, 'タイピング: 最初は片手でやっていましたが、両手でお願いしたらやってくれました。'),
  ('064e85ec-cbc2-5e69-bfde-40e3d19ae47d', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-08-25', '16:30:00', null, '通常 / ジャンプゲームの復習', '勇作君と協力して作っていきました。まずはゲームを読み取れる要素を探してもらいました。岳君は、「スペースキーでジャンプできる、障害物に当たるとゲームオーバー」とメイン要素ではなく、「ジャンプで音が鳴る、障害物が本数が違ったり、速さも違う、そしてぶつかると点滅しておわる」とより詳細な観察眼が発揮していました。作成に当たると、ジャンプなどの動きは勇作君率先して共有してもらって作っている場面があったが、初期位置や大きさなどのコードは岳君から共有して作っていました。次に、障害物の動きについて考えてもらうと、「右から左に繰り返し動く」ことは認識できているが、そこからコードで再現がまだ厳しい感じでした。ジャンプの作成時あったが、上下左右と座標の大小の対応が瞬時に使えこなせることではなく、少し考えて使える程度です。がなので、まずは、右から左にうごくだけに意識させたら、作成することができました。 次回は、この動きを繰り返す条件の読み解きと当たり判定をお願いします。', null, 'タイピング: 五十音とローマ字の対応覚えていてノーミスでできています'),
  ('bf1bc6b6-6056-5751-8a0f-b90b778c5566', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-08-25', '17:30:00', null, '通常 / ジャンプゲーム', 'ジャンプゲームを作成していきました。動作に関しては最初の試遊でポイントを全て押さえられていたので、スムーズに作成できていました。変数に乱数を当てはめて使うところは新鮮で新しく知れてよかったそうです。途中で、障害物が動かないことがあったが、自分で変数の違いに気づけて直せていました。順調に完成できました。', null, null),
  ('826ed11f-edbc-5ab1-b012-d02e9f5ee41d', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-08-25', '17:30:00', null, '通常 / ロブロックス', '今日は珍しく授業時間前に進めずに、あそんでしました。夏休み最後でやる気が低迷してしていたそうです。動画を見始めるのも遅く、今日は寛容に見逃しました。なので、30分くらいしかやらず、後は遊んでいました。だいきくんみたいにあんまだらだらやってほしくないので、次はしっかりやるように', '続き 文字列の結合が出てくるので、何を学んだか聞くとき、その方法を確認してみてください', null),
  ('130f57b9-9ca0-57c6-b807-ea277a99b6a8', '1c7005cc-2815-558f-993a-9c7617d34c44', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2025-08-25', '16:30:00', null, '通常 / 検定がどうかの確認', '問題を読むこと自体が辛そうで。「全く意味が分からない」と言っていました。ほかの子の画面を覗いたり、飴を食べに行ったり。全く取り組めない様子でした。日本語を読むのが苦手なのではないかと思われます。 とはいえ、動画をみて最初のコードを考えたので。途中でやめるのはイマイチかなと思い。ひとまず、見本のコードをうつしてもらいました。少なくとも、「な？？」と思ったことを、コードを写すことで少し発見できればと思いました。 本人も、写して動くので急に顔が晴れやかになりました。', '基本操作コースをしっかりやりつつ。ドリルで短文の日本語からコードを作る練習を増やしましょう', '盛り上がり: お母さまと、帰りがけ話をしました。どうやら、本人とも話をしていたようで。こちらがお伝えする前に、「今回は検定は難しそうです」と言ってました。'),
  ('b4d2d339-a70b-5f66-8234-06df91380e5b', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2025-08-25', '16:30:00', null, '振替 / U16 の作品つくりかな？本人と相談', 'もくもくと、ちゃくちゃくと作品を作っています。仕上がりのイメージがあるようなので、次に何を作りこむかも頭の中で計画ができているようです (*´艸`*) 放置になってしまわないように。もう少し作品ができあがったら、先生がうらでコードをみておいて、一緒に意見交換（ここ、すごいね、とか。ここもうちょっとスムーズにできる？など）できるようにしてあげるといいですね。', null, null),
  ('9366bf62-71cd-5d0b-8cdb-2ad5701dc6b4', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-08-28', '16:30:00', null, '通常 / 検定練習', '検定練習を行っていきました。途中途中、この動きおかしくない？と正解の動きに突っ込みながら作っていました。「ステージの端に触れるまで繰り返し、5歩」という文章では、文が長く理解に苦しんでいました。なので、文節で区切り分けて考えて行けば、作れることができました。また、「以下のa,bを順に動作する」では、文からコードの構造が理解できていませんでした。中身のコードは組み立て手られても20回繰り返しとどう組むか迷っていた場面がありました。ほかのところは、スキル的につまずくことがなく、作成できました。途中、たまごっちに気にとらわれる時間があったが、、、 ほどよく文章理解を進めていけたらよいと思います。', null, '盛り上がり: たまごっちにはまっているそうです'),
  ('a4ec5a2c-1eac-54f1-986f-de3667db4425', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-08-28', '16:30:00', null, '通常 / 検定練習', '2級の問題を初めてやっていきました。この問題の難点のじゃんけんの勝ち条件の組合せにつまずいていました。ここの考え方として、まずじゃんけんと変数の数字対応についてヒントを与えて、勝ち条件のペアの数字を考えてもらったら、最後まで自力で作れることができました。変数の扱いに少し苦手意識があると見えます。そのほかの部分は、音がかわいくないと勝手にアレンジを途中でしてしまう場面もあったが、60分いっぱいで作り切るところまで行けました。答え合わせができてないので、次回っ最初に見てあげてください。', null, null),
  ('2b3b5afd-33c2-5e58-9a86-1a308ab7f6ec', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-08-28', '17:30:00', null, '通常 / 検定練習残り＆大会作品作り', '前回の残りからやっていきました。主に修正の部分が残っていました。15分程度でできたと報告してくれたので、答え合わせしてみると、ミスなく作成をできていました。途中座標のふと号の向きに悩んだと言っていたが、自分で正解の方向まで修正できていました。バグのあらさがしも習慣として身についているので、あと必要なのは、素早く問題を解くくらいです。 後半は大会作品を作成しました。', null, null),
  ('f07f970d-4ae4-5047-9431-915d60e32546', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-08-28', '17:30:00', null, '通常 / 検定練習', '今日は来たらだいぶお疲れムードでした。初めて見ても、先生が横についていないと、なかなか進まない程度でした。たいよう君の話につられてしまう部分もあるが、文から読み取る事態が頭に働いてなかったです。横についてないときは、コードのところで右往左往していた時が多かったです。ついてあげたときは、書いてあることからコードの色を連想してあげると、特定のコードを言わなくても持ってこれていました。ぱっと見文章を読むことが苦手に見えるので検定は向いてないかも？？', null, null),
  ('8bf8336c-55e2-5874-9be8-2a3c5f35c47c', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-08-28', '17:30:00', null, '通常 / 検定練習', '2回目の練習。ひと段落まで作り終えたらと思ったら、魔法が出ない、ドラゴンも動かないなのに、スコアだけ上がっていくバグが発生していました。まずは、文章と作ったコードを対応してみてごらんと見直しの一言を言ってあげました。そこで、読み飛ばしによる条件の入れ忘れなどは直せることができました。だが、バグはまだ残っていたので、一緒に見直していきました。コード自体はできているが、「もし」の入る場所がこんがらがっていました。「以下のa~e」の入れるはずが、中にもう一つ「もし」があったため、その中に続いて作ってしまう場面があったので、コードの順番を意識して見直すように助言しました。また、おとも最初から「終わるまで」を入れてしまったので、必要な時だけに入れるように言いましh田。最初にひと文に書いたように、バグが何個も滞在していたので、スプライトごとに見直す癖をお伝えください', null, 'タイピング: ノーミスで4級くらいまで上達できていました。'),
  ('d65e8391-a18a-5075-abe5-98f3d923434b', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '19c3ff7e-f3fb-5570-9f85-06429f30290f', '2025-08-29', '16:30:00', null, '通常 / 検定1級対策', '本日は検定1級の対策として、引数を複数使った定義やリスト、「割ったあまり」を使ったゲームの作成を行いました。説明書通りに書いていき、引数が複数ある定義も詰まることなく使うことができていました。 ゲームシステムの理解で時間がかかってしまいほぼ時間いっぱい使って終わらせることができました。次回以降でも今回使ったブロックを使えるよう復習していけるとよいと思います。', null, null),
  ('6e5e1707-f85a-54c5-94ba-7b45f52f5fbb', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '19c3ff7e-f3fb-5570-9f85-06429f30290f', '2025-08-29', '16:30:00', null, '通常 / 検定2級対策', '本日は検定2級に向けて引数を複数使った定義、「〇〇〇を「X座標」に追加する」 、「割ったあまり」の演算を使うことを覚えるためのゲーム制作を行いました。 手順書通りに進めることができ引数を複数使った定義も戸惑うことなく実装できていました。途中半角全角を間違え正常に動作しなかった際、バグフィクスが少し面倒そうでした。 次回以降も今回学んだブロックを使いながら検定対策をしていければよいと思います。', null, null),
  ('ebe199d3-a6af-59cd-bc40-d98310cd8883', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '19c3ff7e-f3fb-5570-9f85-06429f30290f', '2025-08-29', '17:30:00', null, '振替 / 検定練習', '4級を受ける予定ですが、前回に引き続きゲーム制作を行いました。前回コードは途中まで組めており、今回は動画を見ながらゲームに使う背景の制作に時間をかけていました。 今回15分辺りまで終わっているため、次回は動画に沿ってコードを組んでいけるとよいと思います。', null, null),
  ('970dc4e3-46bf-5d24-9638-c2e5c04ec482', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '19c3ff7e-f3fb-5570-9f85-06429f30290f', '2025-08-29', '17:30:00', null, '通常 / 検定2級対策', '今日は検定2級対策の2問目のじゃんけんゲームの制作を行いました。検定の流れはわかっているためお手本を見てスムーズに作成に入りました。 基本的には問題通りに作れましたが、「じゃんけんに勝った時」の条件を『「自分がグーかつ相手がチョキ」または「自分がチョキかつ相手がパー」または「自分がパーかつ相手がグー」』と具体化して条件分岐するところでつまずきました。 また、自分が完成したと思ったらバグがあっても修正するのが面倒くさくやる気がなくなってしまうようでした。', null, null),
  ('391fd243-dd47-593e-b4ea-2aee918100bf', '337872be-4ce4-5436-88f8-5f97e8c5252e', null, '19c3ff7e-f3fb-5570-9f85-06429f30290f', '2025-08-29', '17:30:00', null, '通常 / 検定1級対策', '前回の検定1級対策でクローンの処理に苦戦したため、まず「アルくん危機一髪」でクローンの挙動について確認してから1級目1問目のバグフィクスにチャレンジしました。 「アルくん危機一髪」は20分程度でクリアし、問題なく理解できたようでした。その後のバグフィクスでは治しきるところまではいきませんでしたが、原因は理解できたようなので次回直して時間があったら2問目に行けるとよいと思います。', null, null),
  ('254879d2-e251-59b7-9e32-79ec3a2d317a', '0d16e234-e60d-5fdb-978f-1722acf9a2b2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-28', '16:30:00', null, '通常 / 授業をきちんと受ける', 'アルスタジオを開いたら、自分でレッスンを探し始めたので、本人の希望のより、予定していた教材（チーズ）ではなく「アイスを食べに」で上下左右の動きや条件分岐の学習をすることにしました。授業前に、Scratchのマイクラを熱心にやっていたので、今日やるところができたらマイクラタイムにする約束をして始めました。 見本のゲームをプレイしておかしいところをあげてもらい、そこを直していくには何をすればよいかを考えさせてから授業を進めました。以前のレッスンの進め方を覚えていて、初めは「動画を見る」と言って見始めましたが案の定？途中で飽きてしまったので、講師との対話形式に切り替えました。 「敵に触れてもなにもおこらない」「アイスに触れても何もおこらない」「上と右にしか動けない」という問題点から、これから何をすれば良いか考えさせたところ、本人のイメージがふくらんできて、授業時間いっぱい、作成とアレンジを含め、熱心に取り組むことができました。（久しぶりにきちんとした授業になりました！） 上下左右に動かすときの使用するブロックを通して「まわす」と「向ける」の違いを復習したら、残りのアルくんの動きは自力で作成できました。 条件分岐に「ずっと」を併用するのは知らなかったというので、意味を説明しましたが、半分聞き流していたかも…。 本人のアイディアで、ダミーの敵キャラを作成しましたが、こちらの条件分岐の追加は、迷路の道以外の場所に触れたらアウトというアレンジをヒントに追加することができました。', null, 'タイピング: ローマ字が少しわかっていそうだったので、その点を褒めたところ「タイピングをやりたい」と言い始めて、自分で少し進めていました。家でもやりたいと言っていたので、「お問い合わせ」でIDを送りました。
盛り上がり: 最終的に、自分で考えた通りのゲームにできたようで、とても嬉しそうでした。アイディアを話すときに、生き生きとしていました。'),
  ('24e0e47e-ef14-563c-965f-79a2e6369d12', 'd3885e29-ee68-501b-bf31-6c050fd50c36', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-08-29', '16:30:00', null, '通常 / 検定練習', '「設計書通りにゲームを作るテスト」「何のときの動作なのか読む」などの注意点を復習してから検定練習に取り組みました。集中力がなかなか持たなかったので大変でしたが、「ロブロックスのレッスンをやりたい」と以前言っていたのでそのために必要だということで多少モチベーションは生まれたようでした。「他のスクリプトを止める」の概念は難しかったのでしっかり教えましたが、他の部分の一つ一つは理解できていました。一気に全てやろうとすると厳しいので、半分終わったら休憩という形で進めました。前回は全体の5割くらいしか終わらなかったのが今回は7割くらい行けたので、少しずつ慣れてきているようです。', null, null),
  ('b61de196-a578-57c7-a6cd-86d250f0416d', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-08-29', '17:30:00', null, '通常 / U13作成', 'しばらくはアルスタジオのコンテストゲームで遊んでいましたが、U13に出したいとのことなので、9月中に一旦完成させられるように促しました。ゲームの原型は既にけっこうできているので、追加の要素のアイデア出しをしました。「コーラ以外にも炭酸飲料を出す」「ただクリックするだけでなく、クリックごとに工場から飲み物を出荷して売り上げを上げられるようにする」というように、面白いアイデアを出せていました。自動クリックのボタンがうまく動かない(ボタンを押すのに必要なコストが正しく使われない)バグがありましたが、該当箇所を絞り込んで数値の間違いを見つけることで自己解決していました。', null, null),
  ('2b511785-1c69-5726-aee7-6579f5523340', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-08-29', '17:30:00', null, '通常 / roblox', '検定をやる予定でしたが気が乗らずrobloxの方を希望したのでそちらで進めました。 前々回はホラーゲームの作成をしていたようでしたが、やはりそんなに面白いものができそうにないとボツになってしまいました... 代わりにシューティング系のゲームの製作を始めました。簡単なものでもいいからひとまず完成までもっていくことが大事と伝えてからやってもらいました。ステージ、プレイヤー、敵(ゾンビ)の作成をして、とりあえず敵を撃って倒せるようにはできました。 今後の展望として、 ・敵がこちらに向かって攻めてくるようにしたい ・あるいは、プレイヤー同士で対戦できるようにしたい というイメージを話してくれました。', null, null),
  ('b75f1e29-f6b2-57c2-b788-978cd1add78a', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-08-29', '17:30:00', null, '通常 / 変数、演算の活用', '遊んでみたあと、変数を使ってボールの速度をだんだん変える部分から取り組みました。左や下に行くとき速度変化がマイナスになる理由について問いかけると、x座標やy座標を変えるとき逆向きにしないといけないからと答えてくれて、ざっくり理解しているようでした。何もしないとボールが減速する部分もやりましたがうまく減速しなかったので、次回は仕組みを理解しつつ間違った点を直したいところです。', null, null),
  ('dd9e04bb-337c-546e-9b19-f7acc2263f27', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-08-30', null, null, '通常 / ロブロックス', '最初に教室用のIDがわからず、やり始めるのに時間がかかっていました。すでに保存されているパスワードが間違っていたので、修正しておきました。操作方法におぼつかなさあったので、ショートカットキーを混ぜて、復習しておきました。色替えのコードがメインだったので、難なく進められてしました。次回は応用編で終わってから確認テストです。', null, '時間帯: その他'),
  ('fda608a4-50cb-5bd8-a083-fc8f09ce7a38', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-28', '17:30:00', null, '通常 / U１６大会作品の準備、Excel検定の準備', 'Excelはグラフの書式設定でしばらく悩んでいましたが、自分でショートカットからメニューを見つけて設定できて満足そうにしていました。Excel検定受験については、コンテストの進み具合を見て前向きに検討するとのことでした。 U16大会の作品として、以前より作成していたものをいじっていましたが、途中で学校の自由研究で作成した元素探しのゲームを見せてくれました。（冒頭に宿題に対する個人的なぼやきが入っているせいか？初めはとても恥ずかしがっていましたが、見せたいという気持ちもあったようで、照れながら見せてくれました） これがとてもよくできていて、正直これまで作成していたものよりもコンテスト向きだったのと、既に形になっていてプレゼン資料も作りやすいので、こちらでエントリーすることを勧めました。承太郎君自信も、意外と作成していて楽しかったとのことで、こっちで頑張ってみようかな、とのことでした。', null, 'タイピング: ローマ字に何度かチャレンジしていました
盛り上がり: 宿題の作品が承太郎くんの想像以上に好評だったのが嬉しそうでした。コンテストに対するイメージも固まってきたようで、やる気を出しているように見えました。'),
  ('9e41468b-83f2-5baa-853e-aa79272816f7', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-08-30', null, null, '通常 / ロブロックス', '色次々と変えていくコードの作成だったので、特に迷うことはなくスムーズに進められていました。確認テストでも、ミスなく答えられていました。 次に進み、順調に前半部分を作り終えていました。おそらく次からwhile分を触れれるので、理解をできているか確認を取っておいてください。', null, '時間帯: その他'),
  ('f06e2207-a2ca-5984-809c-9615ade72287', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-28', '17:30:00', null, '通常 / 検定の準備、またはU13大会作品', '少しだけ遅刻してきました。 一応本人の意思を確認した上で、どうしようか迷う様子だったので、様子見として検定問題にチャレンジしてもらいました。 一応問題は解き終わりましたが、集中力が途中で切れることが何度かあり、そのたびに少し雑談をしたりしました。感想としては、演算や調べるのブロックにイマイチ自信がもてないとのこと。また、繰り返しや条件分岐のブロックを使用したとき、次の動作のブロックをどこに入れるのかがかなり不安定でした。 問題文と実際の動きを考えるよう助言すると、そこから自分で解決はできるのですが、本人としては自信はイマイチだそうです。 イラストと隔週なことと、コンテストの作品作りもあるので、自宅で相談して来てもらうよう促しました。', null, '盛り上がり: 教室でおしゃべりをするのは楽しいらしく、話しているときはとても楽しそうでしたが、イラストに比べてプログラミングに対しては自信なさげな様子が目立ちました。
備考: テニスの関東の大会？で優勝したそうです！都のランキングにも入っているとのこと。テニスの推薦で高校に行って、ゆくゆくはプロを目指したいそうです！'),
  ('13076de5-cd9c-5fa1-8531-4952663c2630', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-08-30', null, null, '通常 / 1級練習の続き', '前回解き終わらなかった1級問題の続きを作っていきました。主に修正部分が残っていたが、1度で完璧に直せず、違ったところを自分で治して、作っていました。コードの理解力はあるが、判別しだす時間が少々かかります。不等号部分を中心にほかの部分の復習を進めます。 残りの時間は、検定作品でアレンジをして、球のスピードを速くして、臨場感あふれん菅ジニアなっていました。', null, '時間帯: その他'),
  ('7c10c006-f61f-5903-a0c0-6dffcead3204', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-28', '17:30:00', null, '通常 / U16大会作品の作成', '武将同士が触れたらスプライトを小さくしていくことで戦いを表現したいといって、参考にしたScratchの作品を見せてくれました。ただ、そこから何に手をつけたらいいのかわからず、仕様の詳細を考えていなかったようなので対話をしながらスプライトの動作のイメージを固めていきました。スプライト同士が触れたら双方ともランダムに小さくしていく、とのことですが、勝敗が完全に運になっても良いのかと確認すると考えこんでいました💦 こちらから、各武将の兵力を変数で持っておき、それを演算式にいれることで小さくなる割合を変えていくことを提案すると、それでやってみる！とのことで、兵力をリストに入れる作業をやっていました。', '兵力を演算式にどのように入れていくかを検討', '盛り上がり: やりたいことはあるものの、その詳細を考えるのがまだ難しいようだったので、会話によってやることが見つかっていくのが嬉しそうに見えました。'),
  ('1df6be74-d3f7-580a-8cc6-79e8a0a100e7', '655ad2c9-dfb5-5fc7-b41a-1d784603c1d0', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-28', '17:30:00', null, '振替 / 検定問題に慣れることを目標に、できたらアレンジなどを楽しむ', '検定問題については、画像効果を「〇回繰り返す」の中に、次にくる「画像効果を消す」を入れていて、挙動がおかしいことに悩んでいました。繰り返す必要があるのはどのブロックなのかということを考えた上で問題文をよく読みなおすことで解決できました。 「左右のみ」の日本語の書かれ方がわからず、「回転方法を左右のみにする」のブロックと結びつかなかったようで、ヒントを出すと驚いていました。 全体的に、問題を読んで丁寧にチェックをし、先生が巡回したときに、飛ばしておいたわからなかったところを聞くという態度ができていました。 ムービーもしっかり見直して、自分の作品の動作と照らし合わせることができていました。', null, 'タイピング: 調子がよいときは1級を出せるのですが、ミスタイプの連打にはちょっと苦戦していました。とにかく落ち着いて、スピードを落とすことを心がけるよう勧めました。
盛り上がり: タイピングも検定もある程度のレベルでできているせいか、どちらも意欲的に、楽しそうに取り組めていました。'),
  ('4bae6022-7955-5ad3-9f12-83310b6cde8e', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-08-30', null, null, '通常 / ゲームを細分化してみてみよう', 'ジャンプゲームを細分化ありきで作っていきました。まず試遊の段階で、このゲームの動きについて気づいたところをメモをこちらがとっていきました。ジャンプの動き、木が1か、2本になったり、速さが変わっているところを気づけていました。そこから自ら一から作ってみたいとのことだったので、いったん作らせてみました。怖い音を作る時間もありましたが、ジャンプの「何回繰り返す」の発想をこちらが説明しなくても動欠かせることできました。その後、木の動きについて「右から左に動くことを繰り返す」をそのままでは自力でコードへ移れませんでした。作成のヒントとして、「ずっと」と「まで繰り返す」を併用して使うよと説明したら、今まで片方のみずつしか使ったことのない組み合わせパニックっていました。それで、なかなか作業が進まず、時間が終わってしまってたので、 次回、木の動きについてこうしろうくんが納得できるまで説明してあげてから、速さや本数などの変数をつけ加えてください。', null, '時間帯: その他'),
  ('982b3f25-e733-5d2d-a069-276535968885', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-08-30', null, null, '通常 / 検定練習', 'イラストを使ったオリジナル作品を進めても良かったですが、本人はきょうは検定を選択しました。「変数が〇のとき」を「変数を〇にする」としてしまうミスはありましたが、言われればわかる程度に理解していました。「～まで繰り返す」や「～に触れたではないまで待つ」などの少し複雑なところも、きちんと問題文やヒントを読みながらできていました。お邪魔キャラのカニを追加して、ほどよくコードを追加したアレンジもできました。', null, '時間帯: その他'),
  ('3a3f23e4-b855-547c-b7cc-17a76e7745d5', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-29', '16:30:00', null, '通常 / 検定問題に慣れる', 'ほぼ自力でさっさとできていました。 2つのコスチュームを指定しての切り替えの際に、待つを間に1つしか入れておらずに動きがおかしくなっていたので、「ずっと」の中の仕組みを解説したところ、直すことができました。 「セリフが消さずに動作を止める」のところで少し混乱が見られたため、このスクリプトを止めると他のスクリプトを止めるの違いを確認して見直しをしました。', null, 'タイピング: 授業初めと終わりに、自主的に熱心に練習していました。1級をねらいたいとのことだったので、ミスを減らすようスピードを調整することを促したところ、1級を出すことができて喜んでいました。
盛り上がり: タイピングも検定の準備も調子よく進み、楽しそうでした。'),
  ('fa6521f7-8a88-5e17-a523-34f959221a4e', '82396ac6-71bd-59d4-a372-57212866fd5d', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-08-30', null, null, '通常 / 横スクロール、新しい変数の使い方など', 'アルスタジオ/【Prg】20 ジャンプゲームを作ろう！', null, '時間帯: その他
盛り上がり: 序盤は、前回の検定問題のアレンジをまだやりたいと言ったので、背景やスプライトを変えるなどしていました。時間で区切って今回のレッスンに入りました。スペースキーを押してジャンプする、木に当たるとゲームオーバー、木はランダムな本数になるなど基本的な細分化について、少し話を振ると自分から説明してくれました。背景用スプライトを使った横スクロールについて、コードは難しいので触れませんでしたが、2枚の背景が隣り合って左向きに流れていくという仕組みは理解してくれました。フラグ変数「飛ばなくする」が出てきたときに内容に触れようとしましたが、そのときは速く作業を進めてしまいたいと集中していたため、うまくできませんでした。動画の11分くらいまで終わりました。'),
  ('946e23de-6dd1-5067-83a9-706f919ae756', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-08-30', null, null, '通常 / エクセル 大会作品に向けて', '依然悩んでいたところを復習として1つやりました。四捨五入や数字の表記などはものの3分くらいで完成することができていました。以前は10分くらいかかっていたので、よいスピードをなっています。 そのあとは、U16作品を制作していました。', null, '時間帯: その他'),
  ('ed3c9e6e-8a4e-5f4a-a59e-933155e96cce', '49fc73e4-fc37-5c75-a77f-02a27f5e169b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-08-30', null, null, '通常 / 乱数、条件分岐', '最初に各キャラクターを一緒に細分化し、ダイヤの座標やクラゲの行先がランダムに決まっていることを理解していました。乱数で座標を決めるコードが少し長いので面倒くさがっていましたが、「座標を設定するブロックを置く→乱数を決める」という流れで誘導すると、実はそんなに複雑ではないと分かったようでした。「他のスクリプトを止める」「あかるさの効果」といった慣れていないコードも、複数回使うと使い方を覚えられました。 前半は文字をふざけて打ったりして遊んでしまうことが多かったですが、きりのいいところまで終わったタイミングで休憩を挟むと集中してくれました。中盤のダイヤの動作までできました。', null, '時間帯: その他'),
  ('f3ef6d61-ec56-5114-8023-ce21639dfa92', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-08-30', null, null, '通常 / 定義、リスト、演算', '2級の問題が余裕そうだったので、少し背伸びして1級レベルの内容をやってみました。ブロック定義には慣れていないようだったので、「定義の内容を決める→実際に使う」という流れで一緒に作成しました。引数は定義の使用時に毎回指定することも説明しました。同じく1級範囲のリストについては以前の元素ゲーム制作で慣れており、うんざりしているくらいだと言っていました。また算数は得意なので「割ったあまり」の演算もそこまで詰まることなく理解できていました。 難しいと言いながらも、時間内に完成までもっていけて満足していました。', null, '時間帯: その他'),
  ('b3b34b74-63bf-579d-b6e0-601d1cb97daf', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-29', '16:30:00', null, '振替 / 検定の準備', 'ロブロックスをやれるようになりたいとのことだったので、検定を着実にとっていくことを勧めました。英語を打つことも読むこともできるので、検定さえ頑張れば、ロブロックスには親しみやすいはずと励ますと、頑張りたいとのことでした。 4級②の方では、問題の進め方や注意点を念入りに説明し、一緒に解いていきました。。大事なところに線をひいたりするのは素直にやっていて、問題の読み飛ばしも防ぐことができました。 止めるブロックの使い分けが曖昧だったため、を念入りに復習しました。 コスチュームを指定しての切り替えの際に、待つを1つしか入れていなかったので、「ずっと」の中の仕組みを解説したところ、納得していました。 応用課題1は自力でやるように促したところ、素直に解いていましたが、問題最後の「他のスクリプトを止める」の問題文の書かれ方にちょっと悩んでいました。', null, '盛り上がり: 1時間近く前に来室して、しばらく教室に生徒一人だったせいか、とても嬉しそうにおしゃべりをしていました。授業に入っても楽しかった気持ちが残っていたのか、質問も積極的にしてきて、課題も2回分、よくがんばっていました。'),
  ('8de7fcdb-45d5-5914-b148-fe767fdbbdda', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-08-29', '18:40:00', null, '通常 / 3次元座標', 'x,y,z座標の設定を初めて扱いました。空間座標の概念自体はよく理解しましたが、良いステージを作るための座標や大きさの調整をじっくりやっていました。レッスン終盤、オブジェクトを回転させようとしたときに、全然違う場所が回転軸になってしまってうまく回らなかったのでその修正を次回やると良さそうです。', null, null),
  ('78bd406c-2f98-530a-805e-53b592bf9c12', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-08-30', '16:30:00', null, '通常 / キャッチゲームコード復習', 'コード復習として基本操作コース10キャッチゲームをやっていきました。基本操作コース通りだと簡単に作れてしまうので、「乱数」や「まで繰り返す」などに難しいものに代用できるところは変えてやっていきました。スライムの位置に乱数を使ってあげようと言ってあげたら、「らんすう？？」って感じになっていたので、意外となじみが浅いものだとわかりました。そこで、乱数の範囲の決め方や有用性について説明してあげました。次に、落下を繰り返すことについて、まず、端に触れたらや色判定を思いついていましたが、上端にも触れているので、悩んでいました。そこで、座標の不等号の条件式を教えたら、「え、めんどくさいよ」と言われましたが、勉強のためならと説得して使ってくれました。座標不等号は親子でのパズルの時にも使ったので、使用機会が増えて、もっとなじみになってくれたらいいなと思います。キャッチするところまでできたので、次回「まで待つ」を使ったスコアの仕方をやってください。', null, null),
  ('5c7b8e2f-17e5-5848-a181-75cf098a077e', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-29', '17:30:00', null, '通常 / Excelの学習', '特に問題なく進めていました。途中何度か立ち歩いたり、しゅうくんとジオメトリーダッシュをやったりしていました。 来月は修学旅行やテストがあるので教室に来れなくなると、少し残念そうに話していました。', null, '盛り上がり: しゅうくんがいたので、中学校の話をしたりしながら、楽しそうに息抜きをしていました。'),
  ('7181ae92-7f61-528a-9ad1-5c2e0920650f', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-08-29', '18:40:00', null, '通常 / roblox', 'エクスプローラーでのフォルダの作成やオブジェクトの複数選択から学びました。そのあとアンカーのかけ忘れをしてしまったのですが、ここで複数選択が実際に役立ったので覚えたと思います。1秒ごとにすり抜けの有無が切り替わるscript作成では、CanCollideを使うことはしっかり思い出していました。ただ、wait(1)を2か所におかないといけないのに1か所にしかないというバグになかなか気づいていませんでした。まだ英語のscriptをじっくり読んでデバッグするのにはまだ慣れがいるようでした。', null, null),
  ('b06257b7-a85f-55e3-98a5-c6bf509cbac7', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-29', '17:30:00', null, '通常 / 検定2級の問題形式に慣れる', 'じゃんけんに勝つ条件のところで、使用するブロックに記載されている「かつ」と「または」の組み合わせをどう使うか見当もつかないと言っていたので、一緒に「じゃんけんで自分がパーのとき、相手がグーなら勝ち」というように一つ一つ丁寧に考えていくと、納得できたようでした。なにこれ面倒～！といいながらも、残りは自力でできていました。', null, 'タイピング: 真面目に練習していました
盛り上がり: 問題にツッコミをいれたり感想を口に出したりと、大変と言いながらもそれなりに盛り上がってやっていました。'),
  ('fd00a573-43e9-599d-a19e-a6393cf4c466', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, null, '2025-08-28', '17:30:00', null, '休み（未対象）', '振替日の予定でしたが来室せず。 翌日来室したときに、すっかり忘れていて、気が付いたら時間が過ぎていた、と話していました。', null, null),
  ('39ad562d-5ae7-593c-9fc1-1a8662af743b', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-29', '17:30:00', null, '通常 / Excel体験またはScratch', 'ほとんどの時間をタイピングで初段を出すことにかけていました。 たまに部長とおしゃべりしたり、ジオメトリーダッシュのコードを見てアレンジしたりしていましたが、あとはひたすらランキング1位を目指してゲームをしていました。', null, 'タイピング: かなり熱心にやっていて、初段が出せたと喜んでいました。
盛り上がり: ランキング1位が出せて嬉しそうでした…'),
  ('e14ed892-ef2c-5eb1-8705-a56a00a5b0f1', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-29', null, null, '通常 / 検定問題に慣れる', '問題の読み方と、回答するときの注意点を一緒に復習してから開始しました。 当初はコードを作成するスプライトの切り替えを見落としていましたが、先生の指摘で注意することができるようになりました。 コスチューム名の指定と「次のコスチュームにする」ブロックの混同が見られ、2つのコスチュームを順に指定するところを「次のコスチュームにする」を2つ使用していて、動きがおかしいと不服そうにしていたので説明をしました。 繰り返しの中にどこまで入れるかについて、少し混乱していたので、問題文を参考に、繰り返したいのはどの動作かなどをしっかり考えさせていきました。 止めるブロックの使い分けについてはまったく迷わず、よく理解できていました。', null, '時間帯: その他
盛り上がり: 時々「ナニコレ、わからない～」などとぼやくこともありましたが、しっかり最後まで完走できて、やり切った感が出ていました。'),
  ('d70c354a-5549-5dee-aa0e-76ae7ed183ca', 'ec153bd8-5b4d-5684-9704-382af23cf64a', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-30', null, null, '通常 / 検定問題に慣れる', '初めての検定なので、解き方を軽く説明してから始めましたが、わりと先まで気になって質問しまくるタイプで、「そこは問題に書いてあるから読んでみてね」ということが何度かありました。 「答えを聞いて待つ」「りんごとばなな」のブロックは初めて使うと言っていたので説明をしてから問題を解いてもらいました。 問題文の演算式において、文字列の結合のため「りんごとばなな」を使うのと、正解判定の演算式は数値のため、足し算の式を使うという使い分けがよくわからなかったようで、解説をしましたが、納得いったようないっていないような、という感じでした。 詳しいところもそれなりにありますが、教室歴が浅い分、スキルの抜けているところもあるので、今回はじっくりと2級に取り組んでもらい、次回1級⇒ロブロックスと進んだ方がよいかと思われます。', '検定2級①の3ページ2の(2)から', '時間帯: その他
タイピング: タイピングはあまり得意ではないそうです
盛り上がり: 問題文に沿って作成する、というのがとても新鮮だったようで、終始ハイテンションでした。'),
  ('36df423a-e78d-55ee-8039-a9894e620d56', '31feac25-f850-5d21-8e43-ed4d7badb6a0', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-30', null, null, '通常 / 基本のスキル確認', '基本操作コースは、カードを見せて使用するブロックを答えてもらう感じでスキル確認をしながら軽く流していきました。〇秒で座標を動かすだけ使い慣れていなかったので、実際に作成して確認しました。 「チーズをさがせ」では、ミミを動かすときに座標を変えるで動かしていましたが、向きと動かすの組み合わせで作成すると全方向を複製で作れることを提案すると感心して、作成しなおしていました。 壁を通れない動きは、壁にあたったらはねかえる⇒-動かすというのを自分で考えて導き出せていました。 虫の向きを変えるのに変数を使うのは、難しそうだけどそういうふうにするのか！と感動していました。残りは自走でスコアとクリアを付け加えて満足そうでした。', null, '時間帯: その他
タイピング: 学校でやっているといって、自主的に取り組んでいました
盛り上がり: 座標を乱数で指定したり、変数で確率によって向きを変えるなどのコードを、見たことがあったけどこうやるのか！という感じで盛り上がっていました。'),
  ('4fc7ca04-ae84-5745-82bf-5457b2d5de4a', '0d16e234-e60d-5fdb-978f-1722acf9a2b2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-08-30', null, null, '振替 / 基本スキルの確認', '今日の振替を忘れていたようで、30分遅れで来室しました。授業時間が30分になることを親御さん了承の上で受け入れました。 木曜日に作成したのがよほど楽しかったのか、席に着いてすぐに、今日はこれの続きを作りたいと言って作業を始めました。 ゲームを3ステージにするアイディアから、ステージが変わったらアルくんの位置を戻したい、ステージが進むにつれて難しくしたい、などと積極的にやりたいことを話してくれて、そのための説明はおとなしく聴くことができていました。 位置を指定するための座標や、背景が変わった時などの初出のブロックも、一度一緒にやったら、残りは自分で覚えていてしっかりと作成ができていました。 ステージによって背景の色を変えたため、すべての色で触れたらゲームオーバーにするというのも、「または」の使い方をしっかり聞いて作成していました。', null, '時間帯: その他
盛り上がり: 前回に引き続き、作品を思い通りに仕上げるための説明を熱心に聴いて積極的に作業する姿勢が見られ、正直驚きました。周りの雰囲気によるのかもしれませんが、作成が楽しいと思えるようになったのかもしれません。'),
  ('b2e99234-44b4-5ddf-9e45-eddaac56b2bb', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-09-01', '16:30:00', null, '通常 / ジャンプゲームの動きを考える', '声をかけると、わりと素直に学習に戻るのですが、ちょっと目をはなすとすぐに岳くんとタワーディフェンスゲーム（https://scratch.mit.edu/projects/652952319/）をしていました。このゲームがよほど面白かったのか、いつもより飴を食べに行く頻度は少なかったかも…。一応、ゲームをしても学習に戻るよう声をかけると話を聞くようになっただけ進歩か？ 前回の続きからだと、キツネが左端に行ったままになっているのに少し困惑していました。もう一度、自分がどういうコードを書いたのか見てもらい、この後キツネがどういう動きをすればよいか考えさせると、「一度消えてから右にいく」と答えることはできました。 自分でコードにする際、「もし端にふれたなら」で作成したため、右端に戻った時も触れた判定になることで、「どうしたらいいのかわからない」とぼやいていたので、現在のスプライトの座標の数値を読ませることで、座標を使うことを意識することができました。 現在のスプライトのx座標と、それがどこまで左に動いたら繰り返しをやめて座標を右端にする、ということまでは理解できたようですが、不等式についてはまだ難しそうでした。 触れた判定についてはスムーズにできましたが、ジャンプしたときに変数を増やすところでは、ジャンプのコードがどれかまではできても、コードのどこに変数を増やすブロックを入れるのかがかなり適当でした。（適当にジャンプの最中などに入れながら、ここ？ここ？とせっついてくる感じ…）', 'ジャンプゲームはひとまず完成ということで、次の課題に進んでください。', '盛り上がり: ゲームを完成させようとする意志は一応あったようで、かなり気が散りながらも、定期的に「次は？」と催促したりしていました。 タワーディフェンスゲームは相当楽しかったようで、いつかこういうのが作りたい、と言っていました。'),
  ('d0db13e6-e251-508f-807a-09927ff3800f', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-09-01', '16:30:00', null, '通常 / ジャンプゲームの動きを考える', '基本的には、勇作くんがやっていたタワーディフェンスゲーム（https://scratch.mit.edu/projects/652952319/）を覗いて意見を出すのに夢中でした。 それでも自分が作成しているゲームに興味はあったようで、バスケットボールがソードに刺さらないように調整をしたり、ボールに触れた時の音をいろいろ検討した結果、声を録音したものにして楽しんだりしていました。 座標が〇以下になる、という不等式は、式の意味は理解が難しそうでしたが、とりあえず数が小さくなったら動くのをやめて消えて、指定した座標に戻る、というのはなんとなくわかったようでした。 触れた判定については、「ずっと」の入れ忘れが指摘されるまで気づけませんでした。', '一応今回の作品は完成ということなので、次に進んでください。', '盛り上がり: 完成した作品には満足できたようで、ゲームオーバーのたびに自分の声が流れるのをとても喜んでいました。'),
  ('fadf3031-13da-5f39-bdda-5c83898ab364', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-09-01', '17:30:00', null, '通常 / 親子大会決勝のプレゼン資料作成', '決勝大会に対しての「おめでとう」にはニコニコしていましたが、久しぶりに開いた自分の作品の細かいところ（電車の細部やブレーキの利き方など）が気になって仕方なくなったようで、コスチュームや定義の中の細かい数値をちょこちょこといじっていました。 プレゼン資料については、一昨年の良冶くんのスライドを見せましたが、自分で作成することにはあまり興味がなく、ひたすら作品の細部に手を入れていました。 （Googleスライドは学校で使ったことがあるそうです。） とりあえずこちらのPCでPowerPointを見せ、背景のデザインを選んでもらい、必要そうなタイトルを入れてComiruで親御さんに送りました。自己紹介やアピールポイントなどは、ちょっと照れてしまってこちらではなかなか口にできなかったので、自宅で考えてくるように伝えました。', null, '盛り上がり: 作品自体は気に入っているのか、とにかくいじっていたくて仕方ない、といった感じでした。'),
  ('73e97f6c-eec7-57b7-94d0-98f8889233a2', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-09-01', '17:30:00', null, '通常 / Excel検定の準備', '知識試験については、問題を見た時は「こういうのあまり好きじゃない」と苦笑いでしたが、Excelを実際にさわって構わないことにすると、自分でチェックしながら進めていました。すべての問題について、実践さえすれば納得ができた、とのことでした。 マクロの登録が未修だったのですが、元のファイルが見つけられなかったので、過去の適当な表を開いて、例題36の手順を実践してもらいました。特に問題なくマクロの自動記録とボタンへの登録ができたようで、「面白かった」と感想を言っていました。', null, 'タイピング: 教材準備の待ち時間にやっていました
盛り上がり: マクロの機能は楽しかったようで、記録されるVBAにも少し興味を示していました。'),
  ('cbef1d2c-5c6c-5de0-ba2b-58c232fa6ac0', '1c7005cc-2815-558f-993a-9c7617d34c44', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-09-02', null, null, '通常 / 基本操作コース', '基本操作コースを進めました。物語とピンポンゲームを提示したところ後者を選びました。マウスに沿ってボールが動くことやパドルに触れると跳ね返ることなど、細分化は問題なくできました。 すぐに「答えのコードを見たい」と言っていましたが、問いかけてサポートするとけっこうな部分を自力で作れました。横に動くときx座標を変えればいいことや、斜めに直進するとき「～歩動かす」すればいいことが身についていました。また、「旗が押されたとき」や「ずっと」が必要なときにはそれに気づくことができました。 次回はゲームオーバーの処理からやることになりそうです。', null, '時間帯: その他
盛り上がり: やはりスタンプを自分で押すのが楽しいようです'),
  ('cd3c395e-bc8d-5c26-91c8-1586107a0fa4', '337872be-4ce4-5436-88f8-5f97e8c5252e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-09-02', '17:30:00', null, '通常 / 検定振り返り、刀剣ゲームでスキルアップ', '検定1級①の見直しからやりました。消えるべき敵が消えないバグがあったので直していきました。「ある程度バグ原因のあたりをつけたうえで、その箇所の問題文を忠実に読み込む」ことを一緒にやっていきました。結果として、以下が原因だったと分かりました。 ・問題文の単純な読み落とし ・「a,bを順に行う」という指示で、aとbを分けて読めずに2つが混ざってしまった(箇条書きされたものが同じ階層に作れているかチェックすることを勧めました) ・余分な「ずっと」ブロックを入れていた(検定では「ずっと」が必要なら明記されるので、書いていないときは自己判断で入れる必要はないことを伝えました) 本人もこれらについて納得したようで、少し誘導するとすぐにコードを修正できました。 そのあと、レッスンの残り時間があまりなかったですが刀剣ゲーム作成に入りました。「アル君の向き」変数の意味を問いかけると、刀や残像をついて来させるために必要だと考察できていました。りんごの動きの途中まで作れました。', null, 'タイピング: タイプスピードが速いぶん、一度ミスしたときのリカバリーで詰まっていました。それを意識して練習すると二段相当の成績を獲得できました。'),
  ('31fe9596-9f63-5e95-b615-bd2993338669', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, 'd45d6c5d-18cd-5aa2-99ea-932c81442c55', '2025-09-02', '16:30:00', null, '通常 / 演算式を利用した座標の指定、状態を示す変数の使い方、定義などに慣れる', '刀剣のゲームのクオリティをあげようを行いました。 使っている中でアレンジをしたいという部分がいくつか出てきたので紙にまとめ、斬撃の形を変えるアレンジを行いました。押したキーによって斬撃の形が変わるようにしたいようなので次回以降行えればと思います。 制作書を読む前から剣のレイヤーの違いや差などを理解して説明してくれました。また制作書を読むだけで完全にコードの意味を理解できていました。', null, null),
  ('44bc54e3-615a-5a0e-90f5-92ed251df328', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'd45d6c5d-18cd-5aa2-99ea-932c81442c55', '2025-09-02', '17:30:00', null, '通常 / 演算式を利用した座標の指定、状態を示す変数の使い方、定義などに慣れる', 'タイピングの練習を20〜30分ほど行ったのちに、刀剣ゲームのクオリティをあげるを行いました。 タイピングではミスタイプが少なく徐々に慣れていってる様子でした。(2級、準2級レベルは安定して取れていました) 刀剣ゲームでは集中して作成をしていました。 途中、繰り返しの回数は何と結びついているのか、thinkの部分に記載されている内容などを質問したところ考え方を理解している様子でした。 剣のレイヤー部分に関しては、お手本を見ながらレイヤーの違いを一緒に確認しました。', null, 'タイピング: 1級を出したいと頑張っていました（2級は出せるようです）'),
  ('2be6638d-a6df-5fd2-844a-0906ad34bc1e', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-09-02', '16:30:00', null, '通常 / 1級範囲のスキルの確認', '教材として、手順書のあるインベーダーゲームを用意していましたが、プレイしてみてイマイチ気が乗らなかったようで…しばらく、「何か作りたいの無いかなあ」とアルスタジオを探しまくっていました。 ゲームを作ってみたいけど面倒くさい、というので、「定義を使いこなす」ことを目標に、定義を使用しているスプライトだけを作成してみようと声をかけ、キャットランをやらせました。教材を渡した際は、それでも「ブロックの量が多い、めんどくさい」とぼやいていましたが、一緒にコードを見て難しいところがあるかと聞くと「わりと簡単」といい、いくつか示したコードもきちんと読み取って解説ができました。そこで、みうちゃんと二人がかりで「すごい」と持ち上げ、このくらいのコードはそうすけくんならすぐできちゃう！と声をかけたところ、黙々と作業にとりかかりました。コードの読み取りはできたので、完成形の写経のようなかたちにはなってしまいましたが、作成中は集中して10分くらいで完成させていました。 コードの意味がわかるならアレンジできるよね、ということで、残りは好きにアレンジをしていました。', null, '盛り上がり: めんどくさい、と何度か言いながらも、話にはのってきて、雑談をしながら手を動かしていました。時折、祥太くんの作品をのぞいたりもしていました。 学校では工作クラブに入っているけど、絵に比べて工作は思った通りにできないのであまり楽しくないそうです💦。'),
  ('277b83ed-c50e-525f-93a3-fcc7658a6d4d', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-09-02', '17:30:00', null, '振替 / Excel2級の対策', '資格受付オンラインから、itjiyukenkyuのアカウントで取り組みました。 知識問題は正答率60%でした。「アクティブセル」「数式バー」「シート見出し」など、用語に慣れなくて間違えたものも多かったようです。見直したらわかったものも多かったようで、覚えておきたいものがあったときのためのメモも使わずじまいでした。 実技練習の方は少し難しかったようで、ピボットテーブルの作成途中で授業時間が終了となりました。答え合わせをしておきたいということで、授業後20分くらいかけて、わからなかった箇所の確認をしました。 ・日付データを「日曜日」と表示させるやり方がわからなかったとのこと。ユーザー定義の表示形式「aaa」と「aaaa」を実際に入力して結果を見てもらいました。ちょっとびっくりしていました。 ・条件に一致したときはA、そうでないときに、参照した値が〇より大きければB、小さければC、のような問題がわからなかったそうです。答えとなる数式を見せて問題文と照らし合わせていくと、普通の条件分岐だと気が付いて納得していました。 ・DSUM関数は未履修とのことだったので、改めて一緒に関数ウィザードから作成しました。納得はできたようですが、あと何回か練習したいとのことです。 ・ピボットテーブルが合っているのかわからない、とのことで、完成形と見比べてみました。 以下、次回対応に記載。', '※前回のピボットテーブルを再度作成し、以下の直し方を教えて下さい。 ・完成例ではA列に利用部屋、B列に曜日となるはずが、新規作成したピボットテーブルではA列に利用部屋と曜日が表示されてしまう ⇒デフォルトでは[フィールドの設定]-[レイアウトと印刷のレイアウト]がアウトライン形式になっているので、ここを表形式にすると解決 ・行と列のラベルは入力の必要あり。 ※ユーザー定義の表示形式を何種類かと、DSUM関数の学習、また、前回到達できなかったが、問題文を読んで未履修だと言っていた「ゴールシーク」の学習ができると良いかと思います。', '盛り上がり: 初見では知らないことがまだまだあったようですが、自分で振り返って納得できていることも多く、熱心に学習できていました。'),
  ('a7f69d22-d759-5c9a-b731-a88d911b9929', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2025-09-04', '16:30:00', null, '通常 / 問題文を読んで作成する練習', '問題文を読む練習をしたくて単元別演習を用意していましたが、こういうのは気分じゃないと一蹴し、今日はゲームを作りたいと言って、手順書の中から課題を選んでいました。 お試しプレイをしたあとは、「何すればいいの？」と人任せになっていたので、スプライトごとにどんな動きを作ればよいのかを少し考えさせました。最初のレベルボタンを押す動作のところで、手順書に「このスプライトが押されたとき」が無い、と騒いでいたので、そこは一応、どんなコードがくるのか自分で考えられたようです。その代わりになっているコードは、まったく想像がつかなかったようでした💦 口では、ロブロックスをやりたいから検定を取らなきゃ、と素直に言っているのですが、課題に取り組む集中力が5分と持ちません。基本的に先生頼りなので、自走はほぼできていない状態です。手順書や単元別演習の単文でも、読解するのが厳しそうです。お手本と問題文をうまく照らし合わせて、コードの想像がつくようになってくれると良いのですが…。 今日はレベルボタンのコードを写すのが精いっぱいだったようでした。', null, '盛り上がり: 授業前には、自分でログインしたりと準備の手伝いもしてくれました。作業をしたりゲームをしたりしながら、ひっきりなしにこちらに話しかけたりと、教室にいることはとても楽しんでいるようです。授業についてもこちらの話は聞いて、「じゃあやる」とやる気を見せたりもするのですが…もう少し自分で考えようとしてほしいところです。'),
  ('2592facd-2f87-58f5-831d-2624247af140', '57f45872-1f3e-5540-b676-bf9023444e39', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-09-04', '16:30:00', null, '通常 / 自力で問題文から作成する練習', '単元別演習やドリルは、パッと見て「やったことがあるのが多いからイマイチ」とのこと、prgで検索した結果も、できそうなものはやったことがあるし、やったことがないのは難しそうとの感想でした。実際、prg後半のものは、まだ理解が難しいと思われます…。 今日は先生が足りないにも関わらず、指導必須の子が多かったため付きっ切りになれなかったせいもあるのか、自力ではほぼ進めることができませんでした。 最終的に、コンテストのような作品を作りたい、と課題を選びはしたものの、コードを開いた瞬間に「むずかしい」「無理」となり、かろうじて背景スプライトのスクロールのところだけ、一緒に読み解いていきました。最初にどの座標に表示されて、どこまで繰り返して動く、など、一つ一つのコードが何をしていて、それがどのような動作になっているか、というのは一応答えられるのですが、それが数行積み重なると混乱して「やっぱわからない」とぼやいていました。複数の組み合わせを考えるのが苦手？なのでしょうか？ 難しいとなるとすぐに席をたって逃避してしまうので、最終的に、スプライトが左端に消えるまで繰り返す、というコードをメインとクローンの両方に作成するだけで終了しました。', null, 'タイピング: 「ちぢむ」の「ぢ」を「zi」と打って、先に進めずに困っていたので、「だぢづでど」は「dadidudedo」と打つことを教えました。「つづき」の打ち方も知らなかったようで、とても驚いていました。
盛り上がり: 作成には苦戦していましたが、リレーの選手に選ばれたと嬉しそうで、50mや100mのタイムをりくくんと比べ合ったりしていました。（こういう数値はとてもよく覚えています！）'),
  ('cbb4da15-b243-5e4d-9312-5e1a48ae2018', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-09-05', '16:30:00', null, '通常 / 検定4級を意識してのゲーム作成', 'プラットフォーマーゲーム作成の基礎から復習しつつゲーム作成を開始しました。滑らかにジャンプするスクリプトを理解した上で作成。背景スクロールの作成中に、背景はスクロールさせたくないとのこと。背景スクロールして欲しかったのですが、何かゲーム構想があるそうで、かつ、背景スクロールは途中まで作成して、作り方を理解しているようだったので、良真くんの意見をOKとして、そのままゲーム作成を継続。プレイヤーを二人にして、スマブラみたいなゲームを作るとのこと。元々教えてようとしていたプラットフォーマーゲームの基礎スキルで覚えて欲しかった項目を入れてもらいつつ、来週、もしくは再来週までに、作成完了させる方向で進めれば良いかと思います。', null, 'タイピング: 集中して取り組んでいました。準一級レベルとの結果'),
  ('db5c169f-c734-552f-be15-89ec7484c142', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-09-05', '17:30:00', null, '通常 / ロブロックスゲーム制作', 'レッスン始まっても、何かロブロックスのゲームをして遊んでいて、全然レッスンとしてのゲーム制作をスタートしてくれず、だいぶ時間が経ってから、渋々「やるか」とはじめてくれました。デジタネの中から何か興味のありそうなものを選んで、それベースでのゲーム制作をして欲しかったのですが、全部興味がないやりたくないとのことで、雑談がてら、ひとまず、ゲーム制作画面を立ち上げてもらい、自由制作を始めてもらいました。ここで、デジタねで覚えるべきスクリプトを試してもらおうとしたのですが、何かと理由をつけて拒否するので、思うがままに自由制作を続けてもらいました。今日は、NPCをどついてステージから落とすようなゲームを作っていましたが、ツールボックスからいろんなモデルを持ってきて、それを組み合わせているだけ。シンプルな決まった動きしか表現できず。スクリプトをしっかり学んで思い通りの動きを表現して欲しいと思うのですが、なかなかそうはいかず、ハルくんに関しては、ロブロックスの教え方を根本的に見直さないといけないのかなと思ったりしています、、、。', null, null),
  ('86d6e290-310f-5412-9f5b-811369e62fec', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-09-05', null, null, '通常 / ロブロックスの続き', '前回途中で終わっていたハラハラピンポールの続きから。質問は、roblox studioの使い方に関するものだけで、特にデジタネのレッスン内容については、問題なく理解できていたようで、ハラハラピンボールのレッスンを完了させ、確認問題も、１００％で完了できました。その後、ゲームをアレンジしたいと言うことで、楽しんでアレンジをしていました。次回は、次の動画からです。', null, '時間帯: その他'),
  ('45c93353-60a2-5e1a-abeb-e9a2914c303b', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-09-08', '16:30:00', null, '通常 / ジャンプのコードを進化させよう', '前回のジャンプゲームが終わったので、そのジャンプのコードを復習しながら、放物ジャンプへ導入していきました。まず、等速ジャンプを作ってみていっても、2人ともコスチュームへの寄り道が絶えず起こり、なかなかコード作成に目を向けてくれませんでした。作り終わったら、「回数」と「高さ」の変数を導入しました。ただそのまま入れただけでは動かないので、なせ動かなくなったのか考えてもらったところ、「マイナスが足りない」とすぐ気づき、修正法も引き算のブロックを持ってこれていたので、頭の回し方はよいです。数年前の大貴君みたいにかんじです。 最後、駆け込みで放物ジャンを写経でコード作成をしましたが、あまり内容を触れずに、時間が来てしまったので、次回の頭でも触れて解説したいところです。', null, 'タイピング: 9級に入れるようになりました。'),
  ('5102692d-b6f9-5f81-9cac-9872cf2e8b0a', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2025-09-04', '17:30:00', null, '通常 / U13大会作品をつくる', '自分で描いたイラストをアルスタジオにもってきて。着せ替えゲームを作成する予定でしたが。間があいたこともあり、制作のイメージを忘れていたので。 まずは、見本とした着せ替えゲームを遊んだ。 次に、自分の作品を 髪の毛⇒目⇒口、、、、と。順番にパーツを当てはめていく構想をおさらいした。 髪の毛をセットしたら、「次に」というボタンで「目」の選択肢がでてくる・ これを細分化して考えた。スタートで「髪の毛」が見えるようになる。「次に」のボタンでメッセージが送られ、「髪の毛」がきえて、「目」が配置される、という流れ。 今のままだと、「次に」のボタンが何度も押されてしまうので。そこが工夫のしどころ、考えどころです！ 本人と話をしながら、次々違うパーツを表示させる方法をどうプログラムするかを考えよう、「変数」使うといいね、まで話をしています。', '続きをいきましょう。', '盛り上がり: プログラミングすること自体は、面倒そうですが。どういう方法があるかを試行錯誤することは、嫌そうではなかったです。'),
  ('a7c30ed0-f276-5ae6-ae00-cd995fb8963b', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-09-08', '16:30:00', null, '通常 / ジャンプのコードを進化させよう', 'まずは前回までの復習として等速ジャンプを作っていきました。だが、ほんとにコスチュームの方への寄り道が絶えず、前回のカンニングしてもいいよと言っても20分くらいたってました。次のステップとして、回数と高さを変数で置き換えることやっていきました。ただ置き換えただけではうまく機能しないことを考えてもらったが、勇作君がすぐさま答えてしまい、自分で答えたかった欲が出ていました。ジャンプの高さの調節方法もこちらが教えなくても、勝手に変えてできていました。最後に、放物ジャンプのコードの写経を駆け込んでやりましたが、解説が触れられていないので、次回頭に触れたいところです。', null, 'タイピング: 勇作君を見ててやりたくなり、小文字のキーボードでしたが、取り組んでくれました。'),
  ('9776bdbe-de65-5bc7-b655-26e344968bd6', 'e22d8f70-f1a1-5ca4-9ed4-4d27cb0e164f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-09-08', '16:30:00', null, '通常 / スロットマシーンをつくろう', '最初に遊んでさっそく作る気になっていたので、作成に始めました。スプライトの準備ができ、コードでまずは数字が変わっていくコードを作ってみるかと提案して、勇作岳の方を見ていたら、全く進んでない。コスチュームを変わるからずっとと変わるためには？？とさらにヒントを出して、再び目を離したら、進んでない。そんで、そばについて一緒に考え進めたらできました。優しめナコードなので、自走できるかと思ったら失敗しました。その後、数字を止める仕組みを作ったら、試行錯誤している様子がうかがえたので、「ほかのスプリクトを止める」の使い方を教えていきました。それから、左から順に押していくコードでメッセージまでで待つを紹介したら、全く覚えてないと言ってきて、まだコードの好き嫌いな部類が出ているぽいです。止めるコードは使いこなせていたので、メッセージなど活用できれば、より良くなります。', 'スロット残り', null),
  ('1e58e030-2ddd-5532-aac1-9fcb2e77bc54', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-09-08', '17:30:00', null, '通常 / GUI', '授業始まっても20分過ぎてもゲームをしていました。今回の単元は用語周りに新情報が多かったので、ムズかしい顔をしていました。名前をテキトーに着けていた節もあったので、動画の説明がわからなくならないように動画通りの名前にするように矯正しときました。やっている終盤「新しいことが多すぎて、来週まで覚えている気がしない」「もう一回最初から早く来て見直す」と本人から言っていたので、有言実行通りにさせてあげてください。', null, null),
  ('dbb60f0b-254c-5683-9b9b-b8d92299c9af', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-09-08', '17:30:00', null, '通常 / 親子大会決勝の作品に向けて', '入賞作品が気に入っているようで、電車のより詳細な部分（連結部分）などが追加されていました。現在時刻も表示され、電車さながらになっていきました。プレゼンの資料について進みを聞いてみても、言葉が少ないので詳細は分からないが、進んでいるはそうです。', null, null),
  ('f496e831-3ed1-5c96-a1da-2ab62caa0c7f', 'd3885e29-ee68-501b-bf31-6c050fd50c36', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-09-05', '16:30:00', null, '通常 / 検定に向けたスキル習得', '最初に簡単な細分化をしたところ、プレイヤーの動きやゲームクリア/ゲームオーバー条件などは把握できていました。最初はなかなかやる気が出ない一方で、一度スイッチが入ると作業への集中を止めたくないようでした。そのため「コードをある程度まとめて作り、あとからその内容の振り返りをする」スタイルで進めました。振り返りではそのコードが何をしているものなのか問いかけました。また検定に必要なスキルとして、乱数や他のスクリプトを止めるなどに重点的に触れました。', null, null),
  ('33e1ed4d-33b9-50bf-83bf-48f8724c82ce', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-09-05', '16:30:00', null, '通常 / 大会準備', 'U13大会に向けた制作を進めました。新しい要素として、コーラが工場で生産される部分の動きを作成しました。それにともない不要になった変数について検討し、削除するなどもしました。9月末が締め切りであることは把握しており、すでに全体の8割ほどが完成しているとのことで、比較的余裕を持って調整を進めていました。', null, null),
  ('d9bb80d8-c3eb-542d-926e-ad53e322a366', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-09-05', '16:30:00', null, '通常 / 変数などのスキルアップ', '変数を使ってボールの速度を段々と変化させる部分を進めました。「動画通りにやったのに動かない」とのことだったので、一緒に内容を確認しました。 変数や方向が多く、全体が複雑に見えたため混乱している様子で、以下のような点に間違いが見られました。 ・「もし」ブロックの中身の範囲 ・「ずつ変える」ブロックと「にする」ブロックの混同 これらの点をチェックするよう促したあとも混乱が続いていたため、スクリプトを一度いくつかの部分に分けてしまって、順に確認していきました。結果、その箇所に本人も納得していました。今までよりもレベルが上がっているからこれができたのはすごいと自信を持ってもらいました。', null, null),
  ('55b9bb02-a9c5-56a9-98a0-5caffd1f9391', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-09-05', '17:30:00', null, '通常 / 演算の練習', '検定に向けた演算の練習として、動画をベースとして進めました。座標を使った不等式を扱い、コードの見た目は複雑でしたが、座標がどの範囲にあるのかを視覚的にイメージできていました。質問もあまりなく、スムーズに進めていました。', null, 'タイピング: 段々慣れてきた様子でした'),
  ('cd1a8caf-dd38-507c-b094-4d8a307dfd8d', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-09-05', '18:40:00', null, '通常 / 大会準備', 'U13の制作を進めました。ゲーム本編はほぼ完成しており、新しい要素を追加するかどうか悩んでいました。一緒にアイデアを出し、新しいモードとしてタイムアタックを追加することに決めました。ゲーム本編のコードをうまく流用して作成できました。タイムアタックが場合によって途中で終了してしまったり、不要なスプライトが残っていたりするバグが発生しているため、次回修正予定です。', null, null),
  ('11a49a0a-b7ed-5062-bdf3-8dc290cf9fdc', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-09-05', '18:40:00', null, '通常 / プラットフォーマーでスキルアップ', 'ゲーム制作のパターンを広げるため、プラットフォーマーのセットとしてジャンプから始めました。等速ジャンプについては「上に行く→下に行く」という仕組みを理解して作成できましたが、放物ジャンプの滑らかさにはあまり意義を感じなかったようで、一旦飛ばしました。次の横スクロールについては、いくつか横並びになった背景の動きのイメージができ、x座標とy座標の違いも理解していました。ただ、普段と比べてそこまで題材に興味を持っていないようにも見えました。', null, 'タイピング: 集中していました'),
  ('dec93e13-814e-5eba-988c-233e7e386533', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-09-09', '16:30:00', null, '通常 / 複数の条件が組み合わされた演算式の練習', 'かなりおしゃべりをしながらも、時間内に最後まで解き終えて満足そうでした。 じゃんけんに勝ったとき、の条件式のところが、問題文に一切ヒントがないため、自分で簡単な図を書いて考えていました。自分が〇のとき相手が〇なら、という条件式が3つ必要なことは気づいていましたが、その書き方に詰まっていたので、変数「自分の手」と=を使う、とだけヒントを出しました。その後はすぐに納得できたようで、「または」と「かつ」も自力で組み合わせて「長い」とウケながら演算式を完成させていました。 どこまでを同一スクリプトに続けて作成するのかというところで迷っていました。問題文の書き方が「～の後」なのか、「～が押されたとき」等なのかで判断ができることを教えました。 自分の手の変数を変えるところにミスがあって、何度プレイしてもグーしか出せないというバグがありましたが、時間内に直すことができていました。', '2級レベルのスキルには問題がなさそうなので、しばらくは検定問題からはなれてOKです。変数を複数使用するようなプログラムに慣れておくと良いかもしれません。', 'タイピング: タイピングはイマイチなんだ、とぼやいていました。
盛り上がり: 長めの問題を時間内に解き終わったことが嬉しそうでした。楽しそうにおしゃべりしながらも、常に手はしっかり動かしていました。'),
  ('c928945f-6c39-5657-bdf0-e2173850e7c5', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-09-09', '16:30:00', null, '通常 / ある程度まででも検定問題を進める', '検定に対してやはりめんどくさがっていたので、区切りをつけて半分までやればいいことにすると、レッスン時間の最初から始めてくれました。 リスト関係や「りんごとバナナ」などポイントとなる部分は、どのブロックを使えばいいかすぐに分かっていました。 ただ真剣に読もうとはしていなかったので「～回繰り返し」などを見落とすことがありましたが、もう一回読むように促すとミスに気づいていました。 全体的に「やろうと思えばできるがやりたくない」様子でした。', null, null)
on conflict (lesson_record_id) do update set lesson_date = excluded.lesson_date, start_time = excluded.start_time, end_time = excluded.end_time, title = excluded.title, content = excluded.content, homework = excluded.homework, memo = excluded.memo;

insert into public.lesson_records (lesson_record_id, student_id, course_id, staff_id, lesson_date, start_time, end_time, title, content, homework, memo) values
  ('545fc96a-878a-5c2d-8156-48e88371f924', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-09-09', '17:30:00', null, '通常 / 変数と演算式の組み合わせに慣れる', 'タコから逃げろゲームは過去に作成済みだったので前回の続きとして刀剣ゲームの作成を行いました。 前回保存ができていなかったようで1から作り直しましたが、定義も難なくこなしていました。途中剣の見た目を変えるなどアレンジをしながら取り組んでいました。', null, 'タイピング: タイピングもだいぶ慣れているのか手元を見ずに行なっていました。ミス数も少なく準一級レベルをキープしていました。文章を覚えるとより速く打てるようになるので一級レベルも目指せると思います。'),
  ('a31301ec-e4e2-5bc0-8dba-fa576b823f5f', '31feac25-f850-5d21-8e43-ed4d7badb6a0', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-09-09', '17:30:00', null, '振替', 'アルスタジオの細分化された完成例を見せながら進めました。 「マウスのx座標」を使ってパドルの位置を決めるのは初めてでしたが、x座標とy座標をどうするかを別々に考えるとすぐに納得していました。 特に後半は「跳ね返したらスコアを増やす→5点になったらクリア」のように、何も見ずに細分化と作成ができていてとても理解度が高かったです。 スコアが一気に増えないように0.5秒くらい待つところは自力では思いつかなかったのですが、その考え方を教えると記憶に残ったようでした。 レッスン時間ちょうどくらいで完成しました。', null, 'タイピング: スムーズに打てていました'),
  ('93cb58f1-ccf3-574f-9d64-04d46600b2e3', '337872be-4ce4-5436-88f8-5f97e8c5252e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-09-09', '17:30:00', null, '通常 / 複雑なコードに慣れる', '刀剣ゲームは30分から40分ほどで作成できていました。定義もよく理解しているので難なく作っていました。剣の位置が正常な場所に配置されず苦戦していましたが、数値の入れ間違いと気付き修正を行いました。', null, 'タイピング: タイピングは準一級から一級を安定して取れていた。前回よりもミスタイプ数が減っていたので初段までいけそうな雰囲気です。'),
  ('7281b1b9-8171-5526-8d76-98169134a715', '0d16e234-e60d-5fdb-978f-1722acf9a2b2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-09-04', '16:30:00', null, '通常 / 基本的なスキルの獲得', '向きを作成して動かすのはよく覚えていて、ねずみの動きは自分で作成できていました。 壁にあたったら跳ね返るよりも、壁にあたったらゲームオーバーにしたいというので、モチベを保つためにもまずはそちらで作成させてみました。上下左右それぞれの条件分岐の中に、触れた判定を入れるというのは、一度右にのみ触れた判定を入れてプレイした上で、納得していました。 チーズがあちらこちらに出るというのも、自分から「ランダムにするにはどれを使うんだっけ」と言ってきたので、そこから乱数を教えました。x座標を一緒に作ったら、y座標は自分でできました。 ネコに触れたらゲームオーバーというのも、自分でアレンジを考えて楽しそうに付け足していました。', null, '盛り上がり: 最近は作品作りを楽しんでいるようで、たまに立ち歩いて他の人の作品をのぞいたり、飴をのぞいたりしてはいるものの、続きを作ろうと促すと素直についてきて集中することができていました。'),
  ('4da321f6-53e5-50ea-bb14-39836c394fee', '05439956-11b9-5ac7-a44a-3e6f5a6831d8', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2025-09-04', '16:30:00', null, '通常 / 親子大会のプレゼン作成と選抜大会の準備', '親子大会入賞に対して、作品についてはほぼノータッチだったのですが💦、いくつか指摘したことを「アドバイスありがとうございました」と言ってくれました。 選抜大会作品については、サムネイルの作成手順を聞くと、嬉しそうに詳しく説明してくれました。 たまにこたろうくんと野球のことをしゃべったり、17:30クラスの子たちがやっていた「英語を話したら負け」ゲームに笑ったりと、教室の雰囲気は楽しんでいるようで、良い息抜きになっているのかもしれません。', null, '盛り上がり: 作成は特に質問もなく自力でできているのですが、教室にいること自体を楽しんでくれているようでした。'),
  ('fe9919d5-2c43-5c31-b3d3-76e1e5ccb766', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-09-04', '17:30:00', null, '通常 / U16大会作品の準備', '承太郎君としては、完全な学習アプリではなくゲーム要素を作りたいそうで、ヘリウムをゲットしたら風船で上にのぼるようなゲームを作ろうか、などといろいろ考え込んでいました。アイディアはいろいろ出るものの、時間をとても気にしていたので、手を広げすぎず、今の探索ゲームにもう一つくらい新しい要素があればよいのではないかと提案してみました。家でも少し考えてくるそうです。', null, 'タイピング: 体験版をプレイしていました
盛り上がり: アイディアを考えるのは楽しそうでした。時間があれば、じっくり作らせてあげたいところなのですが…'),
  ('b769e4ce-eb07-5a28-b308-efb78381401c', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-09-04', '17:30:00', null, '通常 / U13大会作品の作成', 'オープニングはできたので、その先を作成していました。少し作成しては、長いオープニングで暇そうにしていたので、長い作品を作るときには、開発用のスキップ機能などを入れてみたらという提案に、興味深そうにしていました。今度やってみる、だそうです。', null, '盛り上がり: 英語を話したら負けゲームをしながら楽しそうに作成していました。'),
  ('d2583fd2-3248-5869-9744-f573ba687b81', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-09-04', '17:30:00', null, '通常 / 楽しんでプログラミングをする', '検定の文章が苦手なのか、前回、前々回とちょっとお疲れモードになっていたので、楽しんで作成することを思い出すことを目的としました。 前半はおしゃべりでほぼ手が動いていませんでしたが、席替えを示唆されると焦ったようで、後半は一生懸命に作成をしていました。手順書を見てほぼ自走していましたが、セリフブロックが、Defaultのセリフの長さと手順書のセリフの短さのために大きさが違いすぎて、同じブロックと判定できていませんでした。', null, '盛り上がり: 今のクラスメンバーと同じ机で学習するのが楽しいらしく、席替えをされないように頑張っていました。'),
  ('67601454-bc13-5787-b971-93fc4b8b9628', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-09-04', '17:30:00', null, '通常 / 条件分岐の作成に慣れる', 'どこまでを条件分岐の中に入れるか、などが苦手なようなので、少し慣れてもらう目的で演習をやってもらいました。 課題クリア型なのがそれなりに楽しかったのか、見本とカードの短い文章できちんと正解を作成することができていました。一つできるごとに嬉しそうに先生を呼びに来ていました。', null, 'タイピング: スムーズに練習できていました。
盛り上がり: 今回の課題は、特に悩むこともなくスラスラとできていました。晴君も自信がついたのか、終始楽しそうにしていました。'),
  ('ebeb528d-5271-5244-9e47-afc4f6f228a5', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-09-04', '17:30:00', null, '通常 / U16大会作品の作成', '前回リストで設定した兵力を、戦いの際の演算式にどのように入れていくかを検討しつつ、 戦いのところの作成を進めていました。新しい家来の武将を誰にするか、楽しそうに検索しては追加をしていました。', null, '盛り上がり: ひっきりなしにおしゃべりしていましたが、一応手も動いていました。今のメンバーが楽しいようで、席替えもしないでほしいようでした。'),
  ('74010053-274f-5b4d-866e-aca3bcd6e90b', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-09-11', '16:30:00', null, '通常 / 【Prg】32 タコから逃げろゲームを作ろう！', '今回のゲーム作成は手順書を見ながら作成していきました．基本的な部分は書かれていたため，スラスラと進めていくことができました．難易度を変数で変更する部分についても自分自身で気づいて変更することができていました．今までに学んだことはしっかりとできていたので，良い完成度となっていました．', null, null),
  ('15b10a0f-8a1c-5af0-ad07-a89cd92c9278', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-09-11', '17:30:00', null, '通常 / 大会作品制作', '今回は，キャラクターメイクのパーツごとにページを分ける際にメッセージを使用していた部分を，変数を利用してのページ移管に変更していきました．原理については説明しながら作っていったところ，なんとなくではありますが理解してくれたようです．次回では座標部分の修正が終了次第，次のパーツへ移っていきたいです．', null, null),
  ('50dc4fed-6e2c-59be-b464-d53a761f8fb5', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-09-11', '16:30:00', null, '通常 / お手本の作品を見てコードを考える練習', '前回の続きの【Prg】32 タコから逃げろゲームを作ろう！を用意していたのですが、とにかく今日はいつも以上に気乗りがしなかったらしく、やりたくないと却下でした。 終始ふらふらとして、虎太朗くんや朔太郎君のPCをのぞいて一緒にゲームをしてみたり、トイレに長めにこもったりと、勉強に取りかかることがなかなかできませんでした。 後半になって、虎太朗君用に「ビンゴおじさん」のサイトを見ていたところ、「ポケポケ」に反応して、「これならやりたい！」とのこと。集中してやるという約束をした上で、作り方のサイトを参考に作成することにして、ようやく席に着いてくれました。 今回参考にした作品は、カードを開封するまでのところなのですが、その先は上級になるということで、ほんの少しだけ、上級に興味を示していました。 カードの絵柄をオリジナルポケモン風のものから、拾ってきた鬼滅の刃の画像に差し替える作業をとても熱心にやって、満足そうでした。 開封のときに、袋の絵が少しずれてしまうのを直そうとして、時間切れとなりました。', null, '盛り上がり: 興味のあるものしかやりたくない、と豪語していただけあって、鬼滅の刃のカードにする作業はとても熱中してやっていました。 はやくロブロックスでゲームを作りたい、と口では言っているのですが、Scratchのスキル習得にはなかなか気持ちが乗らないようです…'),
  ('605d822f-0b33-50c5-a28b-f2fdd0e1df7f', '57f45872-1f3e-5540-b676-bf9023444e39', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-09-11', '16:30:00', null, '通常 / 既存の作品から細分化を考える', 'こちらが用意しておいた野球ゲームは、少しプレイして、イマイチとのことでした。見た目から入るせいか、prgやアルスタジオのゲームにはあまり興味をひかれないようです。 遊ぶときは楽しそうにやっているゲームもあるのですが、自分で作るとなるととにかく注文が多くなります。 ビンゴおじさんのサイトを見ていて、ポケポケなら作ってみたい、というので準備をしましたが、カードの絵柄にピンとこなかったのか、自分でScratchから野球カードのゲームを探してきて、これを作りたいと言ってきました。 https://scratch.mit.edu/projects/754200329/ 野球選手の写真がたくさんあるのが良かったようで、ようやくPCに向かい始めたので、演出スプライトのコードを写経して、そのコードの意味を説明させました。また、複数のメッセージを確認させ、スプライトや各スクリプトの相関関係を考えることで、ゲームの構成を理解させました。', null, 'タイピング: 毎パソは前回あまり良い記録が出なかったためか、今日は寿司打にしておく、と言ってそちらを熱心にやっていました。
盛り上がり: 野球選手のカードの枚数にとても興奮して、今日一番盛り上がってPCをいじっていました。'),
  ('8c6be108-b565-518a-915b-1503b7f8e877', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-09-11', '17:30:00', null, '通常 / U13大会作品の作成', '電車の遅延により、15分ほど遅れて来室しました。 前回話していたオープニングのスキップ機能を嬉々として作成していました。 スキップするとストーリーは飛ぶのですが、背景を秒ごとに変えているコードが動いたままになるのを解決しようと頑張っていました。 スキップが押されたか押されていないかを変数に入れておく提案をすると、納得してサクサクと作り込んでいました。 動いたままでいてほしいコードと、止めたいコードが混在していて、少し混乱していたので、次回もう一度整理して、このあたりを制御できるようにさせたいです。', null, '盛り上がり: 作品のストーリーやラストをどうするかというのは、もう決めているそうなので、それに沿って作っていけばいいだけ、と得意げに説明してくれました。'),
  ('25903f4c-a191-5dab-85c7-5b3dc1dd8a16', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-09-11', '17:30:00', null, '通常 / 条件分岐の確認をする', 'カードの裏を見ないで、お手本の作品をプレイすることと、カードの表面のヒントの文章から作成をしていきました。ほとんどのところは自分で思いつくことができていました。 たまに「ずっと」を忘れた時なども、テストプレイをして気づくことができていました。 そのとき思いついたコードをすべて作成していく傾向があり、ある条件を満たしたらメッセージが送られるのに、メッセージを受け取った時にもう一度、条件を入れていたことがありました。こちらの指摘で気づきましたが、重複する動作のコードを書いてしまうところが以前から見受けられるので、もう少し細分化に慣れさせていきたいところです。', '単元別Gをやろうと予告してあります。', 'タイピング: 最後に準1級が出せて、嬉しそうでした
盛り上がり: Fの単元別演習を最後まで自力でやることができて、嬉しそうでした。 あまった8分ほどで、ファイルに挟み込んであったたくさんのプリントにきちんと穴をあけ、丁寧に閉じて整理して、満足気にしていました。'),
  ('333ba51c-9d29-50f0-95cf-c3679211a97e', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, null, '2025-09-11', '17:30:00', null, '休み（振替対象）', null, null, '備考: 学校都合の為'),
  ('7eaef4a2-d2c7-59c1-9472-1bea1df2087c', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, null, '2025-09-11', '17:30:00', null, '休み（未対象）', null, null, '備考: 学校都合の為、当日連絡'),
  ('cfd44e70-31e6-50b5-a56d-935d4b5036eb', '0d16e234-e60d-5fdb-978f-1722acf9a2b2', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-09-11', '16:30:00', null, '通常 / チーズを探せ完成', '前回作っていたものが気に入っていたので、猫の動きを付け加えることにしました。その前に、迷路に当たると即ゲーム停止になっていたので、お手本のバウンドするのしたいとのことだったので、コードを見せながら、どんなコードになっているか口に出しながら作りました。途中、なぜ歩数にマイナスがつくことで、どの動きを出しているか才覚にしたところ、跳ね返る場面と認識できていました。そして、チーズに何度もとっていたので、変数でスコアもつけました。その際に、初期化の「0にする」も何も言わずに持ってこれていました。入れる場所はまだあやふやでしたが、学んだことが身についています。最後に、猫の動きを写経していきました。その最中、ルイ君たちに気を捕らわれる場面が多かったが、時間何に、すべて作ることができました。', null, null),
  ('08ac1907-824b-558b-aaae-edd8fbf955ab', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-09-11', '17:30:00', null, '通常 / レースゲーム', '前回の続きをやっていきました。今回は中学生組がお休みだったので、結構集中してできていました。車の先端の色判定の仕組みはどのように働いているか聞いたところ道へのセンサと気づけていました。めっせーじのところの勝敗整理は、ミスすることなくそれぞれにわりふることができました。時間が余ったので、プレイヤーのコスをいじって、勝ちやすくなるようにしていました。', null, null),
  ('02a0d3e0-035f-5e80-b19c-e8fd226c90fa', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-09-11', '17:30:00', null, '通常 / 大会作品作り', '電車の遅延があり、10分くらい遅れていきました。今のところ進捗は自己申告で4割程度らしいです。最初のストーリーが終わるまで、時間がかかるのでスキップボタンを作ることにしました。導入すると、バグははやり起こっていました。スキップボタンの効能をみえなくなっても発揮したいとのことだったので、幽霊効果を提案しましたが、授業時間内では完遂することができませんでした。ここは本筋ではないので、手軽に終わらせられたらいいと思います。', null, null),
  ('e7ea81b0-0d5d-54c6-83be-3825aa427c31', 'd3885e29-ee68-501b-bf31-6c050fd50c36', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-09-12', '16:30:00', null, '通常 / 検定のためのスキルアップ', '先週から始めたPrg08がまだきちんと動かないので、その続きをして欲しかったものの、なかなかやる気が起きず。別のゲーム（キューブの戦い）に夢中になっているところで、そのゲームのアレンジに興味が出てきて、こちらから何も言ったわけではないのに、自分からアレンジを始めていました。せっかく集中できているので、その流れに乗っかって、ボタンを押したときに、コスチュームを切り替えて、剣を振り下ろすアクションを作ったり等、要くんと話し合いながら何パターンかのアレンジをして、１、２個新しいスキルを覚えられたかと思います。次回は、できればせっかく始めたPrg08をきちんと動くようにしたいところです。', null, null),
  ('1f7b9533-e25b-5d3f-99a8-a2782d0b64e5', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-09-12', '16:30:00', null, '通常 / 検定のために新しいスキルの習得', null, null, 'タイピング: 集中して取り組んでいました'),
  ('8b418c65-761e-573f-b61d-6d1de3648973', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-09-12', '17:30:00', null, '通常 / U13作品作りの続き', 'クリックでコーラ製造をするゲーム（というかシミューレーション？）の制作続き、家でも進めているようで、特にこれといった質問もなく、ゲームの進め方に関してもある程度固まっているようなので、今日はアドバイスするようなこともなく終了しました。次回以降は、ゲームを実際に遊ばせてもらって、気になることや、こうすればもっと良くなるとか、何かしらのアドバイス・提案をするくらいで良いのかなという感じですね。', null, null),
  ('e01fe2d3-084e-5f5c-9811-8fc068bcbd14', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-09-12', '17:30:00', null, '通常 / 検定のため新しいスキルを身につける', '前回prg25が未完成だと思っていたら、保存がきちんとされていなかっただけで、終わっているとのことだったので、ピンボールに興味があると言うことでprg42を始めてみました。ボールの動きの部分を学んでほしくて、それ以外の部分は、ささっとコピーをする程度で、ボール処理部分は、一つひとつ、理解しながら進めてもらいましたが、乱数生成による条件分岐のところや、ボールの跳ね返りの処理（360-ボールの向き）の部分が、なぜこのようなスクリプトになるのかわからないと言うことで説明しました。納得してもらいましたが、念の為、次回は、この部分の理解の確認から始めて、ボール処理すべての部分をきちんと理解度を確認しながら、何かアレンジ等するか、別の新しいスキルをするか考えたいと思います。', null, 'タイピング: 長時間集中していました。準1級と出ていました'),
  ('b8ff0cb1-1d06-53a2-adcd-04c35b3b9e8e', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-09-12', '17:30:00', null, '通常 / ロブロックスで新しいスキルを身につける', 'レッスン初めの時間、他の生徒の対応に時間を取られる中、ひたすら湊太君と一緒になってロブロックスのゲームを遊んでいました（ロブロックスを一緒に遊ぶような人を近くの席に配置しないように考えた方が良いと思いました）。一度この状態になると、なかなか終わらないので、晴くんについては、レッスン最初に要監視で、初めに何か一つのスキルを挑戦してもらう、覚えてもらった後に、遊んでいいよと約束した上で、レッスンを始めるようにしなきゃいけないかなと思いました。次回からは、何か一つのスキルを覚える、もしくは、デジタねの何か一つの確認テストをやってもらう等のことを最初にして、わからないところを教えて、知識やスキル習得できた上で、そのスキルを使ったオリジナル制作を促す方向でいきたいと思います。', null, null),
  ('61461112-412d-56b3-9596-a13955e2dce7', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-09-12', '17:30:00', null, '振替 / ロブロックス', '晴くんが近くに座っていて、レッスン前からロブロックス談義に夢中になってしまい、二人で同じロブロックスのゲームを遊んでばかりでした。他の生徒につきっきりになる状態だったため、湊太くんの対応が疎かになってしまったのですが、何度「デジタねを始めて」といっても言うことを聞かない状態でした。結局、本来今日やるべきだった、レッツショッピングをほとんど進められませんでした。ロブロックスを一緒に遊んでしまうような生徒とは 席を離すなどした方が良いと強く思いました。今日全然進められなかった分、次回は、しっかりと進めるように促して欲しいです。', null, null),
  ('9c350493-0399-54c4-ba88-b5b4f935ae66', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-09-12', null, null, '通常 / Roblox', 'デジタネ動画を集中して試聴して進めていました。途中何度か声をかけても「大丈夫」と言うことで逆に質問がなく少し心配しましたが、途中で、りょうやくんから、Roblox studio上で、X,Y、Z座標の判断の仕方について質問を受けて説明しました。ちょっとした質問を投げかけても、しっかり理解しているようでしたので、よかったです。この調子で、続けていけば良いかと思います。', null, '時間帯: その他'),
  ('ec1a78f2-d6d4-5394-8058-98c771907372', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-09-12', null, null, '通常 / Roblox', '最初に、前回前々回の２つのレッスンの確認テストが終わっていなかったようなので、そのテストをしてもらいました。特に問題なく正解できていて、きちんと理解できているようです。その上で、魔法のレンガブロックを始めてもらいました。途中何回か進捗確認や、簡単な理解度の質問をしてみたりしましたが、問題なく進められていたようです。黙々と自力で進められているようです。', null, '時間帯: その他'),
  ('42d13e4a-14aa-567f-a1c3-315a7483e5ea', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-09-13', null, null, '通常 / Roblox', '前回検定の１級問題だったので、今日はロブロックスの続きを実施。今日はハラハラピンボールを最初から順調に進めていたようです。進捗率は３０％程で、スピードは速いとは言えないですが、時折理解度の確認等してもしっかり答えて理解しているようですので、問題なく進めていると思います。', null, '時間帯: その他'),
  ('84a00beb-debe-5e7e-979a-501f0920f1ac', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-09-13', null, null, 'Roblox', '前回のレインボーロードの続き、前回からだいぶ時間が経っており、きちんと覚えているか少し心配でしたが、応用課題を一つこなして、確認問題に挑戦したら、１００％できちんと理解しているようでした。その後、コロコロボーリングを始めて、途中で終了となりました。時々、声かけをしましたが、特に問題なく、自走できていました。', null, '時間帯: その他'),
  ('11f78d49-b509-5c24-94a1-0939b2a3e86b', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-09-13', null, null, '通常 / Roblox', 'Robloxのログインが、パスワード一致しないのかうまくできず、IT自由研究室のアカウントで進めることにしました。そうするとコロコロボーリングの途中までのデータがないので、私が、急いでレッスン途中の状態のものをそれなりに作って、そこから始めてもらいました。特に質問もなく自走できて、確認問題も１００％でしっかり理解できているようで、時間が少し余っていたので、ブロックをスクリプトから透明にする（Transparency=01とか0.5とか）という、追加の小ネタ知識を教えて今日は終わりとなりました。問題なく進められています。', null, '時間帯: その他'),
  ('1750ce1d-5c27-5672-88ca-669c48750bc0', 'ec153bd8-5b4d-5684-9704-382af23cf64a', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-09-13', null, null, '通常 / 検定慣れ', '検定の形式に慣れるために練習しました。独特な問題文もだんだん読み込めるようになって、大部分は自力でできていました。抜け漏れのあったスキルは、セリフを消す方法程度でした。ただ、「自分が相手に勝ったなら」のとても難しい部分は一旦飛ばして終わってしまったので、次回時間があれば一緒に紙に書いて整理しながらできるとよいと思います。', null, '時間帯: その他'),
  ('427fa1ef-05f1-581f-a2e8-b4b22daaa56e', '82396ac6-71bd-59d4-a372-57212866fd5d', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-09-13', null, null, '通常 / prg', '木のスクロールの作成から再開しました。x座標を動かすので、「最初の座標はどこか？」「座標がどうなるまで移動し続けるか？」を問いかけながらやったところおおまかにイメージできていたようでした。また、速さを乱数で決めるので、その意味を理解してもらいつつ、乱数の範囲を好きな数値に調整してもらいました。中途半端なところで終わるのは嫌だったようで、レッスン終了後10分くらい粘って完成までこぎつけると達成感を感じていました。', null, '時間帯: その他'),
  ('f68f634b-cc5b-5de2-997c-99fa6dc20833', '49fc73e4-fc37-5c75-a77f-02a27f5e169b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-09-13', null, null, '通常 / prg', '若干ふざけたモードながらもレッスンはしっかりやってくれて、「こんなブロック知らないよ」と言いながらすぐにそれを見つけたりしていました。新しい要素として「スプライトの他のスクリプトを止める」や「画像効果をなくす」を、意味を説明しながら扱いました。そのブロックが2回目に出てきたときは記憶に残っていたようでした。また、あるブロックを繰り返しの中に入れるか外に置くかを一度間違えたりもしましたが、よく観察するとすぐにおかしい場所がわかったようでした。適度に休憩を取りながら作成を進めて完成しました。', null, '時間帯: その他'),
  ('2b8db9cb-121f-5232-bee7-a47226ba049e', '28d52d6e-7571-5090-a2d9-492c997b719e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-09-13', null, null, '通常 / 変数、演算', '続きからやりました。ゲームの仕様を自分で考えたいと言って、一度でも取れなかったらゲームオーバーにする案などが出ましたが、結局プレイ難易度が難しいので30点取ったらクリアにしようということになりました。肝心の「スコア=〇なら」というコードはほぼ自力で作れて、スキル的には余裕そうでした。ゲームクリアの背景も自作して、オリジナルのゲームとして完成しました。', null, '時間帯: その他'),
  ('640dcdae-19c5-5466-97b1-4442ac073c33', '40a476bc-72a5-5bdc-ab75-e89d5310b442', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-09-13', null, null, '初回レッスン', '初めてのレッスンということですが、2024年の大晦日からスクラッチを始めて、ゲームも作ったことがあるということで、まずは②基本操作コース_0211「名前を動かそう」の通りに作ってもらおうと、様子見していましたが、こちらからどのブロックを使うとか指示しなくても、どんどん一人で知っているブロックを使って、こちらのお願いした通りの動きを実現させていました。ただ、もちろんまだ知らないブロックも多いようで、スプライトを動かすにしても、何通りもやり方があるということを説明したら、「そんなやり方もあるんだ」と感心していました。次に、基本操作コース_04「追跡ゲーム」を作ってもらうことにしました。これも、こちらのやって欲しいことを伝えたら、自分のわかっているやり方で、実現させていました。一部ちょっと無理矢理なスクリプトになってはいましたが、それなりにできていましたし、スコア処理時に、自分から「じゃあ変数を使う」と言うふうに言ったり、アレンジで、スコアが５点になったらゲームクリアの文字を表示させようと言ったら、メッセージを使って実現させることをわかっていたようで、ある程度の基礎はすでにできていると感じました。基礎はできていると言っても、まだ、知らないブロックもあるので、次回以降で、基礎レッスンをささっと通しで終わらせられたらと思います。', null, '時間帯: その他
タイピング: まだ小２ということでキーの位置をきちんと把握しているわけではありませんでしたが、ホームポジションに指を置いていたので、家でそれなりに教わったりしているのかな？というのがうかがえます'),
  ('2b789a03-3e60-528e-8c9c-384cbb8ad07f', '5b56509a-ab37-5b95-9b2b-2750525ad8a5', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-09-13', null, null, '通常 / U16作品作り', '前半は黙々と集中していましたが、後半で思い通りに動かない部分があると言うことでヘルプを求められました。背景色以外の色に触れたかどうかをチェックする処理を作りたいとのことでしたが、私もコウ君も、簡単な方法が思い浮かばず、背景以外の色全部を一つ一つ接触判定するしかないのかなと言うことで、ある定義の中で、ループ処理でそれを実装したら、ゲームに耐えられないくらい処理が重たくなってしまいました。このループ処理で、こんなに重たくなる理由がわからず、そもそも、定義が大量に何回も何回も呼ばれすぎているとか、スクリプトの詳細を細かくみないと原因が掴めそうになく、本日中の解決はできませんでした。りゅうとくんの作品はだいぶボリュームもありスクリプトも複雑なので、それなりに、スクリプトを時間をかけてしっかりとみないとなかなか対応できないかも知れず、一つ一つの質問の対応に時間がかかりそうな気がします。→何処かのタイミングでしっかりとスクリプトをみないといけませんね。', null, '時間帯: その他'),
  ('0a710d7a-b923-5bd7-809b-8a6c2cb091ac', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-09-13', null, null, '通常 / Roblox', 'いつものように、ある時間まで少し遊んで、時間になったらRoblox StudioをやりますとのことでRobloXのゲームをしていました。２０分経って、Roblox Studioを立ち上げて、新しい動画未来へジャンプを見始めてくれました。ただ、こちらが目を離しているすきに、ゲームに戻ったりしていたようですが、レッスンしている時の集中力は凄くて、未来へジャンプの進捗率は９０％くらいで、あと少しで完了できそうなところまで一気にできました。', null, '時間帯: その他'),
  ('da3e3c1c-a24d-5748-8a0d-219dc7c22a8a', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-09-15', '16:30:00', null, '通常 / プラットフォーマーゲームの基礎スキル', '前回ジャンプゲームを作成したとのことだったため，今回はその復習も兼ねてプラットフォーマーゲームの基礎スキルのジャンプと横スクロールについてやっていきました．そのうちロブロックスもやっていきたいとのことでしたので，この内容についてはしっかりと理解していく必要があると感じました．ジャンプについては，前回やっていた内容の発展形であったため，それほど苦労することなく座標がどのように扱われているのかについて理解することができていました．横スクロールについては，見えている画面の向こう側についてのことを初めて考えたようなので少し戸惑っていましたが，実際に作成していった際に次の背景がどのように配置されているのかについて答えることができていました．', null, null),
  ('51815624-b792-5481-b474-112dcbc5971e', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-09-15', '17:30:00', null, '通常 / Excel２級練習問題', '２級の実技練習問題２に挑戦していきました．運送会社のデータが問題内容ということで少し複雑なものであったにも関わらず全問正解で終えることができていました．時間としても40分ほどで終えることができていたため，非常に早いペースで進めていくことができていました．次回模擬テストを実施していき本番を想定したもので進めていき，より詳細な実力を測っていきます．', '模擬テスト実施', null),
  ('9c160b84-b9dd-53e5-a42a-3b060152a113', '337872be-4ce4-5436-88f8-5f97e8c5252e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-09-13', null, null, '振替 / 新しい作品作成に取り組む', '特に行き詰まることもなく、淡々と最後まで作成していました。 ただ、出来上がった時点でりんごが表示されず、裏で音だけなっているような状態になり、困惑していました。 丁寧に手順書と照らし合わせてみましたが、間違いが発見できませんでした…', null, '時間帯: その他
タイピング: 二段を記録しました！
盛り上がり: これまで作成したことのないタイプのゲームだったので、興味を持って取り組むことができていました。'),
  ('68cbce14-bc89-5973-a413-1d45d32d9c03', '5b56509a-ab37-5b95-9b2b-2750525ad8a5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-09-16', '17:30:00', null, '振替 / 大会準備', 'プレイヤーがステージに置いたブロックについて、「自分のすぐ上に別のブロックがないとき、プレイヤーが落ちないように足場を広げる」という処理の作り方に困っているそうでした。ブロックの座標を記録したリストの内容を全てチェックしていく方法を提案しました。それを実装してくれて一応動きましたが、場合によっては想定通りの挙動にならないことがありました。動いてほしいブロックがきちんと動いているかどうかを確かめるために、その場所で音を鳴らすなどといったというデバッグのテクニックを伝えて実践してもらいました。しかし完全にはバグが解消しなかったので次回そこからになりそうです。(私も該当コードをじっくり読んでおきます) また、ゲームの動作が全体的に重いのでコードの改善が必要かと思いました(毎回マップをペンで描画しなおすところが重そう？)が、使うパソコンのスペックがそれなりに高い場合そうでもなさそうでした。', null, null),
  ('3cfd93bd-14ef-50fc-8127-1e4a30ca8f6d', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-09-16', '16:30:00', null, '通常 / 複数の変数の扱い', '高度な変数の練習として取り組みました。難易度を表す変数「むずかしさ」や、フラグ変数「押された」が出てきたので、どういう変数かを問いかけると、「こういうときに0、こういうときに1」と説明してくれて、整理できているようでした。ボタンが押されると明るさを変える演出を作ったときには、お手本のゲームをもう一回見て、実際にそうなっていることを納得して進めてました。以前やった「ではないまで待つ」があったので、なぜそれを使うのか復習したところ、頑張って記憶から引っ張りだしていました。次回は続き(タコの動き)からになりそうです。', null, null),
  ('cea76e27-a280-5c3b-ae84-0f77176e46fc', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-09-16', '16:30:00', null, '通常 / 身に付けたスキルを活用して新しいアレンジを考える', '1から作るよりはアレンジが好き、というので、1年以上前に作成した自分の作品から好きなものを選んで、新しい知識を使ってアレンジをしてみるよう促しました。 新規の教材や検定よりはハードルが低かったのか、あまり抵抗なく、過去作品をいろいろと探し始めてくれました。 いろいろ開いては目移りしていたので、こちらから、こういう系統のものが好きなのでは？とカミナリゲームを提示しました。 30分くらい、いろいろいじって完成としていました。', null, '盛り上がり: 昔の自分にツッコミを入れたりしながら、それなりに楽しそうでした。'),
  ('fb459000-f9f3-5c62-9c98-39c0a6b6206f', '337872be-4ce4-5436-88f8-5f97e8c5252e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-09-16', '17:30:00', null, '通常 / 色々なタイプの作品に慣れる', 'しゅんかん記憶ゲームについては、バグが見つからなかったため保留とさせてもらいました。（正解のコードをバックパックから持ってくると動くが、変数名と定義の引数ブロックを壮太くんが作成したものに入れ替えると動かない。） 過去問では、ハンバーガーの問題が面白そうというので取り組んでもらいました。 文字列をつなげる「りんごとばなな」ブロックを知らなかったとのことなので、説明しました。すぐに理解できたようでした。 正解がカウントされないのと、問題が1問限りになるバグがありましたが、コスチューム番号が5の時、という条件式の「5」がタイプミスしていたのと、問題を出すコードに「ずっと」がなかったことが原因でした。どちらもどのコードが怪しいか特定すると、自分で解決ができていました。バグの探し方について、どのスクリプトまでが動いているか、メッセージを受け取ったスクリプトが動いていない場合は、そのメッセージを送ったスクリプトに戻って確認するなどの検証方法を一緒にやってみました。', null, 'タイピング: 今日の最高記録は初段でした。
盛り上がり: 時間内に完成できて、スッキリしたようでした。'),
  ('61344820-9d4a-50d8-860c-d0f413f58b99', '1c7005cc-2815-558f-993a-9c7617d34c44', null, 'd45d6c5d-18cd-5aa2-99ea-932c81442c55', '2025-09-16', '16:30:00', null, '通常 / 条件分岐や変数の使い方を学習する', 'ピンポンゲームの作成の続きを行いました。変数を使用してスコアのカウントを行う部分はよく理解していました。ボールの最初の位置とクリア画面になった時パドルとボールが画面から隠れるように自分で考えて設定しました。（榊原）', null, '盛り上がり: 完成したゲームを嬉しそうに見せてくれました。スタンプも喜んで押していました。（大原）
備考: お母さんが、決勝大会の配信を見ます！とおっしゃってました。（大原）'),
  ('f9fb0e72-2c69-50f8-be56-1621e2f21e4f', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'd45d6c5d-18cd-5aa2-99ea-932c81442c55', '2025-09-16', '17:30:00', null, '通常 / 座標を中心としたコードの見直しをする', '剣の位置がずれていたのでお手本のコードと見比べながら修正をしました。残った時間で剣やりんごの見た目を変更しました。剣の定義が1番難しかったと言っていたので定義を中心に練習できるといいと思いました。（榊原）', null, 'タイピング: 準1級は出せるようになりました
盛り上がり: 残り時間の見た目のアレンジを楽しそうにやっていました。色使いが鮮やかで、オリジナリティーが出せていました。（大原）'),
  ('c2b346da-a40f-5f58-ad96-c6545f6cbe3d', '0d16e234-e60d-5fdb-978f-1722acf9a2b2', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-09-18', '16:30:00', null, '通常 / チーズを探せアレンジ', 'チーズを探せを続きをやっていきました。チーズを大好きなコーラちゃんに変えていきました。ネットから画像を取り込む方法を覚えて、別に要らない画像を取り込む横道があったが、、それだけで満足したのか、、後の時間は、ふらつきが多かったです。猫の動きを動きやすくしたりする？と提案してみても、「いや」と言いてやってくれない場合が多かったです。さいきんは、いやといいつつもやるときはやってくれることが増えてきたのですが、次回は1週空くので、最初から新しいことを提示した方が進めやすいと思います。', null, '盛り上がり: 今日のふらつき癖が多かったです。特に、3人でアメのある裏側に入ろうとしていたので、注意しても戻る気がなかったので、体ごとで引き戻しました。'),
  ('1ef71913-08e0-552a-9215-965dfe8c880c', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-09-18', '16:30:00', null, '通常 / 花火作成', '花火のアートを作成していきました。天順所のデザインに少し気に入らなかったのか少し自分でリデザインして楽しんでいました。背景も星空にお月様を添加して、加賀谷氏くなっていました。ペンツールの使用もありましたが、特に迷うことなく完成形に持ってくることができました。', null, null),
  ('cc394c03-781c-50a8-9b11-d9de71263593', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-09-18', '17:30:00', null, '通常 / ジャンプゲームの基礎を作ろう', '久しぶりに基本操作コースに戻り、ジャンピングゲームを作成しました。やりながら、座標の感覚が備わっているか確認していきました。まずは、ジャンプがどのような座標な変化か尋ねると、ｙが上がって下がると答えてくれました。そこからコード作成に移ると、下がるポイントで手が止まってしまいました。下がるわけだから、逆の動きととらえると、ヒントを出したら、マイナスをつけてくれました。ほかの初期位置や触れる判定はスムーズに用意することができました。コスとして、Ｇをよういして、たまごはＧのたまごに置き換えて、大変気持ち悪い作品が出来上がりました。本人も引きながら楽しんでいました。', null, null),
  ('9d133871-16ce-5944-a394-c95900e13e0b', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-09-18', '17:30:00', null, '通常 / 大会作品作り', '前回のスキップの対処をまず取り掛かりました。スキップを押したのにそのまま続いてしまうことがあったので、詳しくヒアリングをするとスキップのシーンを動かすコードだけではなく、すでに動いているコードを止める必要がありました。なので、「ほかのスプリクトを止める」を助言してあげたら、うまくかみ合いました。その後、オプションシーンをつけてゲーム説明を加えて、ゲームを深さを出していました。肝心のゲームの表現の仕方として、奥行きがある感じにしたいとのことだったが、1人称支店七日、フンツノみたいの遠近感がある感じにしたいのか、ふわふわしていたので、次回を底をまとめていきたいです。', null, null),
  ('2b6b9c9f-fe3d-560a-a821-ed9ea2a48b24', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-09-18', '16:30:00', null, '通常 / 作り始めた作品を投げ出さないで仕上げる努力をする', '授業開始直後は、新しいことがやりたいといって、Scratchでほかのポケポケの作品を開いて遊び始めてしまいました。こういうのが作りたいんだと言いながらしばらく遊んでいましたが、ちょっと厳しめに、この作品を自力で作れるのか、そうでないなら、遊びたいゲームと、教室で授業で作るゲームは別、という話をしてみました。思ったよりも素直に、それならこの前の続きをやる、といって作成に戻ってくれました。 途中、飴を食べに行ったり、虎太朗くんや朔太郎くんのPCをのぞいたりとふらふらもしましたが、カードの封を切るためのスプライトの大きさや位置を何度も試しながら調整したり、新しいカードを増やしたりと、制作時間もそれなりにとることができました。 封を切るスプライトが袋の後ろに隠れてしまう不具合を、「最前面に移動する」で解決したときはちょっと感動していました。', null, '盛り上がり: 鬼滅の刃の絵をネット上から拾ってきた甲斐があって、見た目は本物っぽいゲームができたことが、とても得意そうでした。'),
  ('0e6b717b-20ac-50aa-b0d9-b843f79cf2bc', '57f45872-1f3e-5540-b676-bf9023444e39', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-09-18', '16:30:00', null, '通常 / 作成している作品に集中する', 'これをまねして作りたい、とScratchから取り込んだプロスピのゲームで、しばらく楽しそうに遊んでいましたが、タイトルを変えただけで「これで完成」と言い始めたので…さすがにそれでは許容できないこと、好きな作品を授業で扱いたいなら、それを使って「これを学んだ」というものが必要なことを話しました。それはわかるけど、何をしたらいいのかわからない、下手にアレンジしてゲームが動かなくなるのは嫌だ、とのことなので、一緒にアイディアを話し合い、400枚あるカードのうち、最初の50枚の中から特にレアなカード2枚を作って、それが出たら特別演出をする、コードを作成することにしました。 最初の50枚、というところは、さすがに自分で乱数のブロックを探して変更することができました。特別カードは2枚選んでいたので、コスチューム番号のブロックと、「または」のブロックの学習をしました。 特別演出のところで、メッセージを送って待つ、とゆうれい効果の学習をしました。 一応新しいブロックの学習ができたので、最近の中では比較的授業らしくなったかと…。', '動作確認ができていないので、そこから。', '盛り上がり: 野球選手について、とにかく熱心に語っていました。お迎えのお父さんにも、「プロスピを作っている」と自慢していました。'),
  ('78793e10-dcc8-5894-a8c6-69f2e72f18a2', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-09-13', null, null, '通常 / イラストを活用した作品作りをする', 'アルくんが持っている銃から弾丸が飛んで、恐竜にあてるゲームを作成していました。 イラストが上手なのでそれを活用してオリジナル性を出したいね、と伝えると、とても熱心にコスチュームをいじっていました。 当初はアルくんと銃のスプライトを別にしていましたが、コードで銃を持っているようにするのが難しかったらしく、スプライト同士を一緒にできないかと質問があったので、コスチューム上ですべてを選択→コピー＆ペーストを教えました。 弾丸が飛ぶところまでは自力で作成していましたが、変数の処理や当たり判定などまでには手が回らなかったようでした。', 'アルくんと恐竜の動き、当たり判定、変数の処理を作成して、ゲームを完成させてください。', '時間帯: その他
盛り上がり: コスチュームの編集のときに教えたショートカットキー（Ctrl+a、c、v）に感動していました。'),
  ('43389dfc-288b-524a-90b0-3c953196fcdb', '655ad2c9-dfb5-5fc7-b41a-1d784603c1d0', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-09-13', null, null, '通常 / ゲーム作りを通して基本スキルを学ぶ', 'これまでよりも上級っぽいゲームに興味をもってくれたのか、作成前には何度もゲームプレイを繰り返していました。ボールの加速度がついて、すぐに壁にあたってしまうのを本気で悔しがったりと、とても楽しんでいたようでした。 説明動画もこまめにストップと再生を繰り返し、必要なときは少し戻したりして、きちんと自分で進めようとする姿勢が見られました。', '鍵のコードの途中から、続きを作成', '時間帯: その他
タイピング: とてもよく頑張っています！
盛り上がり: 初めて遊ぶタイプのゲームだったようで、とても面白がってくれました。'),
  ('45dde0b1-14f2-556b-bfde-6c487a10e51a', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-09-13', null, null, '通常 / 学んだブロックを組み合わせて使用することに慣れる', '来室時はいつも通りでしたが、席に着いて授業を始めた直後、パッと解決できないものがあってストレスを感じたのか、そこからしばらく、椅子に座ったままずっと体を上下にゆすり続け、「うーうーうー」と言った声を出し続ける感じの常同行動のようなものが見られました。声は、意図的に出していたのか、身体の振動とともに漏れてしまっていたのかは不明ですが、声をかけても視線がまったく合わず、一点を見たままで、上記の行動が止められない様子でした。 まずは落ち着いてもらおうと、足元に置いていたシャチくんを触ってもいいか尋ねましたが、やはり視線が合わず、返事の言葉も出せないようだったので、意識してゆっくりと話しかけ、「抱っこさせてね」と声をかけながらシャチくんを持ってきて、1号くんか2号くんか尋ねると、そこで初めて返事をしてくれて、そこから少しずつ目が合うようになり、シャチくんについて説明してくれるようになりました。少し落ち着いてきて、シャチくんをPCの向こう側に立てかけてこちらを見るようにしたあたりで、身体の揺れが収まりました。 その後は徐々に普通通りに戻っていき、会話も成立させながら素直にPCに向かうことができました。今日の場合、やろうと思っていることは明確なのに、そのためのブロックが見つけられなくてパニックになったのかもしれません。落ち着いてからも、ブロックが見つからないと、少しイラっとした様子を見せることはありましたが、焦らせずに「一緒に考えよう」と声をかけると少し落ち着いて、答えを聞かなくても自分で考えることができました。 後半は熱心に作成に向き合えていて、ジャンプのコードの数値を細かく調整したりと、少しでも楽しいゲームにしようとする意欲が見られました。背景なども、自分で工夫して熱心に描いていました。（でも、ミャクミャクというと怒ります💦）', 'ジャンプゲームとして遊べるところまで完成していますが、この後ゲームオーバーなどを作りこむかどうか、本人の意思次第で…', '時間帯: その他
盛り上がり: 落ち着いてからは、作成への意欲もしっかりと出て、こうしたらもっとよくなる、とどんどんアイディアを出しながら熱心に作成していました。'),
  ('bf5b11cf-0a95-5dca-b767-94bde8e68ed7', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-09-19', '16:30:00', null, '通常 / 横スクロール＆バスケ', '前回、横スクロールがわからなかったので、既存のコードを見ながら作っていきました。一応図解で説明をしてみましたが、ふーんと流された気がします。ですが、背景を増やしていった時の説明も交えたら、流れの仕組みが理解してくれました。これを使ってオリジナルなげーむをつくってほしかったが、作ることなくタイピングへ一度移りました。 別のprgゲームを提案していく中で、バスケゲームがよさそうになり、オリジナルで作っていきました。横向きの２Dの形で作り、ボールには放物ジャンプのコードを生かせていました。ただ、そのままだとボールのはずみの減衰がないので、そこをうまく作っていくことを次回の目標にしました。', null, 'タイピング: 授業の途中からやり始めました。'),
  ('91cf46f7-2940-566d-900b-e376361bd280', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-09-19', '17:30:00', null, '通常 / Robloxで新しいスキルを身につける', 'いつものように、レッスン開始前からRobloxのゲームをし続けていたので、今日はまず何かスキルを身につけてから自由時間にしようというと、自発的にRobloxStudioを立ち上げて、新しいゲームを作り始めてくれました。ここで、シンプルなPartを作成して、そのPartのプロパティ（色変更・位置移動・透明度変更・接触可能フラグ等々）をスクリプトから操作する方法を教える計画だったのですが、その計画に乗ってくれず、ひたすら自分の作りたいゲーム作成をしていました。ツールボックスから、Slapモデル（ボタン押下でNPCや他プレイヤを引っ叩くアイテムのようなもの）を導入して、対戦ゲームのようなものを作りたいと、NPCも大量にゲーム世界に配置していました。このままではレッスンにならないので、Slapモデルの中のscriptを開いてもらって、そのscript内のそれっぽい名前の変数の値を変更することで、相手を引っ叩いた時のダメージ量をコントロールしたり、相手を吹っ飛ばす量を変えたりして、スクリプトを変更することで色々と自分のやりたいことを実現できると言うことを実感してもらい、本人もこう言うものを作りたいんだと興味を持ってくれました。今日はそのSlapモデル内のscriptがどんなことをしているか、初見ですが自分のわかる限りのことを説明して、変数をいじるくらいしかできませんでしたが、今日のレッスンはずっとこのスクリプトに集中してくれていました。これがきっかけで、きちんとスクリプト作成を基礎から学んで欲しいところですが、、、。次回以降、本当に基礎的なスクリプト作成から教えられたらと思います。', null, null),
  ('2a411730-65cd-5eb0-aea9-33880aa4dd09', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-09-19', '17:30:00', null, '通常 / カギとゴールの判定を作ろう', '今回は、最初にカギの変数を1ずつ取れるようにする、ゴールの判定を作るようにするを目標を伝えて始めました。鍵の判定が色判定で多段ヒットするようになっていたので、ボールの触る判定を提案していきました。自分がやっていない感を出さないために、提案の形で進めたら気持ちよく進められることができました。元の中途半端にできたコードも整理も大事とほめ進めることで無駄のコードを省くこと自分でできていました。自ら作るろうとするときは、先頭が旗が押されたらになるので、メッセージを使う場面は、サポートしていきました。鍵がそろう場面では、変数と＝の結ぶ関係には慣れた手つきで作っていました。最後、微妙にゴールのセリフのメッセージの部分が急ぎ足になったので、もう一度振り返ってから次のステージに進めてください。', null, null),
  ('1086242c-d7f7-5c80-894e-d28d0f1bdd66', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-09-19', '17:30:00', null, '通常 / U16作品制作', 'エクセルとU16作品作りどちらか聞いた上で、U16がいいとのことで、U16のオリジナル作品作り。今日のレッスン最初に聞いた話を共有すると、ゲームの全体構想はできていて、現状の完成率は３０％程度とのこと。レッスン中は、質問もなく、順調に黙々と進めていました。そろそろ、裏でスクリプトを見たりして、こちらから気になるところを質問したりするのも良いかなと思います。', null, null),
  ('b0f90b0b-a042-5f44-a716-0dc7bc96234f', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-09-19', null, null, '通常 / エクセル', '以前は、エクセルの回でも、エクセルを少しやってからロブロックスをやりたいと言っていたのが、最近は、エクセルだけで良いと言うふうになっていまして、以前に比べてロブロックス熱がさめたのかなと、ちょっと感じています。デジタネの進め方だと、最初の方はプログラミングをいじる量が少ないので、もしかしたら飽きがきやすいのかな、、、と思ったり。本人にこの点を聞いたわけではないので推測ですが。 今日のエクセルレッスン自体は、黙々と一人で質問なしで自走していました。', null, '時間帯: その他'),
  ('5416ded3-b6bd-5d05-a712-357cd351d3f4', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-09-19', null, null, '通常 / Roblox', '未来へジャンプの途中から。何度か状況確認しながら進めましたが、質問もなく、自走して完了させることができました。最後に、自分で色々とアレンジをしていましたが、その時に、ちょっとしたRobloxStudioの使い方で質問があった程度で、順調に進められていると思います。', null, '時間帯: その他'),
  ('0b29ad4f-8b18-5021-9aca-2cadbb27c1c7', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-09-19', '18:40:00', null, '通常 / エクセル', '様々なグラフの作成が中心でした。グラフの体裁を整える際に、グラフをいちいち選択しして選びづらそうだったので、右横のプロパティから選択できることを伝えてあげました。', null, null),
  ('3f64cced-5de1-53b8-841e-0d7fc5db3edc', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-09-19', '18:40:00', null, '通常 / エクセル', '円グラフの演習が多めでしたが、問題なく取り組むことができました。印刷の関連での質問があり、設定方法などを教えました。', null, null),
  ('a70c82d4-e88b-595b-abbb-bf42afc8ddb5', 'd3885e29-ee68-501b-bf31-6c050fd50c36', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-09-19', '16:30:00', null, '通常 / 基本スキルの習得', '前回アレンジしたキューブの戦いが気になるようでしたが、「前々回のゲームが完成したら戻ってこようか」と伝えるとスムーズに始められました。現状の動きを観察すると、クリアのメッセージを受け取ったときの動きが何回もやっていておかしいと自分で気づけていたので、そのメッセージの送り主を確認するように促しました。そこのコードにあった全角数字がバグの原因だとわかり、きちんと動くようにできました。 その後はキューブの戦いを続けました。体力が100を切った時に一度だけ50回復する、という効果をつけたいとのことで一緒にやりました。そこで必要な変数の不等式や「ずつかえる」に関しては使いこなせていました。テストプレイした時に、何回でも体力回復してしまうバグの対処法がわからなかったようなので、そのスクリプトを止めればいいことをヒントとして伝えると納得して直せました。', null, '盛り上がり: 作業中はいつもよりも集中していてよかったのですが、なぜか教室の外でお友達が待っていたようで、ときどき様子を気にしたり話しに行ったりしていました...'),
  ('d30eb7a3-ea0f-5a41-870d-a7324b7ea60b', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-09-19', '17:30:00', null, '通常 / ピンポンゲームの仕組みの理解', 'カウントダウンの出てくる順番がおかしいバグから直しました。コードを時系列で一緒に確認すると、コスチュームの名前を間違えて指定していたことがわかりました。 前回は写経しただけだったので、内容をしっかり押さえました。速度をだんだんはやくするためには変数を使えばいいという話をしたり、「360-向き」度を向くと跳ね返ることを具体的な数字で確認したりしました。その後はアレンジで、敵を強くしてみました。敵の動くしくみがよくわかっていなかったようなので、「何秒かかけてマウスの座標についていく」ことをイメージしてもらったところ、その秒数を減らせばいいことを理解していました。その他にも、視界を邪魔するリスが途中で現れるようにもして完成しました。', null, null),
  ('fd30a882-a843-5570-a2b5-aeffbb66d4dd', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-09-19', '18:40:00', null, '通常 / 大会準備', 'ゲームオーバー時に不要なスプライトが残ってしまったり、タイマーが止まらないというバグから修正しました。ゲームオーバー時にメッセージを送って「隠す→他のスクリプトを止める」ことで解決しました。 その後はテストプレイをしながら、「旗を押さなくても自動的に再挑戦できるようにしたい」「正解不正解が音でわかったほうがいい」というように改善点を見つけて実現していきました。一通りアイデアが出尽くして作成が終わると、もう完成としてもいいくらいになりました。', null, null),
  ('a9740c1f-bd17-57f8-92a1-135802cd61ca', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-09-19', '18:40:00', null, '通常 / プラットフォーマースキルの活用', '前回のジャンプや横スクロールを復習したあと、それらを使った簡単なオリジナル作品の作成に入りました。カエルを家に帰せのような「キャラクターの動きに応じた横スクロール」を作っている時間まではなかったため、前回の自動横スクロールをそのまま活用して作りました。自分で描いたキャラクターたちを使い、迫ってくるオオカミをジャンプでよけるというゲームにしました。そこで必要なオオカミのx座標の動きや「～に触れた」について、多少のサポートは要りましたが自分で理解して考えながら作れました。', null, null),
  ('315a0197-1398-51a7-8bb5-ceb1789dc457', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-09-13', null, null, '通常 / 親子大会決勝用のスライドを作成する', 'PowerPointは未経験で、Googleスライドではだめなの？と言っていましたが、大会のほうでPowerPoint推奨なことを話すと、あっさり納得していました。実際にPowerPointを起動すると、初めて使う！と興味津々で、デザインのテーマやバリエーションを選ぶのを楽しんでいました。 文章は保護者の方から送ってくれていたので、その文章をスライドとノートに貼り付けた上で、悠豊くんがスライドに残す言葉を選んで、見やすく編集していく形で作業を進めました。 さすがにスライド作成ばかりでは飽きてしまうようで、ちょくちょくアルスタジオをいじったり、泰徳くんの作品に手を出したりと、気分転換をしていました。', '途中まで作成したものをComiruのお問い合わせから保護者宛に送ってあり、自宅で編集した分を次回までに送りなおしてもらう予定です。次回はこちらを使用して仕上げてください。', '時間帯: その他
盛り上がり: 今日はPowerPointとアルスタジオと、気を惹かれるものが複数あって集中力が分散しがちではありましたが、どれも楽しそうに取り組めていました。'),
  ('68aa6896-0de3-5e56-bfd1-3c5c01ad2330', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-09-18', '17:30:00', null, '通常 / U16大会作品の作成', 'Excelは久しぶりであまり覚えていない、と言いつつも、グラフ作成まではスムーズにできていました。軸の反転と最大項目の選択については、問題の意味がわからなくて手が止まってしまったようで、軸の書式設定を出すところから一緒にやりました。グラフの問題では、基本的には出題対象の書式設定を表示し、該当する項目を探すという手順を納得できたようでした。 残り時間はU16大会作品の作成を進めていました。どうしても会話部分に力が入ってしまうと言っていて、作成していてもそこが一番楽しいようなのですが、そこだけ作りこんでも同じようなコードばかりになってアピール力が弱い、ということも自覚できているようで、会話部分はほどほどにして、この後作りこんでいきたいところを語ってくれました。自分でやるべきことがわかっているようなので、もう少しこのまま本人に任せて進めさせてみようと思います。', null, 'タイピング: 今日は省略していましたが、帰りがけに毎パソの確認をすると、やってみようかな、と前向きでした。
盛り上がり: 作品の全体像が前回より固まってきたようで、作っていきたいところを熱心に語っていました。'),
  ('cb25bb0c-0463-50d7-8477-753e69e3b33f', '31feac25-f850-5d21-8e43-ed4d7badb6a0', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-09-20', null, null, '通常 / 変数の使い方を増やそう', '変数の使い方を増やすために、レースゲームを使っていきました。試遊の段階で、このゲームは面白いと存分に楽しんでくれたので、作成のやる気が高かったです。今回は、動きの中に変数が存在する形でしたが、まずマウスのクリックの有無で変数の値が変わる仕組みを作り、遊んでみたが動かない事態でした。そこで、まだ動きのコードを使っていないことを気づかせると、変数との対応関係に感動していました。そして、色判定についてスポイトで選んで不安定さをなくす方法を教えてあげました。順調に作りあがり、ライバルとのスピード倍速になるバグがあったが、複製の際に作りすぎてしまったことを自分で気づけて授業時間少し過ぎで大方出来上がりました。タイマーのコードが時間がなくそこだけで来ていないので、それが終わったら次でお願いします。', null, '時間帯: その他'),
  ('c0b2755e-a4fc-593a-be27-99137133aa93', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-09-20', null, null, '通常 / 検定２級に慣れる', '若干遅れて来たのでレッスン時間は短かったですが、検定２級②の問題を解いて、終わらせたようです。が、ゲームの動きをみると、ジャンケンでプレイヤーが勝っているのに、あなたの負けとでたりと、動きがおかしいようです。細かくはみれていませんが、ちょこちょことミスがありました。この検定で難しい部分は、じゃんけんの勝負判定処理（xxかつxxの入れ子部分）で、この部分のスクリプトはきちんとできているようですが、なんか動きが怪しいので、それ以外の部分で間違いがあるのかと思います、、、。いずれにせよ、全体的に６割〜７割くらいはできているかなと言う感じでした。もう少し、日本語をきちんと読み込んで凡ミスのようなものを減らしていけたらと。', null, '時間帯: その他'),
  ('70ffbf12-1d94-5146-a9d5-51fb3bb2796b', '82396ac6-71bd-59d4-a372-57212866fd5d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-09-20', null, null, '通常 / 変数の使い方を増やそう', '前半は前回まで作っていたジャンプゲームのアレンジを取り組んでいました。BGMをつけたり、スライムの効果をこだわりをさらに極めたり、凝っていました。前回でほぼ完成をしていたので、次の作品を移りたい感じでしたが、30分くらいまでは取り組めていました。 後半に、アイテム脱出を作っていました。滑りの感覚がある動きを変数を用いて表現すること説明しても、特に抵抗感がなく、始められました。「縦の速さ」「横の速さ」とwasdキーで変数を動かしたいとことも、座標の±と上下左右の関係が完全に理解していたので、変数でも迷うことなく時間をかけて作ることができました。次回は鍵の判定からです、', null, '時間帯: その他
タイピング: ノーミスで仕上げていました。'),
  ('9aa99f9f-d3ca-5ee7-b653-fc35230d0f28', '655ad2c9-dfb5-5fc7-b41a-1d784603c1d0', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-09-20', null, null, '通常 / 基本スキルを学ぶ', '鍵の判定からゴール判定をメインに作っていきました。細やかな作業もコードを作っては試し作業を作る癖が上手に働いていました。ただ、ゴール判定のところで、何度も試しても直せないバグがあったので様子を聞きました。ゴールのコスが1つではなく別々のスプライトで起動していたため、バグ発生していました。そこは動画と見比べで解消できたが、 まだ残っていたので、コスの名前に着目してもらいました。移行前のコードのコスの名前がそのままになっていて存在しない名前になっていてバグが起こっていたので、ややこしい詳細を伝えずに、名前を付ける癖をつけるよう伝えました。このゲーム自体がかなり好きそうなので、集中して取り組んでいます。', '続き', '時間帯: その他
タイピング: 今日はあまり調子がよくなく早めに切り上げました。'),
  ('f44df477-acb4-5ecd-be8a-46f3e104c866', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-09-20', '16:30:00', null, '振替 / 大会作品制作＆プレゼン資料の確認', '授業時間は、中央本線の車両など電車の種類が増えて細部をこだわっていました。授業時間後はお父さんとともに幸先生がプレゼン資料の確認をしていました。アピールポイントでどのようなことを伝えればよいのか、ゲーム画面の録画方法などプレゼン資料に関することを共有していました。', null, null),
  ('12522bc6-2bf7-557b-a16e-b07bb860fc12', '49fc73e4-fc37-5c75-a77f-02a27f5e169b', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-09-20', null, null, '通常 / 動画教材に集中して自走する', '初めての動画ベースの教材でした。初めのうちは、どうすれば良いのかわからず集中できない感じでしたが、動画音声を大きく聞こえやすくして、この動画の声をきちんと聞いてやっていることを真似するだけだよと伝えて、なんとか進められるようになりました。横目で見ていた感じ、動画を見ながら自走する時も、先生が教える時とあまり変わらず、集中が途切れやすく、動画の内容とは別のことを事を進めたりと言う事が、結構な頻度で見られました。遠回りで進みはゆっくりでしたが、ちょっとだけ自分なりにアレンジを加えて、このレッスンを完了させることができました。', null, '時間帯: その他'),
  ('b8682042-532d-52d9-979c-166b2875e678', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-09-20', null, null, '通常 / U16作品作り', '今日はU16作品作りをして、次回はエクセルをやりたいとの自己申告があり、その通りにしました。いつも通り、レッスン中は、黙々集中して、自走していました。次回はエクセルでお願いします。', null, '時間帯: その他'),
  ('10e3daa0-4220-53f5-9eae-3a46f3728556', '5b56509a-ab37-5b95-9b2b-2750525ad8a5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-09-20', null, null, '通常 / 大会準備', '作ったコースをプレイしようとするとラグがひどくなる問題を解決していきました。大規模なバグ直しをする際には作品を違うバージョンとして複製するなど、管理を丁寧にしていました。原因の探り方を自分で考え、怪しいスクリプトを片っ端から外したり、メッセージが何回も送られていないか確認したりしていきました。最終的には、ブロック定義で「再描画せずに実行」をしていたことで実行の回数が増えすぎていたことが原因だと突き止めました。コース上を移動するときにキャラクターが上下に揺れてしまうことを宿題として持って帰っていました。', null, '時間帯: その他'),
  ('4c28d740-a81f-556d-b50c-0ed10d60a73b', '40a476bc-72a5-5bdc-ab75-e89d5310b442', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-09-20', null, null, '通常 / 基本スキルのチェック', '簡単なジャンプの方法については、何もアドバイスなしでは、Y座標をプラスして行って宙に浮かぶまではOKでしたが、着地処理が作れず惜しかったですが、きちんと教えて理解してくれました。このジャンプ処理を作る際に、ジャンプ処理を定義を使って作ろうとするなど、少し、一歩先ゆくものを見せてくれましたが、一方で、基礎の抜けがあるのも感じました。レッスン中に、敵が自分に迫ってきて触れたらゲームオーバー。触れずに画面右端まで辿り着いたらゲームクリアするという、ミニゲーム的なものを完成させました。 それなりの基礎スキルは持っているので、次回は、検定を受けるみるよう提案して、検定４級の類問等進めてはどうかと思います。これで、日本語通りにスクリプトを組み立てる検定なれと、基礎の抜けもれをカバーできるのではと思います。', null, '時間帯: その他'),
  ('f0893fca-fd2d-5890-b87a-ffc2665a7c1f', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-09-20', null, null, '通常 / 検定1級のためのスキル習得', '検定に出るブロック定義やリストの習得のため、瞬間記憶当てゲームに取り組みました。リスト関係のブロックはあまり迷うことなく使えていましたが、内容をきちんと理解できているかは少し怪しい様子でした。理解度を確認しようとしたところ、複雑なブロックの作成作業に一旦集中したい様子を見せていました。そのため次回以降、キリのいい所で内容確認を挟みたいところです。', null, '時間帯: その他'),
  ('a568b195-746e-5195-bc8c-9704b472a930', 'ec153bd8-5b4d-5684-9704-382af23cf64a', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-09-20', null, null, '通常 / 検定練習', '前回の問題で難しい部分(勝敗判定)を飛ばしていたのでそこからやりました。手を数字で表す変数「自分の手」のしくみを復習し、勝利の全パターンを紙に書きだしてもらいました。そこまでできると、「かつ」や「または」の入れ子を作るところにはつまづかずにその部分が完成しました。全体を答え合わせしたところ、変数を変えるブロックで「～にする」とすべきところを「～ずつ変える」として間違えた部分がありました。[どういう問題文だと、「～ずつ変える」ブロックを使うという指示になるのか？]と気になったようなので、他の問題文も照らし合わせたところ納得したようでした。 その後は、検定まで時間の余裕もあるので一旦prgに移る予定でした。しかし本人から、制限時間に解き終われなかったりスキルが不足していたりという不安を早めに解消しておきたいという希望がありました。そのため今回も新しい問題に取り組みました。文章中に乱数が入っているなど少し複雑な指示になったときに、誤読したりヘルプを求めたりしましたが、前よりは慣れてきています。また今回は制限時間にほぼ間に合い、少し自信がついた様子でした。', null, '時間帯: その他'),
  ('b8297581-c76f-5cee-8be7-a3dfb51d7a58', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-09-20', null, null, '通常 / ゲーム完成', '以前イライラ迷路のゲームが途中だったというので続きからやりました。ステージの背景番号や、等号の条件式などのスキルについて内容を確認しながら進めました。コースを細くしてみたり、ボールを手裏剣にしてみたりアレンジもして終わりました。', null, '時間帯: その他'),
  ('2527c0bf-efa0-56aa-b831-b57365ed4460', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-09-20', null, null, '通常 / 跳ね返りの動き', '基本操作コースでもやった「パドルのx座標をマウスのx座標にする」は、復習としてきちんと思い出せていました。また、「(変数)歩動かす」のように、速度を変数で制御するという考え方をつかみながら作っていきました。ボールを壁とパドルで跳ね返すところまでできました。前回はわからないことがあったときにイライラしてしまいましたが、今回は少し難しい部分があっても落ち着いた様子で進められました。', null, '時間帯: その他'),
  ('6dfc2732-0d96-58ee-8974-9dd6d53e4b99', 'e22d8f70-f1a1-5ca4-9ed4-4d27cb0e164f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-09-22', '16:30:00', null, '通常 / スロットマシーン完成', '前回のスロットの順止めの仕組みの復習からはいいりました。メッセージのやり取りをかろうじて覚えていた程度でした。「ほかのスプリクトを止める」に関してはすっぽ抜けていたので、再度説明しました。メインとして、数がそろったときの条件について考えていきました。同じものをそろえる時にはどのようなものを使っていたか質問すると、＝に関しては出てきました。数字の表示は何で変化しているかに着目して考えてもらっても、ピンと来ていませんでした。なので、コードを見ながら考えてもらうと、時間をかけてコスチュームだとわかりました。そこからはコス＃の使い方を教えて条件を作りました。３つ＝で結ぶ必要があったが、＝を2使えばよいことは自ら気づけていました。そろった時のあるくんの音や見た目を変えて、完成することができました。', null, null),
  ('a2a75420-41f9-5dfc-9d45-033fc90e4795', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-09-22', '17:30:00', null, '通常 / エクセル2級模擬練習', '時間内に、問題はすべて解け、わからなかった問題はなかったそうです。答え合わせはできなかったが、自宅でするそうです。模擬問題２も自宅で解いて練習を積みます。次回がエクセル練習最後です。', '模擬問題③', null),
  ('23cd1702-4e05-5622-a68d-0cc6d4946284', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-09-22', '17:30:00', null, '通常 / ロブロックス GUI', '今日は5分オーバーくらいで始めてくれました。この単元は前々から情報量が多いと伝えていたので、しっかり動画に向き合ってくれました。GUIの導入なので、保存先やコード場所の種類が異なっており、操作が迷う場面が何度か見られました。また、変数の定義づけの際にアルファベットの大文字小文字の混同が見られ、バグが発生していました。ちゃんと動画を見変えて名前つけを気を付けるように伝えました。ここらの単元は情報量が多いので、2，3パートずつ進めるそうです。', null, null),
  ('2f54619b-cef2-55f5-b482-811ebb09c2d0', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-09-27', null, null, '通常 / リストや定義を使いこなそう', '前回の順番通りにクリックしていく条件が作りかけだったので、続きをやっていきました。リストや変数、座標が含まれる複雑な条件になっていたので、作り終えたところで、どんな条件を作っていたか確認をしました。リストの活用なところが説明あやふやだったが、全体の趣旨の条件は把握できていました。その後は、順番通りにクリックする動作が1通り出来上がると、それで疲れたのか仕組みをわかったうえで、リンゴを無限に増産させるバグなどで遊んでいました。定義の引数の形もできていたので、そこは大丈夫そうです。残りは、レベルアップの作り終えたら完成です。', null, '時間帯: その他
タイピング: 簡単なところをやるならブラインドタッチを進めてみました'),
  ('1084e15b-f44c-5908-a6c9-5f4077ac6368', '655ad2c9-dfb5-5fc7-b41a-1d784603c1d0', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-09-27', null, null, '通常 / 変数のスキルアップ', '前回の続きで、ゴールしたら次のステージに行けるようにする処理のところから。集中してほぼ自力で完成させることができました。（動画をみながらですが）終わってからアレンジをしてみようと言うことで、最初に、経過時間を表示させるように追加しました。その次に、時間が経つごとに、操作するボールが少しずつ大きくなっていく処理を組み込み時間となりました。順調に変数のスキルを伸ばせたと思います。 また、検定について話をしてみましたが、興味があるかどうかは本人はまだわからないという感じでした。ただ、受ける分には全然問題ないと言う感じだったので、４級受験を親に提案する形で良いかなと思います', null, '時間帯: その他
タイピング: 集中して何回も挑戦していました。'),
  ('81f61f09-6393-56f8-ba5c-6530d9781ded', '31feac25-f850-5d21-8e43-ed4d7badb6a0', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-09-27', '16:30:00', null, '通常 / ジャンピングゲーム', 'ジャンピングゲームを作っていきましたが、ちひろくん的には簡単にできるパートでした。ジャンプの型のコードも自ら作れていました。障害物のコードで、繰り返し右から左に動く動作では、条件として、「端に触れたら」を使っていて、動かないバグが起こっていました。そこで、座標を使った不等号の条件のやり方を教えると、すぐに正しく左端の座標の位置で設定することができました。そのまま、音やスコアの変数をつけ、完成することができました。音の場面で、当たった時と音がずれてしまうバグがありました。ここでは、「とめる」のコードをの種類を場所に応じて使いわけることをおしえてあげました。 新しいことを知ると、喜んで作業が進んでいくのですごく楽しんでそうです。コードの種類の知識を増やすために、コード探求のゲームがよさそう', null, null),
  ('d7eef827-aca9-54d1-880f-868c491b4bc1', '49fc73e4-fc37-5c75-a77f-02a27f5e169b', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-09-27', null, null, '自走する力をつける', '動画で説明されたやるべきことを、きちんと終わらせて自走できたと思います。何か処理を追加するたびに、スプライトをすごい大きくしたり、動きをめちゃくちゃ早くしたりと、かなり脱線しながらだったのでだいぶ時間はかかりましたが。何か脱線するたびに、これすごいでしょとか面白いでしょと言うふうに、見てもらいたくてその都度声をかけてくれました。楽しく完了できたようです。', null, '時間帯: その他'),
  ('56bf4bf4-8f6b-54b9-be23-0a7fc3dc253c', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-09-27', '16:30:00', null, '通常 / 2級練習', '前回やった2級2回目の振り返りをやっていきました。じゃんけんの条件を振り返ったうえで、まだバグが残っていたので、1つずつコードを見直していきました。そこで発覚したので、コードを地続きになっている場面が何個か見られました。もしの条件が、直列につなげるだけなのに中に続ていてしまったり、新しく先頭のぶっろくを用意するところを繋げてしまったりなどです。読み方として、①の跡があるなら続ける、ないなら新しく作るコツを教えてあげました。 そこで、やった応用課題1は、上記のミスが1か所だけに収まったので、回数を重ねていけば、少なくなると思います。また、修正の個所が修正前のコードがそのまま残されていることもあったので、元あるコードから直すよう教えてあげました。', null, null),
  ('693695d4-e151-55b6-9856-abd2e2cbfb62', '40a476bc-72a5-5bdc-ab75-e89d5310b442', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-09-27', null, null, '通常 / 新しいスキルを身につける', 'レッスン前から、自分でスクラッチをいじって何か作っていたようで、スクラッチのやる気と集中力はすごいあると思います。今回はキャッチゲームということで、ゲームの全体像を説明して、やるべきことを細分化して、一つずつ進めてもらいました。やるべきことのスクリプトを書いてもらう際に、自分でどんどん進めていき、１ランク上のレベルのスクリプトを作っていてすごいと思いました。ですが、まわりくどい処理になっていたり（メッセージ使わなくても実現できるのに、メッセージを使ったり）、お願いしていないこともどんどん進めていくので、覚えてほしいブロックの理解を飛ばしたり、（ネガティブな意見ではありませんが）レッスンが思い通りに進みにくい傾向があります。その辺を気をつけながら、今後のレッスンを進めていく必要があると感じます。', null, '時間帯: その他'),
  ('68c97b67-7071-5234-9444-d454224ea174', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-09-27', null, null, '通常 / 変数の使い方', '先週のイライラ迷路を軽く復習したあと、以前最初だけしかできていなかった脱出ゲームを続けました。速度を変数で調整するという考え方を学びながら進めました。ボールの縦の速さと横の速さが紛らわしかったようですが、「今は縦と横のどちらが動いているのか？」を考えさせると整理できたようでした。ボールが動くところまでできました。', null, '時間帯: その他'),
  ('89cff9f3-a04e-5f28-9f1d-4195f8148a63', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-09-27', null, null, '通常 / 跳ね返り処理など', '前回跳ね返り処理がうまくいっていなかったのですが、向きを変えるブロックを入れ忘れていたことが原因でした。跳ね返りの処理のメインは向きの変更だということを確認して続きをやりました。ただ、途中から、アレンジのアイデアを考えたりそのための音を追加したりしていました。まずはアレンジ抜きでの完成を目指したいことを伝えながら進めていきました。', null, '時間帯: その他'),
  ('ea90ddb6-f105-55d4-8511-007391376052', 'ec153bd8-5b4d-5684-9704-382af23cf64a', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-09-27', null, null, '通常 / 検定復習、スキルアップ', '前回の検定問題の答え合わせがまだだったのでそこからやりました。動かない部分があったというので確認したところ、全角半角の概念を初めて知ったようで、全角数字になていたところを修正しました。(タイピングはやや不慣れだと言っていましたが検定練習で徐々に慣れてきています。)しかしそれ以外のミスは軽いケアレスミスくらいだったので、本人も前より検定に対して自信がついて不安は減ってきたようでした。 その後はprgに入りました。お手本ゲームを見た段階で、鳥の上下移動と回転、ビルの横スクロールを作ればいいと細分化できていました。速度を変数で制御する考え方を学びつつ、鳥の動きまでは終わりました。お手本ゲームにはキーの長押しを防止する機能がないのですが、いい学習機会なので、次回「ではないまで待つ」を追加できるとよいと思います。', null, '時間帯: その他'),
  ('19649531-ac76-59bc-8121-4f961c78e250', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-09-27', null, null, '通常 / ロブロックス', '相変わらず教室にくるなりロブロックスのゲームに夢中で、レッスンを始める時間を決めて、進めてもらいました。まずは、「未来へジャンプ」「憧れのマイハウス」の確認テストがまだ終わっていなかったので、そのテストから。時間が空いているからということもあり、忘れてしまったこと、わかっていなかったことを再確認して教えました。座標を変更するときは、X座標のみではなく、３次元座標（x,y,z）をまとめて変更する必要があることだったり、スクリプトを綺麗に書く方法等々。その後は、「ペットを育てよう」を終わらせたようですが、確認テストまでは完了できていないようです。お願いしたのは、その前の「運試しの橋」を終わらせることだったのですが、スキップしてしまったようなので、次回は、ペットを育てようの確認テストをしてから、運試しの端をすれば良いと思います。', null, '時間帯: その他'),
  ('418e036a-01c4-58f2-8a8a-5582c1bbd14c', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-09-27', null, null, '通常 / プログラミング大会決勝の準備', '明日決勝大会ということで、プレゼン練習をしたいとのことだったので、プレゼンをみんなの前で実施。パワポ内の動画が再生されないという問題以外は、特に大きな問題もなく、中身も基本的には問題ない感じでした。準備していた、カンペにちょっと修正や手を加えたりしました。明日プレゼンしなくちゃいけない状況ですが、不安を感じさせず堂々としていて良いと思いました。良い結果になると良いですね。', null, '時間帯: その他'),
  ('53c84a63-c8bc-5fb8-8865-30331caa888e', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-09-27', null, null, '通常 / 変数の活用になれよう', '最初は水泳ゲームを作ろうとしたら、水泳嫌いとのことだったので、別のスポーツゲームを探したら、サッカーゲームを作ることになりました。試遊の段階で、アレンジの候補が何個も出てきていたので作るやる気は高まっていました。スコア以外にも変数があることから変数苦手のグチが出てしまいましたが、動画を見ながら作成していきました。今回は猫の動きの部分でしたが、ボールの動きについて、歩数の部分のコードは共通しているが、相手やゴールの触れた判定で変数スピードそれぞれ異なるきれいにまとまっている構造を理解できればいいと思います。', 'つづき', '時間帯: その他'),
  ('7555dd52-df2e-51a3-8772-95c4b39bdbda', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-09-22', '17:30:00', null, '通常 / 大会作品制作', '今回はデザイン面ではなくプログラム部分を黙々と作成していました．作りたいものは頭の中で完成しているとのことなので，このまま順調にいけば次回か2回後には完成まで持っていけるとのことでした．最後の仕上げに向けてぜひ頑張って欲しいです．', null, null),
  ('500e5da3-c093-514d-8740-b577ca01c518', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-09-28', '16:30:00', null, '通常 / 放物ジャンプと背景スクロール', '前回ジャンプゲームをやっていったとのことで，今回はロブロックスに入っていくための練習の１つとして，放物ジャンプと背景スクロールについて学んでいきました．先週に勇作くんが挑戦していた内容ということもあって，自分もすぐに追いつきたいとのことで気合が入っていました．座標に対しての理解や変数を用いての調整についてもしっかりと理解することができていました．しかし，1回やっただけなので定着しているかは曖昧なところなため，1度覚えているのかについて確認を入れても良いと感じました．', null, null),
  ('0e1c1142-67ee-57e8-aead-4a1881316161', '5e1dea40-5c67-55ca-a3d8-e696d9b49163', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-09-22', '17:30:00', null, '通常 / 検定４級模擬問題１', 'ロボットから5週間で検定の４級を取りたいとのことで今回授業に来てくれました．検定を初めて触ったようなので，問題の解き方のコツや何を聞かれているのかについて理解が追いついていない様子でした．そのため，まずはどのブロックがどこにあるのかをある程度覚えてから検定問題に取り組んでいく必要があると感じました．短い期間での検定となるため，いつもより詰め込んで教えていく必要があると感じました．', null, null),
  ('229f1e2f-4e56-55ac-beec-f334f9d5b93a', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-09-18', '17:30:00', null, '通常 / 演算式の使い方に慣れる', 'ドリル形式はそれなりに楽しいようで、熱心に作成しては「できました」と報告にきていました。完成例を見てコードを細分化して考えるのも、少しずつ慣れてきたようです。 G-3以降のカエルゲームで、コスチュームの番号をしらべるコードにとまどっていましたが、教えるとすぐに理解できたようでした。', null, 'タイピング: 熱心に練習していました
盛り上がり: ドリルが順調に進んでいるのがうれしいのか、毎回意気揚々と報告してくれていました。'),
  ('2229fb77-2263-54dd-87df-5c4436886b10', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-09-18', '17:30:00', null, '通常 / U16大会作品の作成', 'いつものように、ひっきりなしにおしゃべりはしていましたが、それなりに作品の進行も考えているようで、何度か質問をしてきていました。 ゲームのオプションとして、武将図鑑を入れることを思いついたようで、さっそくそちらの作成にも取り掛かっていました。武将についてゲーム内で語れるのがうれしいようでした。', null, '盛り上がり: 武将図鑑を思いついたことがうれしかったようで、どんなふうに作っていきたいのか、楽しそうにしゃべっていました。'),
  ('0b3e36eb-b6a7-5e02-a626-afacadf65e10', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, null, '2025-09-30', '17:30:00', null, '休み（未対象）', null, null, null),
  ('a3f915d8-a33e-5fd8-b434-6b4a27ae56dd', 'f3102a36-fdd8-574f-bf3c-85723faf424f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-09-22', '16:30:00', null, '通常 / 【体験】', '2年生くらいから、独学で本を見ながら作成していたそう。ジャンプゲームやジオメトリーダッシュは見本なしでその場で作成できるレベル。定義やクローンはかなり使い慣れている感じで、定義の引数も使っている。単元別演習G-1をやらせたら、その場で作成して、空中にいくつかブロックを置く余裕もあり。アレンジ対象のカフェゲームは面白がってプレイしたが、アレンジというと、すぐには思いつかなかったよう。【小技】弾幕東方シューティング風 02 基礎編で、角度や発射速度のアレンジをいくつか試した後、自キャラを作成し、さらにバリアを張れるようにアレンジした。かなり楽しんでやれたよう。1時間半くらい、熱心にやっていた。妹さん（しほちゃん）は年長で、ドット絵を描いたりブロックで遊園地を作ったりしていた。そろばんをやっているそう。 作成したゲーム2つをアルスタジオに保存済み。', null, null),
  ('4c4a0276-6cc4-5b4c-add0-702949ef735c', '1c7005cc-2815-558f-993a-9c7617d34c44', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-09-30', '16:30:00', null, '通常 / 基礎スキル習得', 'アルスタジオで一つずつ完成例を見せ、何のブロックをどう使えばいいか考えてもらいながら進めました。座標についての理解は少しずつ身についてきている様子でした。 「10回繰り返す」の中に音を鳴らすブロックを入れてしまったときは、一回だけ鳴らすように促すと、ブロックを外に出すことができました。ときどきスプライトで遊んでしまうこともありましたが、スタンプを押すことをモチベーションに中盤まで終えられました。', null, null),
  ('106df5ae-b017-50d6-aecc-4225fe72bfbb', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-09-30', '17:30:00', null, '通常 / 検定練習', 'わからなかったら一旦飛ばす戦略でやってもらったところ、だいたいの部分は自走して最後までいけました。途中で集中力が切れてしまったようなので、10分ほど休憩を入れるとまた集中が復活しました。わからなかった部分は、長い文を読み解くところや、「～のコスチューム名/番号」などの見慣れないブロックでした。長い文については、言葉のまとまりを丸で囲んでシンプルに理解することを促すとわかったようでした。ただ少しだけ終わらなかった部分があるので、次回の最初にやってもいいかもしれません。', null, 'タイピング: ミスも少なめで安定してきています'),
  ('25b767e5-120f-567e-8782-0b5195596f9a', '337872be-4ce4-5436-88f8-5f97e8c5252e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-09-30', '17:30:00', null, '通常 / スキルアップ', 'U16大会のスケジュールを説明したうえで参加の意思を確認すると、今年はやらないとのことでした。スキルアップとして、prg後半から興味を持ったピンポンゲームに取り組みました。乱数を絡ませながら角度を変更してボールを跳ね返らせる、相手のパドルをボールに自動追従させる、クローンで残像を作る、といったスキルを確認しつつ進めました。詰まったポイントもあまりなく、きちんと動作するものが完成できました。次回は、同じ教材で和田そうすけくんがやったように、同じ処理をブロック定義でまとめるという学習をしてもいいかもしれません。', null, null),
  ('28304fb2-63d6-5dec-832f-ec33993f76e3', '05439956-11b9-5ac7-a44a-3e6f5a6831d8', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-09-30', '16:30:00', null, '振替 / U16大会作品の作成', '選抜大会の作品提出は昨日終わったとのことで、U13大会作品の作成を熱心に進めていました。 行き詰まると、立ち上がって作業する傾向があるかも？ 自分から質問しにくる、というよりは、立ち上がって作業したり、机のそばで立ち尽くしたりするので、声をかけると、「実はここが…」と話してくれる感じでした。 メニューの選択ボタンの一つがうまく動いていないところは、自分で強引に解決した、とのことでした。 シミュレーションゲームをスタートすると、ウイルスや細胞が初期値の倍の数出てくるバグについては、実行中のスクリプトが点灯するはずのところが、何度か点滅していることを指摘しました。一緒に検証したところ、スペースキーが押されたときに「スタート」メッセージが送られるはずのところが、スペースキーを少しでも長押しするとメッセージが何度も送られてしまい、そのたびにスクリプトが実行されて数が2倍、3倍となっていくことが判明しました。長押しを防止するために、キーが押されたではないまで待つ、を併用することを勧めました。あとは自分で、「スペースキーが押されたまで繰り返す」を使用していたところを、「まで待つ」に修正して繰り返しはほかのスクリプトで制御するよう、作り替えていました。', null, '盛り上がり: 作品はだいぶ形が見えてきているようで、作品内容の各ウイルスの特徴などについても、熱心に説明してくれました。 バグが何点か直すことができて、満足そうに見えました。
備考: グランプリの賞金の一部を投資に使うんだと言っていました！'),
  ('097f9bea-779f-5776-9e3a-76ce3da6b16e', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-09-30', '16:30:00', null, '通常 / ブロック定義の活用に慣れる', '親子大会の最終選考ノミネートのお祝いをいうと、音がうるさい作品なのに、なんでこれが通ったのかわからない、審査員が変わってたのかも、などとつぶやきながらも、ちょっと嬉しそうでした。該当箇所の動画を見てみたいというので見せたところ、少し照れていました。 今日はブロック定義に慣れることが目的というのを説明してから、大会作品のコードを見直して、まとめられそうなところがあるかを探させて、ブロック定義にまとめていきました。定義の作り方と使い方は、最初はヒントが必要でしたが、そのあとは自分で3か所、定義を使ってシンプルなコードに書き換えることができました。 ここまで30分ちょっとで終了し、気が抜けてしまったのか、残り時間は「今日はニュースを見る」といって、ひたすらニュースサイトを見ていました。 歴史関係のニュースを見ていたので少し雑談をし、戦国時代が好きという話をしました。', null, '盛り上がり: 自分の作品をよりよく作り替える、というのは、わりと前向きに取り組んでくれました。そのあとの電池切れも早かったですが…💦'),
  ('f9d626f4-715d-5ae5-aa36-eb634dc274bf', '0d16e234-e60d-5fdb-978f-1722acf9a2b2', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-10-02', '16:30:00', null, '通常 / ピンポンゲーム', '最初は気がそれて遊んでばっかでした。お絵描きをしたり、鬼滅の刃のキャラを勝手に検索したり、うろちょろしてました。そこで、ピンポンゲームの背景にして、取り入れてやるように仕向けたら、コードの方に移ってくれました。ボールが跳ね回る動きに関して、単純なので一から作れるか試したものの、頭は遊びモードでコードの知識が全く動いていなかったです。なので、コードを写経させて、ボールとバー（刀）の動きを作りました。そこで、刀がボールを跳ね返させないバグが見て、コードへのやる気は高まっていたが、時間が来て終わりになりました。作り始めの０から1への導線全然進んでいかないので、少し用意したけど、作ってないからバグはある状態から進めていった方がやる気は引き出せそう泣きがします。', null, '盛り上がり: 背景にはいとこが好きな無一郎を選んでくれました。'),
  ('2a526412-e8c0-5004-a2af-3349783d60cf', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-10-02', '16:30:00', null, '通常 / 大会作品つくり', '初めに提出期限まで残り回数を確認しました。今日含めて3回までに完成を周知してもらいました。今回は水辺からバケツで水をくみ、火災の場所にかける動きを作っていました。水をかける回数制限を変数を組み込んで条件をたてられていました。また、水汲みも色判定でバケツの回数をリセットできる仕組みも出来上がっていました。うまく変数を活用してクオリティが高いものができています。授業後もあと2回なら完成できると余裕を持った発言をしていました。', null, null),
  ('fb62a807-2a90-56a8-9dd4-d07c5919276c', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-02', '16:30:00', null, '通常 / とにかく完成させる', 'とにかく作品を投げ出さないで最後まで取り組む練習として続きに取り組みました。コードはほとんど全部できているはずなのにカードの袋が開封できないバグがありました。「どこのスプライトの話？」「そのメッセージはちゃんと送られてる？」などと問いかけることで原因を探るように促しました。結果としては、切り取り線のパーツの数を自分で変えたのに、コード上の設定では変わっていなかったことが原因だったので修正しました。きちんと動いたので、残りの時間は、サムネの背景を変えたり新しいレアカードを追加したりとアレンジし、無事完成しました。', null, null),
  ('ade3c854-3607-548e-b574-3dba16edfe0f', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-02', '17:30:00', null, '通常 / 基本操作の習得、自分で考えて作成する', 'まず遊んでもらい、ざっくり細分化してから始めました。赤りんごと金りんごで点数が違うことに気付いていなかったので、スコアをよく観察してもらうと気づいていました。x座標とy座標の区別や変え方はしっかり理解していました。乱数が絡むなど少し複雑になると迷っていましたが、軽く誘導すれば作れるくらいでした。不等式は慣れていないようだったので丁寧にやりました。繰り返しの範囲を間違えたときは、どこまで繰り返せばよいかを問いかけるとできたので、構造を理解することはできているようでした。スタンプを押しながら中盤まで進められました。', null, null),
  ('b455f164-d51f-57a6-931d-095db6788c36', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-02', '17:30:00', null, '通常 / 大会準備', '作りたい部分がまだたくさん残っているようで、忙しく作成していました。アピールポイントから順に作ってプレゼンで使えるように促しました。戦が始まる時に、リストを使って指定した武将を出現させて動かす処理などを作っていました。途中、武将のデザインの参考にするために画像を調べたりもしていました。', null, null),
  ('3b1d35eb-6b12-5617-a384-d2de1770027b', '57f45872-1f3e-5540-b676-bf9023444e39', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-10-02', '16:30:00', null, '通常 / 作り始めた作品をしっかり仕上げる', '野球に関連することだからか、作品を作る気はあったようでした。 立ち歩きはいつも通り多かったですが、席についたときは、作品を見ようとする姿勢はありました。ただ、前回まで動いていた自分の作品が全く動かなくなっていて、しばらく一緒にコードの見直しなどをしましたが、コスチュームが選手400名以上分あるせいか、動きがとにかく重くて、少しスクロールをはやくすると、すぐに固まってしまうのが4～5回続いた時点でやる気が失せてしまいました💦 もともとのScratchの作品自体に余分なコードなどが多かったので、不要なスプライトやコードなどを少し一緒にチェックして、残りは次回ということにしました。 次回は動きがスムーズだった「ミント」PCを使う予定です。', '「ミント」PCを使って、特別演出の見直し', 'タイピング: タイピングコンテストの練習を勧めてみましたが、タイピングは普段からやっているので大丈夫、とのことでした
盛り上がり: 野球に関してはとても熱心なので、作品として完成させたいとは話していました。'),
  ('001192e6-b341-5715-9cd6-7a967e7edad9', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-10-02', '17:30:00', null, '通常 / ドリルの知識をまとめよう', '前回までドリルを多く取り組んだことから、それらをまとめ上げるようにタコから逃げろを作っていきました。まず、ボタンの難易度を決めることろでは、難易度ごとに変数を変えればよいというところまで気づけていましたが、「難しさ」だけでなく「押された」まで変えようとしていました。一番下につった「おされた＝１」の意味を考えてもらって、自分だけで難しさの変数だけでいいと気づきました。その後は順調に進めていき、タコの強さの条件について、複雑すぎないと？？と疑問を投げかけ、疲れていました。「2000年から日数」のいもの日ごとで違う乱数と説明してあげました。何度もタコと戦ってくれました。', null, null),
  ('fcc893c8-b891-562e-ab10-c0ac1526aad9', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-02', '16:30:00', null, '通常 / クローンとペン', 'クローンとペンの使い方に慣れるために取り組みました。あまり困ることもなく各ブロックを使いこなしていました。色を段々変えてみたり、スライダーで変数をいじれるようにしたりという細かいスキルも扱えました。デザイン的なアレンジはやはり好きなようで、暗い道でどくろがうずまきを作っているという少しホラーな世界観にしていました。', null, null),
  ('b0389e0f-c6a0-50f9-b074-31356d01199a', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-10-02', '17:30:00', null, '通常 / U16大会作品の作成', '締め切り前最後の授業（10/16）はスライド作成に使いたいので、教室での作成は今日を入れてあと2回、というと、ちょっと焦っていました。 自分がアピールしたいところを中心に作成するよう勧めましたが、どうしても、作りこみたいところは同じようなコードのところになりそうとのこと。 今回はコンセプトでアピールしていこうということにすると、ちょっと嬉しそうになって、一生懸命作成を続けていました。', null, '盛り上がり: 自分で突っ込みを入れたりしながらも、楽しそうに作成をしていました。'),
  ('cccb7b61-bb97-5f24-b8d0-bb6097908315', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-10-02', '17:30:00', null, '通常 / U13大会作品の作成', '前回教えてもらったやり方が、その前の授業で教わったことと変わっていたのと、変数が増えたことでかなり混乱してしまったようで、ひかりちゃんが覚えていた当初のやり方に戻す方向で進めました。 変数での管理が難しくてよくわからない、とのことだったので、パーツの移動をメッセージにしたところ、ようやくコードがわかってきたようでした。 セットの変数についても覚えていて、作品所見の先生にきちんと教えてくれました。 途中で眠くなってしまったようで、うとうとしたりもしていましたが、髪型のところはクリアできたので、次回とその次で完成できるようにがんばるとのことでした。', null, '盛り上がり: 髪型とリセットボタンが動くようになったのを喜んでいました。'),
  ('f340202c-4d15-55f7-88b6-ff2534b02163', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-03', '17:30:00', null, '通常 / 変数の練習', '脱出ゲームの続きをしました。前回ボールが滑らかに動いたところまで作ったことを復習し、カギを集められるようにするところからやろうと目標を確認しました。カギの初期位置がおかしかったので、どのカギの何座標が間違っているのか確かめて直してもらいました。最後、1面をクリアしただけなのに2面までクリアした扱いになってしまうバグが現れました。どうすればいいのか見当もつかないという様子だったので、変数の中身が正しいかチェックする方法を伝えました。するとゲーム開始時からステージ番号の変数が2になってしまっていることはわかりましたが、実際の修正は次回になりそうです。これを機に、問題を解決する姿勢を身に着けてほしいところです。', null, null),
  ('66e4de92-3e00-5be2-9151-c24a9ee2d8a9', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-03', '17:30:00', null, '通常 / 変数の練習', '脱出ゲームの続きを取り組みました。前回ボールが滑らかに動いたところまで作ったことを復習し、「りんごとバナナ」ブロックで変数をセリフに入れる仕組みも振り返りました。カギの初期位置がおかしかったので、どのカギの何座標が間違っているのか確かめて直してもらいました。最後、1面をクリアしただけなのに2面までクリアした扱いになってしまうバグが現れました。どうすればいいのか見当もつかないという様子だったので、変数の中身が正しいかチェックする方法を伝えました。するとゲーム開始時からステージ番号の変数が2になってしまっていることはわかりましたが、実際の修正は次回になりそうです。これを機に、問題を解決する姿勢を身に着けてほしいところです。', null, null),
  ('50c449a5-2172-5bb2-8db9-b1dfaa6d06c5', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-03', '17:30:00', null, '通常 / ではないまでまつなど', '鳥の飛行のコントロールに、「とぶ」という変数を使う仕組みを丁寧に扱いました。スペースキーを押すとプラスに、放置するとマイナスになることを確認しました。また、動画にはなかったのですが、キー長押し防止のための「ではないまで待つ」も一緒に作りました。このスキルは初めてのようだったので、キーが離されるまで待つという意味だと覚えてもらいました。中盤まで終わりました。', null, null),
  ('ee82f446-e80d-5384-8cb5-fa784ea778fd', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-03', '18:40:00', null, '通常 / 変数の練習', '試しに遊んでもらったところ、ボールが滑っていることにいち早く注目していたので、「速さに変数を使うと滑る動きが作れる」ということを伝えてから作り始めました。最初は順調にやっていましたが、テストプレイしたときにボールが動かないバグになりました。コードを見なおすように促すと、送るメッセージの名前が間違っていました。こういうバグが起こるとふてくされる癖があるようなので、嫌にならずに原因を探れるようになるとよいと思います。', null, 'タイピング: 毎パソのローマ字の練習は初めてでした。ローマ字入力には慣れていないようでしたが、反復練習しているうちに徐々にできるようになってきました。'),
  ('8a76fecf-8c6d-55dd-843e-8131b29f4854', 'd3885e29-ee68-501b-bf31-6c050fd50c36', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-03', '16:30:00', null, '通常 / 基礎スキルを身につける', 'PRG10レースゲームを作ろうの、動画講義を見せながら進めてみたのですが、ちょっとしたわからないところから、果てしなく脱線してしまい、最終的に他のゲームを始めてしまう。みたいな状態を繰り返してしまい、PRG10の進みはとても遅く、興味も持てないようだったので、前々回やっていたキューブの戦いのアレンジを少し進めました。剣に触れたら体力が減るような仕組みを作っていました。席に座り続けるのも大変だった最初の頃に比べればだいぶ集中してくれるようになった気はするので、それは良いことですが、自走はまだ厳しいかなと感じました。次回は基礎スキルがきちんと身につけられるレッスンを何かしたいところです。', null, null),
  ('c26206fb-fae7-5202-b13a-babfe062ccfa', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-03', '17:30:00', null, '通常 / デジタネで覚えるべきことの復習', 'これまでデジタネ動画に全く興味を示してくれず、面倒くさいやりたくないという状態になるので、晴くんの分かる範囲で自作ロブロックス作成のサポートをしてきたのですが、そもそも、デジタネ動画の確認テスト部分もやっていなかったので、「頂上を目指せ」と「クイズロブロックス」の確認テストをしてもらいました。わからない部分をその場で説明して理解してもらい、その動画の中で覚えてほしい最低限の知識を理解して欲しかったからです。「頂上を目指せ」に関しては特に問題なし。「クイズロブロックス」に関しては、わからない問題が多かったようです。ただ、単なるRoblox studioのツールの使い方等の知識の問題が多く、覚えれば良いだけなので間違っても良いと思いました。が、確認テストを解くときに横で座ってみていたのですが、問題なのは、晴君が、問題をきちんと読み終わる前（というか、おそらくきちんと問題文を理解する前に）にその問題を答えようとしているところです。この姿勢が晴君の状態を表しているなと思ってしまいました。なんとかしたいところです。次回以降、ロブロックスするときは、初めに、終わっていない確認テストを実施して、わからない部分を丁寧に説明していきたいです。', null, null),
  ('6abccd2b-3a93-5b8c-8c51-bb3c23643039', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-03', '17:30:00', null, '通常 / スクラッチ・U13オリジナル作品作り', null, null, null),
  ('f5f0486e-afaf-5248-9ad2-2f18a398f5ed', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-03', null, null, '通常 / ロブロックス', '特に質問もなく、この動画を自走していました。この辺りから、x、y、z座標をスクリプトで変更して動かしたり、変数を利用したりするので、ある程度できる子でも、不明点・モヤモヤする点が出てきてもおかしくないレベルになってくるのではと思います。動画通り作ってれば動くので、深く考えなくても完了できますが、質問がないと逆に、きちんと理解しているのかなーとも思うので、簡単な質問をして、きちんと答えられるか等考えても良いかもしれません。考えてみます。', null, '時間帯: その他'),
  ('dd0ab8a1-73f7-5115-ba0d-6a2b55412d5e', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-03', null, null, '通常 / ロブロックス', '今日はとても疲れていたみたいで、少し寝たいとのことも言われたので、15分近く仮眠をとって、スッキリしてレッスンを継続できました。今日(2025/10/3)の良冶君のところにも書いたのですが、デジタネの魔法のレンガブロックあたりから、スクリプトに書くプログラムの量が増えてきて、この辺がきちんと理解できるかどうかが、今後の動画についていけるかどうかの鍵にもなると思うので、しっかりと理解度を確認しながら進めていきたいです。', null, '時間帯: その他'),
  ('556c82ce-1fb8-5f1f-97be-f2aa43efd0c1', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-04', null, null, '通常 / ロブロックスの続き', '見た目等も気にしながら、見栄えのあるものを作っていました。ピンボールのボールも大量に作って、かなり難易度の高いゲームを作っていました。まだそんなにレベルの高いことを教えているわけではないので、特に質問もなく、順調に自走できていました。', null, '時間帯: その他'),
  ('d0a93924-0c12-52de-912d-f343fa39f59d', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-04', null, null, '通常 / ロブロックスの続き', 'あおし君と一緒のハラハラピンボールでした。そんなにレベルの高いことを教えているわけではないので、特に質問もなく、順調に自走できていたと思います。若干、オブジェクトの作成（滑り台やボールの発射台のようなもの）の作成に時間がかかっているような気もするので、無駄な動きがないかちょっと確認してみて、何か効率の悪い操作をしていたら、アドバイスするのも良いかもしれません。', null, '時間帯: その他'),
  ('38d03d6d-e266-5f2d-9332-2723ad6dc568', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-04', null, null, '通常 / ロブロックスの続き', 'そんなにレベルの高いレッスンではないということもあり、レッスン内容についての質問はありませんでした。ただ、Partの大きさを変えられなくなったとの質問を受けて、「衝突」ボックスにチェックが入っていると、他のオブジェクトとの干渉で、動かせなくなったり、大きさを変えられなくなったりということを説明しました。おそらくデジタネでは教えていないところかもしれませんね。コロコロボーリングはまだ未完成ですが、順調に進んでいるようです。', null, '時間帯: その他'),
  ('57db8713-0ea3-5a33-ba06-007a51f61dc3', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-04', null, null, '通常 / エクセル', '今日はU16でもエクセルでもどちらでも良いとのことで、最近ずっとU16だったので、エクセルをしてもらいました。３０時間の6章・例題１５、実習２７を終わらせました。特に難しいところはなく自走で完了させることができました', null, '時間帯: その他'),
  ('c4cd6029-4365-530a-9f4e-815197536881', '40a476bc-72a5-5bdc-ab75-e89d5310b442', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-04', null, null, '通常 / 新たなスキルを身につける', 'ダルマさんが転んだの音声を、自分の声で取って楽しんでゲームを作っていました。途中で、引っかかることもなく、きちんと理解しながら進めていたと思います。時間内に完了させて、アレンジとして、変数を使って制限時間を設けて、制限時間内に終わらなきゃゲーム終了にする処理を作っていました。', 'まだ検定のようなものに慣れていないので、検定を受けるつもりであれば、一度４級の簡単な問題を解かせるのでも良いかと思います。', '時間帯: その他
タイピング: プレイグラムのaiueofjを何回かやりました。ホームポジションを取っているのですが、キーの場所はまだ覚えていないようで、キー入力はちょっと時間がかかっているので、毎レッスンごとにタイピングをするようにしていく必要アリですね'),
  ('b386e250-c02a-557a-805c-03a2a3e9c7ff', 'ec153bd8-5b4d-5684-9704-382af23cf64a', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-04', null, null, '通常 / 「ではないまでまつ」などスキルアップ', 'まずは前回部分の復習として、2つあるゲームオーバーの条件を整理してもらい続きに入りました。鳥とビルのx座標を比較する不等式では、ビルのほうが左に来ているということを視覚的にイメージできていました。作り終わったあと、動画にはなかった「ではないまで待つ」を取り入れてもらいました。「キーが押されなくなるまで待つ」という処理を再現してほしいと伝えると、使えそうなブロックをほぼ自力で考えながら探してきて組み合わせることができました。印象に残ってスキルとして定着したようでした。 それも終わったあとはアレンジをしました。この前の検定練習で身に着けた、「りんごとバナナ」ブロックでセリフに変数を入れる方法を活用して得意げにしていました。', null, '時間帯: その他'),
  ('7719487c-6a5f-5bc9-af13-09df230e87cb', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-04', null, null, '通常 / 跳ね返り処理', '振り返りとして、パドルがボールを跳ね返すところまではできてブロックを消すところがまだだということを確認してから始めました。ボールがブロックに触れたときの動作について、「跳ね返す」「得点を入れる」「隠す」のように列挙しながら作っていきました。最後まで終わるとアレンジに入り、お得意のホラー系の演出を入れたり、ラスボスとなるブロックを設定したりと充実した作品になりました。', null, '時間帯: その他'),
  ('3ed627d0-1abd-55b6-961c-309fa70a0381', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-04', null, null, '通常 / 変数の練習', 'ボールをキーで動かすところまではできましたが、少し動くと速くなりすぎて止まらないという状況でした。その流れで、速度が暴走しないよう制限するところから始めようと説明しました。ボールの「縦の速さ」「横の速さ」の制御のコードについて、今は上下左右の動きのうちどれを扱っているのかを確認してもらいながら進めました。それに続くカギの動作も、動画を見ながら途中まで作りました。', null, '時間帯: その他'),
  ('a8342ced-01e6-5324-aebc-3f08c81416b4', '28d52d6e-7571-5090-a2d9-492c997b719e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-04', null, null, '通常 / 座標の制御、変数など', '続きからやりました。「もし敵1に触れたら」「もし敵2に触れたら」...といった条件分岐について、並列に並べるべきところで入れ子になってしまっていました。そこでそれぞれの「もし」ブロックの範囲がどこまでかを問いかけて、範囲についての意識を高めてもらいました。「スピードをスピード*0.9にする」という部分では、学校の算数とは違う掛け算の記号を初めて見たようでしたが、「スピードが段々遅くなる」というコードの意味はしっかり理解していました。最後まで完成し、そのあと若干時間がありましたが、となりのゆうとくんの作っているゲームが気になって遊んでいました。', null, '時間帯: その他'),
  ('023ed80a-7282-5b90-8645-7fb7d57470ea', '31feac25-f850-5d21-8e43-ed4d7badb6a0', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-04', null, null, '通常 / 基礎が身に付いているかの確認', '千尋君をほとんどレッスンで受け持ったことがなかったので、どれくらいの知識・スキルなのか確認の意味合いでレッスンしながら確認していました。キャッチゲームの見本通りに進めるのではなく、やることを説明して、自力でできるかを確認してみましたが、キャッチゲームくらいなら自力で作れるスキルがありました。', 'スキルの抜けがないかを確認しつつ、検定を受けるのであれば、検定問題になれるようなことをしても良いかと思いました。検定対策がまだ早いのであれば、前回ジャンプゲームをやっていたので、横スクロールのプラットフォームゲームを作るのでも良いかと思います。', '時間帯: その他
タイピング: ゲーム的に進められるココアタイピングが気に入ったようで、だいぶ時間をかけていました。'),
  ('320724c9-f263-595a-914d-a8ab3d9c65dd', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-04', null, null, '通常 / オリジナルゲームを作成する', '弾丸スプライトの本体を隠して、クローンを連射のように動かすやり方を学習しました。クローンについては経験が少なく、あまりよくわかっていないようだったので、一緒に作成する形で学習を進めました。 クローンの作成ブロックを「ずっと繰り返し」していたため、クローンの数がオーバーしてしまい、途中から出てこなくなってしまったので、クローンの上限が300のため、必要なくなったクローンは削除する必要があること、繰り返しの回数を決めることを説明し、本人が納得した上で修正することができました。 恐竜がランダムに「ドン！」とさせたい、という構想についても、「ドン」とするとはどういうことか⇒コスチュームに絵を描いてあるのでそれを使いたい⇒コスチュームをどういうときに切り替えればいいのか⇒ランダムな時間を待って、コスチュームを変え、元に戻す、といった感じで、やりたいことをブロックに置き換えるとどういうことになるのか、丁寧に発問していくと、自分でブロックを探すことができるようでした。 恐竜が出す矢印と雲についても、1つと2つのバージョンをランダムに切り替えたい、というので、ジャンプゲームのように1つと2つのコスチュームを作成し、変数の値によって切り替えることを思い出させて作成させました。 独力では手が止まってしまうことが多いのですが、丁寧に会話をしていくと、その過程で理解できることが多いので、一人で細分化できるまでもう少し、といった感じでした。', null, '時間帯: その他
盛り上がり: お迎えがくるまで1時間半以上、一生懸命に取り組んでいました。やりたかったことはできてきたようで、嬉しそうでした。
備考: 授業のあとは、トランポリンのおけいこがあるそうです。'),
  ('a1e37e7a-11b7-5f7e-9a4b-c58a9d08cd50', '655ad2c9-dfb5-5fc7-b41a-1d784603c1d0', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-04', null, null, '通常 / クローン、乱数', 'クローンを初めて扱いましたが、お手本のゲームを見ると、自分の分身をたくさん作れるというイメージはわいたようでした。乱数も丁寧に扱い、座標や確率的な動きなど色々なものに使えることを確認しました。動画通りに完成すると気に入って何度も遊んでいました。', null, '時間帯: その他'),
  ('9b8942b4-1703-58af-b543-3487a720e26f', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-04', null, null, '通常 / 検定対策前のスキル底上げ', 'PRG48を進めたのですが、動きがなくて面白くないとのことで他何個か進めたのですが、難しすぎないで動きのあるものということで、最終的にPRG３４をやることに決まりました。鳥の動きだけできているようなので、次回はその続きからできればと思います。', null, '時間帯: その他'),
  ('5618d6a3-e78f-56b3-a675-27e66e5fab64', '80660755-d846-5cdd-91a4-0ab78fe29034', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-04', null, null, '通常 / 検定問題にチャレンジ', '問題自体は自分で最後まで解いたうえで、わからなかったところを質問してきました。 コスチューム番号がコスチューム#と表記されていることを知らなかったようで、これは説明を聞いて納得していました。 あとは、スタンプを初めて使用したようで、こちらもペンツールにあるという説明だけで理解して使用できていました。 演算式が長くなったときに、画面上隠れている右端のほうを見落としていたためのバグはありましたが、それ以外はきちんとできていました。', '最後のコインが出てこないところを解決しきれなかったので、余裕があれば見てやってください。', '時間帯: その他
盛り上がり: 塾からの直行でしたが、きちんと集中して取り組めていました。 残り時間10分弱、のんびりゲームができたのが嬉しそうでした。'),
  ('c7cfdee6-d97b-52f2-b4ff-91ac6681a2c8', '5b56509a-ab37-5b95-9b2b-2750525ad8a5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-04', null, null, '通常 / U16大会作品の作成', '作品自体は今日の授業時間でほぼ完成ということで、全体的に気になるバグを修正していきました。 メニュー画面で、英文字のメニューをクリックした際に、クローンが複数作成されてしまい、文字の背景が濃くなるバグがランダムに出るということで悩んでいましたが、作品の動き自体には直接関係ないため、余裕があったら修正するということで納得していました。 プレゼン作成については、あまり経験がなく自信がないとのことだったので、次回とその次は、プレゼン作成を中心にサポートすることになりました。 自宅でアピールしたい箇所のスクショを用意してきて、パソコンごと持参するとのことです。', '自宅からPC持参するので、よろしくお願いします。プレゼン作成の自信がないとのことだったので、アドバイスをしてあげてください。', '時間帯: その他
盛り上がり: 作品自体がほぼ仕上がったのが嬉しそうでした。 プレゼン作成についても前向きで、教室でサポートしてもらえることにも安心したようでした。'),
  ('f5516de3-0b1f-576b-8755-09c933c4b87d', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-04', null, null, '振替 / タイピング検定・ロブロックスお試し', 'タイピング検定を完了させた後に、ロブロックススタジオのお試しました。最初は、デジタネの動画をせているだけだったのですが、それだと、Roblox studioで何ができるかの全体像が分かりづらそうだったので、実際に、part作成・簡単なスクリプトを作成してもらい、とてもシンプルなアスレチックゲームを作ってもらいました。興味が出たかどうかは正直分かりませんでしたが、ある程度理解はしてもらったかと思います。ただ、表情からは、興味を持ったかどうかは分かりませんでした。', null, '時間帯: その他'),
  ('9e6890a1-cea3-54ff-a35a-4b1961037283', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-10-05', '17:30:00', null, '通常 / 作品制作', '大会作品が満足いくまで完成させることができていなかったため，今回で完成させていきました．取り入れていきたい箇所を全て取り入れることができたようで非常に満足していました．次回からは，別のことに取り組んでいく予定です．', null, null),
  ('07fc0cee-7220-5398-83b8-261ed6e24051', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-10-05', '17:30:00', null, '通常 / Excel検定２級模擬問題３', '検定受験前最後の授業ということで，模擬問題をおこなって総仕上げをしていきました．今までやったことについてもしっかりと理解できているようで，ケアレスミスが１つあったのみで合格は硬い状態でした．本番ではしっかりと今までの成果を発揮して合格してもらいたいです．', null, null),
  ('f7cd1e70-fece-508d-9ac2-8a3dae30e4dd', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-10-05', '17:30:00', null, '通常 / ロブロックス', '前回までやっていたデータが消えてしまってかなり萎えてしまっていたので，サンプルデータを元に動画を見ながら続きに挑戦していきました．確認テストでは満点でしたが，クライアント側とサーバ側の処理についてなど難しい内容も出てきていたため，しっかり理解できているかはかなり怪しい状態です．今回は前編をやったため，次回の後編でわからない箇所が出てきた場合には前編の復習を行なっていく必要があるかもしれません．', null, null),
  ('2ab56b26-ac10-528c-9cf2-86b3d32ebf13', 'e22d8f70-f1a1-5ca4-9ed4-4d27cb0e164f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-10-05', '16:30:00', null, '通常 / コード探求【もし●●なら】', '今回はコード探求【もし●●なら】条件分岐について学んでいきました．今までの知識がしっかりと定着しており，なおかつ新しいものに対しても素直に取り組んでくれたためとてもスムーズに進めていけました．30分ほどで完成まで持っていくことができ，残りの時間で音声の速さを変えての難易度変更などを行なっていました．この調子で次々に新しいことへ挑戦していくことで，さらに上の難易度もこなせるようになると思います．', null, null),
  ('d146e205-866f-5eae-a4c6-aa72f4bf8aa6', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '7ecf31c6-4f7c-5303-8c20-3ec48194781e', '2025-09-29', '16:30:00', null, '通常', '横スクロールのアレンジをしました。終始別のことをやりたいと言っていました。途中でタイピング検定の練習をしたいと言っていたので少し長めに練習をしました。あと少しで7級という時が多く最後に1回7級を合格することができました。安定して7級を取れるように体を慣らしていきたいです。 次回は岳くんと一緒にクローンを使ったスムーズな横スクロールの作成からはじめたいです。', null, null),
  ('b7a7a9ec-1548-5852-8a28-97bcb0849d04', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '7ecf31c6-4f7c-5303-8c20-3ec48194781e', '2025-10-06', '16:30:00', null, '通常', '横スクロールのアレンジを行いました。弾丸を使ったアレンジをしたいようでした。背景を滑らかに動かしてスクロールさせたいとのことだったのでクローンを使った方法で行うことになりました。クローンを使ったことがないとのことだったので次回使い方を少し説明して始めたいです。', null, null),
  ('c0bd95be-7512-52f3-a5d5-ea99ad21da69', 'e22d8f70-f1a1-5ca4-9ed4-4d27cb0e164f', null, '7ecf31c6-4f7c-5303-8c20-3ec48194781e', '2025-10-06', '16:30:00', null, '通常', '色や見た目を変えるチュートリアルを行いました。 タイマー、色と大きさがずつ変わる、色に触れたら〜する、を行いました。また座標の1番最初の問題を途中まで行いました。ブロックの位置を覚えるために色と結びつけて覚えられるように声掛けをしました。後半は一度使ったことがあるブロックはどこにあるのかがわかるようになっていました。ずっとを使わないとどうなるのかを比較しながら理解しました。読めない漢字が多そうだったのでアルスタジオの設定をひらがなにした方が良さそうでした。', null, null),
  ('15b895fd-2ebc-5172-89c9-003265130b32', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-10-06', '16:30:00', null, '通常 / プラットフォーマゲーム', '授業初めから頭が痛いと言ってやる気が底についていたので、ほどほどに進めていきました。前回の横スクロールがやったものの、バグが起きていて、その直しがメインでした。音をいじるときは盛大に楽しんでいて、そうたくんのロブロックスも気が移り、なんか普段のモチベーションががくくんと逆転したみたいです。直すひと例を見せて、同様なところを写経させて、今回は終わらせました。同じプラットフォーマは続いていたので、別のものに切り替えてもいいかもしれません。', null, 'タイピング: 今日はなかなか気が進まなかったです'),
  ('d1548021-8a68-5b09-a252-315caec06e6f', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-10-06', '16:30:00', null, '通常 / プラットフォーマ', '前回作った横スクロールをアレンジしていきました。岳くんのアイデアとして敵を弾で撃ち落としたいのことでした。弾のコードとして、敵に当たるまで進みたいようとしても「もしとずっと」で苦戦していたので、スクロールで使った「横スクロール」を教えたら満足して作れました。また、当たった時の反応として、音だけだと寂しかったので、「倒れる」「ジャンプで回避」を提案したら受け入れてくれました。アイデアの提供でコードはこちらから教えることは多かった、普段使わない「回転するコード」や新しく習った「放物ジャンプ」の使う機会を増やせてよかったです。コードを活かす機会がなければ、アイデアが狭まる可能性があったので良かったです。コード作成途中でも初期条件コードを必ず意識して作ってくれるのは岳君の良いポイントです。コードの類は忘れやすいが、、、それぞれコードが出来上がり、作品は完成することができました。', null, null),
  ('f4d30c1a-e701-5d19-8330-1a14ef91d06b', 'e22d8f70-f1a1-5ca4-9ed4-4d27cb0e164f', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-06', '16:30:00', null, '通常 / 検定に向けての基礎固め', 'ほとんど対応したことのない子だったので、まずは、どれくらいのスキルがあるのか確認するために、どんな方法でもよいからジャンプの処理を自分なりに作れるかお願いしてみました。が、まだ難しいようでした。レッスンとしては、簡単なジャンプ方法、10回y座標を+10して、10回y座標を-10するのは理解してもらい、あとは、障害物が迫ってきて、それに触れたらゲームオーバーにする方法、キャラを左右に動けるようにして画面右端までたどり着いたらゲームクリアとするようなミニゲームを完成させました。ひとつ気になったのが、「ずっと」の中で、必要なブロックを挿入するときに、そのブロックの挿入場所がかなりてきとうでした（何回もです）。「ずっと」の処理がきちんと理解できているか、ひとつひとつ順を追って説明して理解してもらうようなことをした方がよいかもしれません。', null, null),
  ('b6f7df05-1352-5634-a430-58fd582538cf', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '7ecf31c6-4f7c-5303-8c20-3ec48194781e', '2025-10-03', '16:30:00', null, '通常', 'バスケゲームの続きを行いました。シュートするアルくんやシュートされた後の動きの作成を行いました。2段ジャンプをさせようとしたものの上手くいかなかった為、ゴールを比較するなどの工夫を行いました。ネット触れるだけでゴール判定になってしまうバグをボールを持っているかつ、シュートするための入力が押されているとゴールできるように修正していました。次回は変数でスコア判定をつけるなどゲーム性の部分に着手できるといいと思いました。', null, null),
  ('9e9e59b0-ecff-5e9f-b2f3-39d6fa36b696', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '7ecf31c6-4f7c-5303-8c20-3ec48194781e', '2025-10-06', '16:30:00', null, '通常', 'タコから逃げろの作成の続きを行いました。レベルをコントロールするカードの部分が理解できないと言っていたので一緒に考えながら理解しました。早めに完成したので難易度が上がるように数値を変えました。新しくビルの中を潜り抜けるゲーム(鳥が隙間を潜り抜ける)の作成に取り掛かったのですが鳥の動きが難しいと言っていたので次回確認しながらできたらいいと思います。', null, null),
  ('cf1e3ef9-a06d-550e-9eab-68b26984da8c', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-10-06', '17:30:00', null, '通常 / 変数の使い方を増やそう', '大会作品が完璧に完成できたので、しゅうくんのレベル的にアイテム脱出を作成していきました。試遊で、気に入って何度も挑戦して滑る移動をはまっていました。動画を見ながら作成していきました。途中ボールの動きが完成した段階で、確認したところ、ボールが動かないバグが発生していました。一緒に探してみましたが、しゅうくん自身が変数に違いに気づいて自己修正できてました。7割くらい進んだので、次回で完成＆アレンジできそうです。', null, 'タイピング: スムーズに打てるようになってます'),
  ('ec1db415-5c6d-5dc7-abbd-fb281587553d', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-10-06', '17:30:00', null, '通常', 'さぼりです。ずっと 声をかけても半分くらい無視 前回、データが消えたと思い込んでたのが原因 今日探したら前々回のデータが残っていたので、ほぞんをしてありました。 GUIとサーバースクリプトとか大変なので次回は復習してから後半です', null, null),
  ('24c35f57-2020-57b4-bd0a-f810364b60fc', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-07', '17:30:00', null, '振替 / ロブロックス', 'ハラハラピンボールの続きだったのですが、レッスンが始まって少しして、何かソワソワして声をかけたそうだったのですが、何も言ってこず、レッスンを何事もなかったかのように進めている風だったのですが、いざ声をかけてみると、前回のデータが保存し忘れたのか、なぜかないとのことで、動画の初めから見直しているところでした。さすがに、時間が無駄になりそうだったので、完成形のサンプルプログラムをダウンロードしてもらって、それを適用してもらって、完成版だけどこれから教える部分を、削除する等して途中から直接教えました。CanCollideやTransparency, Whileを使って、Partのプロパティをいじる方法を理解してもらいました。動画を使わずに、何も見ずに実際にテキストスクリプトを作成してもらったので（間違いを経験しながら）、少しは動画よりも見になったのではと思います。デジタネ動画は使っていないので、進捗は進んでいませんが、ハラハラピンボールは確認テスト以外は終わっています。次回は、ハラハラピンボールの確認テストからです。', null, null),
  ('5253a812-e5cc-583e-a040-56bdefb6e0ac', '0d16e234-e60d-5fdb-978f-1722acf9a2b2', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-10-09', '16:30:00', null, '通常 / 自由', '初めのうちはずっとscrachのげーむに入れず、遊んでいました。ゲームの切り替え時に今日は何やんの？と言ってくれるのは少しはいい部分です。そのあと遊んで後にそんで思い出したように前回のピンポンゲームを思い出してしてくれました。跳ね返りも一部作ってやりましたが、またあちこちに気が散り、手がつかない状態でした。休会予定なので、少しはめりはりをつけたいところですね', null, 'タイピング: アルスタジオの障害もあり、最後の方にやってくれました。'),
  ('98c145a3-f0bf-50b9-9d78-5cd6a9e93299', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-10-09', '16:30:00', null, '通常 / 検定練習', '本来は2級をやる予定でしたが、高校生の解きかけの1級の問題のゲームを見て、面白そうだからやってみたいと1級に急遽変えました。前半は順調に解き進めていきました。途中に座標でロケットより右側」という文章を解釈して、解け進めていました。ただ、時間はかかるもので、60分ではコード修正の入りたてで、終わりました。やったところまでうまくできてみタイだったので、いったん最後までやってみてもよいかもしれません。', null, null),
  ('18ebd6ea-fe42-554c-bd12-6b73d6af1ad0', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-10-09', '17:30:00', null, '通常 / ボールキャッチ完成', '前回の続きをやってきました。復習のがてらボーナス点のモノを作っていきました。少し、うえで滞留してから落ちてくる場面がありました。そこで、どこで隠れているといいか一緒に考えて隠すの入れる位置を決めることができました。そこから自分で他のスプライトもふえて、大変にぎやかなものになりました。クリアの条件にもスコアの条件式をこちらから支持をしなくても自ら組み立てることができました。最初から不等号も選べて来たのもよかったです。後半はアルスタジオが障害でぐーたらしていました。', null, null),
  ('c778db47-ca7c-5eac-87f2-765bfcb664b5', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-10-09', '17:30:00', null, '通常 / U16大会プレゼン資料作り', '次回が提出最終回なので、プレゼン資料の作成に取り掛かりました。ちひろ君の例に参考にしながら、作成に始めようとしたが、なかなか進みませんでした。自分の学校名を名乗るのが恥ずかしいらしく、手が進んでいませんでした。ゆき先生が散歩をしているに乗っかって散歩したり、今日は特に集中がなかったです。次回は間に合うのか？？せかすしかないです。', null, null),
  ('c3ccad57-7f4b-5196-9c59-cd017ff941ae', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-10-09', '17:30:00', null, '通常 / U13大会作品作り', '今回はバケツ汲みの仕組みを時間をかけて給水する仕組みを作っていました。多少試行錯誤の中で、バグが発生することがありましたが、別のアプローチを自分で考えて作り変えることができていました。変数の不等号に不備があった場合、条件を逆手にとってスムーズに動くようになっていました。ほかに気の体力もつけて火消の機能がゲーム性を帯びていました。あと1回ですが、本人的には終わるかも？なので、少し心配です。', null, null),
  ('33fdfa73-d73b-5d1e-9ff7-38cb6ec07a8c', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-10', '17:30:00', null, '通常 / 検定２級対策→ロブロックス', '本当は、スクラッチ検定２級の対策をしたかったのですが、かたくなに拒否され続けて、できませんでした。検定を本当に受けるのであれば、スクラッチの進め方に関してはヘルプが欲しいです。結局今日はロブロックスの続きを行いました。ロブロックスに関しては、多少講義的なものでも、なんとか聞いてくれるようです。今日は、「レインボーロードを作ろう」「コロコロボーリング」の確認テストを実施しました。前回と同じなのですが、問題文をきちんと読まず理解せずに、適当に回答してしまうことが多いです。結局一人でテストをさせても適当にやってしまいそうなので、横でつきっきりで一緒に問題を解きました。わからないところは、一つ一つ丁寧に教え、理解してもらえたと思います。その後、作成中のオリジナルゲーム、敵をひっぱたいて吹っ飛ばすゲームの、吹っ飛ばす力を、ランダムで変えたいというので、RobloxStudioでの乱数の使い方、変数の使い方の基本を教えました。一回で覚えるのは難しいかもしれませんが、この積み重ねでできるようになったら嬉しいです。', '検定対策をしたいです。', null),
  ('81f345e7-d828-5019-a0d7-7e0396d0aa9f', '10db50c3-a153-502a-b455-c67362b9871c', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-10', '17:30:00', null, '通常 / 検定１級・ロブロックス', '本日１回目です。Robloxをやりたいとのことだけど、まずは検定１級を取って、その後、本格てにロブロックスを始める方向で行こうということで、今日は、検定１級の最初の問題を解いてもらいました。途中で、PCが何かしらおかしくなったらしく、途中でゼロからやり直す必要が出てきたので、このタイミングでロブロックスの進め方を説明して、最初の動画を見てもらいました。スクラッチも、ロブロックスもどちらも、とにかくやる気がとてもあり、楽しく進めています。レッスン時間が終わっても、１９：３０までロブロックスのオリジナルゲーム作成に夢中でした。', '検定１級の最初の問題をもう一度最初からチャレンジして、まずはそれを終わらせたいです。', null),
  ('592bef52-9780-59fe-8d74-022661f2e986', 'd3885e29-ee68-501b-bf31-6c050fd50c36', null, '7ecf31c6-4f7c-5303-8c20-3ec48194781e', '2025-10-10', '16:30:00', null, '通常 / 検定４級できず→基礎がため', '最初に、検定４級の問題をやってほしいことを伝えたら、「４級は受けない・受ける気はない」と拒否姿勢でした。検定はやる気がなさそうで、基礎レッスン、キャッチゲームをすることにしました。 キャッチゲームの作成を行いました。途中やる気が落ちていましたが一緒にカードを見ながらこのコードはどういう動きをするかを確認しながら行いました。 x座標とy座標の違いや一度使ったブロックは使い方をすぐに理解できていました。 次回はボーナスポイントから始めて欲しいです。', null, null),
  ('55599161-b686-5c01-a4bd-82ed654eb1da', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-10', null, null, '通常 / エクセル', 'エクセル３０時間の6章、例題１８の途中まで進めました。特に質問はなく、自走していました。何か用事があったようで、レッスン終了１０分までに教室を出て行きました。', null, '時間帯: その他'),
  ('0db067e5-f192-50c0-9878-b47956d1ef6f', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-10', null, null, '通常 / ロブロックス', '魔法のレンガブロックの途中から。黙々と進めていましたが、「順調」と尋ねてみると、質問してくれました。「Vector3」って何？という質問でした。正直これをきちんと理解してもらうのは今の段階では無理なので、３次元座標x,y,zを扱う時には、必ずこれを使って、座標を変更するようにしてください。というふうにしか話せませんでした。もっと動画が進んだら、細かいことをあらためて教えるようにします。あと、いくつかスクリプトに関して質問したら「+-」のことをきちんと理解していなかったようなので、X += Yの場合、X=X+Yとなるような場合の省略系だというようなことを教えました。レッスン１の後半になると、ぼちぼち、分かりづらいところが出てきているので、他の生徒に対しても、気をつけてみていきたいと思います。', null, '時間帯: その他'),
  ('9c86ca91-66ff-5f77-8de7-800096ee132c', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '7ecf31c6-4f7c-5303-8c20-3ec48194781e', '2025-10-10', '17:30:00', null, '通常', '前半は30分ほどタイピング練習を行いました。長い時間集中しながら行っていました。次回の授業で検定を行うので内容を覚え指を慣れさせることができたと思います。 後半は二級の応用課題1を行いました。あまり時間が無かったため鳥のコードの途中まで行いました。果物の動きが想定とかなり違くて難しい時行っていました。次回はこの続きから行いたいです。', null, null),
  ('2c1d92f1-3b6e-5fb2-b967-b2321b097ceb', '655ad2c9-dfb5-5fc7-b41a-1d784603c1d0', null, '7ecf31c6-4f7c-5303-8c20-3ec48194781e', '2025-10-10', '17:30:00', null, '通常', 'ゆづきくん同様前半30分ほどタイピングを行いました。準一級を平均して取れるほどかなり速く打てていたのですがタイプミスが少しあったので、落ち着いてできればタイプミスも減って一級も狙えると思います。大会に参加するという画面が押せなかったので次回行います。 後半は4級の問題に挑戦しました。完成自体は20分ほどでできていたと思います。ただ思うように動かなかったので一緒に一つづつ確認していきました。〜まで待つの部分をもし〜ならを使っている等の間違いが多かったですが、検定の様式になれたら問題なく進められると思います。', null, null),
  ('aae4a5e3-2e8c-521a-b11d-39f4972a7b93', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '7ecf31c6-4f7c-5303-8c20-3ec48194781e', '2025-10-10', null, null, '通常', '自作の計算爆弾解除ゲーム(?)の作成を行いました。かなり集中して行えていました。くまをもぐらに変更するなどをしました。足し算を乱数にする部分に苦戦している様子でした。お兄ちゃんと一緒に競い合う中でクラウド変数でタイムアタックのスコアを競い合いたいとのことだったので、後半はクラウド変数の使い方を兄弟で模索していました。', null, '時間帯: その他'),
  ('8e288f0d-3fd9-59f6-8891-0de1279fba1b', '31feac25-f850-5d21-8e43-ed4d7badb6a0', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-11', null, null, '通常 / 検定対策', 'タイピングに結構時間を使い１０分経過後くらいに検定4級応用課題２に挑戦。メッセージを消す方法（○と言う）の○の部分を空白で表現することと、「がぞうこうかをなくす」のブロックの存在を知らなかったので、それら二つを教えましたが、それ以外は問題もなく時間も全然余裕で２０分程で終わりました。次回は4級の中でも難しい問題を解いてもらいたいです。', null, '時間帯: その他
タイピング: ゲーム形式でのタイピングが気に入っているようで、楽しく結構な時間続けていました'),
  ('336deadb-4d9f-5d7d-8d19-8b8191f5494b', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-11', null, null, '通常 / 検定対策', '授業始まる前から机に突っ伏していて、体調が良くない様子でした。レッスン開始後も、なんとか検定問題を始めていたようでしたが、とてもつらそうだったので、ゆき先生の声がけでやはりきついと言うことで親に電話して、途中帰宅となりました。', null, '時間帯: その他'),
  ('02f5bb9c-903b-5dba-a500-200810437dbc', '5b56509a-ab37-5b95-9b2b-2750525ad8a5', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-10-11', '17:30:00', null, '通常 / 大会提出資料作り', '授業初めに、前回のちひろくんのスライドを共有しました。そこから、基本構想を立ててみました。自分がこのゲーム自体最初の方しか見ていなかったので、改めて遊んで、どこがアピールポイントなのか、なぜここ仕組みを作っているのかをヒアリングしました。このゲームの対象者がただゲームを遊びたい人だけにとどまっていて悩んでいたので、とりあえず、後回しにしました。ゲーム概要には、さっきヒアリングしたことを基に、流れを共有しました。すると、書くべきことが分かったらしくて、その後は手が止まらずに作成できていました。', '作成のアドバイスや添削をしてもらえるようにコミルで連絡してきてもよいと伝えておきました。', null),
  ('1165d7a6-cc22-5512-b21c-fc68901f6486', '655ad2c9-dfb5-5fc7-b41a-1d784603c1d0', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-11', null, null, '通常 / タイピング本番と検定対策', 'かなり素早くタイピングできています。ほんの少しだけスピードを落としてミスタイプを少なくした方が良いかなと、ちょっと思いました。 検定に関しては、今日の問題だと「このスクリプトを止める」と「スプライト内の他のスクリプトを止める」の使い分けがよく分かっていなかったようで、サンプル動画のような動きにするのにだいぶ苦労していました。教えて理解しましたが、他にも細かいミスがあったので、4級の応用課題を進めて安定して合格点を取れるようにしていけたらと思います。', null, '時間帯: その他
タイピング: いつも通り集中して取り組んでいました。本番も頑張っていました。'),
  ('2a26d3c3-40cc-5587-8735-b9d3bd0f9884', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-11', null, null, '通常 / 検定練習', '以前、ちょっとしたわからないところでパニックになっていたので、最初に「何かあったら落ち着いて先生に質問して」と伝えてから始めました。ただ今日はあまり集中できない日だったようで、検定問題のファイルは開いたものの、コスチュームや音をいじって遊んでしまいました。本人から話を聞くと、 ・このパソコン(Windows/ライオンくん)の画面が自分に合わず目が疲れるので休めたい(→Chromebookに変えました) ・この問題のゲームはあまり好きではない ・ただ検定のためなら少しは頑張れるかも とのことで、今日は最終的に放任して自分のペースで少しだけ進めてもらいました。', null, '時間帯: その他'),
  ('814f956f-efa7-5015-a983-f998bbfdf030', '40a476bc-72a5-5bdc-ab75-e89d5310b442', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-10-11', null, null, '通常', '初めての検定練習だったので、意義を教えつつ一緒に取り組んでいきました。お手本ムービーを見せてたら、猫のスプライトのの古さに気が付いて、検定が長く続いていることを知ってもらえました。コード作成に取り掛かると、まずまずゆっくりなテンポで作成ができていけました。途中、「馬に触れるまで繰り返し、まてーと言いながら5歩」とひと文が長いものには苦戦をしました。最初に作った段階では、一個一個ずっとに挟まれていて過剰になっていました。そこで、まずちかとくんが「まで繰り返す」のブロックを知らなかったので、使い方を教えると、そこから何回か試行錯誤をして正解の動きに近づけることができました。文章からコードの正確な位置を読み取ることは少し難しいが、地道にコードを練り直す体力はありました。ほかに、コスチュームの0.5秒ごとの切り替えも1発では完成できなかったが、コスチュームのコードが連続していることに一緒に気が付かせると、秒待つを増やせばよいと自分で気が付きました。ずっとそばにいて一通り完成するのに40分くらいかかりました。アレンジはBGMと背景を変えて楽しんでいました。', null, '時間帯: その他'),
  ('df9887dd-f9ad-5ba2-8b7f-c967430eaf74', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-11', null, null, '通常 / 検定練習', '簡単そうな様子で解いていき、早めに最後までたどりつきました。テストプレイするとバグがありましたが、ほぼ自走でバグ直しできていました。問題文と照らし合わせて、変数の値の変え忘れなどを発見していました。その後アレンジとして、プレイヤーの速度を変数で段々変えるのをやっていました。そこで使える(速さ)×(-1)という負の数の掛け算を教えてみて、本人は初めて見たそうでしたが使いこなせました。', null, '時間帯: その他'),
  ('9fe752b0-47fe-5cd5-9245-312e6e230569', 'ec153bd8-5b4d-5684-9704-382af23cf64a', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-11', null, null, '通常 / 検定練習', '解いていく中で、「コスチューム名」と「スタンプ」のブロックは初めて使ったようなので、軽く意味を教えたところすぐに使いこなしていました。それ以外の部分はほぼ自走できていました。知識の抜け漏れ確認や「もし～なら」の範囲の確認が必要という程度で、実践にはだいぶ慣れてきています。', null, '時間帯: その他'),
  ('1ac9b0e6-4d47-5986-93f6-9102597f830c', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-11', null, null, '通常 / 検定対策', '本人は、「これ簡単だよ、だって問題に答えが書いてあるんだもん」と言っておりました。こちらからは、「そんなことないよ、国語力がないと理解できないものも多いよ」と伝えたら「俺国語得意いつも１００点とのことでした」。ただ、実際には、細かいケアレスミスが散見されました。問題は理解しているのに、ブロックの位置を間違えたり、一部問題をもう少し深くみないと分かりづらいところに引っかかったりと。まだ慣れていないので仕方ない部分も多いので、検定問題を続けて、慣れていってほしいです。', null, '時間帯: その他'),
  ('9f2a42d7-4d6d-5e19-b3bf-ce6760354334', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-11', null, null, '通常 / ロブロックス', '運試しの橋の確認テストと、白熱ボールレースを最初から確認テストまで終わらせたようです。確認テストは一緒に見ながら進めましたが、プログラムの問題では、理解度は正直あまり高くないと感じました。その場で、while文の処理の流れ、乱数生成の処理の流れ等、動画で教えていたはずのものを基礎から教えました。片手間に動画教材を進めていて、きちんとプログラムの中身は理解していないと感じます。（とはいえ、私の考えとしては、自分で何回も何回もそのプログラムを使って記憶に定着するものだと思うので、確認テストで即答できないのは、ある程度仕方がないともいえます。）', null, '時間帯: その他'),
  ('c577af7b-749d-5635-8d27-2e9e423bf116', '82396ac6-71bd-59d4-a372-57212866fd5d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-10-11', null, null, '通常 / 検定練習', '2回目の検定練習を行いました。問題文を読んでいき、魚のコードを作って試すと、魚が動かないバグが発生してしまいました。そこで、とりあえずコードだけを見て、あちこち動かして直そうとしていたため、問題文を見直すよう伝えました。それでも手を止めることがなかったので、いったん視界を遮って、検定でのバグの見直し方を一緒に取り組んでいきました。まず、どこがおおかしいのかしっかり見るように教えました。何がおかしいのか把握はできていたので、次に問題文を振り返るよう教えていきました。①のあととなっている部分がそのあとに続けていなかったので、バグが起こっていることに気づけました。ほかに、連続してコスが変わるコードで秒待つの抜けていたり、間違えやすいところ振り返ってコードは完成しました。 はじめくんはバグが発生してしまうと、コードだけを見て検討してしまうので、問題文と見直す癖が必要です。次回の始めるときには、バグの減少の内容確認、問題文確認、コード確認の順で意識させましょう。', null, '時間帯: その他'),
  ('80641568-5eeb-584a-bea8-872a3bfbe9e5', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-10', '16:30:00', null, '通常 / クローン、ではないまでまつ', 'クローンによる横スクロールや「ではないまで待つ」の学習として取り組みました。これらのポイントが理解できているか確認しながらすすめ、きちんと分かっているようでした。「抜けた数」を増やす条件として、鳥とビルのx座標を比較するイメージも持てていました。前回はほんの序盤しかできなかったとのことでしたが、今回は集中して完成までこぎつけました。', null, null),
  ('8259b7fc-c280-5d22-b46f-84129dee0164', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-10', '17:30:00', null, '通常 / 変数の使い方、デバッグの練習', '前回残っていたステージ進行がおかしくなるのを直すところをやりました。バグが直らないと「なんでなの！？」とイライラしてしまう傾向があるので、一緒に冷静に原因を探ろうと提案しました。テストプレイしてみて、変数の中身が正しいか確認する→間違っていたら、その変数を決めているコードを確認する というステップをやってみました。結果として、数値の打ち間違いや、自己判断で余計なブロックが入ってしまっていたことが判明し、修正することができました。', null, null),
  ('22d0f579-b01b-5b4c-98a5-9763fc80c4e4', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-10', '18:40:00', null, '通常 / グラフ', '30時間マスターでグラフの部分は初めてだったため戸惑った部分もありましたが、次第に慣れてスピードを上げていきました。だいたいの部分は自走できました。', null, null),
  ('f92744e0-835f-51c3-aea4-1fda7dd97c13', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-13', '17:30:00', null, '通常 / 大会準備', '発表スライドの作成に移ることも提案しましたが、まだゲーム本体で大事な部分を作らないといけないとのことでそちらを進めました。ときどき様子を見に行くと、荷物の積み下ろしなどの場面を変数で切り替え制御していました。製作とスライドのバランスや計画は次回以降話し合った方がいいかもしれません。', null, null),
  ('fb67ae13-48ec-5a4b-a111-81ed4ef42c91', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-10', '18:40:00', null, '通常 / グラフ', '特に質問もなく自走できていました。ときどき息抜きとしてか、たつきくんのテストプレイや実装方法のアドバイスなどもしながら進めていました。', null, null),
  ('8ee7caf9-c08c-523d-86a7-a5379461f7c7', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-10', '18:40:00', null, '通常 / 変数の使い方', 'ゲームが始まってもカギが表示されないバグがありましたが、カギのコードを見なおしてもらうと、「もし～なら」の範囲を間違えていたので、本当はどこからどこまで入れるのか考えてもらいました。縦と横の速さを変数で制御しましたが、縦なのか横なのかは毎回きちんと区別できていました。結果、ボールを動かしてカギを取れるところまでは行けました。最後まで終わってはいませんが、次回は検定本番が迫りつつあるため練習問題がよさそうです。', null, null),
  ('68263107-fa9b-516b-a6c6-d144f2b696c8', 'f3102a36-fdd8-574f-bf3c-85723faf424f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-10-06', '16:30:00', null, '振替 / 教室に慣れる', 'タイピングは自信があるらしく、嬉々として記録にチャレンジしていました。こういうのがやりたかった！という感じでした。 Scratchも自分のアカウントでかなり作成しているらしく、現在作成中だというたこ焼き屋さんゲームを見せてくれました。 タイピングコンクールにとびついてきたので、流れで検定も紹介してみましたが、試験はあまり自信がないなあ、との反応でした。 基本操作コースの内容をパッと見せたところ、だいたいわかるから、好きなのを作っていい？ときたので、せっかく教室に通いだしたのだから、もっとすごいことができるように、やったことのないものを作って勉強する時間と、好きなものを作る時間の両方をとっていこう、と話し、納得してもらいました。 算数が好きだということなので、図形を描けるか促したところ、四角形はすぐに描けたので、次に円を描いてもらいました。角度などはすぐに360割るxで暗算していました。 円の場合は角度がわかりにくく、線を描く動作を繰り返す回数をとりあえず大きな数、とやっていましたが、1度描くのを何度繰り返すと360度になるか、という誘導で理解していました。 複数の円を並べて描く模様についても、次の円を描くときはペンをあげる、などは自分で判断し、少し試行錯誤はしましたが、うまく完成させることができて喜んでいました。ペンの色や太さを何度も変えてできあがりの絵を楽しんでいました。 ほかの子や、研修にきていた先生たちにも積極的に話しかけていました。', null, 'タイピング: お試しでやったプレイグラムがとても速かったので、毎パソを勧めました。慣れたら初段まで出すことができ、その場で参加を決めていました。お母さんは、タイピングが得意なのでこういう大会があるのか探したいところだったと話されていました。
盛り上がり: とにかく楽しそうで、よくしゃべりながらもしっかり手を動かしていました。'),
  ('7a8279d3-597b-5fa7-873b-26170d11251e', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-10-07', '16:30:00', null, '通常 / リストの使い方を復習する', 'リストの使い方の復習のため、好きな歴史の話を振りながら、クイズを作ってみないかと促してみました。元の完成形からリストの部分だけブロックを削除し、復習を兼ねて作成させてみましたが、リストを最初に削除するなどは忘れていたので、そのまま作成させ、削除をしないとどうなるかを確認して納得してもらいました。 問題をどう考えてよいのかわからない、というので、今学校でやっていることを聞き出していくとアイディアがわいてきたようで、自分でネットで調べながら問題を作成して公開してくれました。', null, '盛り上がり: 問題を考えてこちらにゲームをさせるときは少し楽しそうでしたが、長続きはしない、といった感じでした。'),
  ('a50185da-791a-53a6-b54c-6ed92405bded', '1c7005cc-2815-558f-993a-9c7617d34c44', null, 'd45d6c5d-18cd-5aa2-99ea-932c81442c55', '2025-10-07', '16:30:00', null, '通常 / ジャンプゲームを完成させる', 'ジャンプゲームの続きを行いました。見た目を変える、スコアには変数を使う、まで待つが理解できていました。変数の〜づつ変えると変数を〜にするの違いがわかっていなさそうだったので次回以降で違いを理解できるようにしたいです。', null, null),
  ('c6c8b38c-fc1d-5cec-a1b1-9831d3c9bc77', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'd45d6c5d-18cd-5aa2-99ea-932c81442c55', '2025-10-07', '17:30:00', null, '通常 / スクロールの復習などをしながら、シューティングゲームを作成する', 'シューティングゲームの穴埋めを行いました。 普段のシューティングゲームよりやりごたえがあるようで集中して遊んでいました。ボールの部分の穴埋めが難しいようで疲れも相まって行き詰まっている様子でした。次回他にやりたいことが無さそうだったら、ボールの穴埋めの続きから行いたいです。', null, 'タイピング: タイピングはタイプミスが少なく準一級を安定して取れているようだったので、特に心配することはなさそうです。'),
  ('8b6cd626-7286-554b-9554-2a3732f7cdbe', '337872be-4ce4-5436-88f8-5f97e8c5252e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-10-07', '17:30:00', null, '通常 / 定義の使い方の演習', '検定1級に向けての定義の確認ということで、ゲームの完成形から自分で定義を使ったアレンジをしてもらいました。 わりとじっくり丁寧にやっていたので、時間はかかりましたが、一通り完成したといっていました。 得点が入ったあとの変数が変化せず、ゲーム開始時に戻ってしまうバグが残っています。', '得点が入ったあと、ゲーム開始時に戻ってしまうバグの修正（できたら）', 'タイピング: かなり熱心に練習していました。
盛り上がり: タイピングもプログラミングも、集中してやっていました。'),
  ('7361e024-d90d-53bf-bb87-e0ba1221596a', '1c7005cc-2815-558f-993a-9c7617d34c44', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-10-14', '16:30:00', null, '通常 / アルくんの冒険', '前回のジャンプの復習でアルくんの冒険を作成していきました．動画を見ながら作っていき，素直に進めていくことができていました．時々詰まっている箇所もありましたが，ブロックを入れる場所を間違えていたり，処理を行なっていなかったりと細かな部分で間違えていたようなので，見直しをできるようになればさらに完成度を高くすることが可能だと感じました．', null, null),
  ('40fa784e-efe9-5bb9-8488-db1eba3d2617', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-10-14', '17:30:00', null, '振替 / 大会作品制作，毎パソ本番', null, null, 'タイピング: 今日本番に挑戦するとのことで，練習の段階から張り切っていました．この時間では他にも受ける子がおり，かなり早くタイピングできていたため自分も負けじと頑張っていました．結果としては，少しミスがあったようであまり満足ではなかったようですが，大会作品制作にすぐ切り替えていました．大会作品制作では，メイン部分は完成しており現在はミニゲームについて作成しているとのことでした．今回完成しなかった部分は家でやってきて，仕上げを金曜日に行なっていく予定です．'),
  ('3586684f-5599-5e0d-bf98-d6a2f1236f36', '337872be-4ce4-5436-88f8-5f97e8c5252e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-10-14', '17:30:00', null, '通常 / 毎パソ本番，Prg42', '今回の毎パソ本番はかなり気合いを入れて挑んでいるようで，事前の練習で30分ほど使って準備万端で挑んでいました．結果としてはそれなりに満足のいく内容だったようで，１〜２段ほどの結果だと思うと言っていました．その後は前回作成していたPrg42のバグ修正を行なっていきました．バグのある箇所と直し方はわかっていたようなのですぐに終えることができました．次回からは検定対策へと移っていきたいです．', null, 'タイピング: 気合を入れてやっていました'),
  ('9e257a86-cb14-5bf2-8068-562adef4bf6c', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-10-08', '16:30:00', null, '通常 / 検定か、何かゲームを選んで作成。いずれにせよ、「完成までやりきる」ことを目標に。', '検定を勧めたりもしてみましたが、作成していたポケポケが気に入っているのか、まだ手を入れたいのか、封を切るところを少し直しては遊ぶ、といった繰り返しでした。 口では「ロブロックスをやりたいから検定とりたい」とはいうのですが、なかなか腰をすえて向き合うのが難しいようです…。 教室自体はとても楽しんでいるのですが💦', null, '盛り上がり: 毎回ちょっとずつ手を入れては楽しそうにしているので、今作成している作品については満足しているようです。'),
  ('afadd40f-45ab-545f-82c4-928774b0a403', '57f45872-1f3e-5540-b676-bf9023444e39', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-10-09', '16:30:00', null, '通常 / プロ野球スピリッツ（Scratch公開作品のアレンジ）を完成までやりきる', '相変わらず立ち歩きも多く、なかなかじっくりと作品に取り組むことはできませんでした。 それでも、今作成しているものには愛着があるのか、飽きずにちょこちょこ手は入れているようです。研修にきていた高校生のお二人に作品の説明をしたり、りくくんと野球の話をしたり、17時半チームの話に参加したりと、教室自体はおおいに楽しんでいるようです。', null, 'タイピング: 来週毎パソの本番という話もしましたが、大丈夫とのこと
盛り上がり: 教室にいること自体はとても楽しそうです…'),
  ('375a48db-4d68-5259-8cdb-974b368c2785', '05439956-11b9-5ac7-a44a-3e6f5a6831d8', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-10-09', '16:30:00', null, '通常 / U16大会作品の作成', '作品がまだ完成していないということだったので、プレゼンとどちらを進めたいか確認したところ、プレゼンは家でお母さんと作れるので作品の続きをしたい、とのことでした。 細かいバグの検証を一緒にやりましたが、コードの順序やメッセージのタイミングなど、このあたりが怪しいかも、という指摘をするだけで、自分で納得して直すことができていました。 行き詰まると、直接質問してくるのではなく、とりあえず立ち上がってきょろきょろしたり、どこか遠くを見つめたりする傾向があるかも…？そういうときに声をかけると、喜んで相談をしてきてくれます。自分からは言い出しにくいのかもしれないので、挙動を見過ごさないよう意識しておきました。 残りは家でできそう、と言っていたので、何かあったらComiruで連絡してもらうよう伝えました。', null, '盛り上がり: 学校で親子大会の表彰をされたそうで、ちょっと嬉しそうでした。'),
  ('4c9313c2-35da-52cf-8f8e-bbf9d860826e', 'f3102a36-fdd8-574f-bf3c-85723faf424f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-10-09', '16:30:00', null, '通常 / スキルの確認を兼ねて検定に挑戦', '今日は前回よりも自分の作品を好きに作りたい、という気分だったようで、しばらくうだうだしていましたが、検定問題をやる目的を説明したところ、それならやってもいい、とのことだったのでやらせてみました。 ムービーをしっかり見るのはよいのですが、それである程度構成が浮かぶらしく、問題の順序と自分が作っていきたい順序が異なることがとても気になるようで、途中何度も、「ここはこうしなくてはいけないはずなのに、問題に書いてないけどいいの？」と言ってきていました。とりあえず最後までやったらムービー通りになるはずだ、ということを何度か説明しました。 やりながらアレンジをしたくて「ここはこうしてもいい？」という質問も何度かありました。 とりあえず、時間はそれほどかからずに、それらしきものを作成することはできましたが、細かいところを問題文を読んでいないため、検定の結果としてはやや怪しいです。答え合わせができる様子でもなかったので、余った時間はオリジナル作品に作成に移行しました。 2級相当のスキルはありそうですが、今のところは検定自体にあまり向いていないようなので、今回の検定は見送って、作品を作りながらスキル固めをしたほうがよさそうです。', null, 'タイピング: とても盛り上がってやっています。かなりの好成績が出るので、本人も楽しそうでした。
盛り上がり: タイピングとオリジナル作品の作成は、とても楽しそうでした。'),
  ('8b9df843-d131-5f49-be58-50d5df59c713', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-10-09', '17:30:00', null, '通常 / U16大会作品の作成', '間に合わない、と言いながら一生懸命作っていました。 特に問題になるところはなさそうですが、とにかく時間との闘い、といった感じでした。 前回のリベンジをしたい気持ちも強いようで、家でも少しやっておくとのことでした。', null, 'タイピング: 不正回数によって、結果が極端に変わるのにちょっと怯えてました💦
盛り上がり: 作業をしながら、学校のことなどを話すのが気晴らしになるのか、楽しそうに会話をしていました。'),
  ('cb7ef420-69a1-5df6-8b8b-1273c0eb34f3', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-10-09', '17:30:00', null, '通常 / 検定3級応用課題', '取組中は、とくに質問もなく、淡々と進めていました。 完成はできたのですが、ゴールの出るタイミングやキーバーの動きが少しおかしかったので、一緒に見直しをしました。 どこまでを制御ブロックの中に入れ、どこから外に出すのか、というところが一か所あいまいだったため、ムービーの動きからの細分化と問題文の書かれ方の両方から説明をしました。', null, 'タイピング: 自分で何回か練習して、「大丈夫」とのこと、わりと切り替えがしっかりしています
盛り上がり: 概ね自力で解くことができて、わからなかったところも納得して、すっきりしたようでした。珍しく、しばらく教室で遊んでから帰っていきました。'),
  ('713cd0ed-7f2b-5c8d-9579-b4c3d602f96f', '0d16e234-e60d-5fdb-978f-1722acf9a2b2', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-10-16', '16:30:00', null, '通常 / ピンポン完成！！', '教室来たのが授業開始直後だったので、またゲームに気移りしてしまうのかと思っていましたが、「今日何すんの？」といいつつピンポンゲームの作成画面を開いてくれました。やる気が最初からやる気を続くように、カードのコードを見せつつ作成していきました。変数でのスコアは何度もやってくれたので、そこのところはカードを見ずに作成ができていました。クリアまで作成できて、鬼滅の無一郎バージョンのゲームが完成できました。1つ完成できたので、残りの時間は30分程度ありましたが、ゲームで遊んでくれました。', null, null),
  ('2e644fd6-e034-57bc-aa62-43710134680d', '57f45872-1f3e-5540-b676-bf9023444e39', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-10-16', '16:30:00', null, '通常 / マイパソ本番', '今日はマイパソの本番があったのか、それで授業気分は終わったらしく、前回までのゲームを遊び倒していました。ほかのことを提案しても、気がむけずやらずに終わりました。教室を歩き回ったり、他人のパソコンをちょっかいかけたりでした。その調子が、17時半に影響するにはまずかったので、うるさいまたは邪魔と感じるようであれば、厳しめに対応しました。', null, 'タイピング: さほど練習をせずに、本番に臨みました。'),
  ('46575a71-0ad2-5fa8-b014-936e0e3a22d6', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '5e39d6ee-e2e6-54dd-a7f3-0368008373da', '2025-10-16', '16:30:00', null, '通常 / 1級問題つづき', '前回の検定練習の続きをやっていきました。検定の時間が気になっていたので、50分と答えたら、「短すぎてできないよ、だったら2級だけの受験にする」とのことでした。続きの修正をやっていき、読み終えて確認したら、複数のバグが見当たりました。問題を読んでいて、コードがわからないということは少なく、読み間違いによるミスが多かったです。変数に座標を入れるところを座標に変数を入れたり、動きのブロックを座標異動ではなく、何歩動くになっていたり。修正部分もやり方を聞いていましたが、おおむねミスは少なかったです。', '2級の練習', null),
  ('5a0569d7-f345-58f9-b093-d994f732905b', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-16', '16:30:00', null, '通常 / 検定練習', 'ロブロックスコースに行くためという目的を出したところ、今日はすんなり検定問題を解いてくれました。「①のあとに②」「a,bの順で」といった記号を読み取るのに苦労していましたが、その記号が何を指しているのかを一緒に確認すると納得できたようでした。また、「回転方法を左右のみにする」「端に触れたら跳ね返る」など使用頻度がやや低いブロックを忘れかけていましたが、自分で探し出せていました。いつもに比べると集中して進められ、全体の7割くらいできました。', null, null),
  ('deee595e-fe1c-5df7-8dcb-1907f75969ea', 'f3102a36-fdd8-574f-bf3c-85723faf424f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-16', '16:30:00', null, '通常 / スキルチェック', '自分の作品を作りたがっているので、そのためのスキル確認をするということでやってもらいました。変数の中身をだんだんアップデートしていくやり方は理解していたようで、ほぼ自力で試行錯誤しながら作っていました。猫を加速させていく問題では、普通に作るだけでは物足りなかったようで回転させたりクローンを生成したりしていましたが、変数の大事な部分は取り入れられていました。', null, 'タイピング: 本番をやりました。先に本番をやっていたこたろうくんに続いて奥の席に移動し、頑張っていました。'),
  ('1e0086e6-2f98-5f48-80bf-2031920deb8e', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-10-16', '17:30:00', null, '通常 / U13作品完成', '今回が再生最後でしたが、結論から言うと終わりませんでした。今回は、燃えている木を増やして背景で移動しながら消火するようにする作っていました。ただ、燃える木を増やしたことで全体的にコードが重くなっている状態です。決してバグが発生していないと思いますが、最後の方がそれが気になり終わりませんでした。おそらく、すべてを消火し終えた後の話が作れていないので早急に対応すべきです。 以下気になったところ 黄色のボタンで背景を移動したら、戻れなくなっているので、直す時間がなければ、木のスプライトを9から3に減らしてもよいかも(全体的に重いため) ディラックを常に最前面に持ってこれたら見栄えはよい', null, null),
  ('d22b4f53-8254-56a2-8f3b-d3fdc963bbe8', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-16', '17:30:00', null, '通常 / 大会準備/スライド', 'スライドは一から作り始めましたが、前回入賞作品のスライドなどを参考にしつつ、もくもくと形にしていきました。ゲーム本体には未完成の部分が残っていると言っていましたが、スライドに載せるスクリーンショットは調達できていました。最後まではいかなかったのでオンラインで対応する予定です。', null, 'タイピング: 早くスライド作成に行きたいというのもあり、数回練習するとさらっと本番を終えていました。'),
  ('d74d9060-a4a9-5100-a7f4-10ea9e3d625f', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-16', '17:30:00', null, '通常 / 大会準備', '周りの人と話したりして集中力がもたない中でしたが、締め切りが近づく危機感を持ってなんとか進めていました。使用対象者や開発環境から一つずつ埋めていき、最低限の構成はできました。ゲーム内容の説明などもう少し肉付けしたい部分もあるので、comiruで連絡を取りながら対応する予定です。', null, null),
  ('860cf03d-1fed-54c1-b17d-2cbc551d2d38', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-10-16', '17:30:00', null, '通常 / マイパソ本番、検定練習', 'タイピングで30分くらい費やしたので、残りは3級の練習をやるだけになりました。おばけの問題で答え合わせ浜でできていませんが、出来上がったものを見ると、即ゲームオーバーになっているので、バグの直しのやり方から次回進めます。', null, 'タイピング: 20分ほど練習をしてから、本番に臨みました。手ごたえはあったそうです'),
  ('313a561c-43dc-50dd-b18d-cac9eeeae646', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-17', '16:30:00', null, '通常 / 検定対策', '検定４級応用課題１ですが、「セリフが消える」というところ以外は、スムーズに回答して、だいぶ時間があまった状態で終了となりました。セリフが消えるは、文字を空っぽにする必要があり、一回経験しないとわからないかもなので、ほぼパーフェクトだと思います。もしかしたら３級でもいけそうかなという感じはあります。次回は、４級の中でも一番難しいのか、もしくは３級の問題をやってみても良いかもしれません、。', null, null),
  ('e3b1b0de-f155-5d71-8bba-9314f9d51be4', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-17', '17:30:00', null, '通常 / タイピング検定本番と検定対策', 'レッスン最初に、随分と長い時間タイピング練習をして、いざ本番を始めようという頭巾k、なかなかスタートボタンを押せず、結構緊張しているような素振りを見せていました。結果の感触としては、いつもの練習と同じくらいだとのことです。その後、検定２級応用課題２の途中から始めました。最後までやってみて、実際に動かしたところ、見本通りに動かな買ったので、その原因探しをしているところで時間になってしまいました。何箇所が間違ったところを一緒に見て行ったのですが、問題の理解度がまだ少し足りないと感じました。「１が終わった後に、◯のメッセージを送る」とかいう問題があったとして、１が終わる、のが具体的に何をしたら終わりなのか理解しないまま進めていた。みたいな箇所が２つほどありました。それ以外にもまだ、間違いはありますが、次回その部分を見ていて、間違いの原因を深掘りして行って、同じ間違いを繰り返さないようにして欲しいです。', null, 'タイピング: 本日検定本番だったので、だいぶ長い時間タイピング練習した上で挑みました'),
  ('f74c4449-efb5-588e-9431-530e6202572b', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-17', '17:30:00', null, '通常 / U13大会ゲームの仕上げ', 'U13ゲームのブラッシュアップをしていました。ミニゲーム部分（コーラを操作して、前から迫ってくる車をよけまくるゲーム）の細かい仕様で悩んでいたので、一緒に考えて改善していきました。大体完成はしているのですが、本人的にはまだ気になるところがあるようで、家で納得できるところまで作り込んで、家から作品を提出するとのことでした。途中、晴くんにちょっかいを出したり、他の子のゲームを見たりしていつも通りの感じでした。', null, null),
  ('df9b37e4-c6f1-5e35-a425-e62055bb0177', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-17', null, null, '通常 / ロブロックス', '魔法のレンガブロックを、特に問題なくスムーズに完了させて、まだ時間が余裕があったので、憧れのマイハウスを途中までやりました。デジタネのステージ１は、中学生レベルだと、正直だいぶ飽きるかもなあと感じますね。瑞くんも、ロブロックスを始めた初期の頃のような、ロブロックスに対してのやる気が最近小さくなったと感じます。次回ちょっとそれとなく聞いてみて、進め方を考えてみたいと思います。', null, '時間帯: その他'),
  ('dfcfd52c-1cf7-5e53-b12e-c588dd4b00d8', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-17', null, null, '通常 / ロブロックス', '最初に質問があるということで、その対応をしました。Partに穴を開けたりして形を変えることはできるか、という質問だったので、そのやり方を教えました。（Partを二つ用意して、片方のPartをnegative設定して、両方のPartを選択して、Unionすると、二つのPartの重なっている部分で、、片方がnegative設定のところが繰り抜かれて形を変えることができる）デジタネでは教えていないが、とても役に立つ小ネタです。こういう小ネタ集を作ってみんなに教えられたら良いなと思ってます。ともかく、りょうやくんが自分から積極的に、やりたいことで、できないことのやり方を聞いてくれて嬉しかったです。早速教えたやり方で、自分の家を作っていました。入口や窓を、壁をくり抜いて作っていました。少しでも身になったら嬉しいです。憧れのマイハウスはまだ完了していませんが、動画で教えられたこと以外のことにも手を出して、いろいろ作っているようなので、良い感じだと思います。', null, '時間帯: その他'),
  ('95b449b3-f4b5-5288-8598-f43c27f7fb8b', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-18', null, null, '通常 / ロブロックス', 'ハラハラピンボールの確認テストから始めました。問題文をしっかりみないまま回答して一つ間違ったのと、覚えてないとそもそも正解できない問題の２問間違えました。なつめちゃんだけじゃなく、他の人も全般的に言えるのですが、問題文をきちんと１００％理解しないまま答えてしまい間違う子が多いので、「しっかり問題文を理解してから問題を解く」ことの重要性を伝えました。次に、未来へジャンプに進んで、X,Y、Z座標の概念の説明がありましたが、Vector3のことについてデジタネだと、そういうものだから気にしないで進んでと言っているけど、少しだけ、Vector3の概念を初心者にもわかりやすいように伝えたつもりです。それ以外は問題なく自走していました。', null, '時間帯: その他'),
  ('7b1aaf09-6806-5b4f-a251-e9977ec74915', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-18', null, null, '通常 / Roblox', '折を見て、わからないところ、モヤモヤする部分とかないか聞いてみましたが、大丈夫とのこと。問題なく自走しているようには見えましたが、今日はコロコロボーリングの途中（残りは後半ちょっと）からだったので、すぐ終わって確認問題に進むのかなと思ったら。そこまで辿り着きませんでした。進みが若干遅いのが気になります。進め方に非効率的なところがあるのか、それとも、Partの操作等に時間がかかっているのか、理解に時間がかかっているのか、ちょっと様子を見てみたほうが良いかなと思いました。', null, '時間帯: その他'),
  ('a7230b0f-050e-5ab2-938e-1ebe65617200', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-18', null, null, '通常 / U16プレゼン資料作成', null, null, '時間帯: その他'),
  ('eba2ca7d-e00c-512c-abb1-8cf00d8b931f', 'ec153bd8-5b4d-5684-9704-382af23cf64a', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-18', null, null, '通常 / 検定練習', '前回、「コスチューム名」と「スタンプ」、「このスプライトが押されたとき」のブロックは初めて使ったので、記憶の定着をはかろうと復習したところ記憶は残っていました。その上で今回の問題に入りました。演算ブロックがやや難しく、いつも使うものとは違う掛け算と割り算の記号を取り違えていました。ただ、「～の切り下げ」は初見でしたが自力で見つけ出せていました。また、最近使った「ではないまで待つ」に既視感を感じるくらい定着していました。難しく感じたところもあったようでしたが、全体的によくできていました。', null, '時間帯: その他'),
  ('b47b419e-8fb9-54dc-a6e0-28e23a0a6e09', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-18', null, null, '通常 / オリジナル作品完成を目指す', '検定練習をやる予定でしたが、今作っている恐竜シューティングゲームが完成したら検定に移ることにしました。弾丸をうった回数によって銃の威力を変えるという処理の作成で詰まっていました。こういうときに撃った回数を変数で管理するのには慣れていないようでした。「いつ変数が増える？」「変数がどうなったら威力を変える？」と一つずつ問いかけながら進めたところ、理解を伴いながら作成できました。敵が倒れて爆発したときのコスチュームを用意する際、アルスタジオのスプライトには良いものがなく、フリーイラストの使い方を学びました。 ゲームとして一通り成立するくらいにはできてきたのですが、何を持って完成とするか聞けなかったので次回確認したいところです。', null, '時間帯: その他'),
  ('71a75384-1d70-50dd-80e6-d07b1e2687e0', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-18', null, null, '通常 / ロブロックス', '息抜きのロブロックスゲームの合間に、デジタネでのレッスンを進めていました。今日から、ステージ２が始まりどんどん理解が難しくなるのですが、今日はアスレチックで冒険（全編）の６０％程度完了したところですが、今のところは何も質問なしで進められました。', null, '時間帯: その他'),
  ('f458c67a-64dd-5d19-b0f2-fe626cd38115', '40a476bc-72a5-5bdc-ab75-e89d5310b442', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-18', null, null, '通常 / 検定に慣れる', '初めての検定練習は前回やったようですが、記憶が抜けている部分が多かったのでもう一度説明しました。「このゲームをリニューアルしてもいい？」と質問が来たので、「設計書の部分が終わったあとならいいよ」と答えると納得してくれました。序盤は一緒に一文ずつ読んでいきましたが、残りは自力でできた部分が多かったです。難しい所は音読するなどしっかり読み取ろうとする姿勢が見えました。「まで繰り返す」や「コスチュームを～秒ごとに変える」など前回学習したコードは、少しヒントを出せばだいたい思い出すことができていて成長がありました。', null, '時間帯: その他'),
  ('c3eb695e-e306-5b51-b723-472086e3f1f6', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-18', null, null, '通常 / 検定練習', '今日の午前中は体調が悪く欠席の予定でしたが、回復して元気になったそうなので来てくれました。最初は頑張っていましたが、徐々に集中が切れて、中途半端に問題を解いたり遊んだりを繰り返していました。体調も万全ではない可能性があるので無理をさせない選択肢も残し、「休憩か検定かどっちかに振り切ろう」と促すと、「検定やります」とやる気を見せてくれました。 一通り最後まで解いてテストプレイしたところ、ゲットする枚数の変数が変わらないバグがありました。結果としては、スプライトの名前の指定間違いというちょっとしたミスでしたが、コードが複雑なため発見するのに時間がかかりました。2級になるとバグ直しが難しいと不安がっていましたが、それでも合格圏内にはいると伝えて安心してもらいました。', null, '時間帯: その他'),
  ('9a0530ca-d41b-58ed-be27-070c6582ea3d', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-18', null, null, '通常 / 検定対策', '前回よりちょっと難しく感じたようです。まだ、検定に慣れていないのか、途中まで進めてうまく動かないところがあると、問題文を読み返すではなく、ブロックを差し替えたりして動きを確認していました。そして、なかなか思い通り動かなくて、そこでスタックしてしまい、かなりの時間を使ってしまったようです。結果的には、問題文の読み飛ばしがあったようでしたので、きちんと問題文を一字一句読んで理解してねと伝えました。わからないところで時間を使い過ぎてしまい、時間内に終わらせることができませんでした。次回は、問題を最後まで解いて、答え合わせして、うまく回答できなかったとこの振り返りをしてほしいです。', null, '時間帯: その他'),
  ('32693260-9d7b-507c-8d04-7d3e164ce683', '31feac25-f850-5d21-8e43-ed4d7badb6a0', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-10-18', null, null, '通常 / 検定練習', '今回は、25分くらいで解き終えていました。答え合わせ前に、自分で見直しすると、座標の打ち間違えを発見して、自己解決でいていました。それで、答え合わせすると、「何秒待つ」が1かっしょ抜けていました。読み飛ばしによるミスなので、能力的には4級は余裕そうです。ためしに3級やるべきです。 アレンジは、ねこが暴れまわって、片づけを妨害する大変愉快なものになり、授業終了まで取り組んでいました。', null, '時間帯: その他
タイピング: 授業前にかなり進めていました。'),
  ('6c651e02-805e-5777-92a3-29615aecaa09', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-10-18', null, null, '通常 / 検定練習', '前回体調不良出来なかった、1級2回目をやっていきました。やっている際中で、あおしの悪い癖が出たな感じでした。まず、コード作成中に試遊で遊びすぎてしまう。1級はある程度形が出来上がっているので、それ楽しくなってちゃうのがコード作成滞ってしまう場面が何度かありました。コード作成の中では、もしの含む範囲がずれてしまう。これは検定中であおしはよく発生していたので、今回も起こっていました。寄り道をするなとは言いませんが、ほどほどにしてほしかったです。。6割程度しか進んでいないので、次回はしっかり終わらせましょう。', null, '時間帯: その他'),
  ('df5c4590-edde-565f-88c9-c7ad928a81f2', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-10-18', null, null, '通常 / 検定練習', '今回自由気ままな日でした。始まっても15分くらいはscratchで遊んだままで、アルスタジオに戻ったらそこでも遊ぶ。検定問題だから完成形を一度遊びたい気持ちはわかるが、動画で我慢してもらいました。そこから検定の問題作品に移ると、音楽をいじり始めました。これまでに5分に一度くらいは設計書見ながらコードを作ってみない？？と話しかけてみても気が乗らない日でした。少しやる気になったのは、授業終わり5分前くらいで、ステージの部分をやりましたが未完でした。次回は気が傾けばよいと思います。', null, '時間帯: その他'),
  ('9add67bb-fa05-5d75-b144-df6c0741f346', '5b56509a-ab37-5b95-9b2b-2750525ad8a5', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2025-10-18', '17:30:00', null, '通常 / 大会書類作成', '書類の最終仕上げをやっていきました。２D視点で３Dを楽しむ作成する技術のすごさをうまく伝えるために、創意工夫を集結させて作成しました。ほぼほぼ出来上がりましたが、最後に、このゲームをやる意義を何を得られるかを追加するとなおよいということを伝えました。', null, null),
  ('ffff66e3-54c3-5dcc-8361-8681fba10fc0', 'd3885e29-ee68-501b-bf31-6c050fd50c36', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-17', null, null, '通常 / 基本操作の定着', '検定は受ける気がないようなので基本操作を進めました。キャッチゲームを前回どこまでやったか復習したあと、続きからやりました。途中は集中が切れて他のゲームを作ってしまったのですが(適当にクローンを大量生成していました)、終盤はここだけ頑張れば完成だよと声をかけて、メリハリをつけて終わらせました。普通のリンゴと金リンゴで得点を分けたり、一定の得点でクリアにしたりと、変数を使いこなす練習になっていました。', null, '時間帯: その他'),
  ('99600b8c-375d-5e42-9cbb-7265a02b0e4f', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-17', '16:30:00', null, '通常 / 検定練習', '早い時間で余裕そうに解き終わったので答え合わせしました。大枠は正解していましたが、ケアレスミスが若干目立ちました。「～にする」と「～ずつ変える」の間違いや不等号の向きなど、原理はしっかり理解しているものの注意不足によって起きたミスが複数ありました。 以前4級を合格した時に満点だったのもあり、今回もできるなら満点を狙いたいということでした。解き終わった時に見直しすることを勧めると、そうする気が出たようでした。', null, null),
  ('22d8f25e-d099-58d5-aa14-895f638b0642', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-17', '17:30:00', null, '通常 / 検定練習', '今日は「16:50になったら始める」と本人と約束したおかげもあってか、すんなり検定に取り組んでくれました。また嫌になってしまわないように「気楽に、できるところまで」と伝えて始めてもらいました。結果として集中が続き、全体の9割くらい解けました。2級特有の修正問題に慣れず戸惑っていましたが、どういうコンセプトの問題か説明するとすぐに飲み込んでいました。次回もやる気が続くなら、 終わっていない部分を解く+答え合わせ をできると良いと思います。', null, null),
  ('64067ba4-b466-5e39-ac40-141b961b1951', '10db50c3-a153-502a-b455-c67362b9871c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-17', '17:30:00', null, '通常 / 検定練習', '前回検定1級の1回目の問題に挑戦してもらいましたが、トラブルが発生して途中までしか進めませんでした。そこで今回は、もう一度最初から取り組んでもらいました。 その際に、 *合格ラインは6割なので、まずは全体を終わらせるのが大切であること *仕様書と違う方法でやりたくても、試験では指示通りに作る必要があること といった基本的な考え方を伝えたところ、しっかり理解してもらえました。解き終わると、お手本ムービーとよく見比べて自分のゲームとの違いを発見していました。その原因を探るため答え合わせすると、 *「もし〜なら」の条件範囲の間違い *修正問題で不要なブロックを削除し忘れていたこと といったミスが見つかりました。本人は少し不安そうでしたが、「合格ラインには達しているし、慣れれば完璧になるよ」と伝え、前向きに終わりました。', null, null),
  ('3c3ae39d-bccc-53c8-b7b5-936ffc518125', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-17', '18:40:00', null, '通常 / Excel', '新しい範囲に入りました。最初は頑張っていたのですが、一つ問題を解いた時点で「あまり調子が良くないので今日はExcelをやめたい」と申し出がありました。その後は、U13締め切り直前となったたつきくんに、ランキング機能などのアイデアを出してあげたり、バグの原因を一緒に探したりしてあげていました。', null, null),
  ('d96de5ef-f2d6-587b-8619-87ecc314f4bc', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-17', '18:40:00', null, '通常 / 大会提出', 'まずは、前回作成したベストスコアのクラウド変数を確認したところ、中身が全く更新されていませんでした。原因のあたりをつけて一緒に確かめましたが、異変はなかったので全体から探してみました。すると、不必要な所で「他のスクリプトを止める」が挟まっていたので削除し、他のブロックも順番を整理するなどしました。結果、クラウド変数はきちんと動くようになりました。 その後、時間がまだ余っていたので何か足せる要素はないかと考え、とらのすけくんからの助言もあり1位だけでなくその下もランキングをつけることにしました。最初はリストを使って記録する計画でしたが、製作時間との兼ね合いもあり、アルスタジオの「ビンゴおじさんたたき_ランキング」のコードを引用することにしました。元コードとは変数名や不等号の向きを変える必要がありましたが、試行錯誤して今回のゲームに合う形に編集できました。 最後に提出作業に入りました。作品をアピールする部分で少し悩みましたが、誰が遊ぶとどんなメリットがあるのか考えてもらうと「暗算能力を鍛えたい人におすすめ」「クラウド変数で世界中と競える」とバッチリ表現できました。レッスン時間を過ぎても最後までやり切り、達成感を感じたようでした。', null, null),
  ('ae02a56c-c2b9-5476-841c-4535b5f3c605', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-10-20', '17:30:00', null, '通常 / Prg29の続き', '前回の続きから作成していきました．ステージ番号の管理についての理解がイマイチだったため，その部分を意識していきました．途中で止まることなく最後までしっかりと完成させることができていました．アレンジ部分では電車のデザインを作成していました．大会でも作成していたようにかなりこだわって作っていき，知識やスキルがよくわかるものとなっていました．', null, null),
  ('9821487d-9ae0-52f6-a047-349b5a86aadd', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-10-20', '16:30:00', null, '通常 / 検定練習', '2度目の検定練習をやっていきました。授業最初は遊びが続いていたので、やり始めたときには幸助君の方が進みがっ早く、追いつこうとやる気が出ていました。内容としては、順調に読み進めていって、4級ではつまずきやすい「まで繰り返す」のところも止まることなく作れていました。ただ、⑤ ③のあとに～～の文章では、そのまま④のコードの後に作ってしまっていたので、そこはこちら側から訂正しながら作り上げていきました。アレンジも含めて30分もかからずに出来上がったので、問題文を読んで、読み飛ばしを少なくできればと思います。', null, null),
  ('57acc4e0-0292-55c1-8eef-d939139d81a3', 'e22d8f70-f1a1-5ca4-9ed4-4d27cb0e164f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-10-20', '16:30:00', null, '通常 / 検定４級サンプル問題', '今回から検定に向けての対策を始めていきました．以前1回だけ検定問題をやったことがあるようですが，本人が忘れていたようなので1から始めていきました．今までにやったことのあるものも多く，特に悩むこともなくスラスラと解けていました．難易度としては問題ないようなので，あとは検定の形式に慣れていくためにひたすら練習を積む必要があると思います．残りの時間でアレンジを行っていき，キャラクターのスプライトの色変更などを行っていましたがコードについては触れていなかったため，次回以降のアレンジの際にはコードにも触れていきたいところです．', null, null),
  ('6674e62e-cd11-535f-8417-b7551b01b874', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-10-20', '16:30:00', null, '通常 / 検定練習', '検定練習は初めてではないものの、前回やったことは全く忘れていました。でもやり始めると、わかんないよと言いつつも着実にコードはくみ上げることができていました。「まで繰り返す」も使いこなせていました。ただやっている最中に、よそ見をすると、その後のコードが全く違う場所に組み立ててしまうことがあったので、問題文とコードとの集中を切り離さないことは必要です。アレンジも含めて30分もかかっていなかったので、時間は余裕があります。練習をしてきれいに組み立てられるようにしよう', null, 'タイピング: 本番の日でしたが、ホームポジションではなくローマ字での登録になってしまい、ローマ字では練習ではほぼできなかったです。なので、今回は見送りにして来年がくくんとともに受けるように切り替えます。'),
  ('c1a5e47f-527b-57bb-bc44-2ee60df3b2d1', '5e1dea40-5c67-55ca-a3d8-e696d9b49163', null, null, '2025-10-20', '17:30:00', null, '通常 / コードの基礎を使いこなせていこう', 'コードを探して持ってこられることを目標に追跡ゲームを作っていきました。左右上下の移動を作る際に、最初は左のコードを見本としてともに作っていきました。そこからほかの方向のコードを作るときに何を持ってくればよいか考えながらやっていきました。その際、縦横の座標や＋ーの方向なども確認できました。途中で、スプライトを変えたいと一度作ったコードが全消しになりましたが、再度いちから自分で覚えたてのコードができる体験ができてよかったと思います。その後、「に触れる」や「もし」のある場所を色を覚えながら作成していきました。最後に、スコアの変数の付け方やり満足げで授業を終えることできました。次回からまた検定問題に戻して形式に慣れていきたいです', null, null),
  ('e97a36a6-da76-56f9-b903-ebce218a3687', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, null, '2025-10-14', '17:30:00', null, '休み（未対象）', null, null, '備考: 微熱のため'),
  ('659e2ff2-dc34-5122-80d0-e3fb1dfb38d9', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-10-14', '16:30:00', null, '振替 / U13大会作品作成', '締切間際のため、残っていた振替分を2回分使用して、2コマ連続の授業をしました。 16時半ではやる気もあり、前回ゆき先生との授業でやり方のめどもついてきたためか、一生懸命に続きを作成しようとしていました。 ただ、ある程度構成が決まっていても、自力で同じように作成していくにはちょっと疲れていたようで、雑談をすると少しは目を覚まして手を動かしますが、講師が席を外すとうとうとしてしまう、という繰り返しになりました。 17:30コマの最後の20分くらいは、完全に熟睡してしまって、お母さんがお迎えにいらしてもなかなか起きられないくらいでした。（前日にあまり寝られなかったとのこと） それでも帰るときに、木曜日の授業でなんとか頑張って完成させたい、と帰っていきました。', '木曜日は可能であれば早めに来てもらうよう伝えました。', '盛り上がり: なんとなく完成のイメージができてきたことは嬉しそうでした。'),
  ('a468bfb7-60ac-5f6c-80ee-7ed2a5a42c6f', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-10-14', '16:30:00', null, '通常 / 途中まででも検定問題に取り組む', '検定問題は、思ったよりもスムーズにやり始めましたが、y座標を◎で割った値を「切り下げ」て〇をかけた数値に●をたした値にする、という記述で嫌になってしまいました。 投げ出してウェブニュースを見始めたので、声をかけたら珍しく自分から、「切り下げを習っていない」と申告してきました。文章を分解して読み解くことを教え、主語と述語を意識して「y座標を〇にする」のブロックを持ってきたら、あとは順番に演算式を区切って考えさせ、そこはなんとなくわかったようでした。 一つ一つのブロックはスムーズにできているし、それなりに頭にも入っているようですが、文章でつなげて書かれてしまうと読み解くのが面倒になるようです。 そのあとはしばらく順調にやっていましたが、「新しいブロックをつくる」で撃沈してしまいました。知らないことをここで一つ覚えたと前向きにとらえるようになだめて、引数を使ったブロックを作成するところまでやってぐだぐだと終了。続きは次回かな。', 'ブロック定義の引数の箇所の続きから', '盛り上がり: 順調に進めているときは、淡々と取り組めていたのですが… 雑談から入ると、会話をしながらなんとなく始めようとする感じでした。'),
  ('f681e25c-b2b0-5427-b42b-ac8eeafaa028', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-10-21', '16:30:00', null, '通常 / 検定問題に取り組む、ブロック定義の引数を理解する', '今日はなんだかやさぐれがひどかったです。疲れてるんだよーと言っては机につっぷしたり、体を痙攣みたいにがくがくさせたりしていました。夜はちゃんと早く寝ているそうですが、とにかく疲れていて、面倒なんだよーとぼやいていました。 授業初めにアルスタジオのコード画面のスクロールが少しおかしくて、下までスクロールができなかったのも、やる気をなくす理由になってしまいました。（読み込みしなおしたら直りました） なんとか今日の目的の、引数を使ったブロック定義の意味の説明だけはおとなしく聞いてくれました。前に引数のないブロック定義を自分で作る、というのを学習していたので、なぜ引数が必要になるのかも、理解してくれました。 なんとか休憩をはさみながら、ブロック定義の作成と、定義を利用したコードの作成までやって、作成問題部分は終了しましたが、そこで力尽きました。残りの修正問題は次回だそうです。今日の学習時間はトータルで20分くらいでしょうか(-_-;)', '修正部分からやる予定', 'タイピング: なんとか1度だけやっていました
盛り上がり: 今日はぐだぐだがひどかったですが…会話には応じてくれただけマシ…かな？ 引数の説明だけは、ちゃんと聞いてくれました。'),
  ('78053eec-0c3a-536d-a8e4-35f0c6cf82b7', '1c7005cc-2815-558f-993a-9c7617d34c44', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-10-21', '16:30:00', null, '通常 / フリエをすくえ1', '前回のアルくんの冒険で動画を見ながらの作成に抵抗なく取り組めていたため，今回も動画を見ながら作成を行っていきました．動画を見ながら作る部分に関してはとても素直に作っていき，完成させることができました．しかし，アレンジ部分になったとたんやる気がなくなり遊び始めてしまいました．恐らく，やることの具体的な指示がある場合には手順がわかっているため従ってくれますが，自由な部分ができた際には考えることが難しくなるようで，やらなくなってしまうと感じました．', null, null),
  ('a2c4d4f4-7bc7-55f8-b047-192bddd6d81b', '337872be-4ce4-5436-88f8-5f97e8c5252e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-10-21', '17:30:00', null, '通常 / 検定に慣れ、スキルの穴埋めをする', '基本的な1級レベルのスキルは身についていると思われるので、知識の抜けを確認する意図をもって取り組むことを最初に説明しました。 順調に進めていましたが、途中、座標が変数プレイヤーの速さの値だけ減り続ける、というところがわからないと質問がありました。変数が10のときに、その数を-10にするためにはどうすればよいか、と考えさせていくと、「-1をかける」と導き出すことができました。 また、コードの修正のところでブロック定義の引数が初出だったので、なぜ引数が必要なのか、定義ブロックを使用しているスクリプトを見ながら一緒に考えていきました。今回の課題で使われている範囲については理解できたようです。 質問は上記２つだけで、あとは自力で完成し、テストプレイをして満足そうにしていました。ちょうど授業時間に終了しました。', 'ブロック定義の引数に慣れるため、応用課題2をやってみる予定', '盛り上がり: わからなかったところが解決してすっきりしたようでした。'),
  ('893561ce-606c-50fe-b32c-268065979510', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-10-23', '16:30:00', null, '通常 / 検定練習2級', '本人希望で2級の問題をやっていきました。解いている際中は、せりふを勝手に変えようとしたり、作る順番を紙面通りではなかったりの寄り道をしていますが、変数を用いた条件式などに迷うことはなかったです。言葉のつなぎ方として「リンゴとバナナ」のブロックの活用がわかっていなかったので、教えてその後活用できていました。1通り終わると微妙にバグが残っていてその原因は、数字の読み間違えでした。コードの能力は時間内に終わるほど十分なので、読み間違え飛ばしを注意が必要です。', null, null),
  ('178b4f1d-a356-590f-881d-5f05d2d5b2bc', '05439956-11b9-5ac7-a44a-3e6f5a6831d8', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-10-23', '16:30:00', null, '通常 / 1級検定練習', '2回目の練習でしたが、時間はかなり余裕でミスもなく作り上げていました。1級の問題文は、簡潔に書かれていることが多いので、2通りのコードパターンができる場所も気づけるほど、能力は高かったです。 隔週なので、1級の応用課題1を自宅学習用として持ち帰りました。', null, null),
  ('5929ce2d-69a7-587a-974d-fe7efad54028', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-10-23', '16:30:00', null, '通常 / 検定にきちんと「取り組む」', '口では「ロブロックスをやりたいから検定受ける」と言いつつ、なかなかゲームから離れられずに問題を始めることをしぶっていましたが、本来は30分以内に解き終わる問題であること、これが終わったら自由時間にしていい、と言ったら急にやる気になりました。 あえて虎太朗くんと同じ問題にしたので、二人で1部の問題を見て一緒に進めていましたが、塁君のほうが問題を読むのははやく、知っているブロックなら見つけてくるのも早かったです。知らないとそこで止まってしまいますが…。 「触れるまで繰り返す」というのを条件分岐と混同していたところがあるのと、イベントが切り替わっているのに気づかずにつなげて作り続けてしまって、もとからあるブロックが余る？となったところはありましたが、そこを指摘すると直すことはできました。 「セリフが表示されたまま」のところで、止めるブロックのどれを選ぶのかはわからずに、虎太朗くんに教えられていました。 それでも、前回受験時よりはできるようになったかな…？', '検定4級の応用課題2以降', '盛り上がり: 検定問題を解き終わってから30分、ひたすら楽しそうに遊んでいました。うるさくなると注意はして、一応そのときは素直に聞いてくれました💦'),
  ('a8c464f8-f347-56ad-9250-55b963c82ad3', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-10-23', '17:30:00', null, '通常 / 2級検定練習', '2級の問題を練習していきました。2級問題はほかの級と比べ、癖アリな問題なので、じゃんけんの条件式をあきらめずにできるか見どころでした。そうちゃん自身では、勝ちの条件での変数との対応は自分で考えてできていました。でもこれらを「または」「かつ」で結びつけることは少し疑いぶっていました。そこを乗り越えて自分で作れたのはすごいです。修正の部分のやり方の説明をこちら側から忘れていたが、文章だけで直していくことをすぐ理解できていました。1か所ミスはあったが、35分くらいで出来上がりました。U13大会の中でも変数の扱いが十分に慣れてきてものにできている感じがします。', null, null),
  ('11f6f580-e026-5f18-93ba-ab2484d950d6', '57f45872-1f3e-5540-b676-bf9023444e39', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-10-23', '16:30:00', null, '通常 / 検定問題に「取り組む」', 'ほかの子が素直に検定問題に入ろうとする中、しばらく、いろいろ理屈をつけてごねていました。「ごほうびにつられてやるのは嫌だ」「これに受かったら何かもらえるのか？」というので、検定はあくまでも自分のためで、これに受かったから賞品がもらえるわけではない、と話したら、ちょっと偉そうに「それならやる」とのこと。 塁くんと同じ問題にしたため、プライドもあったのか、最初だけ「問題むずかしい！読むの大変！」と言っていましたが、塁君が問題を読んで進めるのを見てあわてて自分も始めていました。やりだせば虎太朗くんのほうが理解しているブロックもあり（止めるブロックの使い分けなど）、そのあたりは得意げに教えていました。 「まで繰り返す」を「もし～なら」と間違えたのと、メッセージが切り替わっているのに気づかなかったところ以外はほぼできていました。ただ、基本的に自信がないようで、「ここでいい？」と聞いてくることが多かったです。 冗談か本気かわからない感じで、たかひとくんに絡んで、こう先生やたいようくんが引き離すことが何度かありました。からんだ後は仲良くゲームをしたりもしていたので、喧嘩になっているわけでもなさそうなのですが…。 お父さんのお迎えの際は、けろっと良い子になって、別に当たる気はなかったと嘯いていたディズニーチケットの当選も、すごいだろ、みたいな感じになっていました💦', '検定4級応用課題の2以降', '盛り上がり: 自由時間をごほうびに示したら、すごい勢いで問題を解き終えていました。やればできるじゃない、というと、まんざらでもない様子でした。'),
  ('4d8f06b3-7574-51a9-a86a-8daa2043dfd0', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-23', null, null, '通常 / 検定練習', '2級の最初の練習に取り組みました。とりあえずできるところまで自走してもらったのですが、初めて使うブロックや理解の難しい部分が多く苦戦したため一緒に取り組みました。「りんごとバナナ」や「きいて待つ」は、今までちゃんと使ったことがなかったとのことですが、軽く説明すると分かったようでした。「足し算の答えが正解なら」という文が出たときは、どうやってスクラッチで表現すればいいか困っていたのでサポートしました。「プレイヤーの答え=模範解答」という大枠を示したうえで、プレイヤーの答えは？模範解答は？という細部を考えてもらったところできました。終わったのは全体の7割くらいなので、次回は残りを解いて答え合わせしたいところです。 授業後、roblox studioがどんなものか気になったようなので、製作画面を軽く見てもらったところさらに興味をもってくれました。「検定2級に受かれば、相談次第ではスクラッチとロブロックスのレッスンを並行して進められる」という話をしたところ検定のモチベーションになったようでした。', null, '時間帯: その他'),
  ('e7d7c7f0-fae9-57c3-83d0-062818a2b9a3', '0d16e234-e60d-5fdb-978f-1722acf9a2b2', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-23', '16:30:00', null, '通常 / レッスンor自由製作', '今日は休会前最後のレッスンなので、楽しんで終われるように進めました。最初はアル君の冒険のレッスンをやる気になったのですが、そこに宇宙人のようなキャラクターが置かれていたことをきっかけに、「やっぱり宇宙人と誰かが戦うゲームにしたい」と切り替えました。UFOなどの画像を使いたいとのことだったので、画像を保存してアルスタジオで使う方法を伝えました。キャラクターを追加したり消したりして最終的にはあまり残りませんでしたが、本人は楽しくできたようでした。', null, null),
  ('2db9e8bc-cb34-515d-a8bc-f0f1afebb566', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-10-23', '17:30:00', null, '通常 / Excel検定の学習', '日曜日の夜遅くまでプレゼンを作成したのでさすがに疲れが残っていたのか、今日は気分を変えたいようだったので、Excelにしました。久しぶりで忘れていそうということで、基本的な罫線と数式にしましたが、本人の思っていた以上に覚えていてスムーズにできたようで、ほっとしたようでした。 残り時間はなんとなくScratchをいじっていました。 授業の終わりごろから、SFミステリーを読んでいて、時間旅行がテーマのようだったので、筒井康隆の話をふったら、興味深そうにメモしていました^^;', null, '盛り上がり: 思っていたよりもExcelがよくできたようで、安心したようでした。 大会の結果を結構気にしていました。'),
  ('9c0ea7a3-00ec-5099-a94f-43118d4f9abf', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-10-23', '17:30:00', null, '通常 / 検定対策', '応用課題3については、成功したはずなのにまとが消えてしまうバグがあると質問してきました。この場合、見直さなければいけないのはどこのコードかというのを考えてもらい、まとのコードを見直しさせました。「かくす」をどこで使っているかを自分で探させましたが、コードだけ見て「あっていると思う」という感じだったので、問題文をもう一度読ませました。結局、「メッセージ成功を受け取ったとき」と「メッセージ失敗を受け取ったとき」の2つのイベントのうち、後者を見落としていて、すべてのコードを「成功」のところに作成していたのが原因でした。 本人も指摘されれば納得できるのですが、細かい問題文の見落としをしがちなので、線を引くなど問題文にもっと注意させるよう促した方がよいかもしれません。', null, '盛り上がり: バグが直せた後は、コードをほかの色に複製してすぐに直すことができ、完成したゲームで遊んで嬉しそうでした。'),
  ('c0f99e52-0a0b-5f9f-8b3c-6adfadbc5588', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-10-17', null, null, '通常 / 検定の対策', 'タイピングの本番後でしたが、おとなしく問題に取り組んでいました。 たまに眉を寄せるのは、真剣に考えているときなのか、苦戦しているときなのか…までは、ちょっとわかりませんでしたが💦 概ね自力で解けていて、一通り終わった後に、猫の動きがムービーと違うと自己申告してきました。 問題文とコードを見直すよう促し、ヒントとして、どういうところがおかしいのか→猫が歩かない→歩く動きのプログラミングはどこでしている？、と誘導したところ、該当スクリプトのメッセージ名が「メッセージ1」のままになっていたことに気づき、直すことができました。本人もすっきりしたようでした。', null, '時間帯: その他
タイピング: 本番をがんばっていました
盛り上がり: 頑張って取り組めていたと思います。 間違いに気づいて直せたときは嬉しそうでした。'),
  ('ce6fb7f3-7bd5-5e61-8c09-20834bd8d0d5', 'f3102a36-fdd8-574f-bf3c-85723faf424f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-23', '16:30:00', null, '通常 / 検定練習', '前回「検定は自由に作成できないからつまらない」といった反応だったようですが、「まずは設計書通りに」という原則は記憶に残っていたようで、今回は素直に問題を解き進めてくれました。きちんと集中して終わらせたので、「もうアレンジやっていい？」という質問にOKを出しました。本番は制限時間内にアレンジも終えないといけないので、ある程度短時間でできるものを勧めました。その後答え合わせすると、ほぼ正解できていました。設計書と全く同じ動作だがやり方が違う部分(「もし～なら」のところで「～まで待つ」を使っていた)が一つだけありましたが、書いてあるのと同じ方法でもできる？と聞くとすぐに作り直せていました。ただ、崇仁くんオリジナルのやり方の方がむしろスマートだったので、そこはすごいねと伝えました。', null, null),
  ('1ba20905-7861-559f-a179-76ab0c1d25d2', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-23', '17:30:00', null, '通常 / 検定練習', '気が乗らないことを懸念していましたが、「設計書にそってゲームを作るテストだよ」とコンセプトを説明すると乗ってくれました。全部できたらアレンジしてもいいと説明しましたが、むしろそれは苦手だと言っていたので、忠実にお手本を再現することに集中してもらいました。答え合わせすると、コスチューム名やセリフ忘れなどの細かい読み落とし以外はだいたい完璧でした。猫のコードと同じ間違いを馬のコードでもしていたので、馬の方は自力でやってもらうとばっちり直せました。', null, null),
  ('2d019062-f9ab-55f2-85a2-b5dcc9b9af10', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-24', '16:30:00', null, '通常 / 検定対策', '今日は、前回４級応用課題１がスムーズに解けたので３級もいけるかと思いましたが、もう一度４級の少し難易度の高い問題をチェックしてみようと、応用課題４に挑戦。結果、制限時間をだいぶ余る感じで余裕に終わり、アレンジがまだだったので、アレンジもやってもらい、制限時間内に終了。答え合わせをしましたが、細かいミスが二つほどありました、問題文をきちんと読んでいないためのケアレスミスと思いますが、前回も似たようなミスをしていたので、その点注意が必要です。が、合格の６０％には十分届いているので、３級を考えても良いレベルだと思います。次回は３級の初回の問題でも良いかもしれません。', null, null),
  ('a32a4371-1aa7-5af8-b2c8-3b59f686ba3c', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-24', '17:30:00', null, '通常 / ロブロックス→スクラッチオリジナル作品', '今日はロブロックスの日だったのですが、ロブロックスよりスクラッチをやりたいと言っていました。理由を聞いていくと、ロブロックス、、、というか、デジタネの教材があまり面白くないという感じでした。私が、前半は確かにつまらないかもしれないけど、後半はどんどん難しくなって興味が出てくるよ。と言いましたが、あまり心に響かなかったようで、結局、スクラッチのオリジナル作品をつくるということになってしましました。帰り際も、迎えにきたお母さんとも何やら話していて、お母さんとケイト君から、スクラッチ検定の１級の上はないの？と聞いてきて、私は詳しくないので明言は避けましたが、大体１級が受かるような子であれば、プログラムコードを書くようなことをしても大丈夫なので、スクラッチ以外のことも出来る旨伝えると、お母さんから、次のステップになるようなものを進めてくださいというふうに言われました。ロブロックスをどうするか？JaveScriptとかに進ませるか？等考える必要があるかもしれません。', null, null),
  ('210d84d5-ebcb-5e95-89de-e466c8185905', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-24', '17:30:00', null, '通常 / 検定対策', '２級応用課題１の答え合わせから。大体できていたのですが、問題文をきちんと理解していないまま進めたり、読み飛ばしてしまったりというミスが３つほど。それと、なぜか、間違って複製してしまったスクリプトが悪さをして、変な動きになっていたので、そのスクリプトを削除して正しく動くようになりました。何で余計なスクリプトを複製してしまったのかは謎ですが、その不要なスクリプトがおかしな挙動を起こしているということに気づくまでが、ものすごく時間がかかってしまったので、デバッグのコツを少し教えました。残り時間で、応用課題２を進めまたのですが、こちらは、制限時間４０分に対して３０分ほどで終わらせたようです。次回答え合わせからです。今の所、合格圏ではあると思いますが、まだケアレスミスが多いので問題文の読み方を気をつけるように、毎回促して行きたいですね。', null, null),
  ('1b285bfc-6dd6-5e8d-9846-c1e90419eea7', '10db50c3-a153-502a-b455-c67362b9871c', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-24', '17:30:00', null, '通常 / 検定対策', '１級２回目ですが、制限時間内に終わらせることができ、点数も６０％はまあ確実に超えているとは思います。まだ、検定をしっかり読んで、問題文の書いてある通りにするというところで、ちょっとしたケアレスミスが散見されるので、そこを気をつければ、高得点で合格もできるかなというところ。しかし、原因不明のバグ？というかおかしい挙動が発生して、私もコウくんも原因を特定できませんでした（スプライトを最背面に設定したの全面に表示されてしまう問題）ので、ちょっと気持ち悪い状態で終わりとなってしまいました。', null, null),
  ('3f2fc7c7-dc0c-59ba-85fa-ef65e2932d8f', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-24', '17:30:00', null, '通常 / エクセル', '最初に、U16作品の状態を聞いたら、まだ完成していないので、U16をやりたいとのことでしたが、エクセル検定の話をして、検定に向けてエクセルを頑張ってみようかと促してみて、「はい」とのことだっので、今日はエクセルを実施。３０時間はまだ手付かずだったので、一緒にどの辺からやってみよっかと話し合い、１〜３章までは既にわかっていそうな簡単そうなところだから、4章から始めようとなりました。レッスン時間中は、黙々と自走していて質問等もなくスムーズに終わったようです。', null, null),
  ('56a869e5-2614-56f4-ad18-59c0a7ee6358', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-24', null, null, '通常 / エクセル', 'レッスン開始時に、エクセル検定を受けて欲しくて頑張ってほしいというような話をしました。反応は薄いものの、はいわかりました。日程が決まったら教えてくださいとのことでした。今日も、特段質問点もなく、自走して終了しました。', null, '時間帯: その他'),
  ('3b77970a-4aea-5b1e-a81f-188263b455b4', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-24', null, null, '通常 / ロブロックス', '前回からの続きで、デジタネ通りの家づくりではなく、私が前回教えた小ネタ（Partに穴を開けたりして形を変える方法）を使って自分のオリジナルの家を作っていました。教えた小ネタを使ってPartに穴を開けると、たまに、当たり判定がおかしくなることもあって、穴を開けたのにそこを通過できないみたいな現象が起きたので、当たり判定を可視化する方法と、当たり判定を正常にする方法を教えました。ひとまず、りょうやくんは顔にはあまり出ていませんが、デジタネ通りではない自分なりの作品作りを楽しんでいるように思います。', null, '時間帯: その他'),
  ('e5ee579d-ca10-5693-802e-f79d72215ecd', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-25', null, null, '通常 / エクセル検定対策', 'エクセル検定を受けてほしい旨を伝えて、OKとのことで、エクセルの対策を実施しました。実習４７で、処理条件の「それぞれ条件付き集計の関数を利用して分析結果を求める」の部分が分からなかったようで、その部分を教えることで理解してくれました。実習４７の途中で終わったので、次回はその続きからと思います。', null, '時間帯: その他'),
  ('b2c24970-f76b-57d4-824d-71848215ba9a', '31feac25-f850-5d21-8e43-ed4d7badb6a0', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-25', null, null, '通常 / 検定対策', '前回まで４級問題を解いていたが、結構余裕を持って合格できる感じだったので、今日から３級問題を実施。制限時間内に、終了していました。結果としては、問題文通りに回答できていない箇所が複数箇所あったので、その点気をつける必要はありますが、十分合格点に達しています。次回以降、問題文の書いてある順番通りにブロックを追加することをしっかりと認識させた上で開始お願いします。', null, '時間帯: その他'),
  ('b5a48f39-58da-54f9-bd96-6173f8bf8d4d', '655ad2c9-dfb5-5fc7-b41a-1d784603c1d0', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-10-25', null, null, '通常 / 検定連取', '今回の問題は順調に進んでいきました。やっている最中も、特に迷うことがなくミスなく完成することができました。アレンジはそれぞれの色合いを変えて、色豊かになっていました。時間以内に終わっているため、3級にチャレンジしてみてもいいかもしれません。', null, '時間帯: その他'),
  ('e3b79414-3dd9-5de9-aa3e-dc7f5db90fcf', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-25', null, null, '通常 / 検定対策→気乗りせずできず', '前回全然進めることができなかった検定問題を、今日も挑戦しようとしていたが、今日も検定に集中することができず、録音でホラーの音を作ったり、検定とは別のことをしていました。なかなか検定に取り組んでくれる状況ではなかったので、やりたいことをそのままさせることにしました。最後の方は、ビット絵を作るツールで、ハロウィンの絵を描いて楽しんでいました。今回、検定を受けられるのか？ちょっと疑問符がつくような状況だと思います。', null, '時間帯: その他'),
  ('aa2125c0-0568-589b-986f-3f8945f0f9ff', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-10-25', null, null, '通常 / ロブロックス', 'いつも通り、ロブロックスで遊び、デジタネを進めるの両方を進める形でした。ステージ２に入って、少し難しくなると思うので、分からないところがないかをしっかり確認するようにしていますが、本人はまだ、分からないところはないよ。とのこと、だけど、確認テストに挑戦している時、横で見ていたのですが、スクリプトの動きを説明する問題を全く理解できていないところがあったので、１行ずつ、プログラムの動きを説明して理解してもらいました。教えれば納得してくれたのですが、正直、デジタね教材は、ささっと分からないところもすっ飛ばして進めているような気がします、ステージ２はその点、放っておくと、全然分からなくなる可能性があるので、注意深く監視していきたいと思います。', null, '時間帯: その他'),
  ('e651b5b1-75dd-55cf-9732-a1b91fe54209', '82396ac6-71bd-59d4-a372-57212866fd5d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-10-25', null, null, '通常 / 検定練習', '始める前に、前回の注意点のバグが発生すると、コードでしか検討しなくなることを伝えて、問題文も見るようアドバイスをしました。進めていくと、バグが発生していました。マウスで触れると動くはずなのに動かないことわかっていたので、「問題文で見直してみよう」と声を掛けました。けど、書かれてもいない「ずっと」で入れて直そうとしていました。「ずっと」を使わなければいけない謎の信頼感があるようです。そこで紙の方へ視線を誘導させて、自分で間違え個所を探して直すことができました。この直しの作業もあっても、30分以内で終えました。バグ直しが苦手なようなので、読み間違えをなくすこともアドバイスしてください。', null, '時間帯: その他'),
  ('5be10de8-c790-5f46-8199-00ce4f92823c', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-10-25', null, null, '通常 / 検定練習', '今回の問題は、悩む様子もなくスムーズに溶けていました。それで、30分もかからずに解きあがり、ミスもなかったので、検定の能力は十分についています。あまりにも早く解いたので、隔週なのでもう1問やるか聞いたら、2つ目はいいですと断られました。残り時間はスクラッチで遊んでいました。', null, '時間帯: その他'),
  ('dcf5c5e0-2575-5de7-b131-bc5c40c1d0d5', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-10-25', null, null, '通常 / 検定練習', '一通りは素早く解いてくれるが、今回、バグが多かったね。そこで半分くらいは見直しで変数の違いや入れ忘れ直せていました。それでも、まだ残っていたので、問題文の見直しを進めました。検定時間内に見つけられなかったら、もう答え合わせをするもとで、やってもらいました。ゲーム自体の遊び方が間違っていたので、その方法のアシストもしました。それでも見つからず、答え合わせで、もしの範囲の違いで残っていました。直す力はあるのだが、一発目から正しく作ることが今回はよくなったので、時間も余裕があるので、丁寧に作ってもらいたいです。', null, '時間帯: その他'),
  ('e1cd0c6b-c26c-5f8b-ac4a-44a99dc480ca', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-10-21', '17:30:00', null, '通常 / 検定１級②', '今回は少しレベルアップした内容に挑戦していきました．大体の部分はしっかりと完成させることができていましたが，引数について少しわからないことがあったようなので一緒に解いていきました．また，ビルのクローンの際に９９９層奥にするという処理が特殊なもののため悩んでいました．合格点は取れている内容だったため，このまま１級の問題を進めても問題ないと思います．', null, null),
  ('d5870cad-a2d0-52a2-a29f-7213635685b5', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-10-21', '17:30:00', null, '通常 / 検定２級応用課題４', '本日は眠かったようであまり集中して進めていられないようでした．内容が途切れ途切れになってしまい，一度やった箇所についても覚えていない部分が多くもう一度見直していくという作業を何回も繰り返していました．しかし，作業スピードは早く行うことができており，万全の状態であれば余裕を持って終えることができるスピードでした．今回は８割ほど終了した状態で終わったため，次回で完成させていきたいです．', null, null),
  ('d3f23cdf-866a-55be-87a9-53e38877585f', 'e22d8f70-f1a1-5ca4-9ed4-4d27cb0e164f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-10-27', '16:30:00', null, '通常 / 検定練習', '授業始まったら、今日の検定は何やるんだとやる気満々でした。マウスポインター含む問題でしたが、②のあとなどの1行目もしっかり読んで、検定のやり方に慣れてきました。20分ちょっとで問題文は1度完成しましたが、コスが変化しないバグが残っていました。そこで、その箇所のコードの順番について考え方を教えると、0.1秒待つの追加で入れる場所を修正できていました。アレンジの方では、「うまかった」の後にさらにセリフを追加したり、ヒラメを追加したりにぎやかなものとなりました。ここまで35分くらいなので、能力として備わってきました。', null, null),
  ('360ca6d9-bd48-59b3-804a-ba8fb8a84afb', '5e1dea40-5c67-55ca-a3d8-e696d9b49163', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-10-27', '17:30:00', null, '通常 / 検定練習', '前回まで基礎を踏んできたので、検定練習を試していきました。問題文を読み始めていくと、知識不足からのコードブロック探しに時間がかかってしまいます。4級は基本文章そのままにコードのぶっろくがあるので、「問題文と同じ言葉を探してみよう」をアドバイスをしていきました。だが、文章では「送られる」のところをコードブロック「おくる」がなかなか見つからなかったり、文章「消える」コード「隠す」のような微妙なニュアンスの違いが判らず時間がかかってしまいます。前回、触れるのこーどやったが、これも時間がかかっていました。 また、一つ一つコードを入れていくたびに、「あってる？」のような顔の様子をうかがうことがほぼ毎度ありました。「信じてみよう」「試してみよう」と自分でゲームを確かめるよう促していますが、回数が多かった。少し自力でやるよう先生が離れると、ほかの子を見に行ったり、悩んでなかなか進まなくなるので、どうしたことか、、 1時間かけて問題文は終わりましたが、覚えてもらいたいこととして次回の予定で書いたことを確かめました。次も始める前確かめてください。', 'アドバイス 問題文と同じ言葉のブロックを探してみよう 繰り返しは「ずっと」が書いてあればずっと、なければ「繰り返し」のブロック', null),
  ('115763e7-96b3-5d3f-9ecf-c8a74c8d01fe', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-10-27', '17:30:00', null, '通常', '前回に引き続き遊んで1時間逃げをされてしまいました。10月はなんやかんやサーバー障害もあり、何も進まずに終わってしまっているので、本人も言っていたが、レッツショッピングの記憶がほぼないと思います。情報の整理をお願いいたします。 遊び続けてしまうのも、こちらが絶えず声かければよいのですが、けいだいくんの指導もあり、10月がうまくいきませんでした。', '金曜だとおもうので、りょう先生レッツショッピングの動画では伝わりにくい情報を整理してあげてください。', null),
  ('e8bc271a-38fc-5767-95a0-6f4cd2ad9c08', 'd3885e29-ee68-501b-bf31-6c050fd50c36', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-24', '16:30:00', null, '通常 / 基本スキル習得', '前半はScratchのマイクラ風ゲームに夢中になってしまい、なかなか始めてくれませんでした。「5時になったら始めるよ」と約束し、なんとかレッスンを開きました。迷路を自分で描くところまではできましたが、そこで止まってしまったので「コードは何かしら作ろう」と伝えました。動画を見るのはどうしても面倒だというので、自分で考えて「キャラがマウスポインターについていく」というコードはできました。次回はもっと進めたいところです。', null, null),
  ('6e04f44d-3d90-554a-9876-f29929832ba6', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-24', '16:30:00', null, '通常 / 検定練習', '大枠はできていて合格圏に達していましたが、ケアレスミスできちんと動作しませんでした。確認すると、紛らわしいスプライト名を間違えたり、周りと離れている文を見落としたりというミスでした。途中しゃべりながらやっていたというのもあり、「実力はあるんだから本番に向けてもくもくと集中したほうがちゃんとできるかもね」と伝えました。', null, null),
  ('1c570cf2-f78c-500d-b373-d3860547e02e', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-24', '17:30:00', null, '通常 / 検定練習', '終わっていないところから進めて、一通り解き終わることができました。おそらく正答率6割に達するくらいにはできていましたが、複雑な演算に苦戦していました。数式の部分を日本語で書いたところについて、文構造が取れなくなったようなのでした。「○○に○○○○を掛けた値」というように、何と何を掛けているのかを確認すると理解できていました。この数式によってまた自信をなくし気味になりましたが、手は動かせているし他はできているからと励ましました。', null, null),
  ('9670de23-16de-5758-ae67-6bb2f8be263c', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-24', '17:30:00', null, '通常 / 検定練習', '今回は4級の中で難しめな問題に取り組みました。 「スプライトの他のスクリプトを止める」ブロックを置いた場所と、実際に止まるスクリプトが異なることに混乱していました。どこに置けばいいのか分からない様子だったので、「遠くから止める」というイメージを持たせながら説明しました。また、繰り返しといえば「ずっと」だというイメージが抜けていないようで、「まで繰り返す」ができていませんでした。これらのポイントを一度直してもらうと、同じミスをしていた他の場所は自力で直すことができました。 去年4級対策していたのに受けられなかったので、3級も受ける選択肢がありましたが、とりあえずは4級に専念したほうが無理がなさそうです。', null, null),
  ('a1d66a58-7ef9-5233-ac25-5acb4cd00f35', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-24', '17:30:00', null, '通常 / 検定練習', 'おてほんムービーとアルスタジオをウィンドウ分割で同時に見ながら取り組み、ムービー通りにできているかをしっかり確認しようとする意識が感じられました。しかし、「問題文通りに作ったのに女の子がまったく喋らない」という状況になったため、一緒にコードを確認しました。結果、「メッセージが送られた」という受け身の表現を「メッセージを受け取った」という意味だと勘違いしていたことがわかりました。「（女の子によって）メッセージが送られた」＝「女の子がメッセージを送った」というように、主語と述語の関係を整理していく中で、誤解が解けたようでした。他の部分はおおむねできていました。', null, '盛り上がり: 今日は学校でハロウィンパーティーがあったらしく、そのままスパイダーマンの恰好で来て楽しそうにしていました。授業はちゃんとできました。'),
  ('f56cc7e6-4a91-5c70-96a5-4bfc89ee6945', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-24', '18:40:00', null, '通常 / 検定練習', '使っているブロックはおおむね正しかったものの、2つが入れ替わっていたり、「もし～なら」の中身が異なっていたりと、配置がずれている箇所がいくつか見られました。そのため、「プログラミングでは順番と範囲が大切」という点を重点的に伝えました。 その結果、移動が必要なブロックを的確な位置に差し込むことができ、全体の流れも整いました。集中と休憩のメリハリをつけながら取り組み、予定より少し早めに授業を終えることができました。 ただし、検定問題自体にはあまり楽しさを感じていない様子も見られたため、受験については本人の意欲を見ながら判断するのがよさそうです。', null, null),
  ('de5ac7e9-f05c-5f7b-ac35-cfd64be3140e', 'ec153bd8-5b4d-5684-9704-382af23cf64a', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-25', null, null, '通常 / 検定練習', '2級にはやや余裕あるため、1級をやる選択肢もありましたが、抜け漏れているスキルがないか確かめたいという狙いで今回も2級に取り組みました。だいたいできていましたが、演算の部分だけ苦戦していました。足し算と掛け算を組み合わせた式を作る部分で、計算の順番が間違っていました。そのため、「この文だと最初は何算をする？→掛け算→何かける何？」というように、順を追って細分化していくと苦手意識が小さくなったようでした。「りんごとバナナ」「聞いて待つ」などこれまでの検定練習で出たスキルは身についており、自信になっていました。', null, '時間帯: その他'),
  ('e4b4650d-7a5a-5a73-8fc9-4f4346a0c24a', '40a476bc-72a5-5bdc-ab75-e89d5310b442', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-25', null, null, '通常 / 検定練習', 'スキルはあるのですが集中が持っていなかったので、本番では30分の制限時間があることを確認し、きちんと終わらせる意識を持ってもらいました。 答え合わせすると、「～歩動く」と「x座標を～ずつ変える」のように、同じ動きでも違うやり方で作っている部分が見られました。作成方法まで同じじゃないと「ちゃんと読めてないからダメ」だとして減点されるというコンセプトを改めて説明したところ、採点官の考えがイメージできたようで納得してくれました。アレンジもしたいと言っていたのでしてもらい、アレンジの説明を書くという練習もできました。', null, '時間帯: その他'),
  ('fddf4283-026c-56bd-9d99-922256983110', '28d52d6e-7571-5090-a2d9-492c997b719e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-24', null, null, '通常 / 検定練習', '前回は苦戦したようでしたが、今回は慣れてきた様子が見られました。途中は背景がきちんと遷移しないバグなどもありましたが、自分で冷静にコードを見なおして修正できました。「まで待つ」と「まで繰り返す」を一瞬間違えていましたがきちんと使い分けられました。', null, '時間帯: その他'),
  ('2cce3f76-32a1-5b07-b795-6de97a613e2d', '5b56509a-ab37-5b95-9b2b-2750525ad8a5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-10-25', null, null, '通常 / 検定練習', 'U16が落ち着いて検定練習に復帰しました。スキル的には大丈夫そうなのでレベルやや高めのものをやってもらいました。久しぶりの検定でしたが、複雑なブロック定義もきちんと実装し、U16でやったように複雑な計算式も正しく組み立てられていました。ミスとしては、ブロックの複製時に余計なブロックを増やしてしまった程度で、ほぼできていました。', null, '時間帯: その他'),
  ('582f8f52-e21a-5d9d-8a50-c97e2694e609', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-11-06', '16:30:00', null, '通常 / 検定練習', 'この問題は、ほかの人がやっても凡ミスが多い部類でしたが、その通りに凡ミスが発生してしまいました。ほかのスプライトのパラメータを表す「○○の○○」のブロックがなじみがなくわかっていなかったので、教えてあげました。「にむける」と「に向きの値になる」と混同していたそうです。ほかは「にする」と「ずつ変わる」が間違っていたり、切り捨ての表現がわからなかったり、知らないブロックで迷っていました。条件式は問題なくできていました。えみちゃんは文章を最後まで読むんでほしいです。能力があるので、', null, null),
  ('93aa36e8-cfff-5aea-b5ea-c2cd21409520', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-11-06', '16:30:00', null, '通常 / 検定練習', '検定は受けるので、やる気を持ってやってほしかったが、前半はやる気もって遊び惚けてしまい、後半は集中切れてしまいました。こたろうくんに翻弄されて、コードあやふやになっていました。それで、後半は集中力が持たなくなり、何をしても続かない状態でした。次回は、離して検定に集中してもらいたいです。', null, null),
  ('917f89b6-3a57-52b5-8514-4e9ec4b8e312', 'f3102a36-fdd8-574f-bf3c-85723faf424f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-11-06', '16:30:00', null, '通常 / 検定練習', '検定の内容は理解できて、間違えずに作ることはできますが、はやり途中でメッセージ名や変数の名前を変えようとしていました。また、授業時間外は見逃していましたが、本物のマイクラをやっていました。、検定を早く終わって自由時間にもやろうとしていたので、スクラッチとは関係はないので、さすがに止めました。授業時間外にもるいこたろうが反応してしまうので、やめた方がいいか？', null, null),
  ('836899cc-bdd1-5b3e-9fd0-574a6f7b641e', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-11-06', '17:30:00', null, '通常 / 検定練習', '内容自体はあまり迷わずにできていました。途中、「かつ」の使い方に忘れたような気がしていましたが、1つヒントを与えれば、自分で理解できていました。終わって確認してもらうので、先生に遊んでもらったり、余裕でできていました。次回はスロットのやつをやりたいそうです。', null, null),
  ('f5ae76fb-c25f-56ea-a7db-4fac02ee2244', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-11-06', '17:30:00', null, '通常 / 検定練習', '変数の値に関して悩んでいました。変数に「変数に-1を掛けた値」となっていて、言葉が連続して混乱していました。＊の使い方もあやふやだったので、まずは７＊６などを数字に置き換えて、考えていけば理解できていました。そこから変数ぶっろっくに直せていけば、文の理解ができました。また、一通りできたとしても動きがぎこちなかったので、おかしい所を問題文からみなおしました。、音ブロックに「終わるまで」が必要ないのに入っていたミスでした。このミスは、はる君がよくやりがちなので、次回に声かけをした方がよいことです。時間は、悩まなければ終わりそうです。', null, null),
  ('b3e01877-a689-5f1f-a711-a751dd50b505', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'baf0d64d-8a04-5f1d-b7ba-c0c76d280c08', '2025-11-07', '17:30:00', null, '通常 / 検定練習', '走者きょうりゅうの動作で馬に触れた時に恐竜も一緒に動いてしまうところでつまずいていた。ブロックを一つずつ噛み砕いて確認していったら無事動いた。基本的に一人で黙々と進めていた。 15分ほど余ってゲームをしていた。', null, '盛り上がり: 真面目に取り組んでいた。落ち着きがあった。'),
  ('e538f10a-52fe-554b-8ba0-bbad7a655d48', '10db50c3-a153-502a-b455-c67362b9871c', null, 'baf0d64d-8a04-5f1d-b7ba-c0c76d280c08', '2025-11-07', '17:30:00', null, '通常 / 検定練習', '基本的に一人で進めれていた。ハンバーガーの具材をクリックしても反応しないバグで少しつまずいていたが、ほぼ一人の力で解決していた。50分ほどで課題の内容はクリアした。あとの時間は具材を増やしたり、注文される具材の確率をアレンジしていた。全体的に集中力が途切れることなく取り組んでいた。', null, '盛り上がり: 終始楽しそうに勉強していた。'),
  ('5bf8bf43-9206-5af0-af22-a62b5f558d70', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-11-08', null, null, '通常 / 検定１級対策', '１級応用課題１に取り組みました。特にこれといった質問もなく進み時間となりましたが、答え合わせはできませんでした。次回は答え合わせをして、理解が弱いところを復習してから、別の問題ができたらと思います。', null, '時間帯: その他'),
  ('62f04a14-1db1-5aac-b477-308c15b05497', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-11-08', null, null, '通常 / ロブロックス', '今日は、魔法のレンガブロックを最初から始めて８０％ほど完了させました。状況を確認しながら、時々不明点がないか確認しましたが、特になく、問題なく自走できていました。まだ、そんなに難しいとは感じていない状態で順調だと思います。', null, '時間帯: その他')
on conflict (lesson_record_id) do update set lesson_date = excluded.lesson_date, start_time = excluded.start_time, end_time = excluded.end_time, title = excluded.title, content = excluded.content, homework = excluded.homework, memo = excluded.memo;

commit;
